def runtime_path(path: str | Path) -> Path:
    p = Path(path)
    if p.is_absolute():
        return p
    parts = p.parts
    if parts and parts[0] == "output":
        return OUTPUT_DIR.joinpath(*parts[1:])
    if parts and parts[0] == "alerts":
        return ALERTS_DIR.joinpath(*parts[1:])
    return project_path(p)


