ROXY_THREE_UNIVERSE_RUNTIME_TEMPLATE_PATH = project_path("assets/runtime/roxy_three_universe_runtime.js.html")
ROXY_THREE_INLINE_SOURCE_MARKER = "__ROXY_THREE_INLINE_SOURCE__"


@lru_cache(maxsize=1)
def roxy_three_universe_runtime_template() -> str:
    try:
        template = ROXY_THREE_UNIVERSE_RUNTIME_TEMPLATE_PATH.read_text(encoding="utf-8")
    except OSError as exc:
        raise RuntimeError(f"Roxy Three universe runtime resource unavailable: {exc}") from exc
    if template.count(ROXY_THREE_INLINE_SOURCE_MARKER) != 1:
        raise RuntimeError("Roxy Three universe runtime has an invalid vendor marker contract")
    required = ("MutationObserver", "roxy-three-canvas", "roxy-three-fallback-hidden", "</script>")
    if len(template) < 15_000 or any(marker not in template for marker in required):
        raise RuntimeError("Roxy Three universe runtime is incomplete")
    return template


def roxy_three_universe_runtime_markup(three_inline_source: str) -> str:
    return roxy_three_universe_runtime_template().replace(
        ROXY_THREE_INLINE_SOURCE_MARKER,
        roxy_json_for_inline_script(three_inline_source),
    )


