def roxy_user_display_name(default: str = "Roberto") -> str:
    def clean_display_name(raw: Any) -> str:
        value = text_display(raw).strip()
        if not value or value in {"-", "—", "None", "null"}:
            return ""
        return value.split("@")[0].strip().title()

    profile = st.session_state.get("roxy_user_profile")
    if isinstance(profile, dict):
        for key in ("name", "username", "email"):
            value = clean_display_name(profile.get(key))
            if value:
                return value
    user_value = clean_display_name(st.session_state.get("user"))
    if user_value:
        return user_value
    return default


def roxy_auth_db_path() -> str:
    return text_display(getattr(storage, "DB_PATH", project_path("db/roxy.db"))).strip() or str(project_path("db/roxy.db"))


def roxy_auth_attempt_guard() -> AuthAttemptGuard:
    configured = text_display(os.environ.get("ROXY_AUTH_ATTEMPT_DB_PATH")).strip()
    return AuthAttemptGuard(configured or roxy_auth_db_path())


def roxy_secure_auth_db_permissions() -> None:
    database_path = Path(roxy_auth_db_path())
    for candidate in (
        database_path,
        Path(f"{database_path}-wal"),
        Path(f"{database_path}-shm"),
        Path(f"{database_path}-journal"),
    ):
        try:
            if candidate.exists():
                os.chmod(candidate, 0o600)
        except OSError:
            continue


def roxy_auth_db_init() -> None:
    try:
        storage.init_db()
    except Exception:
        pass
    try:
        conn = sqlite3.connect(roxy_auth_db_path())
        cur = conn.cursor()
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS roxy_auth_users (
                username TEXT PRIMARY KEY,
                email TEXT,
                name TEXT,
                profile_json TEXT,
                session_token TEXT,
                updated_at TEXT
            )
            """
        )
        cur.execute("CREATE INDEX IF NOT EXISTS idx_roxy_auth_email ON roxy_auth_users(email)")
        cur.execute("CREATE INDEX IF NOT EXISTS idx_roxy_auth_session ON roxy_auth_users(session_token)")
        conn.commit()
        conn.close()
        AuthAttemptGuard(roxy_auth_db_path())
        roxy_secure_auth_db_permissions()
    except Exception:
        pass


def roxy_load_users_from_file(path: Path) -> dict[str, Any]:
    try:
        raw = path.read_text(encoding="utf-8")
        data = json.loads(raw)
    except (OSError, json.JSONDecodeError):
        return {"users": {}}
    if not isinstance(data, dict):
        return {"users": {}}
    users = data.get("users")
    if not isinstance(users, dict):
        data["users"] = {}
    return data


def roxy_load_users_from_db() -> dict[str, Any]:
    roxy_auth_db_init()
    users: dict[str, dict[str, Any]] = {}
    try:
        conn = sqlite3.connect(roxy_auth_db_path())
        cur = conn.cursor()
        cur.execute("SELECT username, profile_json FROM roxy_auth_users")
        for username, profile_json in cur.fetchall():
            try:
                profile = json.loads(profile_json or "{}")
            except Exception:
                profile = {}
            if isinstance(profile, dict) and username:
                users[text_display(username).strip().lower()] = profile
        conn.close()
    except Exception:
        return {"users": {}}
    return {"users": users}


def roxy_save_users_to_db(data: dict[str, Any]) -> None:
    roxy_auth_db_init()
    users = data.get("users") if isinstance(data, dict) else {}
    if not isinstance(users, dict):
        return
    try:
        conn = sqlite3.connect(roxy_auth_db_path())
        cur = conn.cursor()
        now = datetime.now(timezone.utc).isoformat()
        for username, profile in users.items():
            if not isinstance(profile, dict):
                continue
            clean_username = text_display(username or profile.get("username")).strip().lower()
            if not clean_username:
                continue
            profile = dict(profile)
            profile["username"] = clean_username
            cur.execute(
                """
                INSERT INTO roxy_auth_users (username, email, name, profile_json, session_token, updated_at)
                VALUES (?, ?, ?, ?, ?, ?)
                ON CONFLICT(username) DO UPDATE SET
                    email=excluded.email,
                    name=excluded.name,
                    profile_json=excluded.profile_json,
                    session_token=excluded.session_token,
                    updated_at=excluded.updated_at
                """,
                (
                    clean_username,
                    text_display(profile.get("email")).strip().lower(),
                    text_display(profile.get("name")).strip(),
                    json.dumps(profile, ensure_ascii=True),
                    str(profile.get("session_token") or "").strip(),
                    now,
                ),
            )
        conn.commit()
        conn.close()
        roxy_secure_auth_db_permissions()
    except Exception:
        pass


def roxy_migrate_legacy_session_tokens(data: dict[str, Any]) -> bool:
    """Replace legacy plaintext session tokens with one-way hashes in memory."""
    users = data.get("users") if isinstance(data, dict) else None
    if not isinstance(users, dict):
        return False
    changed = False
    migrated_at = datetime.now(timezone.utc).isoformat()
    for profile in users.values():
        if not isinstance(profile, dict) or "session_token" not in profile:
            continue
        legacy_token = text_display(profile.pop("session_token", None)).strip()
        changed = True
        if len(legacy_token) < 24:
            continue
        profile["session_token_hash"] = hashlib.sha256(legacy_token.encode("utf-8")).hexdigest()
        if roxy_session_timestamp(profile.get("session_updated_at")) is None:
            profile["session_updated_at"] = migrated_at
        profile["session_storage_migrated_at"] = migrated_at
    return changed


def roxy_load_users() -> dict[str, Any]:
    db_data = roxy_load_users_from_db()
    primary_data = roxy_load_users_from_file(ROXY_USERS_PATH)
    fallback_data = roxy_load_users_from_file(ROXY_USERS_FALLBACK_PATH) if ROXY_USERS_FALLBACK_PATH != ROXY_USERS_PATH else {"users": {}}
    merged: dict[str, Any] = {"users": {}}
    for source in (fallback_data, primary_data, db_data):
        users = source.get("users") if isinstance(source, dict) else {}
        if isinstance(users, dict):
            for username, profile in users.items():
                if isinstance(profile, dict):
                    clean_username = text_display(username or profile.get("username")).strip().lower()
                    if clean_username:
                        merged["users"][clean_username] = dict(profile, username=clean_username)
    migrated_legacy_sessions = roxy_migrate_legacy_session_tokens(merged)
    if migrated_legacy_sessions:
        roxy_save_users(merged)
    elif merged["users"] and (not db_data.get("users") or len(merged["users"]) > len(db_data.get("users", {}))):
        roxy_save_users_to_db(merged)
    return merged


def roxy_save_users(data: dict[str, Any]) -> None:
    roxy_save_users_to_db(data)
    serialized = json.dumps(data, indent=2, ensure_ascii=True)
    for path in dict.fromkeys([ROXY_USERS_PATH, ROXY_USERS_FALLBACK_PATH]):
        temporary_path: Path | None = None
        try:
            path.parent.mkdir(parents=True, exist_ok=True)
            lock_path = path.with_name(f".{path.name}.lock")
            with lock_path.open("a+", encoding="utf-8") as lock_handle:
                try:
                    os.chmod(lock_path, 0o600)
                except OSError:
                    pass
                if fcntl is not None:
                    fcntl.flock(lock_handle.fileno(), fcntl.LOCK_EX)
                fd, temporary_name = tempfile.mkstemp(
                    prefix=f".{path.name}.",
                    suffix=".tmp",
                    dir=str(path.parent),
                )
                temporary_path = Path(temporary_name)
                try:
                    os.fchmod(fd, 0o600)
                    with os.fdopen(fd, "w", encoding="utf-8") as handle:
                        handle.write(serialized)
                        handle.flush()
                        os.fsync(handle.fileno())
                    os.replace(temporary_path, path)
                    temporary_path = None
                    os.chmod(path, 0o600)
                    try:
                        directory_fd = os.open(str(path.parent), os.O_RDONLY)
                    except OSError:
                        directory_fd = None
                    if directory_fd is not None:
                        try:
                            os.fsync(directory_fd)
                        finally:
                            os.close(directory_fd)
                finally:
                    if temporary_path is not None:
                        temporary_path.unlink(missing_ok=True)
                    if fcntl is not None:
                        fcntl.flock(lock_handle.fileno(), fcntl.LOCK_UN)
        except OSError:
            continue


def roxy_hash_password(
    password: str,
    salt: str,
    iterations: int = ROXY_PASSWORD_LEGACY_ITERATIONS,
) -> str:
    safe_iterations = max(ROXY_PASSWORD_LEGACY_ITERATIONS, int(iterations))
    return hashlib.pbkdf2_hmac(
        "sha256",
        password.encode("utf-8"),
        salt.encode("utf-8"),
        safe_iterations,
    ).hex()


def roxy_upgrade_password_hash(username: str, password: str, profile: dict[str, Any]) -> dict[str, Any]:
    try:
        current_iterations = int(profile.get("password_iterations") or ROXY_PASSWORD_LEGACY_ITERATIONS)
    except (TypeError, ValueError):
        current_iterations = ROXY_PASSWORD_LEGACY_ITERATIONS
    if current_iterations >= ROXY_PASSWORD_ITERATIONS:
        return profile
    data = roxy_load_users()
    stored_profile = data.get("users", {}).get(text_display(username).strip().lower())
    if not isinstance(stored_profile, dict):
        return profile
    salt = secrets.token_hex(16)
    stored_profile["password_salt"] = salt
    stored_profile["password_hash"] = roxy_hash_password(password, salt, ROXY_PASSWORD_ITERATIONS)
    stored_profile["password_iterations"] = ROXY_PASSWORD_ITERATIONS
    stored_profile["password_upgraded_at"] = datetime.now(timezone.utc).isoformat()
    roxy_save_users(data)
    profile.update(stored_profile)
    return profile


def roxy_b64url_encode(data: bytes) -> str:
    return base64.urlsafe_b64encode(data).rstrip(b"=").decode("ascii")


def roxy_b64url_decode(value: Any) -> bytes:
    clean = text_display(value).strip()
    if not clean:
        return b""
    clean += "=" * (-len(clean) % 4)
    return base64.urlsafe_b64decode(clean.encode("ascii"))


def roxy_json_b64url_encode(payload: dict[str, Any]) -> str:
    return roxy_b64url_encode(json.dumps(payload, separators=(",", ":"), ensure_ascii=True).encode("utf-8"))


def roxy_json_b64url_decode(value: Any) -> dict[str, Any]:
    try:
        decoded = roxy_b64url_decode(value).decode("utf-8")
        payload = json.loads(decoded)
    except Exception:
        return {}
    return payload if isinstance(payload, dict) else {}


def roxy_find_user(identifier: str) -> tuple[str, dict[str, Any]] | tuple[str, None]:
    ident = text_display(identifier).strip().lower()
    if not ident:
        return "", None
    users = roxy_load_users().get("users", {})
    if ident in users and isinstance(users[ident], dict):
        return ident, users[ident]
    for username, profile in users.items():
        if not isinstance(profile, dict):
            continue
        if text_display(profile.get("email")).strip().lower() == ident:
            return str(username), profile
    return "", None


def roxy_user_passkeys(profile: dict[str, Any] | None) -> list[dict[str, Any]]:
    if not isinstance(profile, dict):
        return []
    passkeys = profile.get("passkeys")
    if not isinstance(passkeys, list):
        return []
    return [item for item in passkeys if isinstance(item, dict) and text_display(item.get("id")).strip()]




def roxy_passkey_challenge_key(action: str) -> str:
    return "pending_passkey_registration" if action == "register" else "pending_passkey_auth"


def roxy_store_passkey_challenge(username: str, action: str, challenge: bytes) -> None:
    safe_username = text_display(username).strip().lower()
    if not safe_username:
        return
    data = roxy_load_users()
    users = data.setdefault("users", {})
    profile = users.get(safe_username)
    if not isinstance(profile, dict):
        return
    profile[roxy_passkey_challenge_key(action)] = {
        "challenge": roxy_b64url_encode(challenge),
        "created_at": datetime.now(timezone.utc).isoformat(),
    }
    roxy_save_users(data)


def roxy_pending_passkey_challenge(profile: dict[str, Any], action: str) -> bytes:
    pending = profile.get(roxy_passkey_challenge_key(action))
    if not isinstance(pending, dict):
        return b""
    try:
        created = datetime.fromisoformat(text_display(pending.get("created_at")).replace("Z", "+00:00"))
    except Exception:
        return b""
    if created.tzinfo is None:
        created = created.replace(tzinfo=timezone.utc)
    if datetime.now(timezone.utc) - created > timedelta(seconds=ROXY_PASSKEY_PENDING_SECONDS):
        return b""
    return roxy_b64url_decode(pending.get("challenge"))




def roxy_expected_webauthn_context(payload: dict[str, Any]) -> tuple[str, str]:
    origin = text_display(payload.get("origin")).strip()
    rp_id = text_display(payload.get("rpId")).strip().lower()
    parsed = urlparse(origin)
    host = text_display(parsed.hostname).strip().lower()
    if not origin or not rp_id or not host:
        return "", ""
    if rp_id != host and not host.endswith(f".{rp_id}"):
        return "", ""
    if parsed.scheme == "http" and host not in {"localhost", "127.0.0.1"}:
        return "", ""
    if parsed.scheme not in {"http", "https"}:
        return "", ""
    return origin, rp_id


def roxy_passkey_registration_options(username: str, profile: dict[str, Any]) -> tuple[bool, str, dict[str, Any]]:
    if not ROXY_WEBAUTHN_AVAILABLE:
        return False, "Face ID necesita instalar la dependencia webauthn en el servidor.", {}
    assert generate_registration_options and options_to_json and AuthenticatorSelectionCriteria
    display_name = text_display(profile.get("name") or username).strip() or username
    existing = []
    for passkey in roxy_user_passkeys(profile):
        try:
            existing.append(PublicKeyCredentialDescriptor(id=roxy_b64url_decode(passkey.get("id"))))
        except Exception:
            continue
    options = generate_registration_options(
        rp_id="localhost",
        rp_name="Roxy Trading",
        user_name=username,
        user_id=hashlib.sha256(f"roxy:{username}".encode("utf-8")).digest(),
        user_display_name=display_name,
        timeout=60000,
        authenticator_selection=AuthenticatorSelectionCriteria(
            resident_key=ResidentKeyRequirement.PREFERRED if ResidentKeyRequirement else None,
            user_verification=UserVerificationRequirement.REQUIRED if UserVerificationRequirement else None,
        ),
        exclude_credentials=existing or None,
    )
    roxy_store_passkey_challenge(username, "register", options.challenge)
    return True, "", json.loads(options_to_json(options))


def roxy_passkey_authentication_options(identifier: str) -> tuple[bool, str, dict[str, Any], str]:
    if not ROXY_WEBAUTHN_AVAILABLE:
        return False, "Face ID necesita instalar la dependencia webauthn en el servidor.", {}, ""
    username, profile = roxy_find_user(identifier)
    if not username or not isinstance(profile, dict):
        return False, "Escribe el usuario o correo registrado antes de usar Face ID.", {}, ""
    passkeys = roxy_user_passkeys(profile)
    if not passkeys:
        return False, "Esta cuenta todavia no tiene Face ID activado. Entra con contrasena y actívalo.", {}, username
    descriptors = []
    for passkey in passkeys:
        try:
            descriptors.append(PublicKeyCredentialDescriptor(id=roxy_b64url_decode(passkey.get("id"))))
        except Exception:
            continue
    if not descriptors:
        return False, "No pude preparar el passkey de esta cuenta.", {}, username
    assert generate_authentication_options and options_to_json
    options = generate_authentication_options(
        rp_id="localhost",
        timeout=60000,
        allow_credentials=descriptors,
        user_verification=UserVerificationRequirement.REQUIRED if UserVerificationRequirement else None,
    )
    roxy_store_passkey_challenge(username, "auth", options.challenge)
    return True, "", json.loads(options_to_json(options)), username


def roxy_clear_passkey_query_params() -> None:
    for key in (ROXY_PASSKEY_ACTION_PARAM, ROXY_PASSKEY_RESULT_PARAM):
        try:
            del st.query_params[key]
        except Exception:
            pass


def roxy_process_passkey_result() -> tuple[bool, str]:
    action = first_query_param_value(st.query_params, ROXY_PASSKEY_ACTION_PARAM)
    encoded = first_query_param_value(st.query_params, ROXY_PASSKEY_RESULT_PARAM)
    if action not in {"register", "auth"} or not encoded:
        return False, ""
    payload = roxy_json_b64url_decode(encoded)
    credential = payload.get("credential") if isinstance(payload, dict) else None
    username = text_display(payload.get("username")).strip().lower() if isinstance(payload, dict) else ""
    origin, rp_id = roxy_expected_webauthn_context(payload)
    if not ROXY_WEBAUTHN_AVAILABLE or not isinstance(credential, dict) or not username or not origin or not rp_id:
        roxy_clear_passkey_query_params()
        return False, "No pude validar Face ID. Usa usuario y contrasena e intenta activar el passkey otra vez."
    data = roxy_load_users()
    users = data.setdefault("users", {})
    profile = users.get(username)
    if not isinstance(profile, dict):
        roxy_clear_passkey_query_params()
        return False, "No encontre la cuenta asociada a este Face ID."
    challenge = roxy_pending_passkey_challenge(profile, "register" if action == "register" else "auth")
    if not challenge:
        roxy_clear_passkey_query_params()
        return False, "El intento de Face ID expiro. Vuelve a intentarlo."
    try:
        if action == "register":
            assert verify_registration_response
            verified = verify_registration_response(
                credential=credential,
                expected_challenge=challenge,
                expected_rp_id=rp_id,
                expected_origin=origin,
                require_user_verification=True,
            )
            credential_id = roxy_b64url_encode(verified.credential_id)
            passkeys = profile.setdefault("passkeys", [])
            passkeys = [item for item in passkeys if not isinstance(item, dict) or item.get("id") != credential_id]
            passkeys.append(
                {
                    "id": credential_id,
                    "public_key": roxy_b64url_encode(verified.credential_public_key),
                    "sign_count": int(verified.sign_count or 0),
                    "device": "Face ID / Passkey",
                    "created_at": datetime.now(timezone.utc).isoformat(),
                    "last_used_at": "",
                    "rp_id": rp_id,
                }
            )
            profile["passkeys"] = passkeys
            profile.pop("passkey_offer_dismissed", None)
            profile.pop(roxy_passkey_challenge_key("register"), None)
            users[username] = profile
            roxy_save_users(data)
            roxy_clear_passkey_query_params()
            st.session_state.pop("roxy_passkey_registration_options", None)
            st.session_state.roxy_passkey_offer_visible = False
            roxy_remember_authenticated_user(username, profile)
            return True, "Face ID / Passkey quedo activado para esta cuenta."
        assert verify_authentication_response
        credential_id = text_display(credential.get("id") or credential.get("rawId")).strip()
        passkeys = roxy_user_passkeys(profile)
        matched = next((item for item in passkeys if text_display(item.get("id")).strip() == credential_id), None)
        if not matched:
            raise ValueError("Passkey no reconocido para esta cuenta.")
        verified = verify_authentication_response(
            credential=credential,
            expected_challenge=challenge,
            expected_rp_id=rp_id,
            expected_origin=origin,
            credential_public_key=roxy_b64url_decode(matched.get("public_key")),
            credential_current_sign_count=int(matched.get("sign_count") or 0),
            require_user_verification=True,
        )
        matched["sign_count"] = int(verified.new_sign_count or matched.get("sign_count") or 0)
        matched["last_used_at"] = datetime.now(timezone.utc).isoformat()
        profile["passkeys"] = passkeys
        profile.pop(roxy_passkey_challenge_key("auth"), None)
        users[username] = profile
        roxy_save_users(data)
        roxy_clear_passkey_query_params()
        st.session_state.pop("roxy_passkey_auth_options", None)
        st.session_state.pop("roxy_passkey_auth_username", None)
        roxy_remember_authenticated_user(username, profile)
        return True, f"Bienvenido, {text_display(profile.get('name') or username)}. Face ID confirmado."
    except Exception as exc:
        roxy_clear_passkey_query_params()
        return False, f"Face ID no se pudo validar: {text_display(exc)}"


def render_roxy_passkey_launcher(action: str, username: str, options: dict[str, Any], label: str) -> None:
    if not isinstance(options, dict) or not options:
        return
    options_json = json.dumps(options)
    action_js = json.dumps(action)
    username_js = json.dumps(text_display(username).strip().lower())
    label_html = html.escape(label)
    components.html(
        f"""
        <div class="rx-passkey-frame">
          <button id="rxPasskeyButton" type="button">{label_html}</button>
          <small id="rxPasskeyStatus">Face ID / Passkey se abre en tu dispositivo seguro.</small>
        </div>
        <script>
        (() => {{
          const parentWindow = window.parent || window;
          const button = document.getElementById("rxPasskeyButton");
          const status = document.getElementById("rxPasskeyStatus");
          const action = {action_js};
          const username = {username_js};
          const originalOptions = {options_json};
          const actionParam = "{ROXY_PASSKEY_ACTION_PARAM}";
          const resultParam = "{ROXY_PASSKEY_RESULT_PARAM}";
          const bytesToB64Url = (buffer) => {{
            const bytes = buffer instanceof Uint8Array ? buffer : new Uint8Array(buffer);
            let binary = "";
            for (let i = 0; i < bytes.length; i += 0x8000) {{
              binary += String.fromCharCode(...bytes.subarray(i, i + 0x8000));
            }}
            return btoa(binary).replace(/\\+/g, "-").replace(/\\//g, "_").replace(/=+$/g, "");
          }};
          const b64UrlToBytes = (value) => {{
            const padded = String(value || "").replace(/-/g, "+").replace(/_/g, "/").padEnd(Math.ceil(String(value || "").length / 4) * 4, "=");
            const binary = atob(padded);
            const bytes = new Uint8Array(binary.length);
            for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
            return bytes;
          }};
          const encodePayload = (payload) => bytesToB64Url(new TextEncoder().encode(JSON.stringify(payload)));
          const currentOrigin = () => parentWindow.location.origin;
          const currentRpId = () => parentWindow.location.hostname;
          const cleanCreationOptions = () => {{
            const publicKey = JSON.parse(JSON.stringify(originalOptions));
            publicKey.challenge = b64UrlToBytes(publicKey.challenge);
            if (publicKey.user && publicKey.user.id) publicKey.user.id = b64UrlToBytes(publicKey.user.id);
            if (publicKey.rp) publicKey.rp.id = currentRpId();
            (publicKey.excludeCredentials || []).forEach((cred) => {{ cred.id = b64UrlToBytes(cred.id); }});
            return publicKey;
          }};
          const cleanRequestOptions = () => {{
            const publicKey = JSON.parse(JSON.stringify(originalOptions));
            publicKey.challenge = b64UrlToBytes(publicKey.challenge);
            publicKey.rpId = currentRpId();
            (publicKey.allowCredentials || []).forEach((cred) => {{ cred.id = b64UrlToBytes(cred.id); }});
            return publicKey;
          }};
          const sendPayload = (credential) => {{
            const url = new URL(parentWindow.location.href);
            url.searchParams.set(actionParam, action);
            url.searchParams.set(resultParam, encodePayload({{
              username,
              rpId: currentRpId(),
              origin: currentOrigin(),
              credential,
            }}));
            parentWindow.location.href = url.toString();
          }};
          const register = async () => {{
            const publicKey = cleanCreationOptions();
            const cred = await navigator.credentials.create({{ publicKey }});
            sendPayload({{
              id: cred.id,
              rawId: bytesToB64Url(cred.rawId),
              type: cred.type,
              response: {{
                clientDataJSON: bytesToB64Url(cred.response.clientDataJSON),
                attestationObject: bytesToB64Url(cred.response.attestationObject),
                transports: cred.response.getTransports ? cred.response.getTransports() : [],
              }},
              authenticatorAttachment: cred.authenticatorAttachment || null,
              clientExtensionResults: cred.getClientExtensionResults ? cred.getClientExtensionResults() : {{}},
            }});
          }};
          const authenticate = async () => {{
            const publicKey = cleanRequestOptions();
            const cred = await navigator.credentials.get({{ publicKey }});
            sendPayload({{
              id: cred.id,
              rawId: bytesToB64Url(cred.rawId),
              type: cred.type,
              response: {{
                clientDataJSON: bytesToB64Url(cred.response.clientDataJSON),
                authenticatorData: bytesToB64Url(cred.response.authenticatorData),
                signature: bytesToB64Url(cred.response.signature),
                userHandle: cred.response.userHandle ? bytesToB64Url(cred.response.userHandle) : null,
              }},
              authenticatorAttachment: cred.authenticatorAttachment || null,
              clientExtensionResults: cred.getClientExtensionResults ? cred.getClientExtensionResults() : {{}},
            }});
          }};
          button.addEventListener("click", async () => {{
            try {{
              if (!window.PublicKeyCredential || !navigator.credentials) {{
                status.textContent = "Este navegador no soporta passkeys. Usa contraseña.";
                return;
              }}
              status.textContent = "Abriendo seguridad del dispositivo...";
              if (action === "register") await register();
              else await authenticate();
            }} catch (error) {{
              status.textContent = error && error.name === "NotAllowedError"
                ? "Face ID fue cancelado o expiró. Inténtalo otra vez."
                : "No pude abrir Face ID: " + (error && error.message ? error.message : error);
            }}
          }});
        }})();
        </script>
        <style>
          .rx-passkey-frame{{font-family:Inter,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;padding:2px 0 8px;background:transparent}}
          .rx-passkey-frame button{{width:100%;min-height:54px;border:1px solid rgba(125,211,252,.42);border-radius:10px;background:linear-gradient(180deg,#10b4ff,#0b63f6 66%,#063bbb);color:white;font-size:16px;font-weight:900;box-shadow:0 16px 34px rgba(37,99,235,.34),0 0 24px rgba(56,189,248,.20);cursor:pointer}}
          .rx-passkey-frame small{{display:block;margin-top:8px;color:#9cc7e8;font-size:12px;line-height:1.25;text-align:center}}
        </style>
        """,
        height=86,
    )


def render_roxy_passkey_setup_panel() -> None:
    username = text_display(st.session_state.get("user")).strip().lower()
    if not username:
        return
    _, profile = roxy_find_user(username)
    if not isinstance(profile, dict):
        return
    passkey_count = len(roxy_user_passkeys(profile))
    manage_visible = bool(st.session_state.get("roxy_passkey_manage_visible"))
    if passkey_count and not manage_visible:
        return
    if not manage_visible and bool(profile.get("passkey_offer_dismissed")):
        return
    if not manage_visible and not st.session_state.get("roxy_passkey_offer_visible", passkey_count == 0):
        return
    display_name = text_display(profile.get("name") or username).strip() or username
    st.markdown(
        f"""
        <section class="roxy-passkey-panel">
          <div><i class="material-symbols-outlined">passkey</i></div>
          <article>
            <strong>Activar Face ID para {html.escape(display_name)}</strong>
            <span>Roxy usara un passkey seguro del dispositivo. En iPhone se abre Face ID; en Mac puede abrir Touch ID o passkey.</span>
          </article>
        </section>
        """,
        unsafe_allow_html=True,
    )
    col_enable, col_skip = st.columns([2, 1])
    with col_enable:
        if st.button("Activar Face ID / Passkey", key="roxy_enable_passkey"):
            ok, msg, options = roxy_passkey_registration_options(username, profile)
            if ok:
                st.session_state["roxy_passkey_registration_options"] = options
            else:
                st.error(msg)
    with col_skip:
        if st.button("Ahora no", key="roxy_skip_passkey"):
            data = roxy_load_users()
            stored_profile = data.get("users", {}).get(username)
            if isinstance(stored_profile, dict):
                stored_profile["passkey_offer_dismissed"] = True
                data["users"][username] = stored_profile
                roxy_save_users(data)
            st.session_state.roxy_passkey_offer_visible = False
            st.rerun()
    options = st.session_state.get("roxy_passkey_registration_options")
    if isinstance(options, dict) and options:
        render_roxy_passkey_launcher("register", username, options, "Abrir Face ID ahora")


def roxy_session_token_from_query() -> str:
    token = text_display(first_query_param_value(st.query_params, ROXY_SESSION_PARAM)).strip()
    return token if len(token) >= 24 else ""




def roxy_issue_session_token(username: str) -> str:
    safe_username = text_display(username).strip().lower()
    if not safe_username:
        return ""
    data = roxy_load_users()
    users = data.setdefault("users", {})
    profile = users.get(safe_username)
    if not isinstance(profile, dict):
        return ""
    token = secrets.token_urlsafe(32)
    profile["session_token_hash"] = hashlib.sha256(token.encode("utf-8")).hexdigest()
    profile.pop("session_token", None)
    profile["session_updated_at"] = datetime.now(timezone.utc).isoformat()
    roxy_save_users(data)
    return token


def roxy_session_max_age_seconds() -> int:
    raw = text_display(os.environ.get("ROXY_SESSION_MAX_AGE_SECONDS")).strip()
    try:
        configured = int(raw) if raw else ROXY_SESSION_MAX_AGE_SECONDS_DEFAULT
    except (TypeError, ValueError):
        configured = ROXY_SESSION_MAX_AGE_SECONDS_DEFAULT
    return min(365 * 24 * 60 * 60, max(60 * 60, configured))


def roxy_session_timestamp(value: Any) -> datetime | None:
    clean = text_display(value).strip()
    if not clean:
        return None
    try:
        parsed = datetime.fromisoformat(clean.replace("Z", "+00:00"))
    except ValueError:
        return None
    if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=timezone.utc)
    return parsed.astimezone(timezone.utc)


def roxy_find_user_by_session_token(
    token: str,
    *,
    now: datetime | None = None,
) -> tuple[str, dict[str, Any]] | tuple[str, None]:
    clean_token = text_display(token).strip()
    if len(clean_token) < 24:
        return "", None
    current = now or datetime.now(timezone.utc)
    if current.tzinfo is None:
        current = current.replace(tzinfo=timezone.utc)
    current = current.astimezone(timezone.utc)
    data = roxy_load_users()
    users = data.get("users", {})
    supplied_hash = hashlib.sha256(clean_token.encode("utf-8")).hexdigest()
    for username, profile in users.items():
        if not isinstance(profile, dict):
            continue
        stored_hash = text_display(profile.get("session_token_hash")).strip()
        legacy_token = text_display(profile.get("session_token")).strip()
        hash_match = len(stored_hash) == 64 and secrets.compare_digest(stored_hash, supplied_hash)
        legacy_match = len(legacy_token) >= 24 and secrets.compare_digest(legacy_token, clean_token)
        if hash_match or legacy_match:
            issued_at = roxy_session_timestamp(profile.get("session_updated_at"))
            if issued_at is None and legacy_match:
                issued_at = current
                profile["session_updated_at"] = current.isoformat()
            expired = issued_at is None or (current - issued_at).total_seconds() > roxy_session_max_age_seconds()
            if expired:
                profile.pop("session_token_hash", None)
                profile.pop("session_token", None)
                profile["session_expired_at"] = current.isoformat()
                roxy_save_users(data)
                return "", None
            if legacy_match:
                profile["session_token_hash"] = supplied_hash
                profile.pop("session_token", None)
                roxy_save_users(data)
            return str(username), profile
    return "", None


def roxy_set_authenticated_user(username: str, profile: dict[str, Any], *, announce: bool = True) -> None:
    safe_username = text_display(username).strip()
    display_name = text_display(profile.get("name") or safe_username).strip()
    st.session_state.user = safe_username
    st.session_state.roxy_user_profile = {
        "username": safe_username,
        "name": display_name or safe_username,
        "email": text_display(profile.get("email")).strip(),
        "language": text_display(profile.get("language") or "es").strip() or "es",
    }
    if announce:
        st.session_state.roxy_launch_message = f"Bienvenido, {display_name or safe_username}. Roxy ya reconoce tu perfil."
    try:
        storage.create_account_if_missing(safe_username)
    except Exception:
        pass
    try:
        del st.query_params["auth"]
    except Exception:
        pass


def roxy_public_profile_payload(username: str, profile: dict[str, Any], token: str = "") -> dict[str, Any]:
    safe_username = text_display(username or profile.get("username")).strip().lower()
    return {
        "username": safe_username,
        "name": text_display(profile.get("name") or safe_username).strip(),
        "email": str(profile.get("email") or "").strip().lower(),
        "language": text_display(profile.get("language") or "es").strip() or "es",
    }


def roxy_remember_authenticated_user(username: str, profile: dict[str, Any]) -> None:
    roxy_set_authenticated_user(username, profile)
    st.session_state.roxy_passkey_offer_visible = (
        len(roxy_user_passkeys(profile)) == 0 and not bool(profile.get("passkey_offer_dismissed"))
    )
    token = roxy_issue_session_token(username)
    if token:
        st.session_state.roxy_session_token = token
        st.session_state.roxy_public_profile = roxy_public_profile_payload(username, profile, token)




def roxy_clear_session_query_secrets() -> None:
    for key in (ROXY_SESSION_PARAM, ROXY_PROFILE_PARAM):
        try:
            del st.query_params[key]
        except Exception:
            pass


def roxy_restore_user_from_session() -> bool:
    if st.session_state.get("user"):
        return True
    token = roxy_session_token_from_query()
    if not token:
        return False
    username, profile = roxy_find_user_by_session_token(token)
    if not username or not isinstance(profile, dict):
        st.session_state.roxy_invalid_session_token = True
        roxy_clear_session_query_secrets()
        return False
    roxy_set_authenticated_user(username, profile, announce=False)
    st.session_state.roxy_session_token = token
    st.session_state.roxy_public_profile = roxy_public_profile_payload(username, profile, token)
    st.session_state.pop("roxy_invalid_session_token", None)
    roxy_clear_session_query_secrets()
    return True


def roxy_logout_user() -> None:
    username = text_display(st.session_state.get("user")).strip().lower()
    if username:
        data = roxy_load_users()
        profile = data.get("users", {}).get(username)
        if isinstance(profile, dict):
            profile.pop("session_token_hash", None)
            profile.pop("session_token", None)
            profile["session_revoked_at"] = datetime.now(timezone.utc).isoformat()
            roxy_save_users(data)
    for key in (
        "user",
        "roxy_user_profile",
        "roxy_session_token",
        "roxy_public_profile",
        "roxy_passkey_offer_visible",
    ):
        st.session_state.pop(key, None)
    roxy_clear_session_query_secrets()
    st.query_params["auth"] = "login"
    st.query_params[ROXY_LOGOUT_PARAM] = "1"


def roxy_verify_diagnostic_probe_token(
    token: Any,
    *,
    secret_path: str | Path = ROXY_DIAGNOSTIC_PROBE_SECRET_PATH,
    now: int | None = None,
    max_age_seconds: int = 180,
) -> bool:
    parts = str(token or "").strip().split(".")
    if len(parts) != 3:
        return False
    timestamp_text, nonce, supplied_signature = parts
    if not timestamp_text.isdigit() or len(nonce) < 24 or len(supplied_signature) != 64:
        return False
    current = int(time.time() if now is None else now)
    timestamp = int(timestamp_text)
    if timestamp > current + 15 or current - timestamp > max(30, int(max_age_seconds)):
        return False
    path = Path(secret_path)
    try:
        secret = path.read_bytes()
    except OSError:
        return False
    if len(secret) < 32:
        return False
    message = f"{timestamp_text}.{nonce}".encode("utf-8")
    expected = hmac.new(secret, message, hashlib.sha256).hexdigest()
    return hmac.compare_digest(expected, supplied_signature)


def roxy_restore_diagnostic_probe_session() -> bool:
    token = first_query_param_value(st.query_params, ROXY_DIAGNOSTIC_PROBE_PARAM)
    if not roxy_verify_diagnostic_probe_token(token):
        return False
    st.session_state.roxy_diagnostic_probe = True
    roxy_set_authenticated_user(
        "__roxy_diagnostic_probe__",
        {
            "name": "Roxy Diagnostic",
            "email": "",
            "language": "es",
        },
        announce=False,
    )
    return True


def render_roxy_browser_session_bridge(active: bool = True) -> None:
    token = str(st.session_state.get("roxy_session_token") or "").strip()
    storage_key = html.escape(ROXY_SESSION_STORAGE_KEY, quote=True)
    profile_storage_key = html.escape(ROXY_PROFILE_STORAGE_KEY, quote=True)
    param_key = html.escape(ROXY_SESSION_PARAM, quote=True)
    profile_param_key = html.escape(ROXY_PROFILE_PARAM, quote=True)
    token_js = json.dumps(token)
    profile_payload = st.session_state.get("roxy_public_profile")
    if not isinstance(profile_payload, dict):
        profile = st.session_state.get("roxy_user_profile")
        profile_payload = roxy_public_profile_payload(
            st.session_state.get("user"),
            profile if isinstance(profile, dict) else {},
        )
    profile_js = json.dumps(profile_payload, ensure_ascii=False)
    active_js = "true" if active else "false"
    components.html(
        f"""
        <script>
        (() => {{
          const parentWindow = window.parent || window;
          const storageKey = "{storage_key}";
          const profileStorageKey = "{profile_storage_key}";
          const explicitToken = {token_js};
          const explicitProfile = {profile_js};
          if (explicitToken && {active_js}) parentWindow.localStorage.setItem(storageKey, explicitToken);
          if ({active_js} && explicitProfile && (explicitProfile.username || explicitProfile.email)) {{
            parentWindow.localStorage.setItem(profileStorageKey, JSON.stringify(explicitProfile));
          }}
          const url = new URL(parentWindow.location.href);
          if (url.searchParams.has("{param_key}") || url.searchParams.has("{profile_param_key}")) {{
            url.searchParams.delete("{param_key}");
            url.searchParams.delete("{profile_param_key}");
            parentWindow.history.replaceState(null, "", url.toString());
          }}
        }})();
        </script>
        """,
        height=0,
    )


def render_roxy_session_restore_bridge() -> None:
    storage_key = html.escape(ROXY_SESSION_STORAGE_KEY, quote=True)
    profile_storage_key = html.escape(ROXY_PROFILE_STORAGE_KEY, quote=True)
    param_key = html.escape(ROXY_SESSION_PARAM, quote=True)
    profile_param_key = html.escape(ROXY_PROFILE_PARAM, quote=True)
    logout_param_key = html.escape(ROXY_LOGOUT_PARAM, quote=True)
    invalid_js = "true" if st.session_state.pop("roxy_invalid_session_token", False) else "false"
    components.html(
        f"""
        <script>
        (() => {{
          const parentWindow = window.parent || window;
          const url = new URL(parentWindow.location.href);
          const mustClear = {invalid_js} || url.searchParams.get("{logout_param_key}") === "1";
          if (mustClear) {{
            parentWindow.localStorage.removeItem("{storage_key}");
            parentWindow.localStorage.removeItem("{profile_storage_key}");
            url.searchParams.delete("{logout_param_key}");
            url.searchParams.delete("{param_key}");
            url.searchParams.delete("{profile_param_key}");
            parentWindow.history.replaceState(null, "", url.toString());
            return;
          }}
          if (url.searchParams.get("{param_key}")) return;
          const token = parentWindow.localStorage.getItem("{storage_key}") || "";
          if (!token) return;
          url.searchParams.set("{param_key}", token);
          parentWindow.history.replaceState(null, "", url.toString());
          parentWindow.location.reload();
        }})();
        </script>
        """,
        height=0,
    )

def roxy_register_user(*, name: str, username: str, email: str, password: str, language: str) -> tuple[bool, str]:
    clean_name = text_display(name).strip()
    clean_username = re.sub(r"[^a-zA-Z0-9_.-]+", "", text_display(username).strip()).lower()
    clean_email = text_display(email).strip().lower()
    clean_language = text_display(language).strip() or "es"
    if len(clean_name) < 2:
        return False, "Escribe tu nombre para que Roxy pueda llamarte correctamente."
    if len(clean_username) < 3:
        return False, "El username debe tener al menos 3 caracteres."
    if "@" not in clean_email or "." not in clean_email.split("@")[-1]:
        return False, "Escribe un correo valido."
    if len(password or "") < ROXY_PASSWORD_MIN_LENGTH:
        return False, f"La contrasena debe tener al menos {ROXY_PASSWORD_MIN_LENGTH} caracteres."
    data = roxy_load_users()
    users = data.setdefault("users", {})
    if clean_username in users:
        return False, "Ese username ya existe. Inicia sesion o usa otro."
    for profile in users.values():
        if isinstance(profile, dict) and text_display(profile.get("email")).strip().lower() == clean_email:
            return False, "Ese correo ya esta registrado."
    salt = secrets.token_hex(16)
    users[clean_username] = {
        "username": clean_username,
        "name": clean_name,
        "email": clean_email,
        "language": clean_language,
        "password_salt": salt,
        "password_hash": roxy_hash_password(password, salt, ROXY_PASSWORD_ITERATIONS),
        "password_iterations": ROXY_PASSWORD_ITERATIONS,
        "created_at": datetime.now(timezone.utc).isoformat(),
    }
    roxy_save_users(data)
    roxy_remember_authenticated_user(clean_username, users[clean_username])
    return True, f"Cuenta creada. Hola {clean_name}, Roxy ya sabe tu nombre."


def roxy_login_user(identifier: str, password: str) -> tuple[bool, str]:
    try:
        attempt_guard = roxy_auth_attempt_guard()
        attempt_status = attempt_guard.status(identifier)
    except Exception:
        return False, "El control de acceso no esta disponible. Intenta de nuevo en unos minutos."
    if not attempt_status.allowed:
        retry_minutes = max(1, math.ceil(attempt_status.retry_after_seconds / 60))
        return False, f"Demasiados intentos. Intenta de nuevo en {retry_minutes} minuto(s)."
    username, profile = roxy_find_user(identifier)
    if not username or not profile:
        # Perform the same password KDF work for unknown and known accounts so
        # response timing does not reveal whether an identifier is registered.
        roxy_hash_password(password or "", "roxy-unknown-account-timing-salt", ROXY_PASSWORD_ITERATIONS)
        failure = attempt_guard.record_failure(identifier)
        if not failure.allowed:
            retry_minutes = max(1, math.ceil(failure.retry_after_seconds / 60))
            return False, f"Demasiados intentos. Intenta de nuevo en {retry_minutes} minuto(s)."
        return False, "Usuario o contrasena incorrectos."
    salt = text_display(profile.get("password_salt"))
    expected = text_display(profile.get("password_hash"))
    try:
        password_iterations = int(profile.get("password_iterations") or ROXY_PASSWORD_LEGACY_ITERATIONS)
    except (TypeError, ValueError):
        password_iterations = ROXY_PASSWORD_LEGACY_ITERATIONS
    if not salt or not expected or not secrets.compare_digest(
        roxy_hash_password(password or "", salt, password_iterations),
        expected,
    ):
        failure = attempt_guard.record_failure(identifier)
        if not failure.allowed:
            retry_minutes = max(1, math.ceil(failure.retry_after_seconds / 60))
            return False, f"Demasiados intentos. Intenta de nuevo en {retry_minutes} minuto(s)."
        return False, "Usuario o contrasena incorrectos."
    attempt_guard.clear(identifier)
    profile = roxy_upgrade_password_hash(username, password or "", profile)
    roxy_remember_authenticated_user(username, profile)
    return True, f"Bienvenido, {text_display(profile.get('name') or username)}."


def roxy_change_password(
    username: str,
    current_password: str,
    new_password: str,
    confirmation: str,
) -> tuple[bool, str]:
    clean_username = text_display(username).strip().lower()
    if not clean_username:
        return False, "No hay una cuenta autenticada."
    if new_password != confirmation:
        return False, "La confirmacion no coincide con la nueva contrasena."
    if len(new_password or "") < ROXY_PASSWORD_MIN_LENGTH:
        return False, f"La nueva contrasena debe tener al menos {ROXY_PASSWORD_MIN_LENGTH} caracteres."
    if secrets.compare_digest(current_password or "", new_password or ""):
        return False, "La nueva contrasena debe ser diferente de la actual."
    try:
        attempt_guard = roxy_auth_attempt_guard()
        attempt_status = attempt_guard.status(clean_username)
    except Exception:
        return False, "El control de acceso no esta disponible. Intenta de nuevo en unos minutos."
    if not attempt_status.allowed:
        retry_minutes = max(1, math.ceil(attempt_status.retry_after_seconds / 60))
        return False, f"Demasiados intentos. Intenta de nuevo en {retry_minutes} minuto(s)."
    data = roxy_load_users()
    profile = data.get("users", {}).get(clean_username)
    if not isinstance(profile, dict):
        return False, "No se encontro la cuenta autenticada."
    salt = text_display(profile.get("password_salt"))
    expected = text_display(profile.get("password_hash"))
    if not salt or not expected:
        return False, "Esta cuenta usa OAuth o passkey y no tiene una contrasena local para cambiar."
    try:
        iterations = int(profile.get("password_iterations") or ROXY_PASSWORD_LEGACY_ITERATIONS)
    except (TypeError, ValueError):
        iterations = ROXY_PASSWORD_LEGACY_ITERATIONS
    if not secrets.compare_digest(
        roxy_hash_password(current_password or "", salt, iterations),
        expected,
    ):
        failure = attempt_guard.record_failure(clean_username)
        if not failure.allowed:
            retry_minutes = max(1, math.ceil(failure.retry_after_seconds / 60))
            return False, f"Demasiados intentos. Intenta de nuevo en {retry_minutes} minuto(s)."
        return False, "La contrasena actual no es correcta."
    attempt_guard.clear(clean_username)
    new_salt = secrets.token_hex(16)
    profile["password_salt"] = new_salt
    profile["password_hash"] = roxy_hash_password(new_password, new_salt, ROXY_PASSWORD_ITERATIONS)
    profile["password_iterations"] = ROXY_PASSWORD_ITERATIONS
    profile["password_changed_at"] = datetime.now(timezone.utc).isoformat()
    profile.pop("session_token_hash", None)
    profile.pop("session_token", None)
    roxy_save_users(data)
    token = roxy_issue_session_token(clean_username)
    if token:
        st.session_state.roxy_session_token = token
        st.session_state.roxy_public_profile = roxy_public_profile_payload(clean_username, profile)
    return True, "Contrasena actualizada. Las otras sesiones recordadas quedaron revocadas."


def roxy_config_value(*keys: str) -> str:
    for key in keys:
        if not key:
            continue
        value = os.environ.get(key)
        if value is not None:
            clean = str(value).strip()
            if clean and clean.lower() not in {"-", "none", "null"}:
                return clean
        try:
            value = st.secrets.get(key)  # type: ignore[attr-defined]
        except Exception:
            value = None
        if value is not None:
            clean = str(value).strip()
            if clean and clean.lower() not in {"-", "none", "null"}:
                return clean
    return ""


def roxy_oauth_secret() -> str:
    configured = roxy_config_value("ROXY_AUTH_SECRET", "ROXY_OAUTH_SECRET", "SECRET_KEY")
    if configured:
        return configured
    return hashlib.sha256(f"roxy-oauth:{ROXY_USERS_PATH}:{ROXY_USERS_FALLBACK_PATH}".encode("utf-8")).hexdigest()


def roxy_default_oauth_redirect_uri() -> str:
    configured = roxy_config_value("ROXY_OAUTH_REDIRECT_URI", "ROXY_PUBLIC_URL", "ROXY_BASE_URL", "STREAMLIT_PUBLIC_URL")
    if configured:
        return configured.rstrip("/") + "/"
    context_url = ""
    try:
        context = getattr(st, "context", None)
        context_url = text_display(getattr(context, "url", "")).strip() if context is not None else ""
    except Exception:
        context_url = ""
    if context_url:
        parsed = urlparse(context_url)
        if parsed.scheme and parsed.netloc:
            return f"{parsed.scheme}://{parsed.netloc}/"
    return ""


def roxy_oauth_redirect_uri(provider: str) -> str:
    clean_provider = text_display(provider).strip().lower()
    if clean_provider == "google":
        return roxy_config_value("ROXY_GOOGLE_REDIRECT_URI", "GOOGLE_REDIRECT_URI") or roxy_default_oauth_redirect_uri()
    if clean_provider == "apple":
        return roxy_config_value("ROXY_APPLE_REDIRECT_URI", "APPLE_REDIRECT_URI") or roxy_default_oauth_redirect_uri()
    return roxy_default_oauth_redirect_uri()


def roxy_oauth_state(provider: str) -> str:
    payload = {
        "provider": text_display(provider).strip().lower(),
        "ts": int(time.time()),
        "nonce": secrets.token_urlsafe(18),
    }
    unsigned = json.dumps(payload, separators=(",", ":"), sort_keys=True).encode("utf-8")
    signature = hmac.new(roxy_oauth_secret().encode("utf-8"), unsigned, hashlib.sha256).hexdigest()
    payload["sig"] = signature
    return roxy_json_b64url_encode(payload)


def roxy_verify_oauth_state(encoded: str) -> tuple[bool, str]:
    payload = roxy_json_b64url_decode(encoded)
    if not payload:
        return False, ""
    signature = text_display(payload.pop("sig", "")).strip()
    unsigned = json.dumps(payload, separators=(",", ":"), sort_keys=True).encode("utf-8")
    expected = hmac.new(roxy_oauth_secret().encode("utf-8"), unsigned, hashlib.sha256).hexdigest()
    try:
        created = int(payload.get("ts") or 0)
    except Exception:
        created = 0
    if not signature or not hmac.compare_digest(signature, expected):
        return False, ""
    if created <= 0 or int(time.time()) - created > ROXY_OAUTH_PENDING_SECONDS:
        return False, ""
    provider = text_display(payload.get("provider")).strip().lower()
    return provider in {"google", "apple"}, provider


def roxy_oauth_config(provider: str) -> tuple[dict[str, str], list[str]]:
    clean_provider = text_display(provider).strip().lower()
    if clean_provider == "google":
        config = {
            "client_id": roxy_config_value("ROXY_GOOGLE_CLIENT_ID", "GOOGLE_CLIENT_ID"),
            "client_secret": roxy_config_value("ROXY_GOOGLE_CLIENT_SECRET", "GOOGLE_CLIENT_SECRET"),
            "redirect_uri": roxy_oauth_redirect_uri("google"),
        }
        labels = {
            "client_id": "ROXY_GOOGLE_CLIENT_ID",
            "client_secret": "ROXY_GOOGLE_CLIENT_SECRET",
            "redirect_uri": "ROXY_PUBLIC_URL o ROXY_GOOGLE_REDIRECT_URI",
        }
    elif clean_provider == "apple":
        config = {
            "client_id": roxy_config_value("ROXY_APPLE_CLIENT_ID", "APPLE_CLIENT_ID"),
            "team_id": roxy_config_value("ROXY_APPLE_TEAM_ID", "APPLE_TEAM_ID"),
            "key_id": roxy_config_value("ROXY_APPLE_KEY_ID", "APPLE_KEY_ID"),
            "private_key": roxy_config_value("ROXY_APPLE_PRIVATE_KEY", "APPLE_PRIVATE_KEY").replace("\\n", "\n"),
            "redirect_uri": roxy_oauth_redirect_uri("apple"),
        }
        labels = {
            "client_id": "ROXY_APPLE_CLIENT_ID",
            "team_id": "ROXY_APPLE_TEAM_ID",
            "key_id": "ROXY_APPLE_KEY_ID",
            "private_key": "ROXY_APPLE_PRIVATE_KEY",
            "redirect_uri": "ROXY_PUBLIC_URL o ROXY_APPLE_REDIRECT_URI",
        }
    else:
        return {}, ["Proveedor OAuth no soportado"]
    missing = [label for key, label in labels.items() if not str(config.get(key) or "").strip()]
    if requests is None:
        missing.append("requests instalado en requirements.txt")
    return config, missing


def roxy_oauth_missing_message(provider_label: str, missing: list[str]) -> str:
    if not missing:
        return ""
    return (
        f"{provider_label} todavia no esta configurado en el servidor. "
        f"Falta: {', '.join(missing)}. Cuando esas variables esten en Render/Secrets, el boton entra directo."
    )


def roxy_build_google_oauth_url() -> tuple[str, list[str]]:
    config, missing = roxy_oauth_config("google")
    if missing:
        return "", missing
    params = {
        "client_id": config["client_id"],
        "redirect_uri": config["redirect_uri"],
        "response_type": "code",
        "scope": "openid email profile",
        "state": roxy_oauth_state("google"),
        "prompt": "select_account",
        "access_type": "offline",
    }
    return f"https://accounts.google.com/o/oauth2/v2/auth?{urlencode(params)}", []


def roxy_build_apple_oauth_url() -> tuple[str, list[str]]:
    config, missing = roxy_oauth_config("apple")
    if missing:
        return "", missing
    params = {
        "client_id": config["client_id"],
        "redirect_uri": config["redirect_uri"],
        "response_type": "code id_token",
        "scope": "name email",
        "response_mode": "query",
        "state": roxy_oauth_state("apple"),
    }
    return f"https://appleid.apple.com/auth/authorize?{urlencode(params)}", []


def roxy_decode_jwt_payload(token: str) -> dict[str, Any]:
    parts = text_display(token).split(".")
    if len(parts) < 2:
        return {}
    return roxy_json_b64url_decode(parts[1])


def roxy_apple_client_secret(config: dict[str, str]) -> str:
    from cryptography.hazmat.primitives import hashes, serialization
    from cryptography.hazmat.primitives.asymmetric import ec
    from cryptography.hazmat.primitives.asymmetric.utils import decode_dss_signature

    now = int(time.time())
    header = {"alg": "ES256", "kid": config["key_id"]}
    payload = {
        "iss": config["team_id"],
        "iat": now,
        "exp": now + 15777000,
        "aud": "https://appleid.apple.com",
        "sub": config["client_id"],
    }
    signing_input = f"{roxy_json_b64url_encode(header)}.{roxy_json_b64url_encode(payload)}"
    private_key = serialization.load_pem_private_key(config["private_key"].encode("utf-8"), password=None)
    signature_der = private_key.sign(signing_input.encode("ascii"), ec.ECDSA(hashes.SHA256()))
    r_value, s_value = decode_dss_signature(signature_der)
    signature = r_value.to_bytes(32, "big") + s_value.to_bytes(32, "big")
    return f"{signing_input}.{roxy_b64url_encode(signature)}"


def roxy_exchange_google_oauth_code(code: str) -> tuple[bool, str, dict[str, Any]]:
    config, missing = roxy_oauth_config("google")
    if missing:
        return False, roxy_oauth_missing_message("Google", missing), {}
    assert requests is not None
    token_response = requests.post(
        "https://oauth2.googleapis.com/token",
        data={
            "code": code,
            "client_id": config["client_id"],
            "client_secret": config["client_secret"],
            "redirect_uri": config["redirect_uri"],
            "grant_type": "authorization_code",
        },
        timeout=15,
    )
    if token_response.status_code >= 400:
        return False, f"Google rechazo el acceso: {token_response.text[:220]}", {}
    token_data = token_response.json()
    access_token = text_display(token_data.get("access_token")).strip()
    if not access_token:
        return False, "Google no devolvio access_token.", {}
    info_response = requests.get(
        "https://openidconnect.googleapis.com/v1/userinfo",
        headers={"Authorization": f"Bearer {access_token}"},
        timeout=15,
    )
    if info_response.status_code >= 400:
        return False, f"No pude leer el perfil de Google: {info_response.text[:220]}", {}
    profile = info_response.json()
    return True, "", profile if isinstance(profile, dict) else {}


def roxy_exchange_apple_oauth_code(code: str) -> tuple[bool, str, dict[str, Any]]:
    config, missing = roxy_oauth_config("apple")
    if missing:
        return False, roxy_oauth_missing_message("Apple", missing), {}
    assert requests is not None
    try:
        client_secret = roxy_apple_client_secret(config)
    except Exception as exc:
        return False, f"No pude firmar el client_secret de Apple: {text_display(exc)}", {}
    token_response = requests.post(
        "https://appleid.apple.com/auth/token",
        data={
            "code": code,
            "client_id": config["client_id"],
            "client_secret": client_secret,
            "redirect_uri": config["redirect_uri"],
            "grant_type": "authorization_code",
        },
        timeout=15,
    )
    if token_response.status_code >= 400:
        return False, f"Apple rechazo el acceso: {token_response.text[:220]}", {}
    token_data = token_response.json()
    id_payload = roxy_decode_jwt_payload(text_display(token_data.get("id_token")).strip())
    return True, "", id_payload if isinstance(id_payload, dict) else {}


def roxy_unique_username(base: str, users: dict[str, Any]) -> str:
    clean = re.sub(r"[^a-zA-Z0-9_.-]+", "", text_display(base).strip().lower())
    if len(clean) < 3:
        clean = f"roxy{secrets.token_hex(3)}"
    candidate = clean[:28]
    if candidate not in users:
        return candidate
    for index in range(2, 200):
        next_candidate = f"{candidate[:24]}{index}"
        if next_candidate not in users:
            return next_candidate
    return f"{candidate[:20]}{secrets.token_hex(4)}"


def roxy_find_user_by_oauth(provider: str, subject: str) -> tuple[str, dict[str, Any]] | tuple[str, None]:
    clean_provider = text_display(provider).strip().lower()
    clean_subject = text_display(subject).strip()
    if not clean_provider or not clean_subject:
        return "", None
    for username, profile in roxy_load_users().get("users", {}).items():
        if not isinstance(profile, dict):
            continue
        providers = profile.get("oauth_providers")
        if isinstance(providers, dict):
            stored = providers.get(clean_provider)
            if isinstance(stored, dict) and secrets.compare_digest(text_display(stored.get("sub")).strip(), clean_subject):
                return text_display(username).strip().lower(), profile
    return "", None


def roxy_login_oauth_user(provider: str, oauth_profile: dict[str, Any]) -> tuple[bool, str]:
    clean_provider = text_display(provider).strip().lower()
    subject = text_display(oauth_profile.get("sub") or oauth_profile.get("id")).strip()
    email = text_display(oauth_profile.get("email")).strip().lower()
    name = text_display(oauth_profile.get("name") or oauth_profile.get("given_name") or email.split("@", 1)[0]).strip()
    if not subject:
        return False, f"{clean_provider.title()} no devolvio un identificador de usuario."
    data = roxy_load_users()
    users = data.setdefault("users", {})
    username, profile = roxy_find_user_by_oauth(clean_provider, subject)
    if not username and email:
        username, profile = roxy_find_user(email)
    if username and isinstance(profile, dict):
        profile = dict(profile)
    else:
        username = roxy_unique_username(email.split("@", 1)[0] if email else name, users)
        profile = {
            "username": username,
            "name": name or username,
            "email": email,
            "language": "es",
            "created_at": datetime.now(timezone.utc).isoformat(),
            "auth_method": clean_provider,
        }
    providers = profile.setdefault("oauth_providers", {})
    if not isinstance(providers, dict):
        providers = {}
    providers[clean_provider] = {
        "sub": subject,
        "email": email,
        "linked_at": datetime.now(timezone.utc).isoformat(),
    }
    profile["oauth_providers"] = providers
    if email and not text_display(profile.get("email")).strip():
        profile["email"] = email
    if name and not text_display(profile.get("name")).strip():
        profile["name"] = name
    profile["last_login_at"] = datetime.now(timezone.utc).isoformat()
    users[username] = profile
    roxy_save_users(data)
    roxy_remember_authenticated_user(username, profile)
    return True, f"Bienvenido, {text_display(profile.get('name') or username)}. Entraste con {clean_provider.title()}."


def roxy_clear_oauth_query_params() -> None:
    for key in (ROXY_OAUTH_CODE_PARAM, ROXY_OAUTH_STATE_PARAM, ROXY_OAUTH_ERROR_PARAM, "error_description"):
        try:
            del st.query_params[key]
        except Exception:
            pass


def roxy_process_oauth_callback() -> tuple[bool, str]:
    error = first_query_param_value(st.query_params, ROXY_OAUTH_ERROR_PARAM)
    if error:
        description = first_query_param_value(st.query_params, "error_description")
        roxy_clear_oauth_query_params()
        return False, f"OAuth cancelado o rechazado: {text_display(description or error)}"
    code = first_query_param_value(st.query_params, ROXY_OAUTH_CODE_PARAM)
    state = first_query_param_value(st.query_params, ROXY_OAUTH_STATE_PARAM)
    if not code or not state:
        return False, ""
    valid, provider = roxy_verify_oauth_state(state)
    if not valid or provider not in {"google", "apple"}:
        roxy_clear_oauth_query_params()
        return False, "No pude validar la respuesta OAuth. Intenta entrar otra vez."
    if provider == "google":
        ok, msg, oauth_profile = roxy_exchange_google_oauth_code(code)
    else:
        ok, msg, oauth_profile = roxy_exchange_apple_oauth_code(code)
    if not ok:
        roxy_clear_oauth_query_params()
        return False, msg
    ok, msg = roxy_login_oauth_user(provider, oauth_profile)
    roxy_clear_oauth_query_params()
    return ok, msg


def render_roxy_social_auth_controls() -> None:
    st.markdown('<div class="roxy-auth-divider"><span></span><b>O continuar con</b><span></span></div>', unsafe_allow_html=True)
    google_url, google_missing = roxy_build_google_oauth_url()
    apple_url, apple_missing = roxy_build_apple_oauth_url()
    st.markdown('<div class="roxy-auth-social-action-row">', unsafe_allow_html=True)
    apple_col, google_col = st.columns(2)
    with apple_col:
        if apple_url:
            if hasattr(st, "link_button"):
                st.link_button(" Continuar con Apple", apple_url, use_container_width=True)
            else:
                st.markdown(
                    f'<a class="roxy-auth-social-link" href="{html.escape(apple_url, quote=True)}"> Continuar con Apple</a>',
                    unsafe_allow_html=True,
                )
        elif st.button(" Continuar con Apple", key="roxy_social_apple_missing", use_container_width=True):
            st.error(roxy_oauth_missing_message("Apple", apple_missing))
    with google_col:
        if google_url:
            if hasattr(st, "link_button"):
                st.link_button("G Continuar con Google", google_url, use_container_width=True)
            else:
                st.markdown(
                    f'<a class="roxy-auth-social-link" href="{html.escape(google_url, quote=True)}">G Continuar con Google</a>',
                    unsafe_allow_html=True,
                )
        elif st.button("G Continuar con Google", key="roxy_social_google_missing", use_container_width=True):
            st.error(roxy_oauth_missing_message("Google", google_missing))
    st.markdown("</div>", unsafe_allow_html=True)


def render_roxy_auth_gate() -> None:
    mode = first_query_param_value(st.query_params, "auth") or st.session_state.get("roxy_auth_mode") or "login"
    mode = "register" if str(mode).lower().startswith("reg") else "login"
    st.session_state["roxy_auth_mode"] = mode
    title = "Crea tu cuenta" if mode == "register" else "¡Bienvenido de nuevo!"
    subtitle = "Registrate para que Roxy aprenda tu nombre." if mode == "register" else "Inicia sesion para continuar con Roxy"
    safe_mode_class = "register" if mode == "register" else "login"
    st.markdown(
        f"""
        <section class="roxy-auth-screen roxy-auth-{safe_mode_class}">
          <div class="roxy-universe" aria-hidden="true">
            <i class="roxy-space-nebula"></i>
            <i class="roxy-space-stars roxy-space-stars-far"></i>
            <i class="roxy-space-stars roxy-space-stars-mid"></i>
            <i class="roxy-space-stars roxy-space-stars-near"></i>
            <i class="roxy-space-planet"></i>
            <i class="roxy-space-comet"></i>
            <i class="roxy-space-aurora"></i>
            <i class="roxy-space-constellation roxy-space-constellation-a"></i>
            <i class="roxy-space-constellation roxy-space-constellation-b"></i>
            <i class="roxy-space-moon"></i>
            <i class="roxy-space-stream roxy-space-stream-a"></i>
            <i class="roxy-space-stream roxy-space-stream-b"></i>
          </div>
          <div class="roxy-auth-language"><span>🇪🇸</span><b>Español</b><i class="material-symbols-outlined">expand_more</i></div>
          <div class="roxy-auth-hero">
            {roxy_hologram_avatar_html("speaking", "Roxy bienvenida")}
            <div class="roxy-auth-title"><strong>ROXY</strong><span>AI TRADING CORE</span><em>Analiza. Aprende. Opera. Gana.</em></div>
          </div>
          <div class="roxy-auth-card">
            <header><strong>{html.escape(title)}</strong><span>{html.escape(subtitle)}</span></header>
        """,
        unsafe_allow_html=True,
    )
    if mode == "register":
        with st.form("roxy_register_form", clear_on_submit=False):
            name = st.text_input("Nombre completo", key="roxy_register_name", placeholder="Tu nombre")
            username = st.text_input("Username", key="roxy_register_username", placeholder="usuario")
            email = st.text_input("Correo", key="roxy_register_email", placeholder="correo@email.com")
            password = st.text_input("Contraseña", type="password", key="roxy_register_password", placeholder="Crea tu contraseña")
            language = st.selectbox("Idioma de Roxy", ["Español", "English"], key="roxy_register_language")
            remember = st.checkbox("Recordarme", value=True, key="roxy_register_remember")
            submitted = st.form_submit_button("Crear cuenta")
            if submitted:
                ok, msg = roxy_register_user(
                    name=name,
                    username=username,
                    email=email,
                    password=password,
                    language="es" if language == "Español" else "en",
                )
                if ok:
                    st.success(msg)
                    st.rerun()
                st.error(msg)
        st.markdown(
            """
            <div class="roxy-auth-switch">¿Ya tienes una cuenta? <a href="?auth=login" target="_self">Inicia sesión</a></div>
            """,
            unsafe_allow_html=True,
        )
    else:
        with st.form("roxy_login_form", clear_on_submit=False):
            identifier = st.text_input("Usuario o correo", key="roxy_login_identifier", placeholder="Usuario")
            password = st.text_input("Contraseña", type="password", key="roxy_login_password", placeholder="Contraseña")
            col_remember, col_forgot = st.columns([1, 1])
            with col_remember:
                st.checkbox("Recordarme", value=True, key="roxy_login_remember")
            with col_forgot:
                recovery_submitted = st.form_submit_button("Recuperar acceso")
            submitted = st.form_submit_button("Iniciar sesión")
            passkey_submitted = st.form_submit_button("Entrar con Face ID / Passkey")
            if submitted:
                ok, msg = roxy_login_user(identifier, password)
                if ok:
                    st.success(msg)
                    st.rerun()
                st.error(msg)
            if passkey_submitted:
                ok, msg, options, passkey_username = roxy_passkey_authentication_options(identifier)
                if ok:
                    st.session_state["roxy_passkey_auth_options"] = options
                    st.session_state["roxy_passkey_auth_username"] = passkey_username
                else:
                    st.error(msg)
            if recovery_submitted:
                st.warning(
                    "La recuperacion por correo no esta configurada. Usa tu passkey o solicita un reset al administrador local."
                )
        auth_options = st.session_state.get("roxy_passkey_auth_options")
        auth_username = text_display(st.session_state.get("roxy_passkey_auth_username")).strip().lower()
        if isinstance(auth_options, dict) and auth_options and auth_username:
            render_roxy_passkey_launcher("auth", auth_username, auth_options, "Abrir Face ID ahora")
        render_roxy_social_auth_controls()
        st.markdown(
            """
            <div class="roxy-auth-switch">¿No tienes una cuenta? <a href="?auth=register" target="_self">Regístrate</a></div>
            """,
            unsafe_allow_html=True,
        )
    st.markdown(
        """
            <footer><i class="material-symbols-outlined">shield</i><span>Tu información está protegida con contraseña cifrada por hash y passkeys del dispositivo cuando activas Face ID.</span></footer>
          </div>
        </section>
        """,
        unsafe_allow_html=True,
    )


