def latest_file(pattern: str) -> Optional[str]:
    files = glob(str(runtime_path(pattern)))
    if not files:
        return None
    # choose by modified time
    files.sort(key=lambda p: Path(p).stat().st_mtime, reverse=True)
    return files[0]


def get_ohlcv(symbol: str) -> pd.DataFrame:
    """Query the local `db/roxy.db` ohlcv table for `symbol`.

    Returns a DataFrame indexed by datetime with open/high/low/close/volume.
    """
    conn = sqlite3.connect(storage.DB_PATH)
    cur = conn.cursor()
    try:
        cur.execute(
            "SELECT ts, open, high, low, close, volume FROM ohlcv WHERE symbol = ? ORDER BY ts",
            (symbol,),
        )
        rows = cur.fetchall()
    except sqlite3.OperationalError:
        rows = []
    conn.close()
    if not rows:
        return pd.DataFrame()
    df = pd.DataFrame(rows, columns=["ts", "open", "high", "low", "close", "volume"])  # type: ignore
    df["ts"] = pd.to_datetime(df["ts"])
    df = df.set_index("ts")
    return df


def fetch_direct_yfinance_ohlcv(symbol: str, timeframe: str) -> pd.DataFrame:
    if yf is None:
        return pd.DataFrame()
    clean_symbol = str(symbol or "").strip().upper()
    if not clean_symbol:
        return pd.DataFrame()
    if "/" in clean_symbol:
        clean_symbol = clean_symbol.replace("/", "-")
    normalized_tf = normalize_command_timeframe(timeframe)
    interval = {"1m": "1m", "5m": "5m", "15m": "15m", "1h": "60m", "2h": "60m", "4h": "60m", "1d": "1d", "1w": "1wk"}.get(normalized_tf, "60m")
    period = {"1m": "7d", "5m": "30d", "15m": "30d", "1h": "120d", "2h": "120d", "4h": "180d", "1d": "2y", "1w": "10y"}.get(normalized_tf, "120d")
    try:
        raw = yf.Ticker(clean_symbol).history(period=period, interval=interval, prepost=True, auto_adjust=False)
    except Exception:
        return pd.DataFrame()
    if raw is None or raw.empty:
        return pd.DataFrame()
    data = raw.reset_index().rename(
        columns={
            "Date": "ts",
            "Datetime": "ts",
            "Open": "open",
            "High": "high",
            "Low": "low",
            "Close": "close",
            "Volume": "volume",
        }
    )
    required = ["ts", "open", "high", "low", "close", "volume"]
    if not set(required).issubset(data.columns):
        return pd.DataFrame()
    out = data[required].copy()
    out["ts"] = pd.to_datetime(out["ts"], errors="coerce")
    for column in ["open", "high", "low", "close", "volume"]:
        out[column] = pd.to_numeric(out[column], errors="coerce")
    out = out.dropna(subset=["ts", "open", "high", "low", "close"]).sort_values("ts")
    if normalized_tf in {"2h", "4h"}:
        out = resample_ohlcv(out, normalized_tf)
    return out.reset_index(drop=True)


