def run_video_learning_ingest(limit: int = 1, transcribe: bool = False) -> tuple[bool, str]:
    script = project_path("tools/video_learning_ingest.py")
    if not script.exists():
        return False, "No encuentro `tools/video_learning_ingest.py`."
    cmd = [sys.executable, str(script), "--limit", str(max(1, int(limit))), "--idle-review"]
    from tools.video_learning_ingest import configured_archive_dir

    archive_dir = configured_archive_dir()
    if archive_dir is not None:
        cmd.extend(["--archive-dir", str(archive_dir)])
    if transcribe:
        cmd.extend(["--transcribe", "--model-size", "tiny"])
    try:
        proc = subprocess.run(
            cmd,
            cwd=str(project_path(".")),
            text=True,
            capture_output=True,
            timeout=60 * 20,
        )
    except subprocess.TimeoutExpired:
        return False, "El escaneo tomo demasiado tiempo. Roxy lo deja para el proceso automatico."
    except Exception as exc:
        return False, f"No se pudo ejecutar el escaneo: {exc}"
    output = "\n".join(part for part in [proc.stdout.strip(), proc.stderr.strip()] if part).strip()
    return proc.returncode == 0, output or "Escaneo terminado sin salida."


def browser_voice_fallback_enabled(env: Mapping[str, str] | None = None) -> bool:
    values = env or os.environ
    return str(values.get("ROXY_ENABLE_BROWSER_VOICE_FALLBACK", "1")).strip().lower() not in {
        "0",
        "false",
        "no",
        "off",
    }


def speak_in_browser(text: str, *, key: str, lang: str = "es-US") -> None:
    if os.environ.get("ELEVENLABS_API_KEY"):
        return
    if not browser_voice_fallback_enabled():
        return
    spoken = " ".join(str(text or "").split())[:1400]
    if not spoken:
        return
    payload = json.dumps(spoken)
    lang_payload = json.dumps(lang)
    component_id = json.dumps(f"roxy-voice-{key}")
    st.components.v1.html(
        f"""
        <div id={component_id}></div>
        <script>
        (() => {{
            const message = {payload};
            const lang = {lang_payload};
            const speak = () => {{
                const utterance = new SpeechSynthesisUtterance(message);
                utterance.lang = lang;
                utterance.rate = 0.95;
                utterance.pitch = 1.0;
                const voices = window.speechSynthesis.getVoices() || [];
                const preferred = voices.find(v => (v.lang || '').toLowerCase().startsWith('es'))
                    || voices.find(v => (v.lang || '').toLowerCase().startsWith('en'))
                    || voices[0];
                if (preferred) utterance.voice = preferred;
                window.speechSynthesis.cancel();
                window.speechSynthesis.speak(utterance);
            }};
            if ('speechSynthesis' in window) {{
                if (window.speechSynthesis.getVoices().length === 0) {{
                    window.speechSynthesis.onvoiceschanged = speak;
                    setTimeout(speak, 350);
                }} else {{
                    speak();
                }}
            }}
        }})();
        </script>
        """,
        height=0,
    )


