def cached_roxy_email_snapshot(provider: str, token_fingerprint: str) -> dict[str, Any]:
    _ = token_fingerprint
    return readonly_email_client(provider).inbox(limit=5)


def roxy_email_snapshot(provider: Any = None) -> dict[str, Any]:
    selected = configured_email_provider(provider)
    token_name = "ROXY_OUTLOOK_ACCESS_TOKEN" if selected == "outlook" else "ROXY_GMAIL_ACCESS_TOKEN"
    token = str(os.environ.get(token_name) or "")
    fingerprint = hashlib.sha256(token.encode("utf-8")).hexdigest() if token else "missing"
    return cached_roxy_email_snapshot(selected, fingerprint)


def roxy_os_context() -> dict[str, Any]:
    context = roxy_elevenlabs_page_context()
    profile = st.session_state.get("roxy_user_profile")
    opportunity_snapshot = roxy_resolved_voice_opportunity_snapshot()
    personal_task_snapshot = roxy_personal_task_store().snapshot(roxy_os_user_id(), limit=25)
    shopping_list_snapshot = roxy_shopping_list_store().snapshot(roxy_os_user_id(), limit=100)
    home_assistant_snapshot = dict(st.session_state.get("roxy_home_assistant_snapshot") or {})
    document_snapshot = roxy_document_vault().snapshot(roxy_os_user_id(), limit=25)
    email_snapshot = dict(st.session_state.get("roxy_email_snapshot") or {})
    context.update(
        {
            "surface": "streamlit",
            "user_profile": dict(profile) if isinstance(profile, dict) else {},
            "allowed_permissions": list(st.session_state.get("roxy_os_allowed_permissions") or []),
            "authenticated": bool(st.session_state.get("user")),
            "opportunity_snapshot": opportunity_snapshot,
            "visible_opportunities_text": roxy_voice_snapshot_text(opportunity_snapshot),
            "operational_response_contract": roxy_voice_response_contract(context, opportunity_snapshot),
            "personal_task_snapshot": personal_task_snapshot,
            "shopping_list_snapshot": shopping_list_snapshot,
            "home_assistant_snapshot": home_assistant_snapshot,
            "document_snapshot": document_snapshot,
            "email_snapshot": email_snapshot,
        }
    )
    return context


def roxy_desktop_helper_url() -> str:
    configured = text_display(os.environ.get("ROXY_DESKTOP_HELPER_URL") or "").strip()
    return configured or "http://127.0.0.1:8765"


def roxy_desktop_helper_is_local(url_value: str) -> bool:
    try:
        parsed = urlparse(url_value)
    except Exception:
        return False
    return parsed.scheme == "http" and (parsed.hostname or "") in {"127.0.0.1", "localhost"}


def watchlist_command_action(command_text: Any) -> str:
    text = normalize_roxy_command_text(command_text)
    add_terms = ("agrega", "agregala", "agregar", "anade", "anadela", "guardar", "guarda")
    remove_terms = ("elimina", "eliminala", "quitar", "quita", "remueve")
    references_watchlist = "watchlist" in text or "lista de seguimiento" in text or "mi lista" in text
    if references_watchlist and any(term in text for term in remove_terms):
        return "remove"
    if references_watchlist and any(term in text for term in add_terms):
        return "add"
    return ""


def roxy_mutable_watchlist_name(store: WatchlistStore, user_id: str, requested_name: Any) -> str:
    """Return a user-managed list; system opportunity lists stay read-only."""
    requested = text_display(requested_name or "Principal")
    snapshot = store.snapshot(user_id)
    lists = snapshot.get("lists") if isinstance(snapshot.get("lists"), dict) else {}
    config = lists.get(requested) if isinstance(lists.get(requested), dict) else {}
    return "Principal" if config.get("system_managed") else requested


def sync_roxy_watchlist_session(store: WatchlistStore, user_id: str, list_name: str) -> list[str]:
    """Keep voice/page context aligned with the durable active watchlist."""
    snapshot = store.snapshot(user_id)
    active = (snapshot.get("lists") or {}).get(list_name) or {}
    symbols = [
        text_display(item.get("symbol")).upper()
        for item in (active.get("items") or [])
        if isinstance(item, dict) and item.get("symbol")
    ]
    st.session_state["roxy_watchlist_selected"] = list_name
    st.session_state["watchlist"] = symbols
    return symbols


def execute_roxy_watchlist_command(command_text: Any) -> dict[str, Any] | None:
    action = watchlist_command_action(command_text)
    if not action:
        return None
    context = resolve_roxy_operational_context(st.query_params, st.session_state)
    symbol = context["symbol"]
    market = context["market"]
    store = WatchlistStore(project_path("data/roxy_watchlists.json"))
    user_id = roxy_os_user_id()
    durable_snapshot = store.snapshot(user_id)
    requested_list = text_display(
        st.session_state.get("roxy_watchlist_selected")
        or durable_snapshot.get("active_list")
        or "Principal"
    )
    list_name = roxy_mutable_watchlist_name(store, user_id, requested_list)
    if action == "remove":
        result = store.remove_asset(user_id, list_name, symbol, market)
        message = (
            f"Elimine {symbol} de {list_name}."
            if result.get("removed")
            else f"{symbol} no estaba en {list_name}."
        )
    else:
        result = store.add_asset(user_id, list_name, symbol, market)
        message = (
            f"Agregue {symbol} a {list_name}."
            if result.get("added")
            else f"{symbol} ya estaba en {list_name}."
        )
    if requested_list != list_name:
        message += f" Use {list_name} porque {requested_list} es administrada automaticamente por Roxy."
    sync_roxy_watchlist_session(store, user_id, list_name)
    return {
        "ok": True,
        "intent": f"watchlist_{action}",
        "agent": "platform_context",
        "message": message,
        "data": {"symbol": symbol, "market": market, "list_name": list_name, "result": result},
        "actions": [],
    }


def alert_command_request(command_text: Any) -> dict[str, Any] | None:
    text = normalize_roxy_command_text(command_text)
    if "alerta" not in text and not any(term in text for term in ("avisame", "avisa me", "notifica")):
        return None
    if ("ema" in text or "media" in text) and any(term in text for term in ("cruce", "cruza", "cruzar")):
        periods = [int(value) for value in re.findall(r"(?:ema|media)\s*([0-9]{1,3})", text)]
        direction = ""
        if any(term in text for term in ("sobre", "encima", "alcista", "hacia arriba")):
            direction = "ema_cross_above"
        elif any(term in text for term in ("debajo", "bajista", "hacia abajo")):
            direction = "ema_cross_below"
        return {
            "alert_type": direction,
            "fast_period": periods[0] if len(periods) >= 1 else None,
            "slow_period": periods[1] if len(periods) >= 2 else None,
        }
    if any(term in text for term in ("volumen relativo", "rvol")):
        numbers = re.findall(r"(?<![a-z0-9])([0-9]+(?:[.,][0-9]+)?)", text)
        threshold = safe_float(numbers[-1].replace(",", ".")) if numbers else None
        return {"alert_type": "relative_volume_above", "threshold": threshold}
    direction = ""
    if any(term in text for term in ("sube", "encima", "sobre", "supera")):
        direction = "price_above"
    elif any(term in text for term in ("baja", "debajo", "cae", "pierde")):
        direction = "price_below"
    numbers = re.findall(r"(?<![a-z0-9])([0-9]+(?:[.,][0-9]+)?)", text)
    threshold = safe_float(numbers[-1].replace(",", ".")) if numbers else None
    return {"alert_type": direction, "threshold": threshold}


def execute_roxy_alert_command(command_text: Any) -> dict[str, Any] | None:
    request = alert_command_request(command_text)
    if request is None:
        return None
    context = resolve_roxy_operational_context(st.query_params, st.session_state)
    symbol = context["symbol"]
    alert_type = text_display(request.get("alert_type"))
    threshold = safe_float(request.get("threshold"))
    fast_period = request.get("fast_period")
    slow_period = request.get("slow_period")
    technical_type = alert_type in {"ema_cross_above", "ema_cross_below", "relative_volume_above"}
    technical_valid = (
        alert_type in {"ema_cross_above", "ema_cross_below"}
        and isinstance(fast_period, int)
        and isinstance(slow_period, int)
        and 2 <= fast_period < slow_period <= 400
    ) or (alert_type == "relative_volume_above" and threshold is not None and 0.1 <= threshold <= 100)
    price_valid = alert_type in {"price_above", "price_below"} and threshold is not None and threshold > 0
    if not price_valid and not technical_valid:
        technical_hint = (
            f" Indica ambas medias y la direccion; por ejemplo: avisame cuando EMA9 cruce sobre EMA21."
            if alert_type.startswith("ema_cross") or ("ema" in normalize_roxy_command_text(command_text))
            else f" Indica el umbral; por ejemplo: avisame cuando el volumen relativo supere 1,5."
            if technical_type or any(term in normalize_roxy_command_text(command_text) for term in ("volumen relativo", "rvol"))
            else f" Por ejemplo: avisame si {symbol} sube a 350."
        )
        return {
            "ok": False,
            "intent": "alert_create",
            "agent": "platform_context",
            "message": (
                f"No pude definir una regla verificable para {symbol}." + technical_hint
            ),
            "data": {"symbol": symbol, "reason": "invalid_or_incomplete_alert_rule"},
            "actions": [],
        }
    store = WatchlistStore(project_path("data/roxy_watchlists.json"))
    user_id = roxy_os_user_id()
    list_name = roxy_mutable_watchlist_name(
        store, user_id, st.session_state.get("roxy_watchlist_selected") or "Principal"
    )
    store.add_asset(user_id, list_name, symbol, context["market"])
    if technical_type:
        result = store.create_technical_alert(
            user_id,
            symbol=symbol,
            market=context["market"],
            alert_type=alert_type,
            threshold=threshold if threshold is not None else 0,
            fast_period=fast_period if isinstance(fast_period, int) else 9,
            slow_period=slow_period if isinstance(slow_period, int) else 21,
            timeframe=context["timeframe"],
            watchlist_name=list_name,
            source="voice_command",
        )
    else:
        result = store.create_price_alert(
            user_id,
            symbol=symbol,
            market=context["market"],
            alert_type=alert_type,
            threshold=threshold,
            timeframe=context["timeframe"],
            watchlist_name=list_name,
            source="voice_command",
        )
    sync_roxy_watchlist_session(store, user_id, list_name)
    if alert_type in {"ema_cross_above", "ema_cross_below"}:
        relation = "cruce sobre" if alert_type == "ema_cross_above" else "cruce debajo de"
        rule_label = f"EMA{fast_period} {relation} EMA{slow_period} en {context['timeframe']}"
    elif alert_type == "relative_volume_above":
        rule_label = f"RVol supere {threshold:.2f}x en {context['timeframe']}"
    else:
        direction = "suba a" if alert_type == "price_above" else "baje a"
        rule_label = f"{direction} {price_display(threshold)}"
    message = (
        f"Alerta creada para {symbol} cuando {rule_label}."
        if result.get("created")
        else f"La alerta de {symbol} cuando {rule_label} ya estaba activa."
    )
    return {
        "ok": True,
        "intent": "alert_create",
        "agent": "platform_context",
        "message": message,
        "data": {"symbol": symbol, "market": context["market"], "result": result},
        "actions": [],
    }


ROXY_SPOKEN_TIMEFRAMES = (
    ("1m", ("1m", "1 minuto", "un minuto")),
    ("5m", ("5m", "5 minutos", "cinco minutos")),
    ("15m", ("15m", "15 minutos", "quince minutos")),
    ("20m", ("20m", "20 minutos", "veinte minutos")),
    ("30m", ("30m", "30 minutos", "treinta minutos")),
    ("1h", ("1h", "1 hora", "una hora")),
    ("2h", ("2h", "2 horas", "dos horas")),
    ("4h", ("4h", "4 horas", "cuatro horas")),
    ("1d", ("1d", "diario", "diaria", "un dia", "1 dia")),
    ("1w", ("1w", "semanal", "una semana", "1 semana")),
)


def timeframe_command_request(command_text: Any) -> dict[str, str] | None:
    text = normalize_roxy_command_text(command_text)
    if not any(term in text for term in ("grafica", "timeframe", "temporalidad", "marco temporal")):
        return None
    if not any(term in text for term in ("cambia", "cambiar", "pon", "muestra", "abre", "ve a")):
        return None
    for timeframe, aliases in ROXY_SPOKEN_TIMEFRAMES:
        if any(re.search(rf"(?<![a-z0-9]){re.escape(alias)}(?![a-z0-9])", text) for alias in aliases):
            return {"timeframe": timeframe}
    return {"timeframe": ""}


def execute_roxy_timeframe_command(command_text: Any) -> dict[str, Any] | None:
    request = timeframe_command_request(command_text)
    if request is None:
        return None
    context = resolve_roxy_operational_context(st.query_params, st.session_state)
    timeframe = text_display(request.get("timeframe"))
    if timeframe not in TIMEFRAME_OPTIONS:
        return {
            "ok": False,
            "intent": "chart_timeframe_change",
            "agent": "platform_context",
            "message": "Indica una temporalidad disponible: 1, 5, 15, 20 o 30 minutos; 1, 2 o 4 horas; diario o semanal.",
            "data": {"reason": "missing_or_unsupported_timeframe", "context": context},
            "actions": [],
        }
    return {
        "ok": True,
        "intent": "chart_timeframe_change",
        "agent": "platform_context",
        "message": f"Grafica de {context['symbol']} cambiada a {timeframe}.",
        "data": {"symbol": context["symbol"], "market": context["market"], "timeframe": timeframe},
        "actions": [
            {
                "type": "set_timeframe",
                "symbol": context["symbol"],
                "market": context["market"],
                "timeframe": timeframe,
                "confirmation_required": False,
            }
        ],
    }


@st.cache_data(show_spinner=False, ttl=cache_ttl("local_health"))
def roxy_desktop_helper_status(helper_url: str) -> dict[str, Any]:
    if requests is None:
        return {"ok": False, "available": False, "reason": "requests_unavailable"}
    if not roxy_desktop_helper_is_local(helper_url):
        return {"ok": False, "available": False, "reason": "helper_must_be_localhost"}
    try:
        response = requests.get(f"{helper_url.rstrip('/')}/health", timeout=0.35)
        response.raise_for_status()
        payload = response.json()
    except Exception as exc:
        return {"ok": False, "available": False, "reason": text_display(exc)[:120]}
    return {"ok": True, "available": True, "payload": payload}


def run_roxy_os_command(command_text: str) -> dict[str, Any]:
    command_text = text_display(command_text).strip()
    if not command_text:
        return {"ok": False, "message": "Escribe una instruccion para Roxy."}
    watchlist_result = execute_roxy_watchlist_command(command_text)
    if watchlist_result:
        return watchlist_result
    alert_result = execute_roxy_alert_command(command_text)
    if alert_result:
        return alert_result
    timeframe_result = execute_roxy_timeframe_command(command_text)
    if timeframe_result:
        return timeframe_result
    local_reply = roxy_voice_local_context_reply(command_text)
    if local_reply:
        opportunity_snapshot = roxy_resolved_voice_opportunity_snapshot()
        return {
            "ok": True,
            "intent": "platform_context_query",
            "agent": "platform_context",
            "message": local_reply,
            "data": {
                "source": text_display(opportunity_snapshot.get("source") or "visible_platform_context"),
                "context": roxy_elevenlabs_page_context(),
                "snapshot_available": bool(opportunity_snapshot.get("rows")),
            },
            "actions": [],
        }
    orchestrator = get_roxy_os_orchestrator()
    if orchestrator is None:
        return {
            "ok": False,
            "message": "",
            "silent": True,
            "reason": "roxy_os_unavailable",
            "diagnostic": ROXY_OS_IMPORT_ERROR,
        }
    try:
        response = orchestrator.handle(command_text, user_id=roxy_os_user_id(), context=roxy_os_context())
    except Exception as exc:
        return {"ok": False, "message": f"Roxy OS no pudo procesar la instruccion: {exc}"}
    payload = response.to_dict()
    payload["ok"] = True
    history = st.session_state.setdefault("roxy_os_history", [])
    history.insert(0, payload)
    del history[8:]
    return payload


def apply_roxy_os_safe_actions(result: dict[str, Any]) -> list[str]:
    applied: list[str] = []
    if not result.get("ok"):
        return applied
    permission = result.get("permission") or {}
    if permission.get("allowed") is False or permission.get("risk_level") == "high":
        return applied
    for action in result.get("actions") or []:
        if not isinstance(action, dict):
            continue
        if action.get("confirmation_required"):
            continue
        action_type = text_display(action.get("type"))
        if action_type == "open_module":
            module = normalize_roxy_module(action.get("module"), default="acciones-operar")
            module_config = roxy_module_by_slug(module)
            symbol = text_display(action.get("symbol") or module_config.get("symbol") or "AAPL").upper()
            market = normalize_command_market(action.get("market") or module_config.get("market"), symbol)
            timeframe = normalize_command_timeframe(action.get("timeframe") or module_config.get("tf") or "1h")
            st.session_state["roxy_active_module"] = module
            st.query_params["module"] = module
            apply_roxy_navigation_target(
                page=text_display(module_config.get("page") or "Dashboard"),
                symbol=symbol,
                market=market,
                timeframe=timeframe,
                budget_scope=text_display(module_config.get("scope") or ""),
                message=f"Roxy abrio {module_config.get('label') or module}.",
            )
            applied.append(f"Abrir modulo {module_config.get('label') or module}")
        elif action_type == "run_trading_scan":
            module = normalize_roxy_module(action.get("module"), default=text_display(st.query_params.get("module") or "acciones-operar"))
            st.session_state["roxy_active_module"] = module
            st.session_state["roxy_pending_scan"] = {
                "module": module,
                "symbol": text_display(action.get("symbol") or st.session_state.get("command_symbol") or "AAPL").upper(),
                "market": normalize_command_market(action.get("market"), action.get("symbol")),
                "timeframe": normalize_command_timeframe(action.get("timeframe") or st.session_state.get("command_timeframe") or "1h"),
                "created_at": datetime.now(timezone.utc).isoformat(),
            }
            st.query_params["module"] = module
            applied.append("Preparar scanner operativo")
        elif action_type == "set_timeframe":
            context = resolve_roxy_operational_context(st.query_params, st.session_state)
            timeframe = normalize_command_timeframe(action.get("timeframe"), default=context["timeframe"])
            apply_roxy_navigation_target(
                page=text_display(first_query_param_value(st.query_params, "view") or "Dashboard"),
                symbol=action.get("symbol") or context["symbol"],
                market=action.get("market") or context["market"],
                timeframe=timeframe,
            )
            applied.append(f"Cambiar grafica a {timeframe}")
        elif action_type == "weather_lookup":
            st.session_state["roxy_last_weather_request"] = {
                "location": text_display(action.get("location") or ""),
                "created_at": datetime.now(timezone.utc).isoformat(),
            }
            applied.append("Consultar clima")
        elif action_type == "file_read_request":
            st.session_state["roxy_pending_file_read"] = {
                "path": text_display(action.get("path") or ""),
                "requires_confirmation": bool(action.get("confirmation_required")),
                "created_at": datetime.now(timezone.utc).isoformat(),
            }
            applied.append("Preparar lectura de archivo")
        elif action_type == "screen_capture_summary":
            st.session_state["roxy_pending_screen_summary"] = {
                "requires_confirmation": bool(action.get("confirmation_required")),
                "created_at": datetime.now(timezone.utc).isoformat(),
            }
            applied.append("Preparar lectura de pantalla")
        elif action_type == "browser_search_or_open":
            st.session_state["roxy_pending_browser_action"] = {
                "query": text_display(action.get("query") or ""),
                "created_at": datetime.now(timezone.utc).isoformat(),
            }
            applied.append("Preparar navegador")
    return applied


ROXY_VOICE_COMMAND_REPLAY_SECONDS = 4.0


def roxy_voice_command_replay_state(
    command: Any,
    previous_key: Any,
    previous_at: Any,
    *,
    now: datetime | None = None,
) -> dict[str, Any]:
    command_text = text_display(command).strip()
    command_key = hashlib.sha256(command_text.encode("utf-8", errors="ignore")).hexdigest()
    current = (now or datetime.now(timezone.utc)).astimezone(timezone.utc)
    try:
        prior = datetime.fromisoformat(text_display(previous_at).replace("Z", "+00:00"))
        if prior.tzinfo is None:
            prior = prior.replace(tzinfo=timezone.utc)
        age_seconds = (current - prior.astimezone(timezone.utc)).total_seconds()
    except ValueError:
        age_seconds = None
    replay = (
        text_display(previous_key) == command_key
        and age_seconds is not None
        and 0 <= age_seconds <= ROXY_VOICE_COMMAND_REPLAY_SECONDS
    )
    return {
        "key": command_key,
        "at": current.isoformat(),
        "age_seconds": round(age_seconds, 3) if age_seconds is not None else None,
        "replay": replay,
    }


def process_roxy_os_query_command() -> None:
    command = first_query_param_value(st.query_params, "roxy_os_cmd").strip()
    if not command:
        return
    replay_state = roxy_voice_command_replay_state(
        command,
        st.session_state.get("roxy_os_last_query_command"),
        st.session_state.get("roxy_os_last_query_command_at"),
    )
    if replay_state["replay"]:
        try:
            del st.query_params["roxy_os_cmd"]
        except Exception:
            pass
        return
    st.session_state["roxy_os_last_query_command"] = replay_state["key"]
    st.session_state["roxy_os_last_query_command_at"] = replay_state["at"]
    result = run_roxy_os_command(command)
    applied = apply_roxy_os_safe_actions(result)
    if result.get("ok"):
        spoken_message = text_display(result.get("message") or "Roxy proceso la instruccion.")
        st.session_state["roxy_launch_message"] = spoken_message
        if applied:
            st.session_state["roxy_launch_message"] += " Acciones aplicadas: " + ", ".join(applied)
            spoken_message += " Acciones aplicadas: " + ", ".join(applied)
        st.session_state["roxy_voice_pending_reply"] = {
            "id": hashlib.sha256(
                f"{command}|{spoken_message}|{datetime.now(timezone.utc).isoformat()}".encode(
                    "utf-8", errors="ignore"
                )
            ).hexdigest()[:16],
            "command": command,
            "text": spoken_message,
            "created_at": datetime.now(timezone.utc).isoformat(),
        }
    elif not result.get("silent"):
        spoken_message = text_display(result.get("message") or "Roxy no pudo procesar la instruccion.")
        st.session_state["roxy_launch_message"] = spoken_message
        st.session_state["roxy_voice_pending_reply"] = {
            "id": hashlib.sha256(
                f"{command}|{spoken_message}|{datetime.now(timezone.utc).isoformat()}".encode(
                    "utf-8", errors="ignore"
                )
            ).hexdigest()[:16],
            "command": command,
            "text": spoken_message,
            "created_at": datetime.now(timezone.utc).isoformat(),
        }
    try:
        del st.query_params["roxy_os_cmd"]
    except Exception:
        pass


def render_roxy_os_command_center() -> None:
    if not ROXY_OS_AVAILABLE:
        return
    with st.expander("Roxy OS Core · memoria, acciones y copiloto", expanded=False):
        st.caption(
            "Este puente prueba el cerebro local de Roxy sin operar dinero real. "
            "Puede guardar recuerdos, preparar acciones y bloquear ordenes peligrosas."
        )
        helper_url = roxy_desktop_helper_url()
        helper_status = roxy_desktop_helper_status(helper_url)
        if helper_status.get("available"):
            st.success("Roxy Desktop Helper conectado en localhost. Roxy puede preparar acciones fuera del navegador con permisos seguros.")
            capabilities = (helper_status.get("payload") or {}).get("capabilities") or {}
            if isinstance(capabilities, dict) and capabilities:
                active_caps = [name for name, enabled in capabilities.items() if enabled]
                blocked_caps = [name for name, enabled in capabilities.items() if not enabled]
                st.caption(
                    "Permisos activos: "
                    + (", ".join(active_caps) if active_caps else "ninguno")
                    + ". Protegidos/apagados: "
                    + (", ".join(blocked_caps) if blocked_caps else "ninguno")
                    + "."
                )
        else:
            st.caption(
                "Roxy Desktop Helper local no esta activo. Para pruebas fuera del navegador: "
                "`PYTHONPATH=. python3 -m roxy_desktop_helper.server`"
            )
        quick_cols = st.columns(3)
        quick_prompts = [
            ("Compras", "Hola Roxy, acuerdame comprar pan, cafe y leche."),
            ("Trading", "Roxy abre Roxy Trading y dime las mejores oportunidades."),
            ("Pantalla", "Roxy dime que estoy viendo en la pantalla."),
        ]
        for col, (label, prompt) in zip(quick_cols, quick_prompts):
            if col.button(label, key=f"roxy_os_quick_{label.lower()}"):
                st.session_state["roxy_os_pending_command"] = prompt

        default_command = str(st.session_state.pop("roxy_os_pending_command", "") or "").strip()
        with st.form("roxy_os_command_form", clear_on_submit=True):
            command_text = st.text_area(
                "Instruccion para Roxy",
                value=default_command,
                placeholder="Ejemplo: Roxy, recuerda que prefiero trading conservador y dime que debo revisar hoy.",
                height=86,
            )
            submitted = st.form_submit_button("Enviar a Roxy OS")
        if submitted:
            result = run_roxy_os_command(command_text)
            if result.get("ok"):
                st.success(result.get("message") or "Roxy proceso la instruccion.")
                applied = apply_roxy_os_safe_actions(result)
                if applied:
                    st.info("Acciones aplicadas: " + ", ".join(applied))
            else:
                st.error(result.get("message") or "No se pudo procesar.")

        for item in st.session_state.get("roxy_os_history", [])[:3]:
            permission = item.get("permission") or {}
            with st.container(border=True):
                st.markdown(f"**{item.get('agent', 'roxy')} · {item.get('intent', 'general')}**")
                st.write(item.get("message", ""))
                if item.get("actions"):
                    st.caption("Acciones preparadas")
                    st.json(item.get("actions"), expanded=False)
                if permission:
                    st.caption(
                        f"Permiso: {permission.get('mode', '-')}"
                        f" · Riesgo: {permission.get('risk_level', '-')}"
                    )


def render_roxy_os_action_inbox() -> None:
    pending_weather = st.session_state.get("roxy_last_weather_request")
    pending_file = st.session_state.get("roxy_pending_file_read")
    pending_screen = st.session_state.get("roxy_pending_screen_summary")
    pending_browser = st.session_state.get("roxy_pending_browser_action")
    has_pending = any(isinstance(item, dict) and item for item in (pending_weather, pending_file, pending_screen, pending_browser))
    if not has_pending:
        return

    with st.expander("Acciones preparadas por Roxy", expanded=True):
        st.caption(
            "Roxy puede preparar acciones seguras desde voz. Las acciones fuera del navegador "
            "requieren permisos del sistema o el helper local de Roxy Desktop."
        )

        if isinstance(pending_weather, dict) and pending_weather:
            location = text_display(pending_weather.get("location") or "").strip() or "tu ubicacion configurada"
            with st.container(border=True):
                st.markdown(f"**Clima** · {location}")
                try:
                    from tools import weather_service as roxy_weather_service

                    snapshot = roxy_weather_service.fetch_current_weather(location)
                    if snapshot.status == "ok":
                        temp = f"{snapshot.temperature_c:.1f} C" if snapshot.temperature_c is not None else "-"
                        description = snapshot.description or "condicion no disponible"
                        st.success(f"{snapshot.location}: {temp} · {description}")
                    elif snapshot.status == "missing_key":
                        st.info("Falta OPENWEATHER_API_KEY o ROXY_OPENWEATHER_API_KEY para clima en vivo.")
                    else:
                        st.warning(snapshot.message or snapshot.status)
                except Exception as exc:
                    st.warning(f"No pude consultar clima ahora: {exc}")
                if st.button("Limpiar clima", key="roxy_clear_weather_action"):
                    st.session_state.pop("roxy_last_weather_request", None)
                    st.rerun()

        if isinstance(pending_browser, dict) and pending_browser:
            query = text_display(pending_browser.get("query") or "").strip()
            if query:
                target_url = query if query.lower().startswith(("http://", "https://")) else f"https://www.google.com/search?{urlencode({'q': query})}"
                with st.container(border=True):
                    st.markdown(f"**Navegador** · {html.escape(query)}")
                    st.caption("Abre la busqueda en una pestana nueva; Roxy no llena formularios ni compra sin permiso.")
                    st.link_button("Abrir busqueda preparada", target_url, use_container_width=True)
                    if st.button("Limpiar busqueda", key="roxy_clear_browser_action"):
                        st.session_state.pop("roxy_pending_browser_action", None)
                        st.rerun()

        if isinstance(pending_file, dict) and pending_file:
            requested_path = text_display(pending_file.get("path") or "").strip()
            with st.container(border=True):
                st.markdown("**Lectura de archivo**")
                if requested_path:
                    st.code(requested_path, language="text")
                else:
                    st.caption("Dile a Roxy la ruta del archivo o carpeta que quieres resumir.")
                st.caption("Roxy bloquea .env, llaves privadas y archivos sensibles.")
                cols = st.columns(2)
                if cols[0].button("Autorizar lectura segura", key="roxy_authorize_file_read"):
                    if requested_path:
                        st.session_state["roxy_os_allowed_permissions"] = sorted(
                            set(list(st.session_state.get("roxy_os_allowed_permissions") or []) + ["file_read"])
                        )
                        result = run_roxy_os_command(f"Roxy lee este archivo {requested_path}")
                        st.session_state["roxy_authorized_file_read_result"] = result
                    else:
                        st.session_state["roxy_authorized_file_read_result"] = {
                            "ok": False,
                            "message": "Falta la ruta del archivo."
                        }
                    st.rerun()
                if cols[1].button("Cancelar lectura", key="roxy_cancel_file_read"):
                    st.session_state.pop("roxy_pending_file_read", None)
                    st.session_state.pop("roxy_authorized_file_read_result", None)
                    st.rerun()
                read_result = st.session_state.get("roxy_authorized_file_read_result")
                if isinstance(read_result, dict) and read_result:
                    if read_result.get("ok"):
                        st.success(text_display(read_result.get("message") or "Archivo procesado."))
                    else:
                        st.warning(text_display(read_result.get("message") or "No se pudo leer el archivo."))

        if isinstance(pending_screen, dict) and pending_screen:
            with st.container(border=True):
                context = roxy_elevenlabs_page_context()
                st.markdown("**Pantalla / computadora**")
                st.info(
                    "En esta app web Roxy puede leer el contexto visible de Roxy Trading. "
                    "Para ver toda tu Mac, abrir carpetas y hacer clic fuera del navegador hace falta Roxy Desktop Helper "
                    "con permisos de Screen Recording y Accessibility."
                )
                st.json(
                    {
                        "page": context.get("page"),
                        "module": context.get("module"),
                        "symbol": context.get("symbol"),
                        "market": context.get("market"),
                        "timeframe": context.get("timeframe"),
                    },
                    expanded=False,
                )
                if st.button("Limpiar solicitud de pantalla", key="roxy_clear_screen_action"):
                    st.session_state.pop("roxy_pending_screen_summary", None)
                    st.rerun()


ROXY_ELEVENLABS_RUNTIME_TEMPLATE_PATH = project_path("assets/runtime/roxy_elevenlabs_assistant.js.html")
ROXY_ELEVENLABS_RUNTIME_PAYLOAD_MARKER = "__ROXY_VOICE_PAYLOAD_JSON__"
ROXY_ELEVENLABS_RUNTIME_AVATAR_MARKER = "__ROXY_AVATAR_MARKUP_JSON__"


@lru_cache(maxsize=1)
def roxy_elevenlabs_runtime_template() -> str:
    try:
        template = ROXY_ELEVENLABS_RUNTIME_TEMPLATE_PATH.read_text(encoding="utf-8")
    except OSError as exc:
        raise RuntimeError(f"Roxy voice runtime resource unavailable: {exc}") from exc
    if template.count(ROXY_ELEVENLABS_RUNTIME_PAYLOAD_MARKER) != 2:
        raise RuntimeError("Roxy voice runtime has an invalid payload-marker contract")
    if template.count(ROXY_ELEVENLABS_RUNTIME_AVATAR_MARKER) != 1:
        raise RuntimeError("Roxy voice runtime has an invalid avatar-marker contract")
    if "Conversation.startSession" not in template or "<script>" not in template or "</script>" not in template:
        raise RuntimeError("Roxy voice runtime is incomplete")
    return template


def roxy_json_for_inline_script(value: Any) -> str:
    """Serialize JSON without allowing user text to close the surrounding script."""
    return (
        json.dumps(value, ensure_ascii=False, default=str)
        .replace("&", "\\u0026")
        .replace("<", "\\u003c")
        .replace(">", "\\u003e")
        .replace("\u2028", "\\u2028")
        .replace("\u2029", "\\u2029")
    )


def roxy_elevenlabs_runtime_markup(*, voice_payload: Mapping[str, Any], avatar_html: str) -> str:
    replacements = {
        ROXY_ELEVENLABS_RUNTIME_PAYLOAD_MARKER: roxy_json_for_inline_script(dict(voice_payload)),
        ROXY_ELEVENLABS_RUNTIME_AVATAR_MARKER: roxy_json_for_inline_script(avatar_html),
    }
    marker_pattern = "|".join(re.escape(marker) for marker in replacements)
    return re.sub(marker_pattern, lambda match: replacements[match.group(0)], roxy_elevenlabs_runtime_template())


