def read_dashboard_ui_state(
    path: Path = DASHBOARD_UI_STATE_FILE,
    *,
    user_id: Any | None = None,
) -> dict[str, str]:
    active_user = user_id if user_id is not None else roxy_os_user_id()
    return UIStateStore(path).read(active_user)


def write_dashboard_ui_state(
    *,
    symbol: Any,
    market: Any,
    timeframe: Any,
    page: Any,
    path: Path = DASHBOARD_UI_STATE_FILE,
    user_id: Any | None = None,
) -> None:
    symbol_value = str(symbol or "").strip().upper() or "AAPL"
    payload = {
        "symbol": symbol_value,
        "market": normalize_command_market(market, symbol_value),
        "timeframe": normalize_command_timeframe(timeframe),
        "page": normalize_focused_page(page),
    }
    try:
        active_user = user_id if user_id is not None else roxy_os_user_id()
        UIStateStore(path).write(active_user, payload)
    except Exception:
        return


def normalize_focused_page(value: Any, *, default: str = "Dashboard") -> str:
    text = str(value or "").strip()
    aliases = {
        "Centro": "Dashboard",
        "Plan de trade": "Activo",
        "Riesgo $500": "Capital",
        "Voz": "Dashboard",
        "Roxy Lab": "Roxy IA",
        "Portafolio": "Capital",
        "Aprender": "Estudios",
        "Configuracion": "Diagnostico",
        "Configuración": "Diagnostico",
        "News": "Noticias",
        "Calendar": "Calendario",
    }
    if text in aliases:
        return aliases[text]
    return text if text in FOCUSED_PAGE_LABELS else default


def normalize_command_timeframe(value: Any, *, default: str = "1h") -> str:
    text = str(value or "").strip().lower()
    return text if text in TIMEFRAME_OPTIONS else default


def normalize_command_market(value: Any, symbol: Any = "") -> str:
    text = str(value or "").strip().lower()
    if text in {"stock", "crypto"}:
        return text
    return "crypto" if "/" in str(symbol or "") else "stock"


