def roxy_route_href(route_id: str, **context: Any) -> str:
    route = ROXY_ROUTE_REGISTRY.get(str(route_id or ""))
    if route is None:
        raise KeyError(f"Ruta Roxy desconocida: {route_id}")
    values = {key: value for key, value in route.items() if key != "label"}
    for key in ("symbol", "market", "tf"):
        value = context.get(key)
        if value not in (None, ""):
            values[key] = str(value)
    order = ("view", "module", "tab", "symbol", "market", "tf")
    query = "&".join(f"{key}={quote(str(values[key]), safe='')}" for key in order if key in values)
    return f"?{query}"


