def trade_desk_timeframe_pair(timeframe: Any) -> tuple[str, str]:
    tf = normalize_command_timeframe(timeframe)
    if tf == "1m":
        return "5m", "1m"
    if tf == "5m":
        return "15m", "5m"
    if tf == "15m":
        return "1h", "15m"
    if tf == "20m":
        return "1h", "20m"
    if tf == "30m":
        return "1h", "30m"
    if tf == "1h":
        return "1h", "15m"
    if tf == "2h":
        return "2h", "15m"
    if tf == "4h":
        return "4h", "1h"
    if tf == "1d":
        return "1d", "1h"
    if tf == "1w":
        return "1w", "1d"
    return "1h", "15m"


@st.cache_data(ttl=cache_ttl("chart"), show_spinner=False)
def cached_trade_desk_chart_df(symbol: str, market: str, timeframe: str) -> pd.DataFrame:
    resolved_symbol = resolve_symbol_query(symbol, market)
    normalized_timeframe = normalize_command_timeframe(timeframe)
    try:
        history, _data_source = fetch_symbol_history_with_source(
            resolved_symbol,
            market=market,
            timeframe=normalized_timeframe,
        )
    except Exception:
        history = fetch_direct_yfinance_ohlcv(resolved_symbol, normalized_timeframe)
    if history is None or history.empty:
        history = fetch_direct_yfinance_ohlcv(resolved_symbol, normalized_timeframe)
    return prepare_symbol_chart_data(history)


def chart_df_for_trade_desk_pane(
    chart_df: pd.DataFrame,
    *,
    symbol: str,
    market: str,
    selected_timeframe: str,
    pane_timeframe: str,
) -> pd.DataFrame:
    if normalize_command_timeframe(selected_timeframe) == normalize_command_timeframe(pane_timeframe):
        return chart_df
    try:
        pane_df = cached_trade_desk_chart_df(symbol, market, pane_timeframe)
        return pane_df if isinstance(pane_df, pd.DataFrame) and not pane_df.empty else chart_df
    except Exception:
        return chart_df


TRADE_DESK_CHART_HEIGHT = 520


def render_browser_live_candle_chart(
    chart_df: pd.DataFrame,
    *,
    symbol: str,
    market: str,
    timeframe: str,
    live_price: dict[str, Any] | None = None,
    trade_plan: dict[str, Any] | None = None,
    height: int = TRADE_DESK_CHART_HEIGHT,
) -> bool:
    left_tf, right_tf = trade_desk_timeframe_pair(timeframe)
    left_df = chart_df_for_trade_desk_pane(
        chart_df,
        symbol=symbol,
        market=market,
        selected_timeframe=timeframe,
        pane_timeframe=left_tf,
    )
    right_df = chart_df_for_trade_desk_pane(
        chart_df,
        symbol=symbol,
        market=market,
        selected_timeframe=timeframe,
        pane_timeframe=right_tf,
    )
    if left_df.empty and right_df.empty:
        return False
    st.markdown(
        (
            '<div class="dual-chart-contract-strip" '
            'style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;'
            'margin:3px 0 5px;padding:4px 8px;border:1px solid rgba(34,197,94,.24);'
            'border-radius:6px;background:rgba(15,23,42,.62);color:#cbd5e1;font-size:11px;">'
            '<strong>2 GRAFICAS LIVE</strong>'
            f"<span>{html.escape(text_display(symbol).upper())} · {html.escape(left_tf)} + {html.escape(right_tf)}</span>"
            "<span>EMA9 · Avg20/40 · Bollinger · volumen · sin recargar</span>"
            "</div>"
        ),
        unsafe_allow_html=True,
    )
    left, right = st.columns([1, 1], gap="small")
    rendered = False
    with left:
        rendered = (
            render_browser_live_candle_chart_panel(
                left_df,
                symbol=symbol,
                market=market,
                timeframe=left_tf,
                live_price=live_price,
                trade_plan=trade_plan,
                height=height,
                panel_label="Tendencia",
            )
            or rendered
        )
    with right:
        rendered = (
            render_browser_live_candle_chart_panel(
                right_df,
                symbol=symbol,
                market=market,
                timeframe=right_tf,
                live_price=live_price,
                trade_plan=trade_plan,
                height=height,
                panel_label="Entrada",
            )
            or rendered
        )
    return rendered


ROXY_LIVE_CHART_RUNTIME_TEMPLATE_PATH = project_path("assets/runtime/roxy_live_candle_chart.html")
ROXY_LIVE_CHART_PAYLOAD_MARKER = "__ROXY_PAYLOAD__"
ROXY_LIVE_CHART_VENDOR_MARKER = "__LIGHTWEIGHT_INLINE__"


@lru_cache(maxsize=1)
def roxy_live_chart_runtime_template() -> str:
    try:
        template = ROXY_LIVE_CHART_RUNTIME_TEMPLATE_PATH.read_text(encoding="utf-8")
    except OSError as exc:
        raise RuntimeError(f"Roxy live chart runtime resource unavailable: {exc}") from exc
    if template.count(ROXY_LIVE_CHART_PAYLOAD_MARKER) != 1:
        raise RuntimeError("Roxy live chart runtime has an invalid payload-marker contract")
    if template.count(ROXY_LIVE_CHART_VENDOR_MARKER) != 1:
        raise RuntimeError("Roxy live chart runtime has an invalid vendor-marker contract")
    required = (
        'id="roxy-live-chart-root"',
        "LightweightCharts.createChart",
        "openKlineSocket()",
        "chart.subscribeCrosshairMove",
        "</script>",
    )
    if any(marker not in template for marker in required):
        raise RuntimeError("Roxy live chart runtime is incomplete")
    return template


def roxy_live_chart_runtime_markup(*, payload: Mapping[str, Any], lightweight_inline_source: str) -> str:
    replacements = {
        ROXY_LIVE_CHART_PAYLOAD_MARKER: roxy_json_for_inline_script(dict(payload)),
        ROXY_LIVE_CHART_VENDOR_MARKER: roxy_json_for_inline_script(lightweight_inline_source),
    }
    marker_pattern = "|".join(re.escape(marker) for marker in replacements)
    return re.sub(marker_pattern, lambda match: replacements[match.group(0)], roxy_live_chart_runtime_template())


def render_browser_live_candle_chart_panel(
    chart_df: pd.DataFrame,
    *,
    symbol: str,
    market: str,
    timeframe: str,
    live_price: dict[str, Any] | None = None,
    trade_plan: dict[str, Any] | None = None,
    strategy_profile: str | None = None,
    persisted_chart_state: dict[str, Any] | None = None,
    max_candles: int = 1200,
    height: int = TRADE_DESK_CHART_HEIGHT,
    panel_label: str = "Grafica",
) -> bool:
    if persisted_chart_state is None:
        persisted_chart_state = roxy_chart_state_store().snapshot(
            roxy_os_user_id(),
            symbol=symbol,
            market=market,
            timeframe=timeframe,
        )
    payload = live_candle_chart_payload(
        chart_df,
        symbol=symbol,
        market=market,
        timeframe=timeframe,
        live_price=live_price,
        trade_plan=trade_plan,
        strategy_profile=strategy_profile,
        persisted_chart_state=persisted_chart_state,
        max_candles=max_candles,
    )
    if not payload.get("candles"):
        return False
    lightweight_inline_source = roxy_vendor_js_source("lightweight-charts.4.2.3.min.js")
    candle_count = len(payload.get("candles") or [])
    stream_label = "WS STREAM / STREAM ON" if payload.get("stream", {}).get("enabled") else "HISTORIAL"
    stream_source = text_display(payload.get("stream", {}).get("provider") or payload.get("live", {}).get("source"))
    st.markdown(
        (
            '<div class="live-chart-contract-strip" '
            'style="display:flex;gap:7px;flex-wrap:wrap;align-items:center;'
            'margin:2px 0 3px;padding:3px 6px;border:1px solid rgba(34,197,94,.18);'
            'border-radius:6px;background:rgba(15,23,42,.58);color:#cbd5e1;font-size:11px;">'
            f"<strong>{html.escape(stream_label)}</strong>"
            f"<span>{html.escape(panel_label)} · {html.escape(text_display(symbol).upper())} · {html.escape(normalize_command_timeframe(timeframe))} · velas live</span>"
            f"<span>{candle_count:,} velas · {html.escape(stream_source)}</span>"
            f"<span>{html.escape(text_display(payload.get('strategy', {}).get('detail')))}</span>"
            "</div>"
        ),
        unsafe_allow_html=True,
    )
    html_doc = roxy_live_chart_runtime_markup(
        payload=payload,
        lightweight_inline_source=lightweight_inline_source,
    )
    st.components.v1.html(html_doc, height=height, scrolling=False)
    return True


def render_operational_chart_first(
    chart_df: pd.DataFrame,
    setup: dict,
    confluence: dict | None,
    trade_brief: dict | None,
    *,
    symbol: str,
    live_price: dict[str, Any] | None = None,
    chart_interactive: bool = True,
    render_trade_snapshot: bool = True,
) -> None:
    timeframe = normalize_command_timeframe((trade_brief or {}).get("timeframe") or setup.get("timeframe") or setup.get("tf") or "1h")
    market = normalize_command_market((trade_brief or {}).get("market") or setup.get("market"), symbol)
    clean_window = prepare_chart_window(chart_df, limit=3000)
    if clean_window.empty:
        st.warning("Grafica operativa sin velas limpias todavia; revisa simbolo, mercado o timeframe.")
        return
    chart_plan_row: dict[str, Any] = {}
    for source in (setup, confluence, trade_brief):
        if isinstance(source, dict):
            chart_plan_row.update(source)
    chart_plan_row.setdefault("symbol", symbol)
    chart_plan_row.setdefault("market", market)
    chart_trade_plan = trade_decision_card_status(chart_plan_row)
    if chart_interactive and render_browser_live_candle_chart(
        clean_window,
        symbol=symbol,
        market=market,
        timeframe=timeframe,
        live_price=live_price,
        trade_plan=chart_trade_plan,
    ):
        if render_trade_snapshot:
            render_operational_trade_snapshot(setup, confluence, trade_brief, clean_window, live_price=live_price)
        return
    if render_trade_snapshot:
        render_operational_trade_snapshot(setup, confluence, trade_brief, clean_window, live_price=live_price)
    plot_window = clean_window.tail(1500).copy()
    if go is not None and make_subplots is not None and {"ts", "open", "high", "low", "close"}.issubset(plot_window.columns):
        try:
            fig = make_subplots(
                rows=3,
                cols=1,
                shared_xaxes=True,
                vertical_spacing=0.025,
                row_heights=[0.66, 0.18, 0.16],
            )
            fig.add_trace(
                go.Candlestick(
                    x=plot_window["ts"],
                    open=plot_window["open"],
                    high=plot_window["high"],
                    low=plot_window["low"],
                    close=plot_window["close"],
                    name="Velas",
                    increasing_line_color="#22c55e",
                    increasing_fillcolor="#22c55e",
                    decreasing_line_color="#ef4444",
                    decreasing_fillcolor="#ef4444",
                ),
                row=1,
                col=1,
            )
            ma_colors = {
                "ema9": "#d946ef",
                "sma20": "#22c55e",
                "sma40": "#38bdf8",
                "sma100": "#f59e0b",
                "sma200": "#ef4444",
            }
            for column, color in ma_colors.items():
                if column in plot_window.columns and pd.to_numeric(plot_window[column], errors="coerce").notna().any():
                    fig.add_trace(
                        go.Scatter(
                            x=plot_window["ts"],
                            y=pd.to_numeric(plot_window[column], errors="coerce"),
                            mode="lines",
                            name=column.upper(),
                            line=dict(color=color, width=1.6),
                        ),
                        row=1,
                        col=1,
                    )
            level_sources = [
                ("Entrada", safe_float((trade_brief or {}).get("entry") or (confluence or {}).get("entry")), "#22c55e"),
                ("Stop", safe_float((trade_brief or {}).get("stop") or (confluence or {}).get("stop")), "#ef4444"),
                (
                    "Target 2%",
                    safe_float(
                        (trade_brief or {}).get("target_2")
                        or (trade_brief or {}).get("target")
                        or (trade_brief or {}).get("target_price")
                    ),
                    "#a78bfa",
                ),
            ]
            for label, value, color in level_sources:
                if value is not None and value > 0:
                    fig.add_hline(
                        y=value,
                        line_color=color,
                        line_width=1.5,
                        line_dash="dash",
                        annotation_text=f"{label} {num_display(value, 2)}",
                        annotation_position="top left",
                        row=1,
                        col=1,
                    )
            live_value = safe_float((live_price or {}).get("price"))
            live_freshness = text_display((live_price or {}).get("freshness")).upper()
            if live_value is not None and live_value > 0 and live_freshness in {"LIVE", "FRESH"}:
                live_ts = pd.to_datetime((live_price or {}).get("observed_at"), errors="coerce", utc=True)
                latest_ts = pd.to_datetime(plot_window["ts"], errors="coerce", utc=True).max()
                marker_ts = live_ts if pd.notna(live_ts) else latest_ts
                if pd.isna(marker_ts):
                    marker_ts = latest_ts
                fig.add_hline(
                    y=live_value,
                    line_color="#f8fafc",
                    line_width=1.3,
                    line_dash="dot",
                    annotation_text=f"Tick live {price_display(live_value)}",
                    annotation_position="bottom left",
                    row=1,
                    col=1,
                )
                fig.add_trace(
                    go.Scatter(
                        x=[marker_ts],
                        y=[live_value],
                        mode="markers+text",
                        name="Tick live",
                        marker=dict(size=10, color="#f8fafc", line=dict(color="#0f172a", width=1.5)),
                        text=[f"{live_freshness} {price_display(live_value)}"],
                        textposition="top right",
                        textfont=dict(size=11, color="#f8fafc"),
                    ),
                    row=1,
                    col=1,
                )
            if "volume" in plot_window.columns:
                volume_colors = [
                    "#22c55e" if close >= open_ else "#ef4444"
                    for open_, close in zip(
                        pd.to_numeric(plot_window["open"], errors="coerce").fillna(0),
                        pd.to_numeric(plot_window["close"], errors="coerce").fillna(0),
                    )
                ]
                fig.add_trace(
                    go.Bar(
                        x=plot_window["ts"],
                        y=pd.to_numeric(plot_window["volume"], errors="coerce"),
                        marker_color=volume_colors,
                        name="Volumen",
                        opacity=0.55,
                    ),
                    row=2,
                    col=1,
                )
            if "rsi14" in plot_window.columns and pd.to_numeric(plot_window["rsi14"], errors="coerce").notna().any():
                fig.add_trace(
                    go.Scatter(
                        x=plot_window["ts"],
                        y=pd.to_numeric(plot_window["rsi14"], errors="coerce"),
                        mode="lines",
                        name="RSI 14",
                        line=dict(color="#f8fafc", width=1.5),
                    ),
                    row=3,
                    col=1,
                )
                fig.add_hline(y=70, line_color="#f59e0b", line_width=1, line_dash="dot", row=3, col=1)
                fig.add_hline(y=30, line_color="#22c55e", line_width=1, line_dash="dot", row=3, col=1)
            fig.update_layout(
                template="plotly_dark",
                height=640,
                margin=dict(l=10, r=10, t=12, b=10),
                paper_bgcolor="#0b1220",
                plot_bgcolor="#0b1220",
                legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="left", x=0),
                hovermode="x unified",
            )
            fig.update_xaxes(rangeslider_visible=False)
            fig.update_yaxes(title_text="Precio", row=1, col=1)
            fig.update_yaxes(title_text="Vol", row=2, col=1)
            fig.update_yaxes(title_text="RSI", range=[0, 100], row=3, col=1)
            st.plotly_chart(fig, use_container_width=True, config={"displayModeBar": True, "scrollZoom": True})
            return
        except Exception:
            pass
    try:
        price_chart = build_professional_price_chart(
            clean_window,
            setup,
            confluence or {},
            trade_brief or {},
            paper_snapshot=st.session_state.get("alpaca_paper_journal_snapshot"),
            symbol=symbol,
            hover_interactive=chart_interactive,
        ).properties(height=390)
        st.altair_chart(style_trading_chart(price_chart, interactive=chart_interactive), use_container_width=True)
    except Exception:
        fallback_cols = [col for col in ["close", "ema9", "sma20", "sma40", "sma100", "sma200"] if col in clean_window.columns]
        if fallback_cols:
            st.line_chart(clean_window[fallback_cols].apply(pd.to_numeric, errors="coerce"), height=390)
        else:
            st.warning("No se pudo dibujar la grafica operativa con las columnas actuales.")


def platform_badge_rows(env: dict[str, str] | None = None) -> list[dict[str, str]]:
    rows: list[dict[str, str]] = []
    for platform_id, profile in PLATFORM_PROFILES.items():
        brand = PLATFORM_BADGE_BRANDS.get(platform_id, {})
        try:
            status = platform_credential_status(platform_id, env=env)
        except Exception:
            status = {"mode": "NEEDS_CREDENTIALS", "configured": False}
        mode = str(status.get("mode") or "NEEDS_CREDENTIALS")
        configured = bool(status.get("configured"))
        rows.append(
            {
                "platform_id": platform_id,
                "name": str(profile.get("name") or platform_id),
                "abbr": str(brand.get("abbr") or platform_id[:2].upper()),
                "asset": str(brand.get("asset") or ", ".join(profile.get("assets", []))),
                "use": str(brand.get("use") or profile.get("best_for") or "-"),
                "mode": connection_mode_label(mode),
                "tone": "buy" if configured else "watch",
                "accent": str(brand.get("accent") or "#38bdf8"),
            }
        )
    return rows


def live_provider_rows(env: dict[str, str] | None = None) -> list[dict[str, Any]]:
    source = env if env is not None else os.environ

    def has_key_groups(groups: tuple[tuple[str, ...], ...]) -> tuple[list[str], list[str]]:
        present: list[str] = []
        missing: list[str] = []
        for group in groups:
            group_present = [key for key in group if str(source.get(key) or "").strip()]
            if group_present:
                present.extend(group_present)
            else:
                missing.append(" or ".join(group))
        return present, missing

    provider_specs = [
        {
            "provider": "yfinance",
            "role": "Fallback charts",
            "key_groups": (),
            "mode": "ON",
            "tone": "watch",
            "latency": "Delay/limitado",
            "next": "Mantener como respaldo; no usar como fuente principal de ejecucion.",
        },
        {
            "provider": "Alpaca",
            "role": "Stocks/Crypto live + paper",
            "key_groups": (ALPACA_KEY_ENV_KEYS, ALPACA_SECRET_ENV_KEYS),
            "mode": "PAPER_READY",
            "tone": "buy",
            "latency": "WebSocket",
            "next": "Guardar key/secret en vault o env; iniciar solo paper trading.",
        },
        {
            "provider": "Polygon",
            "role": "Stocks premium candles",
            "key_groups": (POLYGON_KEY_ENV_KEYS,),
            "mode": "STOCK_DATA_READY",
            "tone": "buy",
            "latency": "REST/API",
            "next": "Usar como fuente premium alterna para graficas si Alpaca falla.",
        },
        {
            "provider": "Tradier",
            "role": "Opciones/Greeks",
            "key_groups": (("TRADIER_ACCESS_TOKEN",),),
            "mode": "OPTIONS_READY",
            "tone": "buy",
            "latency": "API",
            "next": "Usar para chain de opciones y scoring con spreads.",
        },
        {
            "provider": "Schwab",
            "role": "Stocks/options broker",
            "key_groups": (
                ("SCHWAB_CLIENT_ID",),
                ("SCHWAB_CLIENT_SECRET",),
                ("SCHWAB_ACCESS_TOKEN",),
                ("SCHWAB_ACCOUNT_HASH",),
            ),
            "mode": "PREVIEW_READY",
            "tone": "watch",
            "latency": "OAuth/API",
            "next": "Completar OAuth; mantener envio real apagado.",
        },
        {
            "provider": "Crypto.com",
            "role": "Crypto exchange data",
            "key_groups": (),
            "mode": "CRYPTO_EXCHANGE_DATA",
            "tone": "buy",
            "latency": "REST publico",
            "next": "Usar tickers/candles publicos; no ejecutar ordenes reales desde Roxy.",
        },
        {
            "provider": "Finviz",
            "role": "Screener Elite/export",
            "key_groups": (),
            "mode": "REFERENCE",
            "tone": "watch",
            "latency": "CSV/API export",
            "next": "Usar como filtro de oportunidades; confirmar con fuente live antes de operar.",
        },
        {
            "provider": "TradingView",
            "role": "Charts + webhooks",
            "key_groups": (),
            "mode": "CHART_CONFIRMATION",
            "tone": "watch",
            "latency": "Webhook/chart",
            "next": "Usar para confirmacion visual y alertas; no ejecutar ordenes desde webhook.",
        },
        {
            "provider": "TC2000",
            "role": "Charting externo",
            "key_groups": (),
            "mode": "MANUAL_LINK",
            "tone": "neutral",
            "latency": "Plataforma",
            "next": "Abrir simbolo/contexto externo; no depender de API para ejecucion.",
        },
    ]
    rows: list[dict[str, Any]] = []
    for spec in provider_specs:
        key_groups = tuple(spec.get("key_groups") or ())
        present, missing = has_key_groups(key_groups)
        configured = not missing if key_groups else True
        if key_groups and not configured:
            status = "Faltan credenciales"
            tone = "avoid" if spec["provider"] == "Alpaca" else "watch"
        elif spec["provider"] == "yfinance":
            status = "Activo fallback"
            tone = spec["tone"]
        elif spec["provider"] == "Crypto.com":
            configured = True
            present = [
                key
                for key in (
                    "ROXY_CRYPTOCOM_BASE_URL",
                    "ROXY_CRYPTOCOM_API_KEY",
                    "CRYPTO_COM_API_KEY",
                    "ROXY_CRYPTOCOM_API_SECRET",
                    "CRYPTO_COM_API_SECRET",
                )
                if str(source.get(key) or "").strip()
            ]
            status = "Listo datos publicos"
            tone = spec["tone"]
        elif spec["provider"] == "Finviz":
            present = [
                key
                for key in (
                    "ROXY_FINVIZ_EXPORT_URL",
                    "FINVIZ_EXPORT_URL",
                    "ROXY_FINVIZ_AUTH_TOKEN",
                    "FINVIZ_AUTH_TOKEN",
                    "FINVIZ_API_KEY",
                )
                if str(source.get(key) or "").strip()
            ]
            configured = bool(present)
            status = "Listo screener" if configured else "Referencia"
            tone = "buy" if configured else spec["tone"]
        elif spec["provider"] == "TradingView":
            present = [
                key
                for key in (
                    "TRADINGVIEW_WEBHOOK_SECRET",
                    "TRADINGVIEW_PUBLIC_WEBHOOK_URL",
                    "ROXY_TRADINGVIEW_WIDGET_ENABLED",
                    "ROXY_TRADINGVIEW_LIBRARY_URL",
                )
                if str(source.get(key) or "").strip()
            ]
            configured = bool(present) or str(source.get("ROXY_TRADINGVIEW_WIDGET_ENABLED") or "true").lower() not in {
                "0",
                "false",
                "no",
                "off",
            }
            status = "Listo visual/webhook" if configured else "Referencia"
            tone = "buy" if any(key.startswith("TRADINGVIEW_") for key in present) else spec["tone"]
        elif not key_groups:
            status = "Referencia"
            tone = spec["tone"]
        elif spec["provider"] == "Polygon":
            status = "Listo data"
            tone = spec["tone"]
        else:
            status = "Listo paper/preview"
            tone = spec["tone"]
        rows.append(
            {
                "provider": spec["provider"],
                "role": spec["role"],
                "status": status,
                "tone": tone,
                "mode": spec["mode"],
                "latency": spec["latency"],
                "configured": configured,
                "present": len(present),
                "present_keys": ", ".join(present) if present else "-",
                "missing": ", ".join(missing) if missing else "-",
                "next": spec["next"],
            }
        )
    return rows


def live_provider_quality_summary(rows: list[dict[str, Any]]) -> dict[str, str]:
    credential_issues = [
        row
        for row in rows
        if row.get("missing") not in {"", "-", None}
        and row.get("provider") in {"Alpaca", "Polygon", "Tradier", "Schwab"}
        and int(row.get("present") or 0) > 0
    ]
    ready_rows = [
        row
        for row in rows
        if bool(row.get("configured"))
        and row.get("provider") in {"Alpaca", "Polygon", "Tradier", "Schwab"}
        and (
            row.get("operational") is True
            or str(row.get("status") or "").startswith("Listo")
        )
    ]
    ready_names = [text_display(row.get("provider")) for row in ready_rows]
    has_alpaca = any(row.get("provider") == "Alpaca" for row in ready_rows)
    has_polygon = any(row.get("provider") == "Polygon" for row in ready_rows)
    has_options = any(row.get("provider") == "Tradier" for row in ready_rows)
    has_broker_preview = any(row.get("provider") == "Schwab" for row in ready_rows)
    fallback_active = any(row.get("provider") == "yfinance" and bool(row.get("configured")) for row in rows)

    if has_alpaca or has_polygon:
        detail_parts = []
        if has_alpaca:
            detail_parts.append(
                "Alpaca tiene credenciales presentes para data/paper, pendiente de validacion por grafica efectiva."
            )
        if has_polygon:
            detail_parts.append("Polygon puede alimentar velas premium de acciones cuando Alpaca no responde.")
        if has_options:
            detail_parts.append("Tradier puede alimentar opciones/Greeks.")
        if has_broker_preview:
            detail_parts.append("Schwab queda solo en preview hasta OAuth completo.")
        return {
            "mode": "PAPER_LIVE_READY" if has_alpaca else "STOCK_PREMIUM_READY",
            "status": "Credenciales presentes",
            "tone": "buy",
            "detail": " ".join(detail_parts)
            + " Cada grafica valida si el proveedor premium realmente respondio o si cayo a fallback.",
            "ready_providers": ", ".join(ready_names) if ready_names else "-",
            "next": "Verificar fuente efectiva en cada grafica antes de tratarla como stream premium.",
        }

    if ready_rows:
        return {
            "mode": "BROKER_PREVIEW_READY",
            "status": "Preview broker listo",
            "tone": "watch",
            "detail": f"{', '.join(ready_names)} listo para preview; falta un stream principal tipo Alpaca para graficas realtime.",
            "ready_providers": ", ".join(ready_names),
            "next": "Conectar Alpaca paper para velas live antes de depender de ejecucion intradia.",
        }

    if credential_issues:
        issue = credential_issues[0]
        return {
            "mode": "CREDENTIALS_INCOMPLETE",
            "status": "Credenciales incompletas",
            "tone": "avoid",
            "detail": f"{text_display(issue.get('provider'))} no esta listo: faltan {text_display(issue.get('missing'))}.",
            "ready_providers": "-",
            "next": "Completar credenciales o apagar esa ruta para evitar falsa seguridad.",
        }

    if fallback_active:
        return {
            "mode": "FALLBACK_ONLY",
            "status": "Fallback activo",
            "tone": "watch",
            "detail": "yfinance mantiene graficas/watchlist, pero puede tener delay y limites; no tratarlo como data premium realtime.",
            "ready_providers": "yfinance",
            "next": "Usar Finviz/TC2000 como referencia visual y conectar proveedor live para operar.",
        }

    return {
        "mode": "NO_LIVE_SOURCE",
        "status": "Sin fuente live",
        "tone": "avoid",
        "detail": "No hay proveedor principal ni fallback activo para graficas en vivo.",
        "ready_providers": "-",
        "next": "Configurar Alpaca paper o revisar dependencias de mercado.",
    }


def realtime_check_by_name(
    realtime_report: dict[str, Any] | None,
    name: str,
) -> dict[str, Any]:
    checks = realtime_report.get("checks") if isinstance(realtime_report, dict) else None
    if not isinstance(checks, list):
        return {}
    return next(
        (
            dict(check)
            for check in checks
            if isinstance(check, dict) and text_display(check.get("name")) == name
        ),
        {},
    )


def apply_live_provider_runtime_status(
    rows: list[dict[str, Any]],
    realtime_report: dict[str, Any] | None,
) -> list[dict[str, Any]]:
    """Overlay credential discovery with the latest runtime validation result."""
    check = realtime_check_by_name(realtime_report, "alpaca_account_probe")
    if not check:
        return [dict(row) for row in rows]

    check_status = text_display(check.get("status")).upper()
    auth_ok = check.get("auth_ok") is True
    error_category = text_display(check.get("error_category")).upper()
    detail = text_display(check.get("detail"))
    updated: list[dict[str, Any]] = []
    for original in rows:
        row = dict(original)
        if row.get("provider") != "Alpaca":
            updated.append(row)
            continue
        row["runtime_status"] = check_status or "UNKNOWN"
        row["runtime_detail"] = detail
        if check_status == "OK" and auth_ok:
            row.update(
                {
                    "status": "Conectado y validado",
                    "tone": "buy",
                    "mode": "PAPER_VALIDATED",
                    "operational": True,
                    "next": "Mantener paper trading; verificar fuente efectiva y latencia por grafica.",
                }
            )
        elif check_status in {"WARN", "FAIL"}:
            auth_invalid = error_category == "AUTH_INVALID" or "auth failed" in detail.lower()
            row.update(
                {
                    "status": "Autenticacion invalida" if auth_invalid else "Validacion fallida",
                    "tone": "avoid",
                    "mode": error_category or "RUNTIME_VALIDATION_FAILED",
                    "operational": False,
                    "next": (
                        "Corregir credenciales/permisos de Alpaca y repetir el diagnostico paper."
                        if auth_invalid
                        else "Revisar el diagnostico de Alpaca y repetir la validacion antes de usar data premium."
                    ),
                }
            )
        updated.append(row)
    return updated


def live_provider_runtime_summary(
    summary: dict[str, Any],
    realtime_report: dict[str, Any] | None,
) -> dict[str, Any]:
    check = realtime_check_by_name(realtime_report, "alpaca_account_probe")
    if not check:
        return dict(summary)
    check_status = text_display(check.get("status")).upper()
    if check_status == "OK" and check.get("auth_ok") is True:
        return {
            **summary,
            "mode": "PAPER_LIVE_VALIDATED",
            "status": "Alpaca conectado y validado",
            "tone": "buy",
            "detail": text_display(check.get("detail")),
        }
    if check_status not in {"WARN", "FAIL"}:
        return dict(summary)

    detail = text_display(check.get("detail"))
    error_category = text_display(check.get("error_category")).upper()
    auth_invalid = error_category == "AUTH_INVALID" or "auth failed" in detail.lower()
    ready = [
        name.strip()
        for name in text_display(summary.get("ready_providers")).split(",")
        if name.strip() not in {"", "-", "Alpaca"}
    ]
    return {
        **summary,
        "mode": "PROVIDER_AUTH_FAILED" if auth_invalid else "PROVIDER_VALIDATION_FAILED",
        "status": "Alpaca no operativo",
        "tone": "avoid",
        "detail": detail,
        "ready_providers": ", ".join(ready) if ready else "-",
        "next": (
            "Corregir credenciales/permisos de Alpaca y repetir el diagnostico paper."
            if auth_invalid
            else "Resolver el fallo de validacion y repetir el diagnostico antes de usar Alpaca."
        ),
    }


def live_provider_effective_summary(
    provider_summary: dict[str, Any] | None,
    source_meta: dict[str, Any] | None,
) -> dict[str, Any]:
    provider_summary = dict(provider_summary or {})
    source = chart_effective_source("stock", source_meta=source_meta)
    source_mode = text_display(source.get("mode")).upper()
    fallback_reason = text_display(source.get("fallback_reason"))
    if (
        text_display(provider_summary.get("mode")) == "PAPER_LIVE_READY"
        and source_mode == "FALLBACK"
        and fallback_reason not in {"", "-"}
    ):
        auth_like = fallback_reason in {"alpaca_auth", "alpaca_feed_permission"}
        return {
            **provider_summary,
            "mode": "PROVIDER_FALLBACK",
            "status": "Proveedor en fallback",
            "tone": "avoid" if auth_like else "watch",
            "detail": f"Alpaca tiene credenciales, pero esta grafica usa fallback: {fallback_reason}. {text_display(source.get('fallback_detail'))}",
            "ready_providers": text_display(provider_summary.get("ready_providers")),
            "next": text_display(source.get("fallback_action") or provider_summary.get("next")),
            "source_label": text_display(source.get("label")),
            "fallback_reason": fallback_reason,
        }
    return provider_summary


def external_confirmation_plan(
    symbol: str | None,
    market: str = "stock",
    realtime_report: dict[str, Any] | None = None,
) -> dict[str, Any]:
    clean_symbol = text_display(symbol).upper()
    if not clean_symbol or clean_symbol == "-":
        return {
            "label": "Sin simbolo",
            "tone": "watch",
            "gate": "NO_SYMBOL",
            "detail": "Selecciona un ticker para abrir confirmacion externa.",
            "links": [],
            "alerts_allowed": False,
        }
    market_value = normalize_command_market(market, clean_symbol)
    market_rows = market_realtime_dashboard_rows(realtime_report)
    market_row = next(
        (row for row in market_rows if text_display(row.get("market")).lower() == market_value.lower()),
        {},
    )
    alerts_allowed = bool(market_row.get("alerts_allowed", True)) if market_row else True
    tone = text_display(market_row.get("tone") if market_row else "")
    provider_recovery = (
        realtime_report.get("provider_recovery")
        if isinstance(realtime_report, dict) and isinstance(realtime_report.get("provider_recovery"), dict)
        else {}
    )
    stock_premium_blocked = bool(provider_recovery.get("premium_blocked")) if market_value == "stock" else False
    blocked = market_value == "stock" and (not alerts_allowed or tone == "avoid" or stock_premium_blocked)

    if blocked:
        label = "Confirmacion externa obligatoria"
        plan_tone = "avoid"
        gate = "NO_TRADE_FROM_FALLBACK"
        detail = "Acciones/opciones estan bloqueadas por proveedor premium; no usar fallback como gatillo rapido."
    elif market_value == "crypto" and tone == "buy":
        label = "Crypto live validado"
        plan_tone = "buy"
        gate = "EXCHANGE_API_CONFIRMED"
        detail = "Cripto tiene ruta exchange/API; confirmar niveles visuales antes de ejecutar manualmente."
    elif market_value == "crypto":
        label = "Confirmar exchange"
        plan_tone = "watch"
        gate = "EXCHANGE_CONFIRM"
        detail = "Revalidar precio y spread en plataforma externa antes de actuar."
    else:
        label = "Confirmar proveedor"
        plan_tone = "watch"
        gate = "PREMIUM_CONFIRM"
        detail = "Validar fuente efectiva y niveles externos antes de tratar la grafica como realtime premium."

    research = company_research_hub_rows(clean_symbol, market_value)
    preferred = (
        ["Finviz", "TradingView", "Nasdaq"] if market_value == "stock" else ["TradingView", "Yahoo", "CoinMarketCap"]
    )
    links: list[dict[str, str]] = []
    if not research.empty:
        for preferred_label in preferred:
            matches = research[research["label"].astype(str).eq(preferred_label)]
            if matches.empty:
                continue
            item = matches.iloc[0].to_dict()
            links.append(
                {
                    "label": text_display(item.get("label")),
                    "kind": text_display(item.get("kind")),
                    "url": text_display(item.get("url")),
                    "why": text_display(item.get("why")),
                }
            )
    return {
        "label": label,
        "tone": plan_tone,
        "gate": gate,
        "detail": detail,
        "links": links,
        "alerts_allowed": alerts_allowed and not blocked,
        "market": market_value.upper(),
        "symbol": clean_symbol,
    }


def render_external_confirmation_plan(plan: dict[str, Any] | None) -> str:
    plan = plan or {}
    links = plan.get("links") if isinstance(plan.get("links"), list) else []
    if not links:
        return ""
    tone = text_display(plan.get("tone"))
    link_html = []
    for link in links[:3]:
        if not isinstance(link, dict):
            continue
        link_html.append(
            f'<a href="{html.escape(text_display(link.get("url")))}" target="_blank" rel="noopener noreferrer">'
            f'<span>{html.escape(text_display(link.get("kind")))}</span>'
            f'<strong>{html.escape(text_display(link.get("label")))}</strong>'
            f'<small>{html.escape(text_display(link.get("why")))}</small>'
            "</a>"
        )
    return (
        f'<section class="provider-confirmation provider-confirmation-{html.escape(tone)}">'
        '<div><span>Confirmacion externa</span>'
        f'<strong>{html.escape(text_display(plan.get("label")))}</strong>'
        f'<em>{html.escape(text_display(plan.get("symbol")))} · {html.escape(text_display(plan.get("market")))} · {html.escape(text_display(plan.get("gate")))}</em></div>'
        f'<p>{html.escape(text_display(plan.get("detail")))}</p>'
        f'<aside>{"".join(link_html)}</aside>'
        "</section>"
    )


def alpaca_operations_gate(
    env: dict[str, str] | None = None,
    *,
    realtime_report: dict[str, Any] | None = None,
) -> dict[str, Any]:
    source = env if env is not None else os.environ
    runtime_report = (
        realtime_report
        if isinstance(realtime_report, dict)
        else read_summary_json("alerts/roxy_realtime_check.json") if env is None else {}
    )

    def env_value(*keys: str) -> tuple[str, str]:
        for key in keys:
            value = str(source.get(key) or "").strip()
            if value:
                return value, key
        return "", ""

    def env_bool_value(key: str, default: bool = False) -> bool:
        raw = str(source.get(key) or "").strip().lower()
        if not raw:
            return default
        return raw in {"1", "true", "yes", "on", "paper"}

    key_value, key_name = env_value("ALPACA_API_KEY")
    secret_value, secret_name = env_value("ALPACA_API_SECRET", "ALPACA_SECRET_KEY")
    endpoint, endpoint_name = env_value("ALPACA_BASE_URL", "ALPACA_ENDPOINT", "ALPACA_API_BASE_URL")
    paper_flag = env_bool_value("ALPACA_PAPER", True)
    endpoint_lower = endpoint.lower()
    endpoint_mode = "paper" if paper_flag or "paper-api.alpaca.markets" in endpoint_lower else "live"
    endpoint_mismatch = bool(
        endpoint
        and (
            (paper_flag and "paper-api.alpaca.markets" not in endpoint_lower)
            or (not paper_flag and "paper-api.alpaca.markets" in endpoint_lower)
        )
    )
    configured = bool(key_value and secret_value)
    live_detected = configured and endpoint_mode == "live"
    paper_ready = configured and endpoint_mode == "paper" and not endpoint_mismatch
    runtime_check = realtime_check_by_name(runtime_report, "alpaca_account_probe")
    runtime_status = text_display(runtime_check.get("status")).upper()
    runtime_error_category = text_display(runtime_check.get("error_category")).upper()
    runtime_auth_ok = runtime_check.get("auth_ok") is True
    runtime_auth_failed = bool(
        configured
        and runtime_status in {"WARN", "FAIL"}
        and (
            runtime_error_category in {"AUTH_INVALID", "AUTH_FORBIDDEN", "ENDPOINT_OR_MODE"}
            or runtime_check.get("auth_ok") is False
        )
    )
    present_keys = [name for name in [key_name, secret_name, endpoint_name] if name]
    missing = []
    if not key_value:
        missing.append("ALPACA_API_KEY")
    if not secret_value:
        missing.append("ALPACA_API_SECRET or ALPACA_SECRET_KEY")
    if endpoint_mismatch:
        status = "Endpoint desalineado"
        tone = "avoid"
        mode = "ENDPOINT_MISMATCH"
        next_step = (
            "Alinear ALPACA_PAPER con el endpoint: paper usa https://paper-api.alpaca.markets y live queda bloqueado."
        )
    elif live_detected:
        status = "Live bloqueado"
        tone = "avoid"
        mode = "LIVE_LOCKED"
        next_step = "Cambiar a ALPACA_PAPER=true y endpoint paper; operar real exige aprobacion manual, kill switch y track record paper."
    elif runtime_auth_failed:
        paper_ready = False
        status = "Autenticacion invalida"
        tone = "avoid"
        mode = runtime_error_category or "AUTH_INVALID"
        next_step = (
            "Ejecutar `.venv/bin/python tools/provider_credential_setup.py alpaca` y repetir Diagnostico; "
            "las ordenes paper permanecen bloqueadas hasta autenticar correctamente."
        )
    elif paper_ready:
        status = "Paper listo"
        tone = "buy"
        mode = "PAPER_ONLY"
        next_step = "Usar solo paper para forward-test; no hay envio real desde el dashboard."
    elif configured:
        status = "Credenciales listas"
        tone = "watch"
        mode = "PREVIEW_ONLY"
        next_step = "Confirmar ALPACA_PAPER=true antes de habilitar cualquier orden paper."
    else:
        status = "Faltan credenciales"
        tone = "avoid"
        mode = "NOT_CONFIGURED"
        next_step = "Configurar variables de entorno fuera del repo; nunca pegar secretos en codigo."
    return {
        "status": status,
        "tone": tone,
        "mode": mode,
        "configured": configured,
        "paper_ready": paper_ready,
        "paper_orders_allowed": paper_ready,
        "live_orders_allowed": False,
        "live_detected": live_detected,
        "endpoint_mode": endpoint_mode,
        "endpoint_mismatch": endpoint_mismatch,
        "paper_flag": paper_flag,
        "runtime_checked": bool(runtime_check),
        "runtime_status": runtime_status or "NO_DATA",
        "runtime_auth_ok": runtime_auth_ok,
        "runtime_error_category": runtime_error_category or "-",
        "present_keys": ", ".join(present_keys) if present_keys else "-",
        "missing": ", ".join(missing) if missing else "-",
        "next": next_step,
    }


def render_alpaca_operations_gate(
    env: dict[str, str] | None = None,
    *,
    realtime_report: dict[str, Any] | None = None,
) -> str:
    gate = alpaca_operations_gate(env, realtime_report=realtime_report)
    tone = text_display(gate.get("tone"))
    paper_state = "ON" if gate.get("paper_orders_allowed") else "OFF"
    live_state = "ON" if gate.get("live_orders_allowed") else "LOCKED"
    return (
        f'<section class="alpaca-gate alpaca-gate-{html.escape(tone)}">'
        '<div><span>Alpaca Safety Gate</span>'
        f'<strong>{html.escape(text_display(gate.get("status")))}</strong>'
        f'<em>{html.escape(text_display(gate.get("mode")))} · Endpoint {html.escape(text_display(gate.get("endpoint_mode")))}</em></div>'
        f'<p>{html.escape(text_display(gate.get("next")))}</p>'
        '<aside>'
        f'<b>Paper orders: {html.escape(paper_state)}</b>'
        f'<b>Live orders: {html.escape(live_state)}</b>'
        f'<small>Creds: {html.escape(text_display(gate.get("present_keys")))} · Faltan: {html.escape(text_display(gate.get("missing")))}</small>'
        '</aside></section>'
    )


def alpaca_paper_account_snapshot(
    env: dict[str, str] | None = None,
    client_factory: Any | None = None,
    *,
    realtime_report: dict[str, Any] | None = None,
) -> dict[str, Any]:
    source = env if env is not None else os.environ
    gate = alpaca_operations_gate(env, realtime_report=realtime_report)
    base = {
        "status": "No conectado",
        "tone": "avoid",
        "mode": gate.get("mode"),
        "connected": False,
        "paper_ready": bool(gate.get("paper_ready")),
        "buying_power": None,
        "cash": None,
        "portfolio_value": None,
        "equity": None,
        "account_status": "-",
        "trading_blocked": None,
        "pattern_day_trader": None,
        "detail": text_display(gate.get("next")),
    }
    if not gate.get("paper_ready"):
        base["status"] = "Paper pendiente" if gate.get("configured") else "Credenciales pendientes"
        base["tone"] = text_display(gate.get("tone"))
        return base

    key = str(source.get("ALPACA_API_KEY") or "").strip()
    secret = str(source.get("ALPACA_API_SECRET") or source.get("ALPACA_SECRET_KEY") or "").strip()
    if not key or not secret:
        return base

    try:
        if client_factory is None:
            from alpaca.trading.client import TradingClient

            def client_factory(api_key: str, secret_key: str):
                return TradingClient(api_key=api_key, secret_key=secret_key, paper=True)

        client = client_factory(key, secret)
        account = client.get_account()
    except Exception as exc:
        return {
            **base,
            "status": "Paper sin conexion",
            "tone": "watch",
            "detail": f"No se pudo leer cuenta paper: {type(exc).__name__}. Revisar env/permiso sin exponer secretos.",
        }

    def attr(name: str) -> Any:
        if isinstance(account, dict):
            return account.get(name)
        return getattr(account, name, None)

    return {
        **base,
        "status": "Paper conectado",
        "tone": "buy",
        "mode": "PAPER_ACCOUNT_SYNC",
        "connected": True,
        "buying_power": safe_float(attr("buying_power")),
        "cash": safe_float(attr("cash")),
        "portfolio_value": safe_float(attr("portfolio_value")),
        "equity": safe_float(attr("equity")),
        "account_status": text_display(attr("status")),
        "trading_blocked": bool(attr("trading_blocked")) if attr("trading_blocked") is not None else None,
        "pattern_day_trader": bool(attr("pattern_day_trader")) if attr("pattern_day_trader") is not None else None,
        "detail": "Lectura read-only de Alpaca paper. Ordenes reales siguen bloqueadas.",
    }


def render_alpaca_paper_account_panel(
    env: dict[str, str] | None = None,
    *,
    realtime_report: dict[str, Any] | None = None,
) -> str:
    snapshot = alpaca_paper_account_snapshot(env, realtime_report=realtime_report)
    tone = text_display(snapshot.get("tone"))
    blocked = "SI" if snapshot.get("trading_blocked") else "NO" if snapshot.get("trading_blocked") is not None else "-"
    pdt = (
        "SI" if snapshot.get("pattern_day_trader") else "NO" if snapshot.get("pattern_day_trader") is not None else "-"
    )
    return (
        f'<section class="alpaca-paper-panel alpaca-paper-{html.escape(tone)}">'
        '<div><span>Alpaca Paper Account</span>'
        f'<strong>{html.escape(text_display(snapshot.get("status")))}</strong>'
        f'<em>{html.escape(text_display(snapshot.get("mode")))} · Estado {html.escape(text_display(snapshot.get("account_status")))}</em></div>'
        '<aside>'
        f'<b>Buying power</b><strong>{html.escape(num_display(snapshot.get("buying_power"), 2))}</strong>'
        f'<b>Portfolio</b><strong>{html.escape(num_display(snapshot.get("portfolio_value"), 2))}</strong>'
        f'<b>Cash</b><strong>{html.escape(num_display(snapshot.get("cash"), 2))}</strong>'
        '</aside>'
        f'<p>{html.escape(text_display(snapshot.get("detail")))} · Blocked: {html.escape(blocked)} · PDT: {html.escape(pdt)}</p>'
        '</section>'
    )


def alpaca_attr(item: Any, name: str) -> Any:
    if isinstance(item, dict):
        return item.get(name)
    return getattr(item, name, None)


def alpaca_time_ago(value: Any, now: datetime | None = None) -> str:
    if value in (None, "", "-"):
        return "-"
    if isinstance(value, str):
        raw = value.strip()
        try:
            parsed = datetime.fromisoformat(raw.replace("Z", "+00:00"))
        except Exception:
            return text_display(value)
    elif isinstance(value, datetime):
        parsed = value
    else:
        return text_display(value)
    current = now or utc_now_naive()
    if parsed.tzinfo is not None and current.tzinfo is None:
        current = current.replace(tzinfo=parsed.tzinfo)
    delta = current - parsed
    seconds = max(0, int(delta.total_seconds()))
    minutes = seconds // 60
    if minutes < 1:
        return "ahora"
    if minutes < 60:
        return f"{minutes}m"
    hours = minutes // 60
    if hours < 48:
        return f"{hours}h"
    return f"{hours // 24}d"


def alpaca_paper_journal_snapshot(
    env: dict[str, str] | None = None,
    client_factory: Any | None = None,
    *,
    limit: int = 8,
    now: datetime | None = None,
) -> dict[str, Any]:
    source = env if env is not None else os.environ
    gate = alpaca_operations_gate(source)
    base = {
        "status": "Paper journal pendiente",
        "tone": text_display(gate.get("tone")),
        "connected": False,
        "positions": [],
        "orders": [],
        "summary": {"open_positions": 0, "recent_orders": 0, "unrealized_pl": 0.0, "exposure": 0.0, "open_winners": 0},
        "detail": text_display(gate.get("next")),
    }
    if not gate.get("paper_ready"):
        return base
    key = str(source.get("ALPACA_API_KEY") or "").strip()
    secret = str(source.get("ALPACA_API_SECRET") or source.get("ALPACA_SECRET_KEY") or "").strip()
    if not key or not secret:
        return base
    try:
        if client_factory is None:
            from alpaca.trading.client import TradingClient
            from alpaca.trading.enums import QueryOrderStatus
            from alpaca.trading.requests import GetOrdersRequest

            def client_factory(api_key: str, secret_key: str):
                return TradingClient(api_key=api_key, secret_key=secret_key, paper=True)

            order_filter = GetOrdersRequest(status=QueryOrderStatus.ALL, limit=int(limit), nested=True)
        else:
            order_filter = None
        client = client_factory(key, secret)
        positions_raw = client.get_all_positions()
        try:
            orders_raw = client.get_orders(filter=order_filter) if order_filter is not None else client.get_orders()
        except TypeError:
            orders_raw = client.get_orders()
    except Exception as exc:
        return {
            **base,
            "status": "Paper journal sin conexion",
            "tone": "watch",
            "detail": f"No se pudo leer journal paper: {type(exc).__name__}. Revisar env/permiso sin exponer secretos.",
        }
    if isinstance(positions_raw, dict):
        positions_raw = positions_raw.get("positions") or positions_raw.get("data") or []
    if isinstance(orders_raw, dict):
        orders_raw = orders_raw.get("orders") or orders_raw.get("data") or []
    entry_time_lookup: dict[str, Any] = {}
    orders: list[dict[str, Any]] = []
    for order in list(orders_raw or [])[: max(1, int(limit))]:
        symbol = text_display(alpaca_attr(order, "symbol")).upper()
        submitted_at = alpaca_attr(order, "submitted_at")
        filled_at = alpaca_attr(order, "filled_at")
        side = text_display(alpaca_attr(order, "side")).lower()
        status = text_display(alpaca_attr(order, "status")).lower()
        if symbol and symbol != "-" and side == "buy" and status in {"filled", "partially_filled"}:
            entry_time_lookup.setdefault(symbol, filled_at or submitted_at)
        orders.append(
            {
                "symbol": symbol,
                "side": side.upper(),
                "status": status.upper(),
                "qty": safe_float(alpaca_attr(order, "qty")),
                "filled_qty": safe_float(alpaca_attr(order, "filled_qty")),
                "type": text_display(alpaca_attr(order, "type")).upper(),
                "order_class": text_display(alpaca_attr(order, "order_class")).upper(),
                "submitted": alpaca_time_ago(submitted_at, now=now),
                "filled": alpaca_time_ago(filled_at, now=now),
                "submitted_at": text_display(submitted_at),
                "filled_at": text_display(filled_at),
                "limit_price": safe_float(alpaca_attr(order, "limit_price")),
                "stop_price": safe_float(alpaca_attr(order, "stop_price")),
                "filled_avg_price": safe_float(alpaca_attr(order, "filled_avg_price")),
            }
        )
    positions: list[dict[str, Any]] = []
    for position in list(positions_raw or [])[: max(1, int(limit))]:
        symbol = text_display(alpaca_attr(position, "symbol")).upper()
        unrealized = safe_float(alpaca_attr(position, "unrealized_pl")) or 0.0
        positions.append(
            {
                "symbol": symbol,
                "qty": safe_float(alpaca_attr(position, "qty")),
                "avg_entry": safe_float(alpaca_attr(position, "avg_entry_price")),
                "current": safe_float(alpaca_attr(position, "current_price")),
                "market_value": safe_float(alpaca_attr(position, "market_value")) or 0.0,
                "unrealized_pl": unrealized,
                "unrealized_plpc": safe_float(alpaca_attr(position, "unrealized_plpc")),
                "entry_at": text_display(entry_time_lookup.get(symbol)),
                "time_in_trade": alpaca_time_ago(entry_time_lookup.get(symbol), now=now),
                "tone": "buy" if unrealized >= 0 else "avoid",
            }
        )
    summary = {
        "open_positions": len(positions),
        "recent_orders": len(orders),
        "unrealized_pl": round(sum(safe_float(row.get("unrealized_pl")) or 0.0 for row in positions), 2),
        "exposure": round(sum(safe_float(row.get("market_value")) or 0.0 for row in positions), 2),
        "open_winners": sum(1 for row in positions if (safe_float(row.get("unrealized_pl")) or 0.0) >= 0),
    }
    return {
        **base,
        "status": "Paper journal conectado",
        "tone": "buy",
        "connected": True,
        "positions": positions,
        "orders": orders,
        "summary": summary,
        "detail": "Lectura read-only de posiciones y ordenes paper; no modifica cuenta.",
    }


def alpaca_paper_strategy_ranking(
    snapshot: dict[str, Any], opportunity_table: pd.DataFrame, *, limit: int = 5
) -> pd.DataFrame:
    columns = ["strategy", "symbols", "open_positions", "orders", "pnl", "exposure", "win_rate", "tone"]
    strategy_lookup: dict[str, str] = {}
    if not opportunity_table.empty and "symbol" in opportunity_table.columns:
        for row in opportunity_table.to_dict("records"):
            symbol = text_display(row.get("symbol")).upper()
            if symbol and symbol != "-":
                strategy_lookup.setdefault(
                    symbol, text_display(row.get("strategy_family") or row.get("Setup") or row.get("setup"))
                )
    grouped: dict[str, dict[str, Any]] = {}

    def bucket(symbol: str) -> dict[str, Any]:
        strategy = strategy_lookup.get(symbol) or "Sin clasificar"
        return grouped.setdefault(
            strategy,
            {
                "strategy": strategy,
                "symbols": set(),
                "open_positions": 0,
                "orders": 0,
                "pnl": 0.0,
                "exposure": 0.0,
                "wins": 0,
                "closed": 0,
            },
        )

    for position in snapshot.get("positions") or []:
        symbol = text_display(position.get("symbol")).upper()
        if not symbol or symbol == "-":
            continue
        item = bucket(symbol)
        pnl = safe_float(position.get("unrealized_pl")) or 0.0
        item["symbols"].add(symbol)
        item["open_positions"] += 1
        item["pnl"] += pnl
        item["exposure"] += safe_float(position.get("market_value")) or 0.0
        if pnl >= 0:
            item["wins"] += 1
    for order in snapshot.get("orders") or []:
        symbol = text_display(order.get("symbol")).upper()
        if not symbol or symbol == "-":
            continue
        item = bucket(symbol)
        item["symbols"].add(symbol)
        item["orders"] += 1
        if text_display(order.get("status")).upper() in {"FILLED", "PARTIALLY_FILLED"}:
            item["closed"] += 1
    rows: list[dict[str, Any]] = []
    for item in grouped.values():
        denominator = max(int(item["open_positions"]), int(item["closed"]), 1)
        win_rate = (int(item["wins"]) / denominator) if denominator else 0.0
        pnl = round(float(item["pnl"]), 2)
        rows.append(
            {
                "strategy": text_display(item["strategy"]),
                "symbols": " · ".join(sorted(item["symbols"])) or "-",
                "open_positions": int(item["open_positions"]),
                "orders": int(item["orders"]),
                "pnl": pnl,
                "exposure": round(float(item["exposure"]), 2),
                "win_rate": round(win_rate, 4),
                "tone": "buy" if pnl >= 0 else "avoid",
            }
        )
    if not rows:
        return pd.DataFrame(columns=columns)
    result = pd.DataFrame(rows, columns=columns)
    return (
        result.sort_values(["pnl", "open_positions", "orders"], ascending=[False, False, False])
        .head(limit)
        .reset_index(drop=True)
    )


def alpaca_marker_timestamp(value: Any) -> pd.Timestamp | None:
    if value in (None, "", "-"):
        return None
    try:
        parsed = pd.to_datetime(value, errors="coerce")
    except Exception:
        return None
    if pd.isna(parsed):
        return None
    timestamp = pd.Timestamp(parsed)
    if timestamp.tzinfo is not None:
        timestamp = timestamp.tz_convert(None)
    return timestamp


def alpaca_paper_chart_markers(snapshot: dict[str, Any], chart_window: pd.DataFrame, symbol: str) -> pd.DataFrame:
    columns = ["ts", "price", "event", "side", "status", "label", "tone"]
    if chart_window.empty or "ts" not in chart_window.columns:
        return pd.DataFrame(columns=columns)
    clean_symbol = text_display(symbol).upper()
    if not clean_symbol or clean_symbol == "-":
        return pd.DataFrame(columns=columns)
    ts_series = pd.to_datetime(chart_window["ts"], errors="coerce").dropna()
    if ts_series.empty:
        return pd.DataFrame(columns=columns)
    first_ts = (
        pd.Timestamp(ts_series.min()).tz_localize(None)
        if pd.Timestamp(ts_series.min()).tzinfo is None
        else pd.Timestamp(ts_series.min()).tz_convert(None)
    )
    last_ts = (
        pd.Timestamp(ts_series.max()).tz_localize(None)
        if pd.Timestamp(ts_series.max()).tzinfo is None
        else pd.Timestamp(ts_series.max()).tz_convert(None)
    )
    rows: list[dict[str, Any]] = []

    def add_marker(ts_value: Any, price_value: Any, event: str, side: str, status: str, tone: str) -> None:
        ts = alpaca_marker_timestamp(ts_value)
        price = safe_float(price_value)
        if ts is None or price is None or price <= 0:
            return
        if ts < first_ts or ts > last_ts:
            return
        label = f"{event} {clean_symbol} {price:.2f}"
        rows.append(
            {"ts": ts, "price": price, "event": event, "side": side, "status": status, "label": label, "tone": tone}
        )

    for order in snapshot.get("orders") or []:
        order_symbol = text_display(order.get("symbol")).upper()
        if order_symbol != clean_symbol:
            continue
        side = text_display(order.get("side")).upper()
        status = text_display(order.get("status")).upper()
        if status not in {"FILLED", "PARTIALLY_FILLED"}:
            continue
        event = "Paper entrada" if side == "BUY" else "Paper salida"
        tone = "buy" if side == "BUY" else "avoid"
        price = (
            safe_float(order.get("filled_avg_price"))
            or safe_float(order.get("limit_price"))
            or safe_float(order.get("stop_price"))
        )
        add_marker(order.get("filled_at") or order.get("submitted_at"), price, event, side, status, tone)

    for position in snapshot.get("positions") or []:
        position_symbol = text_display(position.get("symbol")).upper()
        if position_symbol != clean_symbol:
            continue
        if any(row.get("side") == "BUY" for row in rows):
            continue
        ts = alpaca_marker_timestamp(position.get("entry_at")) or last_ts
        add_marker(ts, position.get("avg_entry") or position.get("current"), "Paper abierta", "BUY", "OPEN", "buy")

    if not rows:
        return pd.DataFrame(columns=columns)
    return (
        pd.DataFrame(rows, columns=columns)
        .drop_duplicates(["ts", "price", "event", "side"])
        .sort_values("ts")
        .reset_index(drop=True)
    )


def alpaca_paper_open_position_plan(
    snapshot: dict[str, Any],
    opportunity_table: pd.DataFrame,
    *,
    limit: int = 6,
) -> pd.DataFrame:
    columns = [
        "symbol",
        "qty",
        "current",
        "avg_entry",
        "stop",
        "target",
        "risk_to_stop",
        "reward_to_target",
        "pnl",
        "pnl_pct",
        "time_in_trade",
        "strategy",
        "status",
        "tone",
    ]
    opportunities: dict[str, dict[str, Any]] = {}
    if not opportunity_table.empty and "symbol" in opportunity_table.columns:
        for row in opportunity_table.to_dict("records"):
            symbol = text_display(row.get("symbol")).upper()
            if not symbol or symbol == "-":
                continue
            entry = safe_float(row.get("entry"))
            target = safe_float(row.get("target_price") or row.get("recommended_target_price"))
            target_pct = safe_float(row.get("target_pct") or row.get("recommended_target_pct"))
            if target is None and entry is not None and target_pct is not None:
                target = entry * (1.0 + target_pct)
            opportunities.setdefault(
                symbol,
                {
                    "stop": safe_float(row.get("stop")),
                    "target": target,
                    "strategy": text_display(row.get("strategy_family") or row.get("Setup") or row.get("setup")),
                },
            )
    rows: list[dict[str, Any]] = []
    for position in snapshot.get("positions") or []:
        symbol = text_display(position.get("symbol")).upper()
        if not symbol or symbol == "-":
            continue
        current = safe_float(position.get("current"))
        avg_entry = safe_float(position.get("avg_entry"))
        plan = opportunities.get(symbol, {})
        stop = safe_float(plan.get("stop"))
        target = safe_float(plan.get("target"))
        risk_to_stop = ((current - stop) / current) if current and stop is not None else None
        reward_to_target = ((target - current) / current) if current and target is not None else None
        pnl = safe_float(position.get("unrealized_pl")) or 0.0
        pnl_pct = safe_float(position.get("unrealized_plpc"))
        if stop is None or target is None:
            status = "Falta plan"
            tone = "watch"
        elif current is not None and current <= stop:
            status = "Stop tocado"
            tone = "avoid"
        elif current is not None and current >= target:
            status = "Target tocado"
            tone = "buy"
        elif risk_to_stop is not None and risk_to_stop > 0.035:
            status = "Riesgo alto"
            tone = "avoid"
        elif reward_to_target is not None and reward_to_target <= 0:
            status = "Sin upside"
            tone = "watch"
        else:
            status = "Controlado"
            tone = "buy" if pnl >= 0 else "watch"
        rows.append(
            {
                "symbol": symbol,
                "qty": safe_float(position.get("qty")),
                "current": current,
                "avg_entry": avg_entry,
                "stop": stop,
                "target": target,
                "risk_to_stop": risk_to_stop,
                "reward_to_target": reward_to_target,
                "pnl": round(pnl, 2),
                "pnl_pct": pnl_pct,
                "time_in_trade": text_display(position.get("time_in_trade")),
                "strategy": text_display(plan.get("strategy") or "Sin clasificar"),
                "status": status,
                "tone": tone,
            }
        )
    if not rows:
        return pd.DataFrame(columns=columns)
    return (
        pd.DataFrame(rows, columns=columns)
        .sort_values(["tone", "pnl"], ascending=[True, False])
        .head(limit)
        .reset_index(drop=True)
    )


def render_alpaca_paper_journal_panel(env: dict[str, str] | None = None) -> dict[str, Any]:
    snapshot = alpaca_paper_journal_snapshot(env, limit=8)
    st.session_state["alpaca_paper_journal_snapshot"] = snapshot
    summary = snapshot.get("summary") if isinstance(snapshot.get("summary"), dict) else {}
    positions = snapshot.get("positions") if isinstance(snapshot.get("positions"), list) else []
    orders = snapshot.get("orders") if isinstance(snapshot.get("orders"), list) else []
    position_cards = []
    for row in positions[:4]:
        tone = text_display(row.get("tone"))
        position_cards.append(
            f'<section class="paper-journal-card paper-journal-{html.escape(tone)}">'
            f'<header><strong>{html.escape(text_display(row.get("symbol")))}</strong><span>{html.escape(text_display(row.get("time_in_trade")))}</span></header>'
            f'<div><b>Qty {html.escape(num_display(row.get("qty"), 2))}</b><b>Entry {html.escape(num_display(row.get("avg_entry"), 2))}</b><b>Now {html.escape(num_display(row.get("current"), 2))}</b></div>'
            f'<p>P&L {html.escape(num_display(row.get("unrealized_pl"), 2))} · {html.escape(pct_display(row.get("unrealized_plpc")))}</p>'
            "</section>"
        )
    order_rows = []
    for row in orders[:6]:
        order_rows.append(
            "<tr>"
            f"<td>{html.escape(text_display(row.get('symbol')))}</td>"
            f"<td>{html.escape(text_display(row.get('side')))}</td>"
            f"<td>{html.escape(text_display(row.get('status')))}</td>"
            f"<td>{html.escape(num_display(row.get('filled_qty') or row.get('qty'), 2))}</td>"
            f"<td>{html.escape(text_display(row.get('submitted')))}</td>"
            f"<td>{html.escape(text_display(row.get('type')))}</td>"
            "</tr>"
        )
    empty_positions = (
        '<section class="paper-journal-empty">Sin posiciones paper abiertas.</section>' if not position_cards else ""
    )
    empty_orders = '<tr><td colspan="6">Sin ordenes paper recientes.</td></tr>' if not order_rows else ""
    st.markdown(
        f'<section class="paper-journal-panel paper-journal-panel-{html.escape(text_display(snapshot.get("tone")))}">'
        f'<header><strong>Paper Trade Journal</strong><span>{html.escape(text_display(snapshot.get("status")))} · {html.escape(text_display(snapshot.get("detail")))}</span></header>'
        '<div class="paper-journal-summary">'
        f'<b><span>Posiciones</span><strong>{int(summary.get("open_positions") or 0)}</strong></b>'
        f'<b><span>P&L abierto</span><strong>{html.escape(num_display(summary.get("unrealized_pl"), 2))}</strong></b>'
        f'<b><span>Exposicion</span><strong>{html.escape(num_display(summary.get("exposure"), 2))}</strong></b>'
        f'<b><span>Ganadoras</span><strong>{int(summary.get("open_winners") or 0)}</strong></b>'
        f'<b><span>Ordenes</span><strong>{int(summary.get("recent_orders") or 0)}</strong></b>'
        "</div>"
        f'<div class="paper-journal-grid">{"".join(position_cards)}{empty_positions}</div>'
        '<div class="paper-journal-table"><table><thead><tr><th>Ticker</th><th>Side</th><th>Status</th><th>Qty</th><th>Hace</th><th>Tipo</th></tr></thead>'
        f'<tbody>{"".join(order_rows) or empty_orders}</tbody></table></div>'
        "</section>",
        unsafe_allow_html=True,
    )
    return snapshot


