def alpaca_paper_autotrade_enabled(env: dict[str, str] | None = None) -> bool:
    source = env if env is not None else os.environ
    raw = str(source.get("ROXY_ALPACA_PAPER_AUTOTRADE") or "").strip().lower()
    return raw in {"1", "true", "yes", "on", "paper"}


def alpaca_paper_order_candidates(
    table: pd.DataFrame,
    *,
    account_equity: float = 500.0,
    risk_pct: float = 0.01,
    limit: int = 3,
) -> pd.DataFrame:
    columns = ["symbol", "side", "qty", "entry", "stop", "take_profit", "risk_dollars", "notional", "reason"]
    if table.empty:
        return pd.DataFrame(columns=columns)
    risk_budget = max(0.0, safe_float(account_equity) or 0.0) * max(0.0, safe_float(risk_pct) or 0.0)
    rows: list[dict[str, Any]] = []
    for item in table.to_dict("records"):
        if not opportunity_is_trade_ready(item):
            continue
        symbol = text_display(item.get("symbol")).upper()
        market = text_display(item.get("market")).lower()
        if not symbol or symbol == "-" or market == "crypto" or "/" in symbol:
            continue
        entry = safe_float(item.get("entry"))
        stop = safe_float(item.get("stop"))
        target = safe_float(item.get("target_price"))
        target_pct = safe_float(item.get("target_pct"))
        if target is None and entry is not None and target_pct is not None:
            target = entry * (1.0 + target_pct)
        if entry is None or stop is None or target is None:
            continue
        per_share_risk = abs(entry - stop)
        if per_share_risk <= 0:
            continue
        qty = int(risk_budget // per_share_risk)
        if qty <= 0:
            qty = 1
        rows.append(
            {
                "symbol": symbol,
                "side": "buy",
                "qty": qty,
                "entry": round(entry, 2),
                "stop": round(stop, 2),
                "take_profit": round(target, 2),
                "risk_dollars": round(qty * per_share_risk, 2),
                "notional": round(qty * entry, 2),
                "reason": text_display(item.get("por_que") or item.get("raw_reason") or item.get("strategy_family")),
            }
        )
        if len(rows) >= limit:
            break
    return pd.DataFrame(rows, columns=columns)


def alpaca_paper_execution_gaps(table: pd.DataFrame, *, limit: int = 4) -> pd.DataFrame:
    columns = ["symbol", "status", "next_step", "entry", "stop", "take_profit"]
    if table.empty:
        return pd.DataFrame(columns=columns)
    rows: list[dict[str, Any]] = []
    for item in table.to_dict("records"):
        symbol = text_display(item.get("symbol")).upper()
        if not symbol or symbol == "-":
            continue
        market = text_display(item.get("market")).lower()
        entry = safe_float(item.get("entry"))
        stop = safe_float(item.get("stop"))
        target = safe_float(item.get("target_price"))
        target_pct = safe_float(item.get("target_pct"))
        if target is None and entry is not None and target_pct is not None:
            target = entry * (1.0 + target_pct)
        if market == "crypto" or "/" in symbol:
            status = "No soportado"
            next_step = "Alpaca paper equity solo opera acciones aqui; crypto queda como alerta/estudio."
        elif not opportunity_is_trade_ready(item):
            status = "Esperando setup"
            next_step = text_display(item.get("cambia_si") or opportunity_change_label(item))
        elif entry is None or stop is None or target is None:
            status = "Faltan niveles"
            next_step = "Necesita entrada, stop y take profit antes de armar bracket paper."
        elif abs(entry - stop) <= 0:
            status = "Stop invalido"
            next_step = "Stop debe estar separado de la entrada para medir riesgo real."
        else:
            continue
        rows.append(
            {
                "symbol": symbol,
                "status": status,
                "next_step": next_step,
                "entry": round(entry, 2) if entry is not None else "-",
                "stop": round(stop, 2) if stop is not None else "-",
                "take_profit": round(target, 2) if target is not None else "-",
            }
        )
        if len(rows) >= limit:
            break
    return pd.DataFrame(rows, columns=columns)


def alpaca_paper_gap_checklist(table: pd.DataFrame, *, limit: int = 4) -> pd.DataFrame:
    columns = ["symbol", "status", "ready", "missing", "next_step", "tone"]
    if table.empty:
        return pd.DataFrame(columns=columns)
    rows: list[dict[str, Any]] = []
    for item in table.to_dict("records"):
        symbol = text_display(item.get("symbol")).upper()
        if not symbol or symbol == "-":
            continue
        market = text_display(item.get("market")).lower()
        entry = safe_float(item.get("entry"))
        stop = safe_float(item.get("stop"))
        target = safe_float(item.get("target_price"))
        target_pct = safe_float(item.get("target_pct") or item.get("recommended_target_pct"))
        risk_pct = safe_float(item.get("risk_pct"))
        if target is None and entry is not None and target_pct is not None:
            target = entry * (1.0 + target_pct)
        ready: list[str] = []
        missing: list[str] = []

        if market == "crypto" or "/" in symbol:
            missing.append("Solo acciones paper")
        else:
            ready.append("Accion soportada")
        if opportunity_is_trade_ready(item):
            ready.append("Setup confirmado")
        else:
            missing.append("15m/1h BUY")
        if entry is not None:
            ready.append("Entrada")
        else:
            missing.append("Entrada")
        if stop is not None:
            ready.append("Stop")
        else:
            missing.append("Stop")
        if target is not None:
            ready.append("Target")
        else:
            missing.append("Target")
        if entry is not None and stop is not None and abs(entry - stop) > 0:
            ready.append("Riesgo medible")
        elif entry is not None and stop is not None:
            missing.append("Stop separado")
        if risk_pct is None:
            missing.append("Riesgo %")
        elif risk_pct <= 0.035:
            ready.append("Riesgo OK")
        else:
            missing.append("Riesgo <= 3.5%")
        if target_pct is None:
            missing.append("Target %")
        elif target_pct >= 0.02:
            ready.append("Target 2%")
        else:
            missing.append("Target >= 2%")

        if not missing:
            continue
        status = "Falta " + missing[0]
        tone = "avoid" if missing[0] in {"Solo acciones paper", "Riesgo <= 3.5%", "Stop separado"} else "watch"
        rows.append(
            {
                "symbol": symbol,
                "status": status,
                "ready": " · ".join(ready[:6]) or "-",
                "missing": " · ".join(dict.fromkeys(missing[:5])) or "-",
                "next_step": text_display(item.get("cambia_si") or opportunity_change_label(item)),
                "tone": tone,
            }
        )
        if len(rows) >= limit:
            break
    return pd.DataFrame(rows, columns=columns)


def alpaca_paper_execution_summary(
    table: pd.DataFrame,
    *,
    account_equity: float = 500.0,
    risk_pct: float = 0.01,
) -> dict[str, Any]:
    candidates = alpaca_paper_order_candidates(table, account_equity=account_equity, risk_pct=risk_pct, limit=50)
    gaps = alpaca_paper_execution_gaps(table, limit=50)
    risk_budget = max(0.0, safe_float(account_equity) or 0.0) * max(0.0, safe_float(risk_pct) or 0.0)
    projected_risk = (
        float(candidates["risk_dollars"].sum())
        if not candidates.empty and "risk_dollars" in candidates.columns
        else 0.0
    )
    projected_notional = (
        float(candidates["notional"].sum()) if not candidates.empty and "notional" in candidates.columns else 0.0
    )
    top_symbol = (
        text_display(candidates.iloc[0].get("symbol"))
        if not candidates.empty
        else text_display(gaps.iloc[0].get("symbol")) if not gaps.empty else "-"
    )
    return {
        "ready": len(candidates),
        "blocked": len(gaps),
        "risk_budget": round(risk_budget, 2),
        "projected_risk": round(projected_risk, 2),
        "projected_notional": round(projected_notional, 2),
        "risk_usage_pct": round((projected_risk / risk_budget) * 100, 1) if risk_budget > 0 else 0.0,
        "top_symbol": top_symbol,
    }


def render_alpaca_paper_execution_summary(summary: dict[str, Any]) -> str:
    return (
        '<div class="paper-exec-summary">'
        f'<b><span>Listas</span><strong>{int(summary.get("ready") or 0)}</strong></b>'
        f'<b><span>Bloqueadas</span><strong>{int(summary.get("blocked") or 0)}</strong></b>'
        f'<b><span>Riesgo usado</span><strong>{html.escape(num_display(summary.get("projected_risk"), 2))}</strong></b>'
        f'<b><span>Presupuesto</span><strong>{html.escape(num_display(summary.get("risk_budget"), 2))}</strong></b>'
        f'<b><span>Uso</span><strong>{html.escape(num_display(summary.get("risk_usage_pct"), 1))}%</strong></b>'
        f'<b><span>Top</span><strong>{html.escape(text_display(summary.get("top_symbol")))}</strong></b>'
        "</div>"
    )


def submit_alpaca_paper_bracket_order(
    candidate: dict[str, Any],
    env: dict[str, str] | None = None,
    client_factory: Any | None = None,
) -> dict[str, Any]:
    source = env if env is not None else os.environ
    gate = alpaca_operations_gate(source)
    if not gate.get("paper_orders_allowed"):
        return {"submitted": False, "status": "blocked", "detail": text_display(gate.get("next"))}
    symbol = text_display(candidate.get("symbol")).upper()
    qty = int(safe_float(candidate.get("qty")) or 0)
    stop = safe_float(candidate.get("stop"))
    take_profit = safe_float(candidate.get("take_profit"))
    if not symbol or symbol == "-" or qty <= 0 or stop is None or take_profit is None:
        return {"submitted": False, "status": "invalid", "detail": "Candidato paper incompleto."}
    key = str(source.get("ALPACA_API_KEY") or "").strip()
    secret = str(source.get("ALPACA_API_SECRET") or source.get("ALPACA_SECRET_KEY") or "").strip()
    if not key or not secret:
        return {"submitted": False, "status": "missing_credentials", "detail": "Faltan credenciales paper en entorno."}
    try:
        if client_factory is None:
            from alpaca.trading.client import TradingClient
            from alpaca.trading.enums import OrderClass, OrderSide, TimeInForce
            from alpaca.trading.requests import MarketOrderRequest, StopLossRequest, TakeProfitRequest

            def client_factory(api_key: str, secret_key: str):
                return TradingClient(api_key=api_key, secret_key=secret_key, paper=True)

            order_data = MarketOrderRequest(
                symbol=symbol,
                qty=qty,
                side=OrderSide.BUY,
                time_in_force=TimeInForce.DAY,
                order_class=OrderClass.BRACKET,
                take_profit=TakeProfitRequest(limit_price=round(take_profit, 2)),
                stop_loss=StopLossRequest(stop_price=round(stop, 2)),
            )
        else:
            order_data = {
                "symbol": symbol,
                "qty": qty,
                "side": "buy",
                "time_in_force": "day",
                "order_class": "bracket",
                "take_profit": round(take_profit, 2),
                "stop_loss": round(stop, 2),
            }
        client = client_factory(key, secret)
        order = client.submit_order(order_data=order_data)
    except Exception as exc:
        return {
            "submitted": False,
            "status": "error",
            "detail": f"Alpaca paper rechazo la orden: {type(exc).__name__}.",
        }
    order_id = getattr(order, "id", None) if not isinstance(order, dict) else order.get("id")
    return {
        "submitted": True,
        "status": "submitted",
        "symbol": symbol,
        "qty": qty,
        "order_id": text_display(order_id),
        "detail": "Orden bracket enviada a Alpaca paper.",
    }


def render_alpaca_paper_execution_panel(
    table: pd.DataFrame,
    *,
    account_equity: float,
    risk_pct: float,
    env: dict[str, str] | None = None,
    risk_state: dict[str, Any] | None = None,
) -> None:
    candidates = alpaca_paper_order_candidates(table, account_equity=account_equity, risk_pct=risk_pct, limit=3)
    summary_html = render_alpaca_paper_execution_summary(
        alpaca_paper_execution_summary(table, account_equity=account_equity, risk_pct=risk_pct)
    )
    if isinstance(risk_state, dict) and not bool(risk_state.get("allowed", True)):
        st.markdown(
            '<section class="paper-exec-panel paper-exec-muted"><header><strong>Paper Execution Gate</strong>'
            f'<span>Bloqueado por Paper Risk Guard · {html.escape(text_display(risk_state.get("state")))}</span></header>'
            '<div class="paper-exec-grid">'
            + summary_html
            + f'<section class="paper-gap-card"><header><strong>Modo protección</strong><span>No abrir nuevas entradas</span></header>'
            f'<p>{html.escape(text_display(risk_state.get("reason")))}</p>'
            f'<small>{html.escape(text_display(risk_state.get("action")))}</small></section>'
            + "</div></section>",
            unsafe_allow_html=True,
        )
        return
    if candidates.empty:
        gaps = alpaca_paper_execution_gaps(table, limit=4)
        checklist = alpaca_paper_gap_checklist(table, limit=4)
        if gaps.empty and checklist.empty:
            return
        cards = [
            f'<section class="paper-gap-card"><header><strong>{html.escape(text_display(row.get("symbol")))}</strong><span>{html.escape(text_display(row.get("status")))}</span></header>'
            f'<div><b>Entry {html.escape(num_display(row.get("entry"), 2))}</b><b>Stop {html.escape(num_display(row.get("stop"), 2))}</b><b>TP {html.escape(num_display(row.get("take_profit"), 2))}</b></div>'
            f'<p>{html.escape(text_display(row.get("next_step")))}</p></section>'
            for row in gaps.to_dict("records")
        ]
        checklist_cards = [
            f'<section class="paper-check-card paper-check-{html.escape(text_display(row.get("tone")))}"><header><strong>{html.escape(text_display(row.get("symbol")))}</strong><span>{html.escape(text_display(row.get("status")))}</span></header>'
            f'<div><b>Listo</b><p>{html.escape(text_display(row.get("ready")))}</p></div>'
            f'<div><b>Falta</b><p>{html.escape(text_display(row.get("missing")))}</p></div>'
            f'<small>{html.escape(text_display(row.get("next_step")))}</small></section>'
            for row in checklist.to_dict("records")
        ]
        st.markdown(
            '<section class="paper-exec-panel paper-exec-muted"><header><strong>Paper Execution Gate</strong><span>Sin orden lista · Roxy muestra que falta antes de enviar a Alpaca paper.</span></header><div class="paper-exec-grid">'
            + summary_html
            + "".join(cards)
            + "".join(checklist_cards)
            + "</div></section>",
            unsafe_allow_html=True,
        )
        return
    auto_enabled = alpaca_paper_autotrade_enabled(env)
    cards = []
    for row in candidates.to_dict("records"):
        key = f"alpaca_paper_sent_{text_display(row.get('symbol'))}_{num_display(row.get('entry'), 2)}"
        status_line = "Auto paper armado" if auto_enabled else "Paper listo / auto OFF"
        if auto_enabled and key not in st.session_state:
            result = submit_alpaca_paper_bracket_order(row, env=env)
            st.session_state[key] = result
        result = st.session_state.get(key)
        if isinstance(result, dict):
            status_line = text_display(result.get("detail"))
        cards.append(
            f'<section class="paper-exec-card">'
            f'<header><strong>{html.escape(text_display(row.get("symbol")))}</strong><span>{html.escape(status_line)}</span></header>'
            f'<div><b>Qty {int(row.get("qty") or 0)}</b><b>Entry {html.escape(num_display(row.get("entry"), 2))}</b><b>Stop {html.escape(num_display(row.get("stop"), 2))}</b><b>TP {html.escape(num_display(row.get("take_profit"), 2))}</b></div>'
            f'<p>Riesgo {html.escape(num_display(row.get("risk_dollars"), 2))} · Notional {html.escape(num_display(row.get("notional"), 2))} · {html.escape(text_display(row.get("reason")))}</p>'
            "</section>"
        )
    state_label = "AUTO ON" if auto_enabled else "AUTO OFF"
    st.markdown(
        f'<section class="paper-exec-panel"><header><strong>Alpaca Paper Execution Queue</strong><span>{html.escape(state_label)} · Solo paper bracket orders: market + take profit + stop.</span></header><div class="paper-exec-grid">'
        + summary_html
        + "".join(cards)
        + "</div></section>",
        unsafe_allow_html=True,
    )


def chart_effective_source(market: str, source_meta: dict[str, Any] | None = None) -> dict[str, str]:
    if isinstance(source_meta, dict) and source_meta.get("source"):
        return {
            "source": text_display(source_meta.get("source")),
            "mode": text_display(source_meta.get("mode")),
            "label": text_display(source_meta.get("label") or source_meta.get("provider") or source_meta.get("source")),
            "detail": text_display(source_meta.get("detail")),
            "fallback_reason": text_display(source_meta.get("fallback_reason")),
            "fallback_detail": text_display(source_meta.get("fallback_detail")),
            "fallback_action": text_display(source_meta.get("fallback_action")),
        }
    market_value = str(market or "stock").lower()
    if market_value == "crypto":
        return {
            "source": "ccxt:binanceus",
            "mode": "EXCHANGE_API",
            "label": "BinanceUS API",
            "detail": "Cripto usa API de exchange via ccxt.",
            "fallback_reason": "-",
            "fallback_detail": "-",
            "fallback_action": "-",
        }
    return {
        "source": "yfinance",
        "mode": "FALLBACK",
        "label": "yfinance fallback",
        "detail": "Acciones usan yfinance para historial/grafica mientras se conecta stream broker directo.",
        "fallback_reason": "-",
        "fallback_detail": "-",
        "fallback_action": "-",
    }


def chart_live_data_status(
    chart_df: pd.DataFrame,
    *,
    market: str,
    timeframe: str,
    provider_summary: dict[str, str] | None = None,
    source_meta: dict[str, Any] | None = None,
    now: datetime | None = None,
    stock_alerts_allowed: bool | None = None,
) -> dict[str, Any]:
    checked_at = now or datetime.now()
    freshness = shared_chart_freshness_status(
        chart_df,
        market=market,
        timeframe=timeframe,
        now=checked_at,
        stock_alerts_allowed=stock_alerts_allowed,
    )
    source = chart_effective_source(market, source_meta=source_meta)
    provider_base = provider_summary or live_provider_quality_summary(live_provider_rows())
    provider = live_provider_effective_summary(provider_base, source_meta)
    provider_mode = str(provider.get("mode") or "")
    source_mode = str(source.get("mode") or "")
    fresh_status = str(freshness.get("status") or "FAIL")
    market_closed_ok = bool(freshness.get("market_closed_accepted"))

    if fresh_status == "FAIL":
        tone = "avoid"
        status = "Grafica no operable"
        action = "No tomar entrada hasta recuperar velas actuales."
    elif market_closed_ok:
        tone = "watch"
        status = "Mercado cerrado OK"
        action = "Mantener watchlist y revalidar en la apertura."
    elif source_mode in {"BROKER_DATA", "EXCHANGE_API"} and fresh_status == "OK":
        tone = "buy"
        status = "Grafica premium viva" if source_mode == "BROKER_DATA" else "Grafica viva"
        action = "Data apta para analisis; la orden real sigue manual."
    elif source_mode == "FALLBACK" and provider_mode == "PAPER_LIVE_READY":
        tone = "watch"
        status = "Premium listo / grafica fallback"
        action = "Usar como analisis; conectar Alpaca directo antes de tratarlo como stream premium."
    elif source_mode == "FALLBACK":
        tone = "watch"
        status = "Grafica fallback"
        action = "Confirmar con Finviz/TC2000 o proveedor premium antes de operar rapido."
    elif fresh_status == "WARN":
        tone = "watch"
        status = "Grafica con retraso"
        action = "Esperar proxima vela o confirmar en plataforma externa."
    else:
        tone = "buy"
        status = "Grafica viva"
        action = "Data apta para analisis; la orden real sigue manual."

    return {
        "status": status,
        "tone": tone,
        "source": source["source"],
        "source_label": source["label"],
        "source_mode": source["mode"],
        "provider_mode": provider_mode,
        "provider_status": text_display(provider.get("status")),
        "provider_tone": text_display(provider.get("tone")),
        "provider_detail": text_display(provider.get("detail")),
        "freshness_label": text_display(freshness.get("label")),
        "freshness_status": fresh_status,
        "age_minutes": freshness.get("age_minutes"),
        "cadence_lag_minutes": freshness.get("cadence_lag_minutes"),
        "health_lag_minutes": freshness.get("health_lag_minutes"),
        "next_expected_update_in_minutes": freshness.get("next_expected_update_in_minutes"),
        "candle_progress_pct": freshness.get("candle_progress_pct"),
        "candle_phase": text_display(freshness.get("candle_phase")),
        "candle_phase_label": text_display(freshness.get("candle_phase_label")),
        "latest": freshness.get("latest"),
        "checked_at": checked_at.isoformat(timespec="seconds"),
        "detail": f"{source['detail']} {text_display(freshness.get('detail'))}.",
        "action": action,
        "fallback_reason": source.get("fallback_reason", "-"),
        "fallback_detail": source.get("fallback_detail", "-"),
        "fallback_action": source.get("fallback_action", "-"),
        "market_closed_accepted": market_closed_ok,
    }


def chart_operational_confidence(live_data: dict[str, Any] | None) -> dict[str, Any]:
    live_data = live_data or {}
    status = text_display(live_data.get("status"))
    source_mode = text_display(live_data.get("source_mode")).upper()
    freshness_status = text_display(live_data.get("freshness_status")).upper()
    fallback_reason = text_display(live_data.get("fallback_reason"))
    age = safe_float(live_data.get("age_minutes"))
    lag = safe_float(live_data.get("cadence_lag_minutes"))
    next_update = safe_float(live_data.get("next_expected_update_in_minutes"))
    age_text = f"{age:.0f}m" if age is not None else "-"
    lag_text = f"lag {lag:.0f}m" if lag is not None and lag > 0 else "sin lag"
    if freshness_status == "FAIL" or status == "Grafica no operable":
        return {
            "label": "No usar",
            "tone": "avoid",
            "detail": f"edad {age_text} | {lag_text} | recuperar velas",
            "mode": "BLOCKED_STALE",
        }
    if bool(live_data.get("market_closed_accepted")):
        return {
            "label": "Revalidar apertura",
            "tone": "watch",
            "detail": f"mercado cerrado | edad {age_text}",
            "mode": "CLOSED_REVALIDATE",
        }
    if source_mode == "FALLBACK":
        reason = fallback_reason if fallback_reason not in {"", "-"} else "fallback"
        return {
            "label": "Confirmar externo",
            "tone": "watch",
            "detail": f"{reason} | edad {age_text} | {lag_text}",
            "mode": "FALLBACK_CONFIRM",
        }
    if freshness_status == "WARN" or (lag is not None and lag > 0):
        wait_text = f"proxima {next_update:.0f}m" if next_update is not None else "esperar vela"
        return {
            "label": "Esperar vela",
            "tone": "watch",
            "detail": f"edad {age_text} | {lag_text} | {wait_text}",
            "mode": "DELAY_CONFIRM",
        }
    if source_mode in {"BROKER_DATA", "EXCHANGE_API"}:
        return {
            "label": "Analisis OK",
            "tone": "buy",
            "detail": f"{text_display(live_data.get('source_label'))} | edad {age_text}",
            "mode": "LIVE_CONFIRMED",
        }
    return {
        "label": "Analisis OK",
        "tone": "buy",
        "detail": f"edad {age_text} | {lag_text}",
        "mode": "ANALYSIS_OK",
    }


def chart_data_contract(live_data: dict[str, Any] | None) -> dict[str, Any]:
    live_data = live_data or {}
    confidence = chart_operational_confidence(live_data)
    mode = text_display(confidence.get("mode"))
    source_mode = text_display(live_data.get("source_mode")).upper()
    fallback_reason = text_display(live_data.get("fallback_reason"))
    latest = text_display(live_data.get("latest"))
    age = safe_float(live_data.get("age_minutes"))
    lag = safe_float(live_data.get("cadence_lag_minutes"))
    next_update = safe_float(live_data.get("next_expected_update_in_minutes"))
    candle_phase = text_display(live_data.get("candle_phase"))
    candle_phase_label = text_display(live_data.get("candle_phase_label"))
    candle_progress = safe_float(live_data.get("candle_progress_pct"))
    age_text = f"{age:.0f}m" if age is not None else "-"
    lag_text = f"{lag:.0f}m" if lag is not None else "-"
    next_text = f"{next_update:.0f}m" if next_update is not None else "-"
    progress_text = f"{candle_progress:.0f}%" if candle_progress is not None else "-"
    if mode == "LIVE_CONFIRMED":
        decision = "Analisis permitido"
        gate = "LIVE_DATA_OK"
    elif mode == "FALLBACK_CONFIRM":
        decision = "Solo referencia"
        gate = "EXTERNAL_CONFIRM_REQUIRED"
    elif mode == "BLOCKED_STALE":
        decision = "Bloqueada"
        gate = "NO_TRADE_STALE_DATA"
    elif mode == "CLOSED_REVALIDATE":
        decision = "Revalidar apertura"
        gate = "MARKET_CLOSED_RECHECK"
    elif mode == "DELAY_CONFIRM":
        decision = "Esperar vela"
        gate = "WAIT_NEXT_CANDLE"
    else:
        decision = "Analisis permitido"
        gate = "ANALYSIS_OK"
    if source_mode == "FALLBACK" and fallback_reason in {"alpaca_auth", "alpaca_feed_permission", "polygon_auth"}:
        gate = "NO_TRADE_FROM_FALLBACK"
        decision = "Bloqueada para entrada"
    detail_parts = [
        f"fuente {text_display(live_data.get('source_label') or live_data.get('source'))}",
        f"modo {source_mode or '-'}",
        f"edad {age_text}",
        f"lag {lag_text}",
    ]
    if candle_phase_label not in {"", "-"}:
        detail_parts.append(f"fase {candle_phase_label} {progress_text}")
    if next_text != "-":
        detail_parts.append(f"prox {next_text}")
    if fallback_reason not in {"", "-"}:
        detail_parts.append(f"fallback {fallback_reason}")
    return {
        "label": text_display(confidence.get("label")),
        "tone": text_display(confidence.get("tone")),
        "mode": mode,
        "gate": gate,
        "decision": decision,
        "detail": " | ".join(detail_parts),
        "action": text_display(live_data.get("action")),
        "latest": latest,
        "source_mode": source_mode,
        "source_label": text_display(live_data.get("source_label")),
        "candle_phase": candle_phase,
        "candle_phase_label": candle_phase_label,
        "candle_progress_pct": candle_progress,
        "fallback_reason": fallback_reason,
        "operable": gate in {"LIVE_DATA_OK", "ANALYSIS_OK"} and text_display(confidence.get("tone")) == "buy",
    }


def live_price_data_contract(snapshot: dict[str, Any] | None) -> dict[str, Any]:
    snapshot = snapshot or {}
    freshness = text_display(snapshot.get("freshness")).upper()
    source_mode = text_display(snapshot.get("source_mode")).upper()
    source_label = text_display(snapshot.get("source"))
    age_seconds = safe_float(snapshot.get("age_seconds"))
    price_timestamp = text_display(snapshot.get("price_timestamp"))
    provider_issue = text_display(snapshot.get("provider_issue"))
    error = text_display(snapshot.get("error"))
    age_text = f"{age_seconds:.0f}s" if age_seconds is not None else "-"
    if freshness == "FAIL" or error not in {"", "-"}:
        tone = "avoid"
        label = "Precio no disponible"
        decision = "Bloqueada"
        gate = "NO_TRADE_PRICE_FAIL"
        action = "No tomar entrada hasta recuperar precio live."
    elif source_mode == "PUBLIC_MARKET_DATA":
        tone = "watch"
        label = "Confirmar externo"
        decision = "Solo referencia"
        gate = "NO_TRADE_FROM_PUBLIC_PRICE"
        action = "Confirmar en TradingView/broker antes de cualquier entrada rapida."
    elif freshness == "STALE":
        tone = "avoid"
        label = "Precio stale"
        decision = "Bloqueada"
        gate = "NO_TRADE_STALE_PRICE"
        action = "Esperar actualizacion de precio antes de analizar entrada."
    elif freshness in {"LIVE", "FRESH"} and source_mode in {"BROKER_DATA", "EXCHANGE_TICKER"}:
        tone = "buy"
        label = "Precio live confirmado"
        decision = "Analisis permitido"
        gate = "LIVE_PRICE_OK"
        action = "Precio apto para analisis; orden real sigue deshabilitada."
    else:
        tone = "watch"
        label = "Validar precio"
        decision = "Esperar confirmacion"
        gate = "WAIT_PRICE_CONFIRMATION"
        action = "Revisar fuente y timestamp antes de actuar."
    detail_parts = [
        f"fuente {source_label}",
        f"modo {source_mode or '-'}",
        f"edad {age_text}",
        f"freshness {freshness or '-'}",
    ]
    if provider_issue not in {"", "-"}:
        detail_parts.append(f"provider {provider_issue}")
    if error not in {"", "-"}:
        detail_parts.append(f"error {error[:90]}")
    return {
        "label": label,
        "tone": tone,
        "mode": "LIVE_PRICE_SNAPSHOT",
        "gate": gate,
        "decision": decision,
        "detail": " | ".join(detail_parts),
        "action": action,
        "latest": price_timestamp,
        "source_mode": source_mode,
        "source_label": source_label,
        "candle_phase_label": freshness,
        "operable": gate == "LIVE_PRICE_OK",
    }


def alpaca_market_data_panel_rows(diagnostic: dict[str, Any] | None) -> pd.DataFrame:
    diagnostic = diagnostic if isinstance(diagnostic, dict) else {}
    status = text_display(diagnostic.get("status")).upper()
    error_category = text_display(diagnostic.get("error_category")).upper()
    configured = bool(diagnostic.get("configured"))
    safe_for_signals = bool(diagnostic.get("safe_for_signals"))
    live_orders_allowed = bool(diagnostic.get("live_orders_allowed"))
    paper_only = bool(diagnostic.get("paper_only", True))
    placeholder_keys = diagnostic.get("placeholder_keys") if isinstance(diagnostic.get("placeholder_keys"), list) else []
    missing_keys = diagnostic.get("missing_keys") if isinstance(diagnostic.get("missing_keys"), list) else []
    credential_keys = diagnostic.get("credential_keys") if isinstance(diagnostic.get("credential_keys"), list) else []
    endpoint_mismatch = bool(diagnostic.get("endpoint_mismatch"))
    credential_detail = "OK" if configured else "Pendiente"
    if placeholder_keys:
        credential_detail = f"Placeholders: {', '.join(text_display(key) for key in placeholder_keys)}"
    elif missing_keys:
        credential_detail = f"Faltan: {', '.join(text_display(key) for key in missing_keys)}"
    elif credential_keys:
        credential_detail = f"Variables: {', '.join(text_display(key) for key in credential_keys)}"
    endpoint_detail = text_display(diagnostic.get("effective_endpoint") or diagnostic.get("expected_endpoint"))
    if endpoint_mismatch:
        endpoint_detail = f"{endpoint_detail} | mismatch con ALPACA_PAPER"
    rows = [
        {
            "Control": "Estado Alpaca",
            "Estado": status or "UNKNOWN",
            "Detalle": error_category if error_category not in {"", "-"} else text_display(diagnostic.get("summary")),
            "Accion": text_display(diagnostic.get("next_action")),
            "_tone": _living_market_tone(status),
        },
        {
            "Control": "Feed",
            "Estado": text_display(diagnostic.get("feed")),
            "Detalle": "Fuente broker read-only para market data.",
            "Accion": "Validar permisos de feed si hay retrasos o FEED_PERMISSION.",
            "_tone": "buy" if safe_for_signals else "watch",
        },
        {
            "Control": "Modo",
            "Estado": text_display(diagnostic.get("mode")),
            "Detalle": "Paper/simulacion" if paper_only else "Revisar configuracion",
            "Accion": "Mantener paper hasta tener metricas estables.",
            "_tone": "buy" if paper_only else "avoid",
        },
        {
            "Control": "Endpoint",
            "Estado": "MISMATCH" if endpoint_mismatch else "OK",
            "Detalle": endpoint_detail,
            "Accion": "Paper debe usar https://paper-api.alpaca.markets.",
            "_tone": "avoid" if endpoint_mismatch else "buy",
        },
        {
            "Control": "Credenciales",
            "Estado": "CONFIGURADO" if configured else "NO LISTO",
            "Detalle": credential_detail,
            "Accion": "Corregir .env y reiniciar el mismo servidor localhost:3000 si cambia el entorno.",
            "_tone": "buy" if configured else "avoid",
        },
        {
            "Control": "Senales",
            "Estado": "PERMITIDAS" if safe_for_signals else "BLOQUEADAS",
            "Detalle": "Market data util para analisis." if safe_for_signals else "Roxy no debe elevar alertas operables desde Alpaca.",
            "Accion": "Usar TradingView/otra fuente para confirmacion hasta recuperar Alpaca.",
            "_tone": "buy" if safe_for_signals else "avoid",
        },
        {
            "Control": "Ordenes reales",
            "Estado": "OFF" if not live_orders_allowed else "ON",
            "Detalle": "Guardrail activo: este panel no coloca ordenes.",
            "Accion": "Solo analisis, paper/manual y diagnostico read-only.",
            "_tone": "buy" if not live_orders_allowed else "avoid",
        },
    ]
    return pd.DataFrame(rows, columns=["Control", "Estado", "Detalle", "Accion", "_tone"])


def opportunity_data_source_status(row: dict[str, Any] | None) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    contract = row.get("chart_data_contract") if isinstance(row.get("chart_data_contract"), dict) else {}
    if not contract and isinstance(row.get("live_price_contract"), dict):
        contract = row.get("live_price_contract") or {}
    if not contract and isinstance(row.get("price_data_contract"), dict):
        contract = row.get("price_data_contract") or {}
    gate = text_display(
        row.get("chart_data_gate")
        or row.get("live_price_gate")
        or row.get("price_data_gate")
        or contract.get("gate")
        or "-"
    ).upper()
    source = text_display(
        row.get("chart_source_label")
        or row.get("price_source_label")
        or row.get("price_source")
        or contract.get("source_label")
        or contract.get("source")
        or "-"
    )
    source_mode = text_display(
        row.get("source_mode")
        or row.get("price_source_mode")
        or row.get("chart_source_mode")
        or contract.get("source_mode")
        or "-"
    ).upper()
    freshness = text_display(row.get("freshness") or contract.get("candle_phase_label") or "-")
    detail = text_display(contract.get("detail") or row.get("data_source_detail") or "")
    lower_source = source.lower()
    if gate in {"LIVE_PRICE_OK", "LIVE_DATA_OK", "ANALYSIS_OK"}:
        if source_mode in {"BROKER_DATA", "EXCHANGE_TICKER", "EXCHANGE_API"} or any(
            name in lower_source for name in ("alpaca", "binance", "coinbase", "polygon", "finnhub", "twelve")
        ):
            state = "Broker/exchange live"
            tone = "buy"
            action = "Apto para analisis; orden real sigue apagada."
        else:
            state = "Analisis OK"
            tone = "buy"
            action = "Confirmar fuente antes de elevar tamano."
    elif gate in {"NO_TRADE_FROM_PUBLIC_PRICE", "NO_TRADE_FROM_FALLBACK", "EXTERNAL_CONFIRM_REQUIRED"} or any(
        name in lower_source for name in ("yfinance", "yahoo", "public")
    ):
        state = "Fallback publico"
        tone = "watch"
        action = "Confirmar en Alpaca/TradingView antes de entrada paper/manual."
    elif gate in {"NO_TRADE_PRICE_FAIL", "NO_TRADE_STALE_PRICE", "NO_TRADE_STALE_DATA"}:
        state = "Datos bloqueados"
        tone = "avoid"
        action = "No tomar entrada hasta recuperar datos frescos."
    elif gate in {"WAIT_PRICE_CONFIRMATION", "WAIT_NEXT_CANDLE", "MARKET_CLOSED_RECHECK"}:
        state = "Esperar confirmacion"
        tone = "watch"
        action = "Esperar siguiente actualizacion o apertura de mercado."
    elif gate in {"", "-"}:
        state = "Sin contrato"
        tone = "watch"
        action = "Adjuntar contrato de precio/grafica antes de alertar."
    else:
        state = "Validar fuente"
        tone = "watch"
        action = "Revisar gate de datos antes de actuar."
    return {
        "state": state,
        "tone": tone,
        "gate": gate,
        "source": source,
        "source_mode": source_mode,
        "freshness": freshness,
        "detail": detail,
        "action": action,
        "operable": tone == "buy" and gate in {"LIVE_PRICE_OK", "LIVE_DATA_OK", "ANALYSIS_OK"},
    }


def opportunity_data_source_bucket(row: dict[str, Any] | None) -> dict[str, Any]:
    status = opportunity_data_source_status(row)
    state = text_display(status.get("state"))
    if state in {"Broker/exchange live", "Analisis OK"}:
        return {
            **status,
            "bucket": "Live real",
            "bucket_tone": "buy",
            "priority_cap": 2,
            "alert_state": "Lista paper/manual",
            "alert_tone": "buy",
        }
    if state == "Fallback publico":
        return {
            **status,
            "bucket": "Fallback",
            "bucket_tone": "watch",
            "priority_cap": 1,
            "alert_state": "Confirmar externo",
            "alert_tone": "watch",
        }
    if state == "Datos bloqueados":
        return {
            **status,
            "bucket": "Bloqueadas",
            "bucket_tone": "avoid",
            "priority_cap": 0,
            "alert_state": "Bloqueada por datos",
            "alert_tone": "avoid",
        }
    if state == "Sin contrato":
        return {
            **status,
            "bucket": "Sin contrato",
            "bucket_tone": "avoid",
            "priority_cap": 0,
            "alert_state": "No operar",
            "alert_tone": "avoid",
        }
    return {
        **status,
        "bucket": "Esperar",
        "bucket_tone": "watch",
        "priority_cap": 1,
        "alert_state": "Solo vigilar",
        "alert_tone": "watch",
    }


def source_memory_bias_from_summary_row(row: dict[str, Any] | None, *, min_sample: int = 3) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    tracked = int(safe_float(row.get("tracked")) or 0)
    hit_2_rate = safe_float(row.get("hit_2_rate")) or 0.0
    hit_5_rate = safe_float(row.get("hit_5_rate")) or 0.0
    stop_rate = safe_float(row.get("stop_rate")) or 0.0
    bucket = text_display(row.get("data_bucket"))
    source = text_display(row.get("data_source"))
    if tracked < max(1, int(min_sample)):
        label = "Aprendiendo"
        tone = "watch"
        action = "No bloquear por memoria; falta muestra paper por fuente."
        priority_delta = 0
    elif stop_rate > hit_2_rate:
        label = "Memoria fuente negativa"
        tone = "avoid"
        action = "Bajar prioridad hasta que esta fuente mejore en paper."
        priority_delta = -1
    elif hit_2_rate > stop_rate:
        label = "Memoria fuente positiva"
        tone = "buy"
        action = "Fuente favorecida por paper; mantener gates de datos y riesgo."
        priority_delta = 0
    else:
        label = "Memoria fuente neutral"
        tone = "watch"
        action = "Mantener prioridad normal; sin edge claro por fuente."
        priority_delta = 0
    detail = (
        f"{bucket} / {source} | n={tracked} | 2% {pct_display(hit_2_rate)} | "
        f"5% {pct_display(hit_5_rate)} | stop {pct_display(stop_rate)}"
    )
    return {
        "label": label,
        "tone": tone,
        "detail": detail,
        "action": action,
        "priority_delta": priority_delta,
        "tracked": tracked,
        "hit_2_rate": hit_2_rate,
        "hit_5_rate": hit_5_rate,
        "stop_rate": stop_rate,
    }


def source_memory_lookup_from_summary(summary: Any, *, min_sample: int = 3) -> dict[tuple[str, str], dict[str, Any]]:
    if isinstance(summary, pd.DataFrame):
        records = summary.to_dict("records")
    elif isinstance(summary, list):
        records = [item for item in summary if isinstance(item, dict)]
    elif isinstance(summary, dict):
        records = [item for item in summary.values() if isinstance(item, dict)]
    else:
        records = []
    lookup: dict[tuple[str, str], dict[str, Any]] = {}
    for row in records:
        bucket = text_display(row.get("data_bucket"))
        source = text_display(row.get("data_source"))
        if bucket == "-":
            continue
        bias = source_memory_bias_from_summary_row(row, min_sample=min_sample)
        lookup[(bucket, source)] = bias
        bucket_key = (bucket, "*")
        current = lookup.get(bucket_key)
        if current is None or int(bias.get("tracked") or 0) > int(current.get("tracked") or 0):
            lookup[bucket_key] = bias
    return lookup


