def backtest_memory_bias_for_opportunity(
    row: dict[str, Any] | None,
    lookup: dict[tuple[str, str, str, str], dict[str, Any]] | None = None,
) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    strategy = dashboard_strategy_label(row)
    timeframe = text_display(row.get("timeframe") or row.get("tf") or "1h")
    symbol = text_display(row.get("symbol")).upper()
    source = text_display(row.get("backtest_source") or row.get("source") or "*")
    memory_lookup = lookup if isinstance(lookup, dict) else {}
    keys = [
        (strategy, timeframe, symbol, source),
        (strategy, timeframe, symbol, "*"),
        (strategy, timeframe, "*", "*"),
        (strategy, "*", "*", "*"),
        ("*", timeframe, symbol, "*"),
    ]
    for key in keys:
        bias = memory_lookup.get(key)
        if bias:
            return bias
    return {
        "label": "Backtest aprendiendo",
        "tone": "watch",
        "detail": f"{strategy} | {timeframe} | {symbol} | sin muestra backtest suficiente",
        "action": "Correr mas backtests por estrategia/timeframe antes de subir peso.",
        "priority_delta": 0,
        "trades": 0,
        "win_rate": 0.0,
        "profit_factor": 0.0,
        "avg_r": 0.0,
        "max_drawdown_pct": 0.0,
    }


