def render_broker_status_hub(table: pd.DataFrame, *, account_equity: float, risk_pct: float) -> None:
    equity = max(0.0, safe_float(account_equity) or 0.0)
    risk_fraction = max(0.0, safe_float(risk_pct) or 0.0)
    risk_budget = equity * risk_fraction
    rows = table.head(6).to_dict("records") if not table.empty else []
    ready_count = sum(1 for row in rows if opportunity_is_trade_ready(row))
    watch_count = max(0, len(rows) - ready_count)
    broker_cards = []
    for platform in platform_badge_rows():
        tone = platform["tone"] if platform["tone"] in {"buy", "watch", "avoid"} else "watch"
        broker_cards.append(
            f'<article class="broker-sim-card broker-sim-{html.escape(tone)}">'
            f'<header><strong>{html.escape(platform["name"])}</strong><span>{html.escape(platform["mode"])}</span></header>'
            f'<p>{html.escape(platform["asset"])}</p>'
            f'<b>{"Configurado" if tone == "buy" else "Servicio no configurado"}</b>'
            f'<small>{html.escape(platform["use"])}</small>'
            "</article>"
        )
    feature_cards = [
        ("Modo ejecución", "PAPER_ONLY", "Órdenes reales apagadas por guardrail."),
        ("Presupuesto 1R", f"${risk_budget:,.2f}", f"Calculado sobre capital ${equity:,.2f}."),
        ("Setups visibles", str(len(table)), "Filas recibidas por el scanner actual."),
        ("Listos", str(ready_count), "Cumplen el contrato operativo actual."),
        ("En vigilancia", str(watch_count), "No se presentan como entradas."),
    ]
    feature_html = "".join(
        f'<div><span>{html.escape(label)}</span><strong>{html.escape(value)}</strong><p>{html.escape(detail)}</p></div>'
        for label, value, detail in feature_cards
    )
    st.markdown(
        '<section class="broker-sim-hub">'
        '<header><div><strong>Estado de brokers y ejecución</strong>'
        '<span>Configuración efectiva, presupuesto y oportunidades visibles</span></div>'
        '<em>PAPER_ONLY · órdenes reales OFF</em></header>'
        f'<div class="broker-sim-grid">{"".join(broker_cards)}</div>'
        f'<div class="broker-feature-grid">{feature_html}</div>'
        '</section>',
        unsafe_allow_html=True,
    )


