def entry_transition_paper_practice_candidates(
    rows: pd.DataFrame | list[dict[str, Any]],
    *,
    account_equity: float = 500.0,
    risk_pct: float = 0.01,
) -> pd.DataFrame:
    records = rows.to_dict("records") if isinstance(rows, pd.DataFrame) else list(rows or [])
    paper_rows: list[dict[str, Any]] = []
    for row in records:
        capture_ready = bool(row.get("_entry_transition_alert") or row.get("_entry_ready_snapshot"))
        if not isinstance(row, dict) or not capture_ready:
            continue
        paper_rows.append(
            {
                "action": "ALERT",
                "symbol": text_display(row.get("_paper_symbol") or row.get("Ticker")).upper(),
                "market": text_display(row.get("_paper_market") or row.get("_market") or "stock"),
                "signal": text_display(row.get("_paper_signal") or "BUY").upper(),
                "decision": text_display(row.get("_paper_decision") or "TRADE_FOR_2PCT").upper(),
                "entry": safe_float(row.get("_paper_entry")),
                "stop": safe_float(row.get("_paper_stop")),
                "target_pct": 0.02,
                "target_price": safe_float(row.get("_paper_target_2")),
                "risk_pct": safe_float(row.get("_paper_risk_pct")),
                "strategy_family": text_display(row.get("_paper_strategy_family") or "Sin clasificar"),
                "timeframe": text_display(row.get("_paper_timeframe") or "-"),
                "data_bucket": text_display(row.get("Bucket datos")),
                "data_source": text_display(row.get("Fuente")),
                "data_gate": text_display(row.get("Gate datos")),
                "por_que": text_display(row.get("Razon") or row.get("Detalle entrada")),
            }
        )
    if not paper_rows:
        return build_alpaca_paper_practice_candidates(pd.DataFrame(), account_equity=account_equity, risk_pct=risk_pct)
    candidates = build_alpaca_paper_practice_candidates(
        pd.DataFrame(paper_rows),
        account_equity=account_equity,
        risk_pct=risk_pct,
        limit=len(paper_rows),
    )
    if candidates.empty or "status" not in candidates.columns:
        return candidates
    return candidates[candidates["status"].astype(str).eq("READY_FOR_PAPER")].reset_index(drop=True)


