def trade_decision_card_status(row: dict[str, Any] | None) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    symbol = text_display(row.get("symbol")).upper()
    market = text_display(row.get("market"))
    signal = text_display(row.get("signal")).upper()
    decision = text_display(row.get("decision") or row.get("trade_decision")).upper()
    data_bucket = text_display(row.get("data_bucket"))
    data_state = text_display(row.get("data_state"))
    data_gate = text_display(row.get("data_gate"))
    source_memory = text_display(row.get("source_memory_bias"))
    strategy_source_memory = text_display(row.get("strategy_source_memory_bias"))
    crypto_context_memory = text_display(row.get("crypto_context_memory_bias"))
    backtest_memory = text_display(row.get("backtest_memory_bias"))
    tradingview_confirmation = text_display(row.get("tradingview_confirmation"))
    market_event_state = text_display(
        row.get("market_event_state")
        or row.get("event_state")
        or row.get("macro_event_state")
        or row.get("earnings_event_state")
    )
    plan = entry_exit_plan_engine(row)
    entry = safe_float(plan.get("entry"))
    stop = safe_float(plan.get("stop"))
    target_2 = safe_float(plan.get("target_2"))
    target_5 = safe_float(plan.get("target_5"))
    target_10 = safe_float(plan.get("target_10"))
    risk_pct = safe_float(row.get("risk_pct"))
    readiness = safe_float(row.get("readiness") or row.get("alert_readiness_score"))
    proximity = entry_proximity_status(row, plan)
    proximity_state = text_display(proximity.get("state"))
    if data_bucket in {"Bloqueadas", "Sin contrato"}:
        action = "No operar"
        tone = "avoid"
        reason = "Datos bloqueados o sin contrato operable."
    elif market_event_state in {"Evento macro activo", "Earnings cercanos"}:
        action = "No operar"
        tone = "avoid"
        reason = text_display(row.get("market_event_detail") or row.get("market_event_action"))
    elif market_event_state in {"Evento macro proximo", "Earnings revisar"}:
        action = "Esperar"
        tone = "watch"
        reason = text_display(row.get("market_event_detail") or row.get("market_event_action"))
    elif tradingview_confirmation == "TradingView contradice":
        action = "Esperar"
        tone = "watch"
        reason = "TradingView webhook reciente contradice la entrada."
    elif strategy_source_memory == "Memoria setup+fuente negativa":
        action = "No operar"
        tone = "avoid"
        reason = "La combinacion estrategia + fuente fallo en paper."
    elif crypto_context_memory == "Memoria crypto negativa":
        action = "Esperar"
        tone = "watch"
        reason = "La memoria crypto de este ticker/timeframe/fuente fallo en paper."
    elif backtest_memory == "Backtest negativo":
        action = "Esperar"
        tone = "watch"
        reason = "El backtest de esta estrategia/timeframe fue debil."
    elif source_memory == "Memoria fuente negativa":
        action = "Esperar"
        tone = "watch"
        reason = "La fuente tiene memoria paper negativa."
    elif data_bucket == "Fallback":
        action = "Confirmar externo"
        tone = "watch"
        reason = "La idea viene de fallback publico; confirmar broker/TradingView."
    elif proximity_state == "Invalida":
        action = "No operar"
        tone = "avoid"
        reason = text_display(proximity.get("detail"))
    elif proximity_state == "No perseguir":
        action = "Esperar pullback"
        tone = "watch"
        reason = text_display(proximity.get("detail"))
    elif opportunity_has_paper_trigger(row) and plan.get("plan_status") == "READY" and proximity_state == "Entrada en zona":
        action = "Entrar paper/manual"
        tone = "buy"
        if tradingview_confirmation == "TradingView confirma" and not opportunity_is_trade_ready(row):
            reason = "TradingView BUY fresco confirma el gatillo paper; plan, precio y riesgo estan alineados."
        else:
            reason = human_alert_reason(row) or "Setup accionable con entrada, stop y target definidos."
    elif signal == "AVOID" or decision.startswith("NO_TRADE"):
        action = "No operar"
        tone = "avoid"
        reason = human_alert_reason(row) or "La estructura actual invalida el trade."
    else:
        action = "Esperar confirmacion"
        tone = "watch"
        reason = watch_movement_label(row) or "Falta gatillo de entrada confirmado."

    invalidation = text_display(plan.get("invalidation_rule"))
    partial_exit = "Parcial 2%, runner 5%, stretch 10%."
    if target_2 is not None and target_5 is not None and target_10 is not None:
        partial_exit = f"2% {price_display(target_2)} | 5% {price_display(target_5)} | 10% {price_display(target_10)}"
    if strategy_source_memory == "Memoria setup+fuente negativa":
        next_step = text_display(row.get("strategy_source_memory_action"))
    elif market_event_state in {"Evento macro activo", "Evento macro proximo", "Earnings cercanos", "Earnings revisar"}:
        next_step = text_display(row.get("market_event_action"))
    elif tradingview_confirmation == "TradingView contradice":
        next_step = text_display(row.get("tradingview_confirmation_action"))
    elif crypto_context_memory == "Memoria crypto negativa":
        next_step = text_display(row.get("crypto_context_memory_action"))
    elif backtest_memory == "Backtest negativo":
        next_step = text_display(row.get("backtest_memory_action"))
    elif source_memory == "Memoria fuente negativa":
        next_step = text_display(row.get("source_memory_action"))
    elif action in {"Confirmar externo", "No operar"}:
        next_step = text_display(row.get("data_source_action"))
    else:
        next_step = "-"
    if next_step == "-":
        next_step = text_display(
            row.get("waiting_for")
            or row.get("cambia_si")
            or row.get("next")
            or "Esperar siguiente actualizacion live."
        )
    return {
        "symbol": symbol,
        "market": market,
        "action": action,
        "tone": tone,
        "reason": reason,
        "entry": entry,
        "stop": stop,
        "target_2": target_2,
        "target_5": target_5,
        "target_10": target_10,
        "entry_zone_low": safe_float(plan.get("entry_zone_low")),
        "entry_zone_high": safe_float(plan.get("entry_zone_high")),
        "rr_to_2": safe_float(plan.get("rr_to_2")),
        "plan_status": text_display(plan.get("plan_status")),
        "risk_pct": risk_pct,
        "readiness": readiness,
        "data_bucket": data_bucket,
        "data_state": data_state,
        "data_gate": data_gate,
        "source_memory": source_memory,
        "strategy_source_memory": strategy_source_memory,
        "crypto_context_memory": crypto_context_memory,
        "backtest_memory": backtest_memory,
        "backtest_memory_action": text_display(row.get("backtest_memory_action")),
        "backtest_memory_detail": text_display(row.get("backtest_memory_detail")),
        "tradingview_confirmation": tradingview_confirmation,
        "tradingview_confirmation_action": text_display(row.get("tradingview_confirmation_action")),
        "tradingview_confirmation_detail": text_display(row.get("tradingview_confirmation_detail")),
        "market_event_state": market_event_state,
        "market_event_action": text_display(row.get("market_event_action")),
        "market_event_detail": text_display(row.get("market_event_detail")),
        "invalidation": invalidation,
        "partial_exit": partial_exit,
        "confirmation_rule": text_display(plan.get("confirmation_rule")),
        "do_not_chase_rule": text_display(plan.get("do_not_chase_rule")),
        "entry_proximity": proximity_state,
        "entry_proximity_tone": text_display(proximity.get("tone")),
        "entry_proximity_detail": text_display(proximity.get("detail")),
        "entry_proximity_action": text_display(proximity.get("action")),
        "entry_distance_pct": safe_float(proximity.get("distance_to_entry_pct")),
        "entry_zone_distance_pct": safe_float(proximity.get("distance_to_zone_pct")),
        "entry_proximity_priority_delta": safe_float(proximity.get("priority_delta")),
        "plan_blockers": list(plan.get("blockers") or []),
        "next_step": next_step,
    }


def compound_steps_required(starting_capital: float, target_capital: float, net_gain_pct: float) -> int | None:
    try:
        start = float(starting_capital)
        target = float(target_capital)
        gain = float(net_gain_pct)
    except (TypeError, ValueError):
        return None
    if start <= 0 or target <= start or gain <= 0:
        return 0
    return int(math.ceil(math.log(target / start) / math.log(1.0 + gain)))


def capital_growth_phase(equity: float) -> tuple[str, str, str]:
    if equity < 1_000:
        return (
            "Proteccion",
            "Fractional shares/crypto pequeno; opciones solo paper o debit muy bajo.",
            "La meta es sobrevivir y medir setups, no forzar trades.",
        )
    if equity < 5_000:
        return (
            "Base",
            "Acciones fraccionadas y calls/puts solo si max loss cabe en riesgo.",
            "Solo operar 1h + 15m confirmados; evitar revenge trades.",
        )
    if equity < 25_000:
        return (
            "Consistencia",
            "Acciones liquidas, opciones con DTE y spread controlado.",
            "Subir tamano solo despues de 20 senales cerradas con edge positivo.",
        )
    if equity < 100_000:
        return (
            "Escala controlada",
            "Acciones + opciones liquidas; evitar concentracion.",
            "Bajar riesgo despues de rachas negativas y proteger ganancias.",
        )
    if equity < 500_000:
        return (
            "Profesional",
            "Portafolio de setups, no una sola apuesta.",
            "Roxy prioriza drawdown bajo antes que crecimiento agresivo.",
        )
    return (
        "Preservacion",
        "Menos riesgo por trade, mas filtros y menos ruido.",
        "El objetivo cambia de crecer rapido a no devolver capital.",
    )


def build_million_growth_plan(
    starting_capital: float = 500.0,
    target_capital: float = 1_000_000.0,
    risk_per_trade_pct: float = 0.01,
) -> dict:
    start = max(1.0, float(starting_capital or 500.0))
    target = max(start, float(target_capital or 1_000_000.0))
    risk_pct = max(0.001, float(risk_per_trade_pct or 0.01))
    milestone_values = [500, 1_000, 2_500, 5_000, 10_000, 25_000, 50_000, 100_000, 250_000, 500_000, 1_000_000]
    milestone_values = sorted({float(value) for value in milestone_values if value >= start} | {target})

    previous = start
    rows = []
    for idx, milestone in enumerate(milestone_values, start=1):
        phase, products, rule = capital_growth_phase(previous)
        rows.append(
            {
                "stage": idx,
                "phase": phase,
                "from": previous,
                "target": milestone,
                "risk_per_trade": previous * risk_pct,
                "daily_stop": previous * risk_pct * 2.0,
                "trades_2pct": compound_steps_required(previous, milestone, 0.02),
                "trades_5pct": compound_steps_required(previous, milestone, 0.05),
                "trades_10pct": compound_steps_required(previous, milestone, 0.10),
                "products": products,
                "rule": rule,
            }
        )
        previous = milestone

    return {
        "starting_capital": start,
        "target_capital": target,
        "multiplier": target / start,
        "risk_per_trade_pct": risk_pct,
        "risk_per_trade": start * risk_pct,
        "daily_stop": start * risk_pct * 2.0,
        "max_option_debit": start * risk_pct,
        "guardrail": build_account_risk_guardrail(start, risk_pct),
        "steps_to_target": {
            "2%": compound_steps_required(start, target, 0.02),
            "5%": compound_steps_required(start, target, 0.05),
            "10%": compound_steps_required(start, target, 0.10),
        },
        "milestones": rows,
        "rules": [
            "No operar si Roxy no marca Operar o una alerta BUY con riesgo y target validos.",
            "Riesgo base 0.5% a 1% por trade; con $500, 1% son $5.",
            "Maximo 2R de perdida diaria; despues de eso Roxy debe pasar a modo esperar.",
            "Opciones solo si el max loss del contrato cabe en el riesgo definido; si no, mirar accion fraccionada o paper.",
            "Subir tamano solo cuando la memoria muestre que el setup llega a 2% mas veces de las que toca stop.",
            "Nunca promediar perdedor; el stop invalida la idea.",
        ],
    }


def build_account_risk_guardrail(
    account_equity: float = 500.0,
    risk_per_trade_pct: float = 0.01,
    *,
    planned_risk_dollars: float | None = None,
    realized_loss_today: float = 0.0,
    open_risk_dollars: float = 0.0,
) -> dict:
    equity = max(1.0, float(account_equity or 500.0))
    risk_pct = max(0.001, float(risk_per_trade_pct or 0.01))
    per_trade_budget = equity * risk_pct
    daily_stop = per_trade_budget * 2.0
    planned_risk = safe_float(planned_risk_dollars)
    if planned_risk is None:
        planned_risk = per_trade_budget
    used_risk = max(0.0, float(realized_loss_today or 0.0)) + max(0.0, float(open_risk_dollars or 0.0))
    remaining_daily_risk = max(0.0, daily_stop - used_risk)

    if used_risk >= daily_stop:
        status = "DAILY_STOP"
        allowed = False
        message = "Modo proteger capital: ya se alcanzo el stop diario 2R."
    elif planned_risk > per_trade_budget:
        status = "REDUCE_SIZE"
        allowed = False
        message = "Reducir tamano: el riesgo planeado supera el presupuesto por trade."
    elif planned_risk > remaining_daily_risk:
        status = "REDUCE_SIZE"
        allowed = False
        message = "Reducir tamano: no queda suficiente riesgo diario disponible."
    else:
        status = "OK"
        allowed = True
        message = "Riesgo permitido dentro del plan 1R por trade y 2R diario."

    return {
        "status": status,
        "allowed": allowed,
        "account_equity": equity,
        "risk_per_trade_pct": risk_pct,
        "per_trade_budget": per_trade_budget,
        "daily_stop": daily_stop,
        "used_risk": used_risk,
        "remaining_daily_risk": remaining_daily_risk,
        "planned_risk": planned_risk,
        "message": message,
    }


def paper_journal_operational_risk_state(
    alpaca_journal: pd.DataFrame | None = None,
    crypto_journal: pd.DataFrame | None = None,
    *,
    account_equity: float = 500.0,
    risk_per_trade_pct: float = 0.01,
    max_open_signals: int = 3,
    max_daily_stops: int = 2,
    now: datetime | None = None,
) -> dict[str, Any]:
    current_time = now or datetime.now(timezone.utc)
    current_day = current_time.date()
    frames: list[pd.DataFrame] = []
    for source, journal in (("alpaca", alpaca_journal), ("crypto", crypto_journal)):
        if isinstance(journal, pd.DataFrame) and not journal.empty:
            data = journal.copy()
            data["_paper_source"] = source
            frames.append(data)
    if frames:
        data = pd.concat(frames, ignore_index=True, sort=False)
    else:
        data = pd.DataFrame(columns=["status", "closed_at", "closed_outcome", "risk_dollars"])

    for column in ["status", "closed_at", "closed_outcome", "risk_dollars"]:
        if column not in data.columns:
            data[column] = None

    status = data["status"].fillna("").astype(str).str.strip().str.upper()
    closed_outcome = (
        data["closed_outcome"]
        .fillna("")
        .astype(str)
        .str.strip()
        .str.upper()
        .replace({"NAN": "", "NONE": "", "<NA>": "", "NULL": ""})
    )
    open_mask = status.eq("READY_FOR_PAPER") & ~status.str.startswith("CLOSED_") & closed_outcome.eq("")
    open_count = int(open_mask.sum())
    open_risk = float(pd.to_numeric(data.loc[open_mask, "risk_dollars"], errors="coerce").fillna(0).sum())

    closed_at = pd.to_datetime(data["closed_at"], errors="coerce", utc=True)
    closed_today_mask = closed_at.dt.date.eq(current_day)
    stops_today_mask = closed_today_mask & closed_outcome.eq("STOP")
    stops_today = int(stops_today_mask.sum())
    realized_loss_today = float(pd.to_numeric(data.loc[stops_today_mask, "risk_dollars"], errors="coerce").fillna(0).sum())

    guardrail = build_account_risk_guardrail(
        account_equity=account_equity,
        risk_per_trade_pct=risk_per_trade_pct,
        planned_risk_dollars=max(1.0, float(account_equity or 500.0) * float(risk_per_trade_pct or 0.01)),
        realized_loss_today=realized_loss_today,
        open_risk_dollars=open_risk,
    )
    max_open = max(1, int(max_open_signals or 3))
    max_stops = max(1, int(max_daily_stops or 2))
    daily_stop = safe_float(guardrail.get("daily_stop")) or 0.0
    used_risk = safe_float(guardrail.get("used_risk")) or 0.0

    blockers: list[str] = []
    warnings: list[str] = []
    if stops_today >= max_stops:
        blockers.append(f"{stops_today} stops paper hoy")
    if guardrail.get("status") == "DAILY_STOP":
        blockers.append("stop diario 2R alcanzado")
    if open_count >= max_open:
        blockers.append(f"{open_count} señales paper abiertas")
    if not blockers and daily_stop > 0 and used_risk >= daily_stop * 0.70:
        warnings.append("riesgo diario usado sobre 70%")
    if not blockers and open_count >= max_open - 1:
        warnings.append("cerca del máximo de señales abiertas")

    if blockers:
        state = "Modo proteccion"
        action = "No abrir nuevas entradas paper"
        tone = "avoid"
        allowed = False
        reason = "; ".join(dict.fromkeys(blockers))
    elif warnings:
        state = "Riesgo alto"
        action = "Solo mejor oportunidad, reducir tamaño"
        tone = "watch"
        allowed = True
        reason = "; ".join(dict.fromkeys(warnings))
    else:
        state = "Puede operar"
        action = "Paper permitido con gates activos"
        tone = "buy"
        allowed = bool(guardrail.get("allowed"))
        reason = text_display(guardrail.get("message"))

    return {
        "state": state,
        "action": action,
        "tone": tone,
        "allowed": allowed,
        "reason": reason,
        "open_signals": open_count,
        "max_open_signals": max_open,
        "stops_today": stops_today,
        "max_daily_stops": max_stops,
        "open_risk_dollars": round(open_risk, 2),
        "realized_loss_today": round(realized_loss_today, 2),
        "daily_stop": round(daily_stop, 2),
        "used_risk": round(used_risk, 2),
        "remaining_daily_risk": round(safe_float(guardrail.get("remaining_daily_risk")) or 0.0, 2),
        "guardrail_status": text_display(guardrail.get("status")),
        "guardrail_message": text_display(guardrail.get("message")),
    }


def render_paper_operational_risk_panel(state: dict[str, Any]) -> None:
    tone = text_display(state.get("tone"))
    st.markdown("**Paper Risk Guard**")
    st.caption("Control operativo paper: limita pérdidas diarias, señales abiertas y riesgo vivo. No ejecuta órdenes reales.")
    cols = st.columns([1.05, 1.2, 0.9, 0.9, 0.9])
    with cols[0]:
        render_kpi_card(
            "Estado",
            text_display(state.get("state")),
            tone=tone if tone in {"buy", "watch", "avoid"} else "watch",
            detail=text_display(state.get("action")),
        )
    with cols[1]:
        render_kpi_card("Razón", text_display(state.get("reason")), tone=tone if tone in {"buy", "watch", "avoid"} else "watch")
    with cols[2]:
        render_kpi_card(
            "Abiertas",
            f"{int(state.get('open_signals') or 0)}/{int(state.get('max_open_signals') or 0)}",
            tone="avoid" if int(state.get("open_signals") or 0) >= int(state.get("max_open_signals") or 1) else "watch",
        )
    with cols[3]:
        render_kpi_card(
            "Stops hoy",
            f"{int(state.get('stops_today') or 0)}/{int(state.get('max_daily_stops') or 0)}",
            tone="avoid" if int(state.get("stops_today") or 0) >= int(state.get("max_daily_stops") or 1) else "watch",
        )
    with cols[4]:
        render_kpi_card(
            "Riesgo libre",
            num_display(state.get("remaining_daily_risk"), 2),
            tone="avoid" if (safe_float(state.get("remaining_daily_risk")) or 0) <= 0 else "buy",
            detail=f"2R {num_display(state.get('daily_stop'), 2)}",
        )


def parse_event_datetime(value: Any) -> datetime | None:
    raw = text_display(value)
    if raw == "-":
        return None
    raw = raw.replace("Z", "+00:00")
    for candidate in (raw, raw.replace("/", "-")):
        try:
            parsed = datetime.fromisoformat(candidate)
            if parsed.tzinfo is None:
                parsed = parsed.replace(tzinfo=timezone.utc)
            return parsed.astimezone(timezone.utc)
        except ValueError:
            continue
    return None


def row_earnings_event_guard(
    row: dict[str, Any] | None,
    *,
    now: datetime | None = None,
) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    symbol = text_display(row.get("symbol")).upper()
    market = normalize_command_market(row.get("market"), symbol)
    if market == "crypto":
        return {"active": False, "label": "Sin earnings", "tone": "neutral", "priority_delta": 0, "action": "-"}
    current_time = (now or datetime.now(timezone.utc)).astimezone(timezone.utc)
    days_to_earnings = safe_float(
        row.get("days_to_earnings")
        or row.get("earnings_days")
        or row.get("earnings_in_days")
        or row.get("days_until_earnings")
    )
    earnings_at = parse_event_datetime(
        row.get("earnings_at")
        or row.get("next_earnings_at")
        or row.get("earnings_date")
        or row.get("next_earnings_date")
    )
    if days_to_earnings is None and earnings_at is not None:
        days_to_earnings = (earnings_at - current_time).total_seconds() / 86400.0
    earnings_flag = bool(row.get("earnings_event") or row.get("has_earnings") or row.get("earnings_risk"))
    if days_to_earnings is not None and -0.25 <= days_to_earnings <= 2.0:
        return {
            "active": True,
            "label": "Earnings cercanos",
            "tone": "avoid",
            "priority_delta": -2,
            "action": "No abrir swing nuevo antes/despues de earnings; esperar reaccion.",
            "detail": f"{symbol} earnings en {days_to_earnings:.1f} dias.",
            "minutes_to_event": round(days_to_earnings * 1440.0, 1),
        }
    if earnings_flag:
        return {
            "active": False,
            "label": "Earnings revisar",
            "tone": "watch",
            "priority_delta": -1,
            "action": "Confirmar fecha de earnings antes de operar.",
            "detail": f"{symbol} trae flag de earnings sin fecha precisa.",
        }
    return {"active": False, "label": "Sin earnings", "tone": "neutral", "priority_delta": 0, "action": "-"}


def market_event_guard(
    row: dict[str, Any] | None,
    macro_context: dict[str, Any] | None = None,
    *,
    now: datetime | None = None,
) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    context = macro_context if isinstance(macro_context, dict) else {}
    current_time = (now or datetime.now(timezone.utc)).astimezone(timezone.utc)
    row_macro_active = bool(row.get("macro_event") or row.get("fed_event") or row.get("event_risk") or row.get("risk_event"))
    news_event = text_display(row.get("news_event") or row.get("market_event") or row.get("calendar_event"))
    row_severity = text_display(row.get("macro_event_severity") or row.get("event_severity") or row.get("impact")).upper()
    if row_severity not in {"HIGH", "MEDIUM", "LOW"}:
        row_severity = "HIGH" if row_macro_active else "-"
    row_macro_detail = text_display(row.get("macro_context") or row.get("event_context") or news_event)

    top_event = context.get("top_event") if isinstance(context.get("top_event"), dict) else {}
    upcoming = context.get("upcoming_events") if isinstance(context.get("upcoming_events"), list) else []
    active_events = context.get("active_events") if isinstance(context.get("active_events"), list) else []
    macro_active = bool(context.get("active") and active_events)
    top_title = text_display(top_event.get("title") or news_event or "Evento macro")
    top_severity = text_display(top_event.get("severity") or row_severity or "HIGH").upper()
    minutes_to_event = safe_float(top_event.get("minutes_to_event"))

    if row_macro_active:
        return {
            "state": "Evento macro activo",
            "tone": "avoid",
            "active": True,
            "priority_delta": -2,
            "action": "No operar hasta reacción post-evento y nueva confirmación.",
            "detail": row_macro_detail if row_macro_detail != "-" else news_event,
            "event": news_event if news_event != "-" else top_title,
            "severity": row_severity,
            "minutes_to_event": minutes_to_event,
        }
    if macro_active and top_severity in {"HIGH", "MEDIUM"}:
        return {
            "state": "Evento macro activo",
            "tone": "avoid",
            "active": True,
            "priority_delta": -2,
            "action": "No abrir entrada nueva durante ventana macro.",
            "detail": text_display(context.get("detail")),
            "event": top_title,
            "severity": top_severity,
            "minutes_to_event": minutes_to_event,
        }
    if top_event and top_severity in {"HIGH", "MEDIUM"} and minutes_to_event is not None:
        threshold = 90.0 if top_severity == "HIGH" else 45.0
        if 0 <= minutes_to_event <= threshold:
            return {
                "state": "Evento macro proximo",
                "tone": "watch",
                "active": False,
                "priority_delta": -1,
                "action": "Esperar evento o reducir tamaño; confirmar despues de la vela de reacción.",
                "detail": text_display(context.get("detail")),
                "event": top_title,
                "severity": top_severity,
                "minutes_to_event": minutes_to_event,
            }

    earnings_guard = row_earnings_event_guard(row, now=current_time)
    if earnings_guard.get("label") == "Earnings cercanos":
        return {
            "state": "Earnings cercanos",
            "tone": "avoid",
            "active": True,
            "priority_delta": -2,
            "action": earnings_guard["action"],
            "detail": earnings_guard.get("detail"),
            "event": "Earnings",
            "severity": "HIGH",
            "minutes_to_event": earnings_guard.get("minutes_to_event"),
        }
    if earnings_guard.get("label") == "Earnings revisar":
        return {
            "state": "Earnings revisar",
            "tone": "watch",
            "active": False,
            "priority_delta": -1,
            "action": earnings_guard["action"],
            "detail": earnings_guard.get("detail"),
            "event": "Earnings",
            "severity": "MEDIUM",
            "minutes_to_event": None,
        }
    return {
        "state": "Sin evento",
        "tone": "buy",
        "active": False,
        "priority_delta": 0,
        "action": "Sin evento macro/earnings bloqueando.",
        "detail": "-",
        "event": "-",
        "severity": "-",
        "minutes_to_event": None,
    }


def render_market_event_guard_panel(table: pd.DataFrame, macro_context: dict[str, Any] | None = None) -> None:
    top = table.iloc[0].to_dict() if isinstance(table, pd.DataFrame) and not table.empty else {}
    guard = market_event_guard(top, macro_context)
    tone = text_display(guard.get("tone"))
    cols = st.columns([1.0, 1.35, 0.8, 1.2])
    with cols[0]:
        render_kpi_card("Eventos", text_display(guard.get("state")), tone=tone if tone in {"buy", "watch", "avoid"} else "watch")
    with cols[1]:
        render_kpi_card("Evento activo", text_display(guard.get("event")), tone=tone if tone in {"buy", "watch", "avoid"} else "watch")
    with cols[2]:
        render_kpi_card("Impacto", text_display(guard.get("severity")), tone="avoid" if guard.get("severity") == "HIGH" else "watch")
    with cols[3]:
        render_kpi_card("Acción", text_display(guard.get("action")), tone=tone if tone in {"buy", "watch", "avoid"} else "watch")


def small_account_product_plan(
    *,
    account_equity: float = 500.0,
    risk_per_trade_pct: float = 0.01,
    market: str = "stock",
    entry: float | None = None,
    stop: float | None = None,
    option: dict | None = None,
) -> dict:
    equity = max(1.0, float(account_equity or 500.0))
    risk_pct = max(0.001, float(risk_per_trade_pct or 0.01))
    risk_budget = equity * risk_pct
    entry_value = safe_float(entry)
    stop_value = safe_float(stop)
    market_value = str(market or "stock").lower()
    option = option or {}
    option_max_loss = safe_float(option.get("max_loss_per_contract"))
    option_contract = text_display(option.get("contractSymbol") or option.get("contract"))

    if entry_value is None or entry_value <= 0:
        return {
            "recommendation": "Solo paper",
            "allowed": False,
            "risk_budget": risk_budget,
            "message": "Falta precio de entrada para calcular tamano.",
            "next_step": "Esperar plan con entrada y stop.",
        }

    risk_per_unit = None
    if stop_value is not None and stop_value > 0 and stop_value < entry_value:
        risk_per_unit = entry_value - stop_value

    if market_value == "crypto":
        if risk_per_unit is None:
            units = min(risk_budget / entry_value, equity / entry_value)
            return {
                "recommendation": "Crypto pequeno",
                "allowed": True,
                "risk_budget": risk_budget,
                "risk_per_unit": None,
                "units": units,
                "message": "Crypto permite tamano fraccionado, pero falta stop valido; usar posicion pequena.",
                "next_step": "Definir stop antes de operar.",
            }
        max_by_risk = risk_budget / risk_per_unit
        max_by_cash = equity / entry_value
        units = min(max_by_risk, max_by_cash)
        risk_used = risk_per_unit * units
        capital_limited = max_by_cash < max_by_risk
        if capital_limited:
            message = (
                f"Tamano crypto capado por capital ${equity:.2f}; "
                f"riesgo real estimado ${risk_used:.2f} de 1R ${risk_budget:.2f}."
            )
            next_step = "Vigilar o esperar entrada con stop mas amplio/medible antes de usar capital."
        else:
            message = f"Tamano crypto calculado para no superar ${risk_budget:.2f} de riesgo."
            next_step = "Colocar orden manual solo si el exchange respeta stop y liquidez."
        return {
            "recommendation": "Crypto pequeno",
            "allowed": True,
            "risk_budget": risk_budget,
            "risk_per_unit": risk_per_unit,
            "units": units,
            "capital_limited": capital_limited,
            "message": message,
            "next_step": next_step,
        }

    option_allowed = option_max_loss is not None and option_max_loss <= risk_budget
    if option_contract != "-" and option_max_loss is not None and not option_allowed:
        option_message = f"Opcion fuera de plan: max loss ${option_max_loss:.2f} supera 1R ${risk_budget:.2f}."
    elif option_contract != "-" and option_allowed:
        option_message = f"Opcion permitida por riesgo: max loss ${option_max_loss:.2f} cabe en 1R ${risk_budget:.2f}."
    else:
        option_message = "Sin contrato de opcion validado para cuenta pequena."

    if option_contract != "-":
        if option_allowed:
            contracts = max(1, math.floor(risk_budget / max(option_max_loss or risk_budget, 0.01)))
            return {
                "recommendation": "Opcion",
                "allowed": True,
                "risk_budget": risk_budget,
                "risk_per_unit": option_max_loss,
                "units": contracts,
                "whole_shares": contracts,
                "option_allowed": True,
                "option_max_loss": option_max_loss,
                "option_message": option_message,
                "message": f"Contrato permitido por riesgo; max loss cabe en 1R ${risk_budget:.2f}.",
                "next_step": "Confirmar spread, volumen, open interest y DTE antes de entrar.",
            }
        return {
            "recommendation": "Solo paper",
            "allowed": False,
            "risk_budget": risk_budget,
            "risk_per_unit": option_max_loss,
            "units": 0,
            "whole_shares": 0,
            "option_allowed": False,
            "option_max_loss": option_max_loss,
            "option_message": option_message,
            "message": "Contrato fuera del plan de cuenta pequena.",
            "next_step": "Priorizar accion/fraccionada o esperar un contrato con max loss dentro de 1R.",
        }

    if risk_per_unit is None:
        return {
            "recommendation": "Solo paper",
            "allowed": False,
            "risk_budget": risk_budget,
            "option_allowed": option_allowed,
            "option_message": option_message,
            "message": "Falta stop valido; con cuenta pequena no se opera sin invalidacion clara.",
            "next_step": "Esperar stop tecnico y target 2% viable.",
        }

    max_by_risk = risk_budget / risk_per_unit
    max_by_cash = equity / entry_value
    units = min(max_by_risk, max_by_cash)
    whole_shares = math.floor(units)
    if whole_shares >= 1:
        recommendation = "Accion"
        message = f"Puedes usar hasta {whole_shares} accion(es) sin superar ${risk_budget:.2f} de riesgo."
        allowed = True
    elif units > 0:
        recommendation = "Accion fraccionada"
        message = f"Usar fraccion aproximada {units:.4f}; una accion completa supera efectivo o riesgo."
        allowed = True
    else:
        recommendation = "Solo paper"
        message = "El riesgo por accion no cabe en la cuenta; usar paper hasta mejor entrada."
        allowed = False

    if option_contract != "-" and not option_allowed:
        next_step = "Priorizar accion/fraccionada; no comprar esa opcion con cuenta pequena."
    elif option_contract != "-" and option_allowed:
        next_step = "Opcion solo si spread, volumen y DTE tambien pasan el filtro."
    else:
        next_step = "Confirmar entrada manual y respetar stop."

    return {
        "recommendation": recommendation,
        "allowed": allowed,
        "risk_budget": risk_budget,
        "risk_per_unit": risk_per_unit,
        "units": units,
        "whole_shares": whole_shares,
        "option_allowed": option_allowed,
        "option_max_loss": option_max_loss,
        "option_message": option_message,
        "message": message,
        "next_step": next_step,
    }


def setup_risk_pct(setup: dict) -> float | None:
    entry = safe_float(setup.get("entry"))
    stop = safe_float(setup.get("stop"))
    if entry is None or stop is None or entry <= 0 or stop <= 0 or stop >= entry:
        return None
    return (entry - stop) / entry


def signal_tone(value: str) -> str:
    normalized = str(value or "").upper()
    if normalized.startswith("BUY") or normalized.startswith("TRADE_FOR") or normalized.startswith("ENTER"):
        return "buy"
    if normalized.startswith("WATCH") or normalized.startswith("WAIT"):
        return "watch"
    if normalized.startswith("AVOID") or normalized.startswith("NO_"):
        return "avoid"
    return "neutral"


def render_kpi_card(label: str, value, *, tone: str = "neutral", detail: str | None = None) -> None:
    tone = tone if tone in {"neutral", "buy", "watch", "avoid"} else "neutral"
    value_text = html.escape(text_display(value))
    label_text = html.escape(str(label))
    detail_html = ""
    if detail:
        detail_html = f'<div class="symbol-kpi-detail">{html.escape(str(detail))}</div>'
    st.markdown(
        f"""
        <div class="symbol-kpi symbol-kpi-{tone}">
            <div class="symbol-kpi-label">{label_text}</div>
            <div class="symbol-kpi-value">{value_text}</div>
            {detail_html}
        </div>
        """,
        unsafe_allow_html=True,
    )


@st.cache_data(ttl=OPPORTUNITY_REFRESH_SECONDS, show_spinner=False)
def cached_living_market_snapshot(
    selected_symbol: str,
    selected_market: str,
    interval_seconds: int,
) -> dict[str, Any]:
    stock_symbols = list(DEFAULT_STOCK_SYMBOLS)
    crypto_symbols = list(DEFAULT_CRYPTO_SYMBOLS)
    symbol = text_display(selected_symbol).upper()
    market = normalize_command_market(selected_market, symbol)
    if symbol and symbol != "-":
        target = crypto_symbols if market == "crypto" or "/" in symbol else stock_symbols
        if symbol not in target:
            target.insert(0, symbol)
    return build_living_market_snapshot(
        stock_symbols=tuple(dict.fromkeys(stock_symbols)),
        crypto_symbols=tuple(dict.fromkeys(crypto_symbols)),
        scan_interval_seconds=max(5, int(interval_seconds or OPPORTUNITY_REFRESH_SECONDS)),
    )


@st.cache_data(ttl=LIVE_PRICE_REFRESH_SECONDS, show_spinner=False)
def cached_live_price_snapshot(selected_symbol: str, selected_market: str) -> dict[str, Any]:
    symbol = text_display(selected_symbol).upper() or "AAPL"
    market = normalize_command_market(selected_market, symbol)
    if market == "stock" and "/" not in symbol:
        return cached_stock_provider_snapshot(symbol)
    return build_live_price_snapshot(symbol, market)


@st.cache_data(ttl=cache_ttl("stock_quote"), show_spinner=False)
def cached_stock_provider_snapshot(symbol: str) -> dict[str, Any]:
    """Single shared provider request for all stock quote consumers."""
    clean_symbol = re.sub(r"[^A-Z0-9.\-]", "", str(symbol or "").upper())
    return build_live_price_snapshot(clean_symbol, "stock") if clean_symbol else {}


@st.cache_data(ttl=LIVE_PRICE_REFRESH_SECONDS, show_spinner=False)
def cached_alpaca_market_data_diagnostic(selected_symbol: str, selected_market: str) -> dict[str, Any]:
    symbol = text_display(selected_symbol).upper() or "AAPL"
    market = normalize_command_market(selected_market, symbol)
    if market == "crypto" or "/" in symbol:
        symbol = "AAPL"
    return build_alpaca_market_data_diagnostic(symbol)


def _living_market_tone(status: str) -> str:
    status = str(status or "").upper()
    if status == "OK":
        return "buy"
    if status == "FAIL":
        return "avoid"
    return "watch"


def _market_news_url(item: dict[str, Any]) -> str:
    url = text_display(item.get("url") or item.get("tradingview_url"))
    if url != "-":
        return url
    symbol = text_display(item.get("symbol") or (item.get("tickers") or [""])[0]).upper()
    if symbol and symbol != "-":
        return f"https://finance.yahoo.com/quote/{quote(symbol)}/news"
    headline = text_display(item.get("headline") or item.get("title") or item.get("company"))
    if headline != "-":
        return f"https://www.google.com/search?q={quote(headline + ' stock news')}"
    return "https://www.nasdaq.com/market-activity/ipos"


def market_news_card_rows(
    news: list[dict[str, Any]] | None,
    new_tickers: list[dict[str, Any]] | None,
    ipos: list[dict[str, Any]] | None,
    *,
    limit: int = 8,
) -> list[dict[str, str]]:
    rows: list[dict[str, str]] = []
    for item in news or []:
        tickers = item.get("tickers") if isinstance(item.get("tickers"), list) else []
        title = text_display(item.get("title"))
        if title == "-":
            continue
        rows.append(
            {
                "kind": "Noticia",
                "title": title,
                "subtitle": ", ".join(text_display(ticker).upper() for ticker in tickers if text_display(ticker) != "-")
                or text_display(item.get("source")),
                "meta": f"{text_display(item.get('impact'))} · {text_display(item.get('published_at'))}",
                "summary": text_display(item.get("summary") or item.get("description") or item.get("source")),
                "url": _market_news_url(item),
            }
        )
    for item in new_tickers or []:
        title = text_display(item.get("headline") or item.get("company") or item.get("symbol"))
        symbol = text_display(item.get("symbol")).upper()
        if title == "-":
            continue
        rows.append(
            {
                "kind": "Ticker nuevo",
                "title": f"{symbol} · {title}" if symbol != "-" else title,
                "subtitle": text_display(item.get("reason")),
                "meta": text_display(item.get("source")),
                "summary": "Roxy lo mantiene en vigilancia porque aparecio como ticker o tema nuevo en fuentes de mercado.",
                "url": _market_news_url(item),
            }
        )
    for item in ipos or []:
        symbol = text_display(item.get("symbol")).upper()
        company = text_display(item.get("company") or item.get("name"))
        if symbol == "-" and company == "-":
            continue
        rows.append(
            {
                "kind": "IPO",
                "title": f"{symbol} · {company}" if symbol != "-" and company != "-" else symbol or company,
                "subtitle": f"{text_display(item.get('exchange'))} · {text_display(item.get('date'))}",
                "meta": f"Precio {text_display(item.get('price'))} · acciones {text_display(item.get('shares'))}",
                "summary": "Candidato de calendario IPO para revisar volumen, primer rango y confirmacion antes de operar.",
                "url": _market_news_url(item),
            }
        )
    return rows[:limit]


def render_market_news_cards(
    news: list[dict[str, Any]] | None,
    new_tickers: list[dict[str, Any]] | None,
    ipos: list[dict[str, Any]] | None,
    *,
    compact: bool = False,
) -> None:
    rows = market_news_card_rows(news, new_tickers, ipos, limit=4 if compact else 8)
    st.markdown("**Noticias, IPOs y tickers que Roxy esta leyendo**")
    if not rows:
        st.info("Sin noticias, IPOs o tickers nuevos utilizables en este ciclo; revisar diagnostico de fuentes.")
        return
    card_html = []
    for row in rows:
        card_html.append(
            '<article class="market-news-card">'
            f'<div class="market-news-kind">{html.escape(row["kind"])}</div>'
            f'<h4>{html.escape(row["title"])}</h4>'
            f'<strong>{html.escape(row["subtitle"])}</strong>'
            f'<p>{html.escape(row["summary"][:420])}</p>'
            f'<small>{html.escape(row["meta"])}</small>'
            f'<a href="{html.escape(row["url"])}" target="_blank" rel="noopener noreferrer">Abrir noticia</a>'
            "</article>"
        )
    st.markdown(
        (
            "<style>"
            ".market-news-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:10px;margin:8px 0 14px;}"
            ".market-news-card{border:1px solid rgba(148,163,184,.24);border-radius:8px;background:rgba(15,23,42,.72);padding:12px;min-height:188px;display:flex;flex-direction:column;gap:6px;}"
            ".market-news-kind{color:#38bdf8;font-size:11px;font-weight:900;text-transform:uppercase;letter-spacing:.04em;}"
            ".market-news-card h4{margin:0;color:#f8fafc;font-size:15px;line-height:1.25;}"
            ".market-news-card strong{color:#bbf7d0;font-size:12px;line-height:1.25;}"
            ".market-news-card p{margin:0;color:#cbd5e1;font-size:12px;line-height:1.35;flex:1;}"
            ".market-news-card small{color:#94a3b8;font-size:11px;}"
            ".market-news-card a{color:#e0f2fe;background:#0369a1;border:1px solid rgba(125,211,252,.38);border-radius:6px;padding:7px 9px;font-size:12px;font-weight:900;text-decoration:none;text-align:center;}"
            "</style>"
            f'<section class="market-news-grid">{"".join(card_html)}</section>'
        ),
        unsafe_allow_html=True,
    )


def render_living_market_pulse(
    controls: dict[str, Any] | None,
    realtime: dict[str, Any] | None,
    *,
    compact: bool = False,
) -> None:
    controls = controls or {}
    realtime = realtime or {}
    selected_symbol = text_display(controls.get("symbol_input") or controls.get("default_symbol") or "AAPL")
    selected_market = normalize_command_market(controls.get("market"), selected_symbol)
    interval = normalize_realtime_refresh_interval(realtime.get("interval_seconds") or 30)

    if not compact:
        st.markdown("### Roxy Live Market")
        st.caption("Analisis para paper trading/simulacion. No coloca ordenes reales.")
        st.caption("Diagnostico live market: precio, Alpaca data, noticias, IPOs y fuentes reales se actualizan en este panel.")
    with st.spinner("Roxy escanea mercado real, noticias e IPOs..."):
        live_price = cached_live_price_snapshot(selected_symbol, selected_market)
        alpaca_diag = cached_alpaca_market_data_diagnostic(selected_symbol, selected_market)
        snapshot = cached_living_market_snapshot(
            selected_symbol,
            selected_market,
            max(OPPORTUNITY_REFRESH_SECONDS, interval),
        )

    generated_at = text_display(snapshot.get("generated_at"))
    next_scan_at = text_display(snapshot.get("next_scan_at"))
    sources = snapshot.get("sources") if isinstance(snapshot.get("sources"), list) else []
    opportunities = snapshot.get("opportunities") if isinstance(snapshot.get("opportunities"), list) else []
    news = snapshot.get("news") if isinstance(snapshot.get("news"), list) else []
    ipos = snapshot.get("ipos") if isinstance(snapshot.get("ipos"), list) else []
    new_tickers = snapshot.get("new_tickers") if isinstance(snapshot.get("new_tickers"), list) else []
    diagnostics = snapshot.get("diagnostics") if isinstance(snapshot.get("diagnostics"), dict) else {}
    source_label = f"{diagnostics.get('real_source_count', 0)} OK / {diagnostics.get('failing_source_count', 0)} fallan"
    state_counts: dict[str, int] = {}
    for item in opportunities:
        state = text_display(item.get("signal_state"))
        if state != "-":
            state_counts[state] = state_counts.get(state, 0) + 1
    dominant_state = max(state_counts.items(), key=lambda pair: pair[1])[0] if state_counts else "API_FAIL"
    state_detail = " | ".join(f"{key}:{value}" for key, value in sorted(state_counts.items())) or "sin senales listas"

    freshness = text_display(live_price.get("freshness"))
    price_tone = "buy" if freshness in {"LIVE", "FRESH"} else "avoid"
    price_detail = f"{live_price.get('source', '-')} | edad {live_price.get('age_seconds', '-')}s"
    provider_issue = text_display(live_price.get("provider_issue"))
    if provider_issue != "-":
        price_tone = "watch"
        price_detail = f"{price_detail} | Alpaca: {provider_issue}"
    if live_price.get("error"):
        price_detail = str(live_price.get("error"))

    if compact:
        tone_class = price_tone if price_tone in {"buy", "watch", "avoid"} else "watch"
        st.markdown(
            (
                "<style>"
                ".roxy-live-strip{display:grid;grid-template-columns:1.1fr repeat(5,minmax(120px,.7fr));gap:8px;align-items:stretch;margin:8px 0 10px;}"
                ".roxy-live-strip>div{border:1px solid rgba(148,163,184,.22);border-radius:8px;background:rgba(15,23,42,.68);padding:9px 10px;min-width:0;}"
                ".roxy-live-strip span{display:block;color:#93a4b8;font-size:10px;font-weight:900;text-transform:uppercase;letter-spacing:.05em;}"
                ".roxy-live-strip strong{display:block;color:#f8fafc;font-size:16px;line-height:1.1;margin-top:3px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;}"
                ".roxy-live-strip small{display:block;color:#cbd5e1;font-size:10.5px;line-height:1.2;margin-top:4px;max-height:26px;overflow:hidden;}"
                ".roxy-live-strip .avoid{border-color:rgba(248,113,113,.48);background:rgba(127,29,29,.26);}"
                ".roxy-live-strip .watch{border-color:rgba(251,191,36,.48);background:rgba(120,53,15,.24);}"
                ".roxy-live-strip .buy{border-color:rgba(74,222,128,.40);background:rgba(20,83,45,.24);}"
                "@media(max-width:900px){.roxy-live-strip{grid-template-columns:1fr 1fr}.roxy-live-strip>div:first-child{grid-column:1/-1}}"
                "</style>"
                '<section class="roxy-live-strip">'
                '<div class="buy"><span>Roxy live</span><strong>Escaneando mercado</strong><small>Paper/manual. No coloca ordenes reales.</small></div>'
                f'<div class="{html.escape(tone_class)}"><span>Precio</span><strong>{html.escape(num_display(live_price.get("price"), 2))}</strong><small>{html.escape(price_detail)}</small></div>'
                f'<div class="{html.escape(tone_class)}"><span>Frescura</span><strong>{html.escape(freshness)}</strong><small>{html.escape(text_display(live_price.get("latency_note"))[:120])}</small></div>'
                f'<div><span>Fuentes</span><strong>{html.escape(source_label)}</strong><small>reales conectadas</small></div>'
                f'<div><span>Proximo scan</span><strong>{html.escape(next_scan_at.split("+")[0].replace("T", " "))}</strong><small>{html.escape(state_detail[:120])}</small></div>'
                f'<div><span>Hoy</span><strong>{html.escape(str(snapshot.get("opportunities_found_today", 0)))} setups</strong><small>{html.escape(str(snapshot.get("active_alerts", 0)))} alertas activas</small></div>'
                "</section>"
            ),
            unsafe_allow_html=True,
        )
        render_market_news_cards(news[:3], new_tickers[:2], ipos[:2], compact=True)
        with st.expander("Diagnostico live", expanded=False):
            if diagnostics.get("data_errors"):
                st.error("Roxy detecto errores de datos reales: " + " | ".join(diagnostics.get("data_errors", [])[:2]))
            if not diagnostics.get("data_errors"):
                st.caption("Sin errores criticos de fuentes en este ciclo.")
        return

    st.caption(snapshot.get("disclaimer") or "Analisis para paper trading/simulacion. No coloca ordenes reales.")
    kpi_cols = st.columns(7)
    with kpi_cols[0]:
        render_kpi_card("Estado", snapshot.get("status", "Escaneando"), tone="buy", detail="Motor live preview/paper")
    with kpi_cols[1]:
        render_kpi_card("Precio live", num_display(live_price.get("price"), 2), tone=price_tone, detail=price_detail)
    with kpi_cols[2]:
        render_kpi_card("Latencia precio", freshness, tone=price_tone, detail=live_price.get("latency_note"))
    with kpi_cols[3]:
        render_kpi_card("Ultima actualizacion", generated_at.split("+")[0].replace("T", " "), tone="buy")
    with kpi_cols[4]:
        render_kpi_card("Fuentes reales", source_label, tone="buy" if diagnostics.get("real_source_count") else "avoid")
    with kpi_cols[5]:
        render_kpi_card("Proximo scan", next_scan_at.split("+")[0].replace("T", " "), tone="watch")
    with kpi_cols[6]:
        render_kpi_card("Oportunidades hoy", snapshot.get("opportunities_found_today", 0), tone="buy" if opportunities else "watch")
    render_kpi_card("Alertas activas", snapshot.get("active_alerts", 0), tone="buy" if snapshot.get("active_alerts") else "neutral")
    render_kpi_card(
        "Estado senal",
        dominant_state,
        tone="buy" if dominant_state == "LIVE_READY" else "avoid" if dominant_state in {"API_FAIL", "STALE_BLOCKED"} else "watch",
        detail=state_detail,
    )
    render_kpi_card(
        "Alpaca data",
        alpaca_diag.get("status", "FAIL"),
        tone=_living_market_tone(alpaca_diag.get("status")),
        detail=f"{alpaca_diag.get('error_category') or 'OK'} | feed {alpaca_diag.get('feed')} | {alpaca_diag.get('mode')}",
    )

    if opportunities:
        chart_rows = pd.DataFrame(
            [
                {
                    "symbol": item.get("symbol"),
                    "confidence": item.get("confidence"),
                    "risk_pct": item.get("risk_pct"),
                    "market": item.get("market"),
                }
                for item in opportunities[:10]
            ]
        )
        if not chart_rows.empty:
            chart = (
                alt.Chart(chart_rows)
                .mark_bar(cornerRadiusTopLeft=3, cornerRadiusTopRight=3)
                .encode(
                    x=alt.X("symbol:N", sort="-y", title="Activo"),
                    y=alt.Y("confidence:Q", title="Confianza"),
                    color=alt.Color("market:N", title="Mercado"),
                    tooltip=["symbol", "market", "confidence", "risk_pct"],
                )
                .properties(width=700, height=180)
            )
            st.altair_chart(chart, use_container_width=False)

        display_rows = []
        for item in opportunities:
            related = item.get("related_news") if isinstance(item.get("related_news"), dict) else {}
            indicators = item.get("indicators") if isinstance(item.get("indicators"), dict) else {}
            display_rows.append(
                {
                    "Ticker": item.get("symbol"),
                    "Mercado": item.get("market"),
                    "Precio": num_display(item.get("price"), 2),
                    "Hora precio": item.get("price_timestamp"),
                    "Razon": item.get("reason"),
                    "TradingView": item.get("tradingview_url"),
                    "Entrada": num_display(item.get("entry"), 2),
                    "Stop": num_display(item.get("stop_loss"), 2),
                    "Take profit": num_display(item.get("take_profit"), 2),
                    "Riesgo": item.get("risk_level"),
                    "Confianza": item.get("confidence"),
                    "Estado senal": item.get("signal_state"),
                    "Bloqueo/confirmacion": item.get("state_reason"),
                    "RSI": num_display(indicators.get("rsi14"), 1),
                    "MACD hist": num_display(indicators.get("macd_hist"), 3),
                    "Vol rel": num_display(indicators.get("volume_ratio"), 2),
                    "Tendencia": item.get("trend"),
                    "Fuente": item.get("source"),
                    "Noticia": related.get("title", ""),
                }
            )
        st.dataframe(pd.DataFrame(display_rows), width="stretch", hide_index=True, height=min(420, 70 + 34 * len(display_rows)))
    else:
        detail = "No hay setups accionables con datos reales en este ciclo."
        if diagnostics.get("data_errors"):
            detail += " Errores: " + " | ".join(str(item) for item in diagnostics.get("data_errors", [])[:3])
        st.warning(detail)

    render_market_news_cards(news, new_tickers, ipos)

    with st.expander("Diagnostico live market", expanded=False):
        st.markdown("**Alpaca market data**")
        alpaca_cols = st.columns(4)
        with alpaca_cols[0]:
            render_kpi_card(
                "Estado Alpaca",
                alpaca_diag.get("status", "FAIL"),
                tone=_living_market_tone(alpaca_diag.get("status")),
                detail=alpaca_diag.get("summary"),
            )
        with alpaca_cols[1]:
            render_kpi_card(
                "Feed",
                alpaca_diag.get("feed", "-"),
                tone="buy" if alpaca_diag.get("safe_for_signals") else "watch",
                detail=f"Senales broker: {'SI' if alpaca_diag.get('safe_for_signals') else 'NO'}",
            )
        with alpaca_cols[2]:
            render_kpi_card(
                "Modo",
                alpaca_diag.get("mode", "-"),
                tone="buy" if alpaca_diag.get("paper_flag") else "avoid",
                detail="Ordenes reales: NO",
            )
        with alpaca_cols[3]:
            render_kpi_card(
                "Endpoint",
                "MISMATCH" if alpaca_diag.get("endpoint_mismatch") else "OK",
                tone="avoid" if alpaca_diag.get("endpoint_mismatch") else "buy",
                detail=alpaca_diag.get("effective_endpoint"),
            )
        st.caption(alpaca_diag.get("next_action") or "Sin accion pendiente.")
        probes = alpaca_diag.get("probes") if isinstance(alpaca_diag.get("probes"), list) else []
        if probes:
            st.dataframe(
                pd.DataFrame(
                    [
                        {
                            "Probe": item.get("probe"),
                            "Estado": item.get("status"),
                            "Precio": num_display(item.get("price"), 2),
                            "Timestamp": item.get("timestamp"),
                            "Edad s": item.get("age_seconds"),
                            "Error": item.get("error_category"),
                            "Detalle": item.get("detail"),
                            "Accion": item.get("action"),
                        }
                        for item in probes
                    ]
                ),
                width="stretch",
                hide_index=True,
                height=170,
            )
        else:
            st.warning("Alpaca market data sin probes: " + ", ".join(alpaca_diag.get("missing_keys") or ["credenciales faltantes"]))

        if sources:
            st.dataframe(
                pd.DataFrame(
                    [
                        {
                            "Fuente": item.get("name"),
                            "Estado": item.get("status"),
                            "Detalle": item.get("detail"),
                            "Ultima respuesta": item.get("last_response"),
                        }
                        for item in sources
                    ]
                ),
                width="stretch",
                hide_index=True,
                height=360,
            )
        for item in sources[:8]:
            render_kpi_card(
                item.get("name", "Fuente"),
                item.get("status", "-"),
                tone=_living_market_tone(item.get("status")),
                detail=item.get("detail"),
            )
        st.write("Demo data:", "NO" if diagnostics.get("using_demo_data") is False else "SI")
        if diagnostics.get("chart_data_errors"):
            st.error("Errores de datos/graficas: " + " | ".join(str(item) for item in diagnostics.get("chart_data_errors")[:6]))
        logs = diagnostics.get("logs") if isinstance(diagnostics.get("logs"), list) else []
        if logs:
            st.code("\n".join(str(item) for item in logs[-20:]), language="text")


def status_tone(value: str) -> str:
    normalized = str(value or "").upper()
    if normalized == "ACTIVE":
        return "buy"
    if normalized == "WATCH":
        return "watch"
    if normalized == "BLOCKED":
        return "avoid"
    return signal_tone(normalized)


def render_strategy_checklist(rows: list[dict[str, str]]) -> None:
    if not rows:
        return
    st.markdown("**Checklist de estrategias**")
    for start in range(0, len(rows), 3):
        cols = st.columns(3)
        for col, row in zip(cols, rows[start : start + 3]):
            detail = f"{row.get('trigger', '-')}. {row.get('action', '-')}"
            with col:
                render_kpi_card(
                    row.get("family", "-"),
                    row.get("status", "-"),
                    tone=status_tone(row.get("status", "")),
                    detail=detail,
                )
    with st.expander("Por que Roxy clasifica cada estrategia asi"):
        st.dataframe(pd.DataFrame(rows), use_container_width=True)


def render_chart_readout(
    setup: dict,
    confluence: dict | None,
    brief: dict | None,
    chart_df: pd.DataFrame,
    *,
    market: str | None = None,
    timeframe: str | None = None,
    source_meta: dict[str, Any] | None = None,
) -> None:
    confluence = confluence or {}
    brief = brief or {}
    market = market or str(brief.get("market") or confluence.get("market") or "stock")
    timeframe = timeframe or str(brief.get("timeframe") or confluence.get("tf") or "1h")
    latest = chart_df.iloc[-1].to_dict() if not chart_df.empty else {}
    close = safe_float(latest.get("close") or setup.get("close") or setup.get("entry"))
    sma20 = safe_float(latest.get("sma20") or setup.get("sma20"))
    sma40 = safe_float(latest.get("sma40") or setup.get("sma40"))
    sma100 = safe_float(latest.get("sma100") or setup.get("sma100"))
    sma200 = safe_float(latest.get("sma200") or setup.get("sma200"))
    rel_vol = safe_float(
        latest.get("relative_volume") or confluence.get("relative_volume_15m") or setup.get("relative_volume")
    )
    rsi14 = safe_float(latest.get("rsi14"))
    macd_hist = safe_float(latest.get("macd_hist"))
    risk = safe_float(brief.get("risk_pct")) or setup_risk_pct(setup)
    target = safe_float(brief.get("recommended_target_pct") or confluence.get("recommended_target_pct"))

    has_stack = close is not None and all(value is not None for value in [sma20, sma40, sma100, sma200])
    bullish_stack = bool(has_stack and sma20 > sma40 > sma100 > sma200 and close > sma20)
    bearish_stack = bool(has_stack and sma20 < sma40 < sma100 < sma200 and close < sma200)
    if bullish_stack:
        trend = "Bull channel"
        trend_tone = "buy"
    elif bearish_stack:
        trend = "Bear channel"
        trend_tone = "avoid"
    elif has_stack and close and sma200 and close > sma200:
        trend = "Above SMA200"
        trend_tone = "watch"
    else:
        trend = "No clean trend"
        trend_tone = "neutral"

    volume_state = (
        "Strong"
        if rel_vol is not None and rel_vol >= 1.1
        else "Weak" if rel_vol is not None and rel_vol < 0.8 else "Normal"
    )
    volume_tone = "buy" if volume_state == "Strong" else "avoid" if volume_state == "Weak" else "neutral"
    risk_tone = (
        "buy" if risk is not None and risk <= 0.025 else "avoid" if risk is not None and risk > 0.035 else "watch"
    )
    target_tone = "buy" if target is not None and target >= 0.02 else "watch"
    if rsi14 is None:
        oscillator_state = "Sin datos"
        oscillator_tone = "neutral"
    elif rsi14 >= 75:
        oscillator_state = "Extendido"
        oscillator_tone = "avoid"
    elif rsi14 >= 45 and (macd_hist is None or macd_hist >= 0):
        oscillator_state = "Con espacio"
        oscillator_tone = "buy"
    elif macd_hist is not None and macd_hist < 0:
        oscillator_state = "Debil"
        oscillator_tone = "watch"
    else:
        oscillator_state = "Neutral"
        oscillator_tone = "neutral"

    live_data = chart_live_data_status(
        chart_df,
        market=market,
        timeframe=timeframe,
        provider_summary=live_provider_quality_summary(live_provider_rows()),
        source_meta=source_meta,
    )
    chart_confidence = chart_operational_confidence(live_data)
    data_contract = chart_data_contract(live_data)
    pulse_symbol = text_display(brief.get("symbol") or confluence.get("symbol") or setup.get("symbol"))

    st.markdown("**Lectura de grafica**")
    st.markdown(render_chart_data_contract(data_contract), unsafe_allow_html=True)
    st.markdown(
        render_chart_realtime_pulse(
            live_data,
            symbol=pulse_symbol,
            timeframe=timeframe,
            interval_seconds=st.session_state.get("roxy_realtime_interval", DEFAULT_REALTIME_REFRESH_SECONDS),
        ),
        unsafe_allow_html=True,
    )
    cols = st.columns([1, 1, 1, 1, 1, 1, 1, 1])
    with cols[0]:
        trend = {
            "Bull channel": "Canal alcista",
            "Bear channel": "Canal bajista",
            "Above SMA200": "Sobre SMA200",
            "No clean trend": "Sin tendencia limpia",
        }.get(trend, trend)
        render_kpi_card("Estructura MA", trend, tone=trend_tone, detail="20 / 40 / 100 / 200")
    with cols[1]:
        render_kpi_card("Ultimo precio", num_display(close))
    with cols[2]:
        volume_state = {"Strong": "Fuerte", "Weak": "Debil", "Normal": "Normal"}.get(volume_state, volume_state)
        render_kpi_card(
            "Volumen",
            volume_state,
            tone=volume_tone,
            detail=f"{num_display(rel_vol)}x" if rel_vol is not None else "Sin datos",
        )
    with cols[3]:
        render_kpi_card("Riesgo a stop", pct_display(risk), tone=risk_tone)
    with cols[4]:
        render_kpi_card("Objetivo", pct_display(target), tone=target_tone)
    with cols[5]:
        macd_label = "+" if macd_hist is not None and macd_hist >= 0 else "-" if macd_hist is not None else "-"
        render_kpi_card(
            "Oscilador",
            oscillator_state,
            tone=oscillator_tone,
            detail=f"RSI {num_display(rsi14, 0)} | MACD {macd_label}",
        )
    with cols[6]:
        latest = text_display(live_data.get("latest"))
        age = safe_float(live_data.get("age_minutes"))
        age_text = f"{num_display(age, 0)}m" if age is not None else "-"
        render_kpi_card(
            "Data grafica",
            live_data["status"],
            tone=live_data["tone"],
            detail=f"{text_display(live_data.get('source_label'))} | {age_text} | {latest}",
        )
    with cols[7]:
        render_kpi_card(
            "Confianza grafica",
            chart_confidence["label"],
            tone=chart_confidence["tone"],
            detail=chart_confidence["detail"],
        )
    fallback_reason = text_display(live_data.get("fallback_reason"))
    fallback_detail = text_display(live_data.get("fallback_detail"))
    fallback_action = text_display(live_data.get("fallback_action"))
    fallback_text = ""
    if fallback_reason not in {"", "-"}:
        fallback_text = f" Motivo fallback: {fallback_reason}."
        if fallback_detail not in {"", "-"}:
            fallback_text += f" {fallback_detail}"
        if fallback_action not in {"", "-"}:
            fallback_text += f" {fallback_action}"
    provider_text = ""
    if text_display(live_data.get("provider_mode")) == "PROVIDER_FALLBACK":
        provider_text = f" Proveedor: {text_display(live_data.get('provider_status'))}."
    st.caption(
        f"Fuente efectiva: {text_display(live_data.get('source_label'))}. "
        f"{text_display(live_data.get('action'))}{fallback_text}{provider_text}"
    )


def explicit_chart_target_rows(
    setup: dict,
    confluence: dict | None,
    brief: dict | None = None,
) -> list[dict[str, Any]]:
    """Collect only provider/engine targets already present in the shared context."""

    confluence = confluence or {}
    brief = brief or {}
    rows: list[dict[str, Any]] = []
    seen_prices: set[float] = set()
    colors = ("#60a5fa", "#a78bfa", "#f472b6", "#22d3ee")

    def add(value: Any, label: str, source: str) -> None:
        price = safe_float(value)
        if price is None or price <= 0 or not math.isfinite(price):
            return
        key = round(price, 8)
        if key in seen_prices:
            return
        seen_prices.add(key)
        rows.append(
            {
                "price": price,
                "label": label,
                "source": source,
                "color": colors[len(rows) % len(colors)],
            }
        )

    ladder = brief.get("target_ladder")
    for item in ladder if isinstance(ladder, list) else []:
        if not isinstance(item, dict):
            continue
        label = text_display(item.get("target") or item.get("label") or "Objetivo")
        add(item.get("target_price") or item.get("price"), f"Objetivo {label}", "brief.target_ladder")

    field_labels = (
        ("target_1", "Objetivo 1"),
        ("target_2", "Objetivo 2%"),
        ("target_5", "Objetivo 5%"),
        ("target_10", "Objetivo 10%"),
        ("target_price", "Objetivo"),
        ("recommended_target_price", "Objetivo recomendado"),
        ("tp2", "Objetivo técnico"),
    )
    for source_name, source in (("brief", brief), ("confluence", confluence), ("setup", setup)):
        for key, label in field_labels:
            add(source.get(key), label, f"{source_name}.{key}")
    return rows


def chart_trade_direction(
    setup: dict,
    confluence: dict | None,
    brief: dict | None,
    *,
    entry: float | None,
    stop: float | None,
    targets: list[dict[str, Any]],
) -> str:
    """Resolve LONG/SHORT from explicit context, then verified level geometry."""

    confluence = confluence or {}
    brief = brief or {}
    short_tokens = ("SHORT", "SELL", "PUT", "BAJISTA", "DOWN", "BEAR")
    long_tokens = ("LONG", "BUY", "CALL", "ALCISTA", "UP", "BULL")
    for source in (brief, confluence, setup):
        direction_text = " ".join(
            text_display(source.get(key)).upper()
            for key in ("direction", "expected_direction", "side", "action", "decision", "signal")
        )
        if any(token in direction_text for token in short_tokens):
            return "SHORT"
        if any(token in direction_text for token in long_tokens):
            return "LONG"
    if entry is not None and stop is not None and stop != entry:
        return "SHORT" if stop > entry else "LONG"
    if entry is not None:
        target_prices = [
            price for price in (safe_float(item.get("price")) for item in targets) if price is not None
        ]
        if target_prices and all(price < entry for price in target_prices):
            return "SHORT"
    return "LONG"


def build_chart_level_plan(
    chart_df: pd.DataFrame,
    setup: dict,
    confluence: dict | None,
    brief: dict | None = None,
) -> list[dict[str, Any]]:
    confluence = confluence or {}
    brief = brief or {}
    latest = chart_df.iloc[-1].to_dict() if not chart_df.empty else {}
    entry = safe_float(brief.get("entry")) or safe_float(confluence.get("entry")) or safe_float(setup.get("entry"))
    stop = safe_float(brief.get("stop")) or safe_float(confluence.get("stop")) or safe_float(setup.get("stop"))
    close = safe_float(latest.get("close") or setup.get("close"))
    rows: list[dict[str, Any]] = []

    def add(level: str, price: Any, role: str, tone: str = "neutral") -> None:
        number = safe_float(price)
        if number is None:
            return
        rows.append({"nivel": level, "precio": number, "uso": role, "tone": tone})

    add("Precio", close, "Referencia actual", "neutral")
    add("Entrada", entry, "Zona valida solo si 15m/1h confirman", "buy")
    add("Stop", stop, "Invalida el trade si lo pierde", "avoid")

    for target in explicit_chart_target_rows(setup, confluence, brief):
        add(
            text_display(target.get("label")),
            target.get("price"),
            f"Nivel explícito · {text_display(target.get('source'))}",
            "buy",
        )

    add("Soporte", latest.get("range_low_60"), "Zona donde debe aparecer rebote", "watch")
    add("Resistencia", latest.get("range_high_60"), "Ruptura valida con volumen", "watch")
    add("SMA20", latest.get("sma20") or setup.get("sma20"), "Media rapida: gatillo/pullback", "neutral")
    add("SMA40", latest.get("sma40") or setup.get("sma40"), "Confirmacion de tendencia corta", "neutral")
    add("SMA100", latest.get("sma100") or setup.get("sma100"), "Soporte medio", "neutral")
    add("SMA200", latest.get("sma200") or setup.get("sma200"), "Filtro principal de tendencia", "neutral")
    return rows


def render_chart_level_plan(
    chart_df: pd.DataFrame, setup: dict, confluence: dict | None, brief: dict | None = None
) -> None:
    rows = build_chart_level_plan(chart_df, setup, confluence, brief)
    if not rows:
        return
    st.markdown("**Plan visual de niveles**")
    primary = [row for row in rows if row["nivel"] in {"Entrada", "Stop", "Objetivo 2%", "Objetivo 5%", "Objetivo 10%"}]
    cols = st.columns(len(primary) or 1)
    for col, row in zip(cols, primary):
        with col:
            render_kpi_card(row["nivel"], num_display(row["precio"]), tone=row["tone"], detail=row["uso"])
    with st.expander("Niveles completos de la grafica"):
        display = pd.DataFrame(rows).drop(columns=["tone"], errors="ignore")
        display["precio"] = display["precio"].map(lambda value: num_display(value))
        st.dataframe(display, width="stretch", hide_index=True)


def chart_zone_band(price: Any, chart_window: pd.DataFrame) -> float:
    reference = safe_float(price)
    if reference is None or reference <= 0:
        reference = (
            safe_float(chart_window["close"].iloc[-1])
            if not chart_window.empty and "close" in chart_window.columns
            else 1.0
        )
    atr_pct = None
    if "atr_pct" in chart_window.columns and chart_window["atr_pct"].notna().any():
        atr_pct = safe_float(chart_window["atr_pct"].dropna().iloc[-1])
    pct = min(0.012, max(0.0025, (atr_pct or 0.006) * 0.35))
    return max(reference * pct, 0.01)


def chart_reference_price(chart_window: pd.DataFrame) -> float | None:
    if chart_window.empty or "close" not in chart_window.columns:
        return None
    close_series = pd.to_numeric(chart_window["close"], errors="coerce").dropna()
    if close_series.empty:
        return None
    reference = safe_float(close_series.iloc[-1])
    return reference if reference and reference > 0 else None


def chart_level_is_near(value: Any, reference: float | None, *, lower: float = 0.60, upper: float = 1.55) -> bool:
    number = safe_float(value)
    if number is None or number <= 0:
        return False
    if reference is None or reference <= 0:
        return True
    return reference * lower <= number <= reference * upper


def prepare_chart_window(chart_df: pd.DataFrame, *, limit: int = 260) -> pd.DataFrame:
    if chart_df.empty:
        return pd.DataFrame()
    window = chart_df.copy()
    if "ts" not in window.columns or "close" not in window.columns:
        return pd.DataFrame()
    with warnings.catch_warnings():
        warnings.simplefilter("ignore", UserWarning)
        window["ts"] = pd.to_datetime(window["ts"], errors="coerce")
    numeric_columns = [
        "open",
        "high",
        "low",
        "close",
        "volume",
        "ema9",
        "sma20",
        "sma40",
        "sma100",
        "sma200",
        "bb_mid",
        "bb_upper",
        "bb_lower",
        "rsi14",
        "macd",
        "macd_signal",
        "macd_hist",
        "range_high_60",
        "range_low_60",
        "volume_sma20",
        "relative_volume",
        "atr_pct",
    ]
    for column in numeric_columns:
        if column in window.columns:
            window[column] = pd.to_numeric(window[column], errors="coerce")
            window[column] = window[column].replace([float("inf"), float("-inf")], pd.NA)
    window = window.dropna(subset=["ts", "close"]).sort_values("ts").tail(limit).reset_index(drop=True)
    if window.empty:
        return pd.DataFrame()
    for column in ["open", "high", "low"]:
        if column not in window.columns:
            window[column] = window["close"]
    window["open"] = window["open"].fillna(window["close"])
    window["high"] = window["high"].fillna(window[["open", "close"]].max(axis=1))
    window["low"] = window["low"].fillna(window[["open", "close"]].min(axis=1))
    window["high"] = window[["high", "open", "close"]].max(axis=1)
    window["low"] = window[["low", "open", "close"]].min(axis=1)
    return window


def chart_time_scale(chart_window: pd.DataFrame) -> alt.Scale | None:
    if chart_window.empty or "ts" not in chart_window.columns:
        return None
    ts_values = pd.to_datetime(chart_window["ts"], errors="coerce").dropna()
    if ts_values.empty:
        return None
    start = ts_values.min()
    end = ts_values.max()
    if pd.isna(start) or pd.isna(end):
        return None
    if start == end:
        end = start + pd.to_timedelta(1, unit="m")
    return alt.Scale(domain=[start, end])


def build_chart_level_values(
    chart_window: pd.DataFrame,
    setup: dict,
    confluence: dict | None,
    brief: dict | None = None,
    targets: list[dict[str, Any]] | None = None,
) -> list[float]:
    confluence = confluence or {}
    brief = brief or {}
    reference = chart_reference_price(chart_window)
    values: list[float] = []

    def add(value: Any, *, lower: float = 0.60, upper: float = 1.55) -> None:
        number = safe_float(value)
        if (
            number is not None
            and math.isfinite(number)
            and number > 0
            and chart_level_is_near(number, reference, lower=lower, upper=upper)
        ):
            values.append(number)

    for column in ["open", "close", "ema9", "sma20", "sma40", "sma100", "sma200", "bb_upper", "bb_lower"]:
        if column in chart_window.columns:
            for value in chart_window[column].dropna().tail(90).tolist():
                add(value)
    for column in ["high", "low"]:
        if column in chart_window.columns:
            series = pd.to_numeric(chart_window[column], errors="coerce").dropna().tail(90)
            if not series.empty:
                add(float(series.quantile(0.05)), lower=0.70, upper=1.35)
                add(float(series.quantile(0.95)), lower=0.70, upper=1.35)
    for column in ["range_high_60", "range_low_60"]:
        if column in chart_window.columns:
            for value in chart_window[column].dropna().tail(3).tolist():
                add(value, lower=0.75, upper=1.25)
    for source in [setup, confluence, brief]:
        for key in ["entry", "stop", "tp2", "recommended_target_price", "target_2", "target_5", "target_10"]:
            add(source.get(key), lower=0.55, upper=1.65)
    for item in targets or []:
        add(item.get("price"), lower=0.55, upper=1.65)
    for item in brief.get("target_ladder", []) if isinstance(brief.get("target_ladder"), list) else []:
        add(item.get("target_price"), lower=0.55, upper=1.65)
    if reference:
        values.append(reference)
    return values


def chart_price_domain(
    chart_window: pd.DataFrame,
    setup: dict,
    confluence: dict | None,
    brief: dict | None = None,
    targets: list[dict[str, Any]] | None = None,
) -> list[float] | None:
    values = build_chart_level_values(chart_window, setup, confluence, brief, targets)
    if not values:
        return None
    series = pd.Series(values, dtype="float64").dropna()
    series = series[(series > 0) & series.map(math.isfinite)]
    if series.empty:
        return None
    low = float(series.quantile(0.01))
    high = float(series.quantile(0.99))
    if high <= low:
        base = high if high > 0 else 1.0
        return [max(0.0, base * 0.97), base * 1.03]
    padding = max((high - low) * 0.12, high * 0.008)
    return [max(0.0, low - padding), high + padding]


def build_visual_zone_rows(
    chart_window: pd.DataFrame,
    setup: dict,
    confluence: dict | None,
    brief: dict | None = None,
) -> list[dict[str, Any]]:
    if chart_window.empty:
        return []
    confluence = confluence or {}
    brief = brief or {}
    first_ts = chart_window["ts"].iloc[0]
    last_ts = chart_window["ts"].iloc[-1]
    latest = chart_window.iloc[-1].to_dict()
    latest_close = chart_reference_price(chart_window)
    entry = safe_float(brief.get("entry")) or safe_float(confluence.get("entry")) or safe_float(setup.get("entry"))
    stop = safe_float(brief.get("stop")) or safe_float(confluence.get("stop")) or safe_float(setup.get("stop"))
    resistance = safe_float(latest.get("range_high_60"))
    support = safe_float(latest.get("range_low_60"))
    zones: list[dict[str, Any]] = []

    def add(label: str, center: Any, tone: str, role: str, *, lower: float = 0.60, upper: float = 1.55) -> None:
        price = safe_float(center)
        if price is None or not chart_level_is_near(price, latest_close, lower=lower, upper=upper):
            return
        band = chart_zone_band(price, chart_window)
        zones.append(
            {
                "ts": first_ts,
                "ts2": last_ts,
                "low": price - band,
                "high": price + band,
                "center": price,
                "zone": label,
                "tone": tone,
                "role": role,
            }
        )

    add("Zona entrada", entry, "buy", "Comprar solo si 15m/1h y volumen confirman.", lower=0.55, upper=1.65)
    add("Zona stop", stop, "avoid", "Si pierde esta zona, el setup queda invalido.", lower=0.55, upper=1.65)
    add("Soporte", support, "watch", "Zona donde Roxy busca rebote o defensa.", lower=0.75, upper=1.25)
    add("Resistencia", resistance, "watch", "Ruptura valida solo con volumen.", lower=0.75, upper=1.25)
    return zones


