def disk_dashboard_status(path: str | Path, *, warn_free_gb: float = 20.0, fail_free_gb: float = 5.0) -> dict[str, Any]:
    disk_path = Path(path)
    if not disk_path.exists():
        return {"label": "No montado", "tone": "avoid", "detail": str(disk_path), "free_gb": None}
    try:
        usage = shutil.disk_usage(disk_path)
    except Exception as exc:
        return {"label": "Sin lectura", "tone": "watch", "detail": str(exc), "free_gb": None}
    free_gb = usage.free / (1024**3)
    total_gb = usage.total / (1024**3)
    used_pct = (usage.used / usage.total * 100.0) if usage.total else 0.0
    if free_gb <= fail_free_gb:
        label = "Critico"
        tone = "avoid"
    elif free_gb <= warn_free_gb:
        label = "Bajo"
        tone = "watch"
    else:
        label = "OK"
        tone = "buy"
    return {
        "label": label,
        "tone": tone,
        "detail": f"{free_gb:.1f} GB libres | {used_pct:.0f}% usado",
        "free_gb": free_gb,
        "total_gb": total_gb,
        "used_pct": used_pct,
    }


def alert_gate_summary_dashboard_status(summary: dict[str, Any] | None) -> dict[str, Any]:
    summary = summary or {}
    total = int(summary.get("total_opportunities") or 0)
    ready = int(summary.get("notifications_ready") or 0)
    blocked_realtime = int(summary.get("blocked_realtime_count") or 0)
    top_gate = text_display(summary.get("top_gate_label") or summary.get("top_gate"))
    avg_readiness = safe_float(summary.get("avg_readiness"))
    if not total:
        return {"label": "Sin setups", "tone": "neutral", "detail": "No hay oportunidades en brief"}
    if blocked_realtime:
        tone = "avoid"
        label = "Datos bloquean"
    elif ready:
        tone = "buy"
        label = f"{ready} lista(s)"
    else:
        tone = "watch"
        label = "Esperando"
    detail = f"{total} setups | {top_gate}"
    if avg_readiness is not None:
        detail += f" | readiness {avg_readiness:.0f}%"
    return {"label": label, "tone": tone, "detail": detail}


def merged_alert_quality_summary(report: dict[str, Any] | None) -> dict[str, Any]:
    report = report or {}
    summary = dict(report.get("summary") if isinstance(report.get("summary"), dict) else {})
    for key in [
        "state",
        "diagnostic_label",
        "diagnostic_severity",
        "diagnostic_detail",
        "blocker_category",
        "recommended_action",
        "silence_mode",
        "silence_reason",
        "silence_severity",
        "false_negative_risk",
        "false_positive_guard",
        "missed_opportunity_watch",
        "missed_opportunity_risk",
        "missed_opportunity_reason",
        "missed_opportunity_action",
        "missed_trigger_plan",
        "confirmation_wait_plan",
        "blocked_markets",
        "market_counts",
        "actionable_market_counts",
        "allowed_markets",
        "missing_allowed_markets",
        "operable_market_count",
        "blocked_market_count",
        "market_coverage_label",
        "market_coverage_action",
        "chart_contract_total_count",
        "chart_contract_checked_count",
        "chart_contract_operable_count",
        "chart_contract_blocked_count",
        "chart_contract_missing_count",
        "chart_contract_market_counts",
        "chart_contract_market_operable_counts",
        "chart_contract_market_blocked_counts",
        "chart_contract_gate_counts",
        "chart_contract_operable_symbols",
        "chart_contract_blocked_symbols",
        "chart_contract_label",
        "chart_contract_action",
        "latest_notifications_ready",
        "latest_total_opportunities",
        "latest_top_gate",
        "latest_top_blocker",
        "latest_top_blocker_streak",
        "waiting_streak",
        "persistent_blocker",
        "persistent_blocker_minutes",
        "dominant_blocker",
        "recurrent_blocker",
        "recurrent_blocker_count",
        "avg_readiness",
        "readiness_delta",
        "ready_rate",
        "rotation_candidates",
    ]:
        value = report.get(key)
        if value not in (None, "", []):
            summary[key] = value
    if summary.get("latest_notifications_ready") in (None, "") and report.get("notifications_ready") is not None:
        summary["latest_notifications_ready"] = report.get("notifications_ready")
    if summary.get("latest_total_opportunities") in (None, "") and report.get("total_opportunities") is not None:
        summary["latest_total_opportunities"] = report.get("total_opportunities")
    if not isinstance(summary.get("missed_trigger_plan"), dict):
        plan_active = report.get("missed_trigger_plan_active")
        if isinstance(plan_active, bool):
            summary["missed_trigger_plan"] = {
                "active": plan_active,
                "primary_symbol": text_display(report.get("missed_trigger_plan_symbol") or ""),
                "primary_readiness": report.get("missed_trigger_plan_readiness"),
                "risk": text_display(report.get("missed_trigger_plan_risk") or ""),
                "review_due": bool(report.get("missed_trigger_plan_review_due", False)),
                "review_status": text_display(report.get("missed_trigger_plan_review_status") or ""),
                "review_pressure": text_display(report.get("missed_trigger_plan_review_pressure") or ""),
                "review_overdue_cycles": report.get("missed_trigger_plan_review_overdue_cycles"),
                "review_cycles_remaining": report.get("missed_trigger_plan_review_cycles_remaining"),
                "review_progress": report.get("missed_trigger_plan_review_progress"),
                "review_cycle_minutes": report.get("missed_trigger_plan_review_cycle_minutes"),
                "review_eta_minutes": report.get("missed_trigger_plan_review_eta_minutes"),
                "review_overdue_minutes": report.get("missed_trigger_plan_review_overdue_minutes"),
                "stale_candidate": bool(report.get("missed_trigger_plan_stale_candidate", False)),
                "auto_review_decision": text_display(report.get("missed_trigger_plan_auto_review_decision") or ""),
                "decision_action": text_display(report.get("missed_trigger_plan_decision_action") or ""),
                "decision_reason": text_display(report.get("missed_trigger_plan_decision_reason") or ""),
                "readiness_delta": report.get("missed_trigger_plan_readiness_delta"),
                "severity": text_display(report.get("missed_trigger_plan_severity") or ""),
                "max_watch_cycles": report.get("missed_trigger_plan_max_watch_cycles"),
                "review_cadence": text_display(report.get("missed_trigger_plan_review_cadence") or ""),
                "review_action": text_display(report.get("missed_trigger_plan_review_action") or ""),
                "exit_condition": text_display(report.get("missed_trigger_plan_exit") or ""),
            }
    if isinstance(summary.get("missed_trigger_plan"), dict):
        plan = dict(summary["missed_trigger_plan"])
        for plan_key, report_key in [
            ("review_cycle_minutes", "missed_trigger_plan_review_cycle_minutes"),
            ("review_eta_minutes", "missed_trigger_plan_review_eta_minutes"),
            ("review_overdue_minutes", "missed_trigger_plan_review_overdue_minutes"),
            ("review_pressure", "missed_trigger_plan_review_pressure"),
            ("auto_review_decision", "missed_trigger_plan_auto_review_decision"),
            ("decision_action", "missed_trigger_plan_decision_action"),
            ("decision_reason", "missed_trigger_plan_decision_reason"),
            ("readiness_delta", "missed_trigger_plan_readiness_delta"),
        ]:
            value = report.get(report_key)
            if plan.get(plan_key) in (None, "") and value is not None:
                plan[plan_key] = value
        if "stale_candidate" not in plan and report.get("missed_trigger_plan_stale_candidate") is not None:
            plan["stale_candidate"] = bool(report.get("missed_trigger_plan_stale_candidate"))
        summary["missed_trigger_plan"] = plan
    if not isinstance(summary.get("confirmation_wait_plan"), dict):
        plan_active = report.get("confirmation_wait_plan_active")
        if isinstance(plan_active, bool):
            summary["confirmation_wait_plan"] = {
                "active": plan_active,
                "primary_symbol": text_display(report.get("confirmation_wait_plan_symbol") or ""),
                "primary_readiness": report.get("confirmation_wait_plan_readiness"),
                "risk": text_display(report.get("confirmation_wait_plan_risk") or ""),
                "review_due": bool(report.get("confirmation_wait_plan_review_due", False)),
                "review_status": text_display(report.get("confirmation_wait_plan_review_status") or ""),
                "review_overdue_cycles": report.get("confirmation_wait_plan_review_overdue_cycles"),
                "review_cycles_remaining": report.get("confirmation_wait_plan_review_cycles_remaining"),
                "review_progress": report.get("confirmation_wait_plan_review_progress"),
                "review_cycle_minutes": report.get("confirmation_wait_plan_review_cycle_minutes"),
                "review_eta_minutes": report.get("confirmation_wait_plan_review_eta_minutes"),
                "review_overdue_minutes": report.get("confirmation_wait_plan_review_overdue_minutes"),
                "severity": text_display(report.get("confirmation_wait_plan_severity") or ""),
                "max_watch_cycles": report.get("confirmation_wait_plan_max_watch_cycles"),
                "review_action": text_display(report.get("confirmation_wait_plan_review_action") or ""),
                "exit_condition": text_display(report.get("confirmation_wait_plan_exit") or ""),
            }
    return summary


def alert_focus_rotation_panel_rows(report: dict[str, Any] | None, *, limit: int = 3) -> dict[str, Any]:
    report = report or {}
    summary = merged_alert_quality_summary(report)
    entry = report.get("latest_entry") if isinstance(report.get("latest_entry"), dict) else {}
    if not entry:
        entry = report.get("entry") if isinstance(report.get("entry"), dict) else {}
    candidates = alert_quality_rotation_candidates(summary, entry, limit=limit)
    recommended_action = text_display(summary.get("recommended_action") or "")
    blocker_category = text_display(summary.get("blocker_category") or "")
    if blocker_category == "MARKET_CLOSED_WAIT" and recommended_action:
        return {
            "visible": True,
            "mode": "SESSION_WAIT",
            "recommended_action": recommended_action,
            "candidates": [],
            "state": text_display(summary.get("state") or entry.get("state") or "-"),
            "waiting_streak": int(summary.get("waiting_streak") or 0),
            "blocker_category": blocker_category,
        }
    if not candidates:
        return {
            "visible": False,
            "recommended_action": recommended_action,
            "candidates": [],
            "blocker_category": blocker_category,
        }
    return {
        "visible": True,
        "mode": "ROTATION",
        "recommended_action": recommended_action,
        "candidates": candidates,
        "state": text_display(summary.get("state") or entry.get("state") or "-"),
        "waiting_streak": int(summary.get("waiting_streak") or 0),
        "blocker_category": blocker_category,
    }




def alert_quality_report_dashboard_status(report: dict[str, Any] | None) -> dict[str, Any]:
    report = report or {}
    summary = merged_alert_quality_summary(report)
    entry = report.get("latest_entry") if isinstance(report.get("latest_entry"), dict) else {}
    if not entry:
        entry = report.get("entry") if isinstance(report.get("entry"), dict) else {}
    if not summary and not entry:
        return {"label": "Sin historial", "tone": "watch", "detail": "Aun no hay reporte de calidad"}
    state = text_display(summary.get("state") or entry.get("state")).upper()
    ready = int(summary.get("latest_notifications_ready") or entry.get("notifications_ready") or 0)
    total = int(summary.get("latest_total_opportunities") or entry.get("total_opportunities") or 0)
    waiting_streak = int(summary.get("waiting_streak") or 0)
    blocker_streak = int(summary.get("latest_top_blocker_streak") or 0)
    persistent_blocker_minutes = safe_float(summary.get("persistent_blocker_minutes"))
    diagnostic_severity = text_display(summary.get("diagnostic_severity") or "OK").upper()
    diagnostic_label = text_display(summary.get("diagnostic_label") or "")
    diagnostic_detail = text_display(summary.get("diagnostic_detail") or "")
    blocker_category = text_display(summary.get("blocker_category") or "")
    recommended_action = text_display(summary.get("recommended_action") or "")
    silence_mode = text_display(summary.get("silence_mode") or "")
    silence_severity = text_display(summary.get("silence_severity") or "")
    silence_reason = text_display(summary.get("silence_reason") or "")
    false_negative_risk = text_display(summary.get("false_negative_risk") or "")
    history_count = safe_float(first_present(summary.get("history_count"), report.get("history_count")))
    history_size_bytes = safe_float(first_present(summary.get("history_size_bytes"), report.get("history_size_bytes")))
    history_max_bytes = safe_float(first_present(summary.get("history_max_bytes"), report.get("history_max_bytes")))
    history_min_entries = safe_float(
        first_present(summary.get("history_min_entries"), report.get("history_min_entries"))
    )
    history_budget_status = (
        "WARN"
        if (
            history_size_bytes is not None
            and history_max_bytes is not None
            and history_max_bytes > 0
            and history_size_bytes > history_max_bytes
        )
        else "OK"
    )
    history_size_budget_ratio = (
        (history_size_bytes / history_max_bytes)
        if history_size_bytes is not None and history_max_bytes is not None and history_max_bytes > 0
        else None
    )
    history_size_budget_margin = (
        (history_max_bytes - history_size_bytes)
        if history_size_bytes is not None and history_max_bytes is not None and history_max_bytes > 0
        else None
    )
    missed_opportunity_watch = bool(summary.get("missed_opportunity_watch", False))
    missed_opportunity_risk = text_display(summary.get("missed_opportunity_risk") or "")
    missed_opportunity_reason = text_display(summary.get("missed_opportunity_reason") or "")
    missed_opportunity_action = text_display(summary.get("missed_opportunity_action") or "")
    missed_trigger_plan = (
        summary.get("missed_trigger_plan") if isinstance(summary.get("missed_trigger_plan"), dict) else {}
    )
    confirmation_wait_plan = (
        summary.get("confirmation_wait_plan") if isinstance(summary.get("confirmation_wait_plan"), dict) else {}
    )
    market_coverage_label = text_display(
        summary.get("market_coverage_label") or entry.get("market_coverage_label") or ""
    )
    market_coverage_action = text_display(
        summary.get("market_coverage_action") or entry.get("market_coverage_action") or ""
    )
    missing_allowed_markets = (
        summary.get("missing_allowed_markets")
        if isinstance(summary.get("missing_allowed_markets"), list)
        else entry.get("missing_allowed_markets") if isinstance(entry.get("missing_allowed_markets"), list) else []
    )
    market_counts = (
        summary.get("market_counts")
        if isinstance(summary.get("market_counts"), dict)
        else entry.get("market_counts") if isinstance(entry.get("market_counts"), dict) else {}
    )
    operable_market_count = int(summary.get("operable_market_count") or entry.get("operable_market_count") or 0)
    chart_contract_label = text_display(summary.get("chart_contract_label") or entry.get("chart_contract_label") or "")
    chart_contract_action = text_display(
        summary.get("chart_contract_action") or entry.get("chart_contract_action") or ""
    )
    chart_operable_count = int(
        summary.get("chart_contract_operable_count") or entry.get("chart_contract_operable_count") or 0
    )
    chart_blocked_count = int(
        summary.get("chart_contract_blocked_count") or entry.get("chart_contract_blocked_count") or 0
    )
    chart_missing_count = int(
        summary.get("chart_contract_missing_count") or entry.get("chart_contract_missing_count") or 0
    )
    chart_blocked_symbols = (
        summary.get("chart_contract_blocked_symbols")
        if isinstance(summary.get("chart_contract_blocked_symbols"), list)
        else (
            entry.get("chart_contract_blocked_symbols")
            if isinstance(entry.get("chart_contract_blocked_symbols"), list)
            else []
        )
    )
    rotation_candidates = alert_quality_rotation_candidates(summary, entry)
    avg_readiness = safe_float(summary.get("avg_readiness"))
    readiness_delta = safe_float(summary.get("readiness_delta"))
    dominant_blocker = summary.get("dominant_blocker") if isinstance(summary.get("dominant_blocker"), dict) else {}
    if not dominant_blocker and summary.get("recurrent_blocker"):
        dominant_blocker = {
            "name": text_display(summary.get("recurrent_blocker")),
            "count": int(safe_float(summary.get("recurrent_blocker_count")) or 0),
        }
    blocker = text_display(summary.get("latest_top_blocker") or entry.get("top_blocker"))
    top_symbol = text_display(entry.get("top_symbol"))
    top_next_action = text_display(entry.get("top_next_action"))
    if state == "READY" or ready:
        label = f"{ready} lista(s)"
        tone = "buy"
    elif state == "BLOCKED_REALTIME" and silence_mode == "MARKET_PARTIAL_BLOCK":
        if operable_market_count > 0 and market_coverage_label and market_coverage_label != "-":
            label = market_coverage_label
            tone = "watch"
        else:
            label = "Bloqueo parcial"
