def alert_silence_kpi_status(report: dict[str, Any] | None) -> dict[str, str]:
    status = alert_quality_report_dashboard_status(report)
    mode = text_display(status.get("silence_mode") or "")
    reason = text_display(status.get("silence_reason") or "")
    risk = text_display(status.get("false_negative_risk") or "")
    if not report:
        return {"label": "Sin historial", "tone": "watch", "detail": "Esperando primer reporte"}
    labels = {
        "ACTIONABLE_READY": ("Listas", "buy"),
        "HEALTHY_WAIT": ("Espera sana", "watch"),
        "MISSED_TRIGGER_WATCH": ("Vigilar gatillo", "watch"),
        "NO_SETUP_SILENCE": ("Sin setups", "neutral"),
        "SYSTEM_BLOCKED": ("Datos bloquean", "avoid"),
        "MARKET_PARTIAL_BLOCK": ("Bloqueo parcial", "avoid"),
        "SUSPICIOUS_SILENCE": ("Sospechoso", "avoid"),
        "UNCLASSIFIED_SILENCE": ("Revisar", "watch"),
    }
    label, tone = labels.get(mode, (status.get("label", "Esperando"), status.get("tone", "watch")))
    detail_parts = []
    if mode:
        detail_parts.append(mode)
    if risk and risk != "-":
        detail_parts.append(f"FN {risk}")
    if reason and reason != "-":
        detail_parts.append(reason)
    if mode == "MISSED_TRIGGER_WATCH":
        review_status = text_display(status.get("missed_trigger_review_status") or "")
        if review_status and review_status != "-":
            review_detail = f"revision {review_status}"
            overdue_cycles = int(safe_float(status.get("missed_trigger_review_overdue_cycles")) or 0)
            cycles_remaining = int(safe_float(status.get("missed_trigger_review_cycles_remaining")) or 0)
            overdue_minutes = safe_float(status.get("missed_trigger_review_overdue_minutes"))
            eta_minutes = safe_float(status.get("missed_trigger_review_eta_minutes"))
            if overdue_cycles:
                review_detail += f" +{overdue_cycles}"
                if overdue_minutes is not None:
                    review_detail += f"/{overdue_minutes:.1f}m"
            elif cycles_remaining and review_status == "PENDING":
                review_detail += f" en {cycles_remaining}"
                if eta_minutes is not None:
                    review_detail += f"/{eta_minutes:.1f}m"
            detail_parts.append(review_detail)
        review_action = text_display(status.get("missed_trigger_review_action") or "")
        if review_action and review_action != "-":
            detail_parts.append(review_action)
    detail = " | ".join(detail_parts) if detail_parts else text_display(status.get("detail"))
    return {"label": text_display(label), "tone": text_display(tone), "detail": detail}


def alert_quality_rotation_candidates(
    summary: dict[str, Any] | None,
    entry: dict[str, Any] | None = None,
    *,
    limit: int = 3,
) -> list[dict[str, Any]]:
    summary = summary or {}
    entry = entry or {}
    if text_display(summary.get("blocker_category")).upper() == "MARKET_CLOSED_WAIT":
        return []
    raw_items = summary.get("rotation_candidates")
    rows: list[dict[str, Any]] = []
    if isinstance(raw_items, list):
        for raw in raw_items:
            text = text_display(raw)
            if not text or text == "-":
                continue
            parts = text.split()
            symbol = parts[0].upper() if parts else "-"
            readiness = None
            quality = "-"
            for part in parts[1:]:
                if part.endswith("%"):
                    readiness = safe_float(part.rstrip("%"))
                elif quality == "-":
                    quality = part
            rows.append({"symbol": symbol, "readiness": readiness, "quality": quality, "label": text})
            if len(rows) >= max(1, int(limit)):
                return rows
    setup_watchlist = entry.get("setup_watchlist") if isinstance(entry.get("setup_watchlist"), list) else []
    for item in setup_watchlist:
        if not isinstance(item, dict):
            continue
        symbol = text_display(item.get("symbol")).upper()
        if not symbol or any(row["symbol"] == symbol for row in rows):
            continue
        readiness = safe_float(item.get("readiness"))
        quality = text_display(item.get("quality") or "-")
        label = f"{symbol} {readiness:.1f}% {quality}" if readiness is not None else f"{symbol} {quality}"
        rows.append({"symbol": symbol, "readiness": readiness, "quality": quality, "label": label})
        if len(rows) >= max(1, int(limit)):
            break
    return rows


def notification_history_dashboard_status(summary: dict[str, Any] | None) -> dict[str, Any]:
    summary = summary or {}
    sample_size = int(summary.get("sample_size") or 0)
    if not sample_size:
        return {"label": "Sin historial", "tone": "watch", "detail": "Aun no hay intentos registrados"}
    cooldown = int(summary.get("cooldown_skipped") or 0)
    sent = int(summary.get("sent_count") or 0)
    channel_count = int(summary.get("channel_count") or 0)
    local_recorded = int(summary.get("local_recorded_count") or 0)
    last_age_minutes = safe_float(summary.get("last_age_minutes"))
    last_reason = text_display(summary.get("last_reason"))
    line_count = int(summary.get("line_count") or 0)
    max_lines = int(summary.get("max_lines") or 0)
    size_bytes = int(summary.get("size_bytes") or 0)
    max_bytes = int(summary.get("max_bytes") or 0)
    line_budget_ratio = (line_count / max_lines) if max_lines > 0 else None
    line_budget_margin = (max_lines - line_count) if max_lines > 0 else None
    byte_budget_ratio = (size_bytes / max_bytes) if max_bytes > 0 else None
    byte_budget_margin = (max_bytes - size_bytes) if max_bytes > 0 else None
    line_budget_status = "WARN" if max_lines > 0 and line_count > max_lines else "OK"
    byte_budget_status = "WARN" if max_bytes > 0 and size_bytes > max_bytes else "OK"
    if channel_count == 0 and local_recorded:
        tone = "watch"
        label = "Local"
    elif cooldown:
        tone = "watch"
        label = f"{cooldown} cooldown"
    elif sent:
        tone = "buy"
        label = f"{sent} enviadas"
    else:
        tone = "neutral"
        label = "Sin envio"
    if line_budget_status == "WARN" or byte_budget_status == "WARN":
        tone = "watch" if tone != "avoid" else tone
        label = "Historial revisar"
    detail = f"{sample_size} eventos | ultimo {last_reason}"
    if last_age_minutes is not None:
        detail += f" hace {last_age_minutes:.1f}m"
    if line_count:
        detail += f" | lineas {line_count}"
        if max_lines:
            detail += f"/{max_lines}"
            if line_budget_ratio is not None:
                detail += f" {line_budget_ratio * 100:.1f}%"
            if line_budget_margin is not None:
                detail += f" margen {line_budget_margin}"
        if line_budget_status == "WARN":
            detail += " WARN"
    if size_bytes:
        detail += f" | hist {size_bytes / (1024**2):.2f}MB"
        if max_bytes:
            detail += f"/{max_bytes / (1024**2):.2f}MB"
            if byte_budget_ratio is not None:
                detail += f" {byte_budget_ratio * 100:.1f}%"
            if byte_budget_margin is not None:
                detail += f" margen {byte_budget_margin / (1024**2):.2f}MB"
        if byte_budget_status == "WARN":
            detail += " WARN"
    if channel_count == 0:
        detail += f" | local {local_recorded} | sin canal externo"
    elif channel_count:
        detail += f" | canales {channel_count}"
    if cooldown and "cooldown" not in label:
        detail += f" | cooldown {cooldown}"
    return {
        "label": label,
        "tone": tone,
        "detail": detail,
        "channel_count": channel_count,
        "local_recorded_count": local_recorded,
        "last_age_minutes": last_age_minutes,
        "line_count": line_count,
        "max_lines": max_lines,
        "line_budget_ratio": line_budget_ratio,
        "line_budget_margin": line_budget_margin,
        "line_budget_status": line_budget_status,
        "size_bytes": size_bytes,
        "max_bytes": max_bytes,
        "byte_budget_ratio": byte_budget_ratio,
        "byte_budget_margin": byte_budget_margin,
        "budget_status": byte_budget_status,
    }


def notification_delivery_dashboard_status(
    realtime_report: dict[str, Any] | None,
    history_summary: dict[str, Any] | None = None,
) -> dict[str, Any]:
    item = check_from_report(realtime_report, "notification_delivery")
    history_summary = history_summary or {}
    status = text_display(item.get("status")).upper() if item else ""
    detail = text_display(item.get("detail") or history_summary.get("last_reason") or "Sin reporte delivery")

    def _safe_int(value: Any) -> int:
        try:
            return max(0, int(value or 0))
        except (TypeError, ValueError):
            return 0

    channel_count = _safe_int(item.get("channel_count") if item else history_summary.get("channel_count"))
    actionable_ready_count = _safe_int(item.get("actionable_ready_count") if item else 0)
    local_file_fallback = bool(item.get("local_file_fallback")) if item else False
    delivery_mode = text_display(item.get("delivery_mode") if item else history_summary.get("delivery_mode"))
    if not delivery_mode or delivery_mode == "-":
        delivery_mode = "external" if channel_count else "local_file"
    malformed_recent_lines = _safe_int(
        item.get("malformed_recent_lines") if item else history_summary.get("malformed_recent_lines")
    )
    cooldown_state_malformed = bool(item.get("cooldown_state_malformed")) if item else False
    channels = item.get("channels") if item else history_summary.get("configured_channels")
    channel_label = ", ".join(text_display(channel) for channel in channels or [] if text_display(channel) != "-")

    if not item and not history_summary:
        return {
            "label": "Sin check",
            "tone": "watch",
            "detail": "No esta en el reporte RT",
            "delivery_mode": delivery_mode,
            "channel_count": channel_count,
            "actionable_ready_count": actionable_ready_count,
        }
    if status == "FAIL":
        return {
            "label": "Sin salida",
            "tone": "avoid",
            "detail": detail,
            "delivery_mode": delivery_mode,
            "channel_count": channel_count,
            "actionable_ready_count": actionable_ready_count,
        }
    if actionable_ready_count > 0 and channel_count == 0:
        return {
            "label": "Listas sin canal",
            "tone": "avoid",
            "detail": f"{actionable_ready_count} alerta(s) listas | {detail}",
            "delivery_mode": delivery_mode,
            "channel_count": channel_count,
            "actionable_ready_count": actionable_ready_count,
        }
    if malformed_recent_lines or cooldown_state_malformed:
        issue = f"historial malformado {malformed_recent_lines}" if malformed_recent_lines else "cooldown malformado"
        return {
            "label": "Historial revisar",
            "tone": "watch",
            "detail": f"{issue} | {detail}",
            "delivery_mode": delivery_mode,
            "channel_count": channel_count,
            "actionable_ready_count": actionable_ready_count,
        }
    if channel_count > 0:
        label = "Canal activo" if channel_count == 1 else f"{channel_count} canales"
        tone = "buy" if status in {"", "OK"} else "watch"
        channel_detail = channel_label or f"{channel_count} canal(es)"
        return {
            "label": label,
            "tone": tone,
            "detail": f"{channel_detail} | {detail}",
            "delivery_mode": delivery_mode,
            "channel_count": channel_count,
            "actionable_ready_count": actionable_ready_count,
        }
    if local_file_fallback or delivery_mode == "local_file" or status == "INFO":
        mode_detail = "sin alertas listas; archivo local operativo"
        if detail and detail != "-":
            mode_detail = f"{mode_detail} | {detail}"
        return {
            "label": "Solo local",
            "tone": "watch",
            "detail": mode_detail,
            "delivery_mode": delivery_mode,
            "channel_count": channel_count,
            "actionable_ready_count": actionable_ready_count,
        }
    label = "Revisar" if status in {"WARN"} else "Sin canal"
    tone = "watch" if status != "FAIL" else "avoid"
    return {
        "label": label,
        "tone": tone,
        "detail": detail,
        "delivery_mode": delivery_mode,
        "channel_count": channel_count,
        "actionable_ready_count": actionable_ready_count,
    }


def notification_delivery_action_status(
    delivery_status: dict[str, Any] | None,
    channel_rows: list[dict[str, Any]] | pd.DataFrame | None,
    *,
    ready_count: int = 0,
    cooldown_minutes: int | float | None = None,
) -> dict[str, Any]:
    delivery_status = delivery_status or {}
    channel_df = pd.DataFrame(channel_rows if channel_rows is not None else [])
    if channel_df.empty:
        configured_count = int(delivery_status.get("channel_count") or 0)
        missing_labels: list[str] = []
    else:
        configured = (
            channel_df[channel_df.get("configured", False).astype(bool)]
            if "configured" in channel_df.columns
            else pd.DataFrame()
        )
        configured_count = len(configured)
        missing = (
            channel_df[~channel_df.get("configured", False).astype(bool)]
            if "configured" in channel_df.columns
            else channel_df
        )
        missing_labels = [text_display(value) for value in missing.get("channel", pd.Series(dtype=str)).tolist()]
    ready_count = max(0, int(ready_count or delivery_status.get("actionable_ready_count") or 0))
    cooldown_label = f"cooldown {int(cooldown_minutes)}m" if cooldown_minutes is not None else "cooldown activo"
    if configured_count:
        return {
            "label": "Salida externa lista",
            "tone": "buy",
            "detail": f"{configured_count} canal(es) activo(s) | {cooldown_label}",
            "action": "Mantener prueba periodica; Roxy puede enviar alertas limpias cuando aparezcan.",
            "configured_count": configured_count,
            "missing_channels": missing_labels,
        }
    if ready_count:
        return {
            "label": "Conectar canal ahora",
            "tone": "avoid",
            "detail": f"{ready_count} alerta(s) listas pero sin salida externa | {cooldown_label}",
            "action": "Activar Mac, Discord, email o webhook antes de depender de alertas en vivo.",
            "configured_count": configured_count,
            "missing_channels": missing_labels,
        }
    return {
        "label": "Preparar delivery",
        "tone": "watch",
        "detail": f"sin alertas listas; salida externa pendiente | {cooldown_label}",
        "action": "Configurar al menos un canal y probarlo antes de mercado abierto.",
        "configured_count": configured_count,
        "missing_channels": missing_labels,
    }


def notification_history_display_table(history: list[dict[str, Any]] | pd.DataFrame) -> pd.DataFrame:
    if isinstance(history, pd.DataFrame):
        table = history.copy()
    else:
        table = pd.DataFrame(history or [])
    if table.empty:
        return table
    rows = table.to_dict(orient="records")
    table["effective_sent"] = [notifier.notification_effectively_sent(row) for row in rows]
    if "message" in table.columns:
        table["message"] = table["message"].astype(str).str.replace("\n", " | ", regex=False).str.slice(0, 260)
    if "cooldown_skipped" in table.columns:
        table["cooldown_skipped"] = pd.to_numeric(table["cooldown_skipped"], errors="coerce").fillna(0).astype(int)
    return table


def chart_realtime_dashboard_status(report: dict[str, Any] | None) -> dict[str, Any]:
    report = report or {}
    summary = report.get("summary") if isinstance(report.get("summary"), dict) else {}
    if not summary:
        return {"label": "Sin reporte", "tone": "watch", "detail": "Ejecuta chart realtime health"}
    label = text_display(summary.get("label"))
    tone = text_display(summary.get("tone")) or "watch"
    checked = int(summary.get("checked_count") or 0)
    fail_count = int(summary.get("fail_count") or 0)
    warn_count = int(summary.get("warn_count") or 0)
    stale_count = int(summary.get("stale_count") or 0)
    data_quality_issue_count = int(summary.get("data_quality_issue_count") or 0)
    max_age_minutes = safe_float(summary.get("max_age_minutes"))
    avg_age_minutes = safe_float(summary.get("avg_age_minutes"))
    operable_checked_count = int(summary.get("operable_checked_count") or 0)
    operable_max_age_minutes = safe_float(summary.get("operable_max_age_minutes"))
    operable_avg_age_minutes = safe_float(summary.get("operable_avg_age_minutes"))
    max_cadence_lag_minutes = safe_float(summary.get("max_cadence_lag_minutes"))
    operable_max_cadence_lag_minutes = safe_float(summary.get("operable_max_cadence_lag_minutes"))
    max_health_lag_minutes = safe_float(summary.get("max_health_lag_minutes"))
    operable_max_health_lag_minutes = safe_float(summary.get("operable_max_health_lag_minutes"))
    next_expected_update_in_minutes = safe_float(summary.get("next_expected_update_in_minutes"))
    operable_next_expected_update_in_minutes = safe_float(summary.get("operable_next_expected_update_in_minutes"))
    operable_min_freshness_margin_minutes = safe_float(summary.get("operable_min_freshness_margin_minutes"))
    operable_min_freshness_margin_ratio = safe_float(summary.get("operable_min_freshness_margin_ratio"))
    operable_freshness_margin_state = text_display(summary.get("operable_freshness_margin_state")).upper()
    operable_freshness_margin_warn_threshold_minutes = safe_float(
        summary.get("operable_freshness_margin_warn_threshold_minutes")
    )
    operable_min_freshness_margin_chart = (
        summary.get("operable_min_freshness_margin_chart")
        if isinstance(summary.get("operable_min_freshness_margin_chart"), dict)
        else {}
    )
    if operable_min_freshness_margin_minutes is None:
        charts = report.get("charts") if isinstance(report.get("charts"), list) else []
        margin_candidates: list[tuple[float, dict[str, Any]]] = []
        for chart in charts:
            if not isinstance(chart, dict):
                continue
            if text_display(chart.get("status")).upper() != "OK":
                continue
            age = safe_float(chart.get("age_minutes"))
            budget = safe_float(chart.get("freshness_budget_minutes"))
            if age is None or budget is None or budget <= 0:
                continue
            candidate = dict(chart)
            candidate["margin_minutes"] = round(budget - age, 1)
            candidate["margin_ratio"] = round(max(0.0, budget - age) / budget, 4)
            margin_candidates.append((float(candidate["margin_minutes"]), candidate))
        if margin_candidates:
            _, margin_chart = min(margin_candidates, key=lambda item: item[0])
            operable_min_freshness_margin_chart = margin_chart
            operable_min_freshness_margin_minutes = safe_float(margin_chart.get("margin_minutes"))
            operable_min_freshness_margin_ratio = safe_float(margin_chart.get("margin_ratio"))
            budget = safe_float(margin_chart.get("freshness_budget_minutes"))
            if budget is not None:
                operable_freshness_margin_warn_threshold_minutes = round(budget * 0.2, 1)
            if (
                operable_min_freshness_margin_minutes is not None
                and operable_freshness_margin_warn_threshold_minutes is not None
            ):
                operable_freshness_margin_state = (
                    "WARN"
                    if operable_min_freshness_margin_minutes <= operable_freshness_margin_warn_threshold_minutes
                    else "OK"
                )
    detail = f"{checked} charts | fallos {fail_count} | warnings {warn_count}"
    if operable_checked_count:
        detail += f" | operables {operable_checked_count}"
    if operable_max_age_minutes is not None:
        detail += f" | operable max {operable_max_age_minutes:.1f}m"
    if max_age_minutes is not None:
        detail += f" | max {max_age_minutes:.1f}m"
    if operable_avg_age_minutes is not None:
        detail += f" | operable avg {operable_avg_age_minutes:.1f}m"
    if avg_age_minutes is not None:
        detail += f" | avg {avg_age_minutes:.1f}m"
    if operable_max_cadence_lag_minutes is not None and operable_max_cadence_lag_minutes > 0:
        detail += f" | operable lag {operable_max_cadence_lag_minutes:.1f}m"
    elif operable_next_expected_update_in_minutes is not None:
        detail += f" | operable next {operable_next_expected_update_in_minutes:.1f}m"
    if operable_min_freshness_margin_minutes is not None:
        margin_text = f" | margen operable {operable_min_freshness_margin_minutes:.1f}m"
        if operable_min_freshness_margin_ratio is not None:
            margin_text += f"/{operable_min_freshness_margin_ratio * 100:.0f}%"
        if operable_freshness_margin_state and operable_freshness_margin_state != "-":
            margin_text += f" {operable_freshness_margin_state.lower()}"
        if operable_freshness_margin_warn_threshold_minutes is not None:
            margin_text += f" warn<={operable_freshness_margin_warn_threshold_minutes:.1f}m"
        if operable_min_freshness_margin_chart:
            margin_text += (
                f" {text_display(operable_min_freshness_margin_chart.get('symbol'))}"
                f" {text_display(operable_min_freshness_margin_chart.get('timeframe'))}"
            )
        detail += margin_text
    if max_cadence_lag_minutes is not None and max_cadence_lag_minutes > 0:
        detail += f" | lag max {max_cadence_lag_minutes:.1f}m"
    elif next_expected_update_in_minutes is not None:
        detail += f" | next vela {next_expected_update_in_minutes:.1f}m"
    if operable_max_health_lag_minutes is not None and operable_max_health_lag_minutes > 0:
        detail += f" | operable health lag {operable_max_health_lag_minutes:.1f}m"
    if max_health_lag_minutes is not None and max_health_lag_minutes > 0:
        detail += f" | health lag {max_health_lag_minutes:.1f}m"
    if stale_count:
        detail += f" | estancadas {stale_count}"
    if data_quality_issue_count:
        detail += f" | calidad {data_quality_issue_count}"
    stalest_chart = summary.get("stalest_chart") if isinstance(summary.get("stalest_chart"), dict) else {}
    operable_stalest_chart = (
        summary.get("operable_stalest_chart") if isinstance(summary.get("operable_stalest_chart"), dict) else {}
    )
    if (
        operable_stalest_chart
        and not summary.get("top_issue")
        and not (operable_max_cadence_lag_minutes is not None and operable_max_cadence_lag_minutes > 0)
    ):
        detail += (
            " | operable vieja "
            f"{text_display(operable_stalest_chart.get('symbol'))} {text_display(operable_stalest_chart.get('timeframe'))}"
        )
    if (
        stalest_chart
        and not summary.get("top_issue")
        and not (max_cadence_lag_minutes is not None and max_cadence_lag_minutes > 0)
    ):
        detail += (
            f" | mas vieja {text_display(stalest_chart.get('symbol'))} {text_display(stalest_chart.get('timeframe'))}"
        )
    top_issue = summary.get("top_issue") if isinstance(summary.get("top_issue"), dict) else {}
    if top_issue:
        detail += f" | {text_display(top_issue.get('symbol'))} {text_display(top_issue.get('timeframe'))}"
    most_overdue_chart = (
        summary.get("most_overdue_chart") if isinstance(summary.get("most_overdue_chart"), dict) else {}
    )
    operable_most_overdue_chart = (
        summary.get("operable_most_overdue_chart")
        if isinstance(summary.get("operable_most_overdue_chart"), dict)
        else {}
    )
    if (
        operable_most_overdue_chart
        and operable_max_cadence_lag_minutes is not None
        and operable_max_cadence_lag_minutes > 0
        and not top_issue
    ):
        detail += (
            " | operable tarde "
            f"{text_display(operable_most_overdue_chart.get('symbol'))} "
            f"{text_display(operable_most_overdue_chart.get('timeframe'))}"
        )
    if most_overdue_chart and max_cadence_lag_minutes is not None and max_cadence_lag_minutes > 0 and not top_issue:
        detail += f" | tarde {text_display(most_overdue_chart.get('symbol'))} {text_display(most_overdue_chart.get('timeframe'))}"
    return {
        "label": label or "Graficas",
        "tone": tone,
        "detail": detail,
        "max_age_minutes": max_age_minutes,
        "avg_age_minutes": avg_age_minutes,
        "operable_checked_count": operable_checked_count,
        "operable_max_age_minutes": operable_max_age_minutes,
        "operable_avg_age_minutes": operable_avg_age_minutes,
        "max_cadence_lag_minutes": max_cadence_lag_minutes,
        "operable_max_cadence_lag_minutes": operable_max_cadence_lag_minutes,
        "max_health_lag_minutes": max_health_lag_minutes,
        "operable_max_health_lag_minutes": operable_max_health_lag_minutes,
        "next_expected_update_in_minutes": next_expected_update_in_minutes,
        "operable_next_expected_update_in_minutes": operable_next_expected_update_in_minutes,
        "operable_min_freshness_margin_minutes": operable_min_freshness_margin_minutes,
        "operable_min_freshness_margin_ratio": operable_min_freshness_margin_ratio,
        "operable_freshness_margin_state": (
            operable_freshness_margin_state if operable_freshness_margin_state != "-" else ""
        ),
        "operable_freshness_margin_warn_threshold_minutes": (operable_freshness_margin_warn_threshold_minutes),
        "operable_min_freshness_margin_chart": operable_min_freshness_margin_chart,
        "stalest_chart": stalest_chart,
        "operable_stalest_chart": operable_stalest_chart,
        "most_overdue_chart": most_overdue_chart,
        "operable_most_overdue_chart": operable_most_overdue_chart,
    }


def chart_provider_effective_dashboard_status(realtime_report: dict[str, Any] | None) -> dict[str, Any]:
    item = check_from_report(realtime_report, "chart_provider_effective")
    if not item:
        return {"label": "Sin check", "tone": "watch", "detail": "No esta en el reporte RT"}
    status = text_display(item.get("status")).upper()
    checked = int(item.get("checked_count") or 0)
    fallback_count = int(item.get("fallback_count") or 0)
    auth_fallback_count = int(item.get("auth_fallback_count") or 0)
    polygon_missing_count = int(item.get("polygon_missing_count") or 0)
    operable_market_issue_count = int(item.get("operable_market_issue_count") or 0)
    blocked_market_issue_count = int(item.get("blocked_market_issue_count") or 0)
    crypto_issue_count = int(item.get("crypto_issue_count") or 0)
    stock_issue_count = int(item.get("stock_issue_count") or 0)
    route_focus_label = text_display(item.get("route_focus_label"))
    reason_counts = item.get("fallback_reason_counts") if isinstance(item.get("fallback_reason_counts"), dict) else {}
    alternate_counts = (
        item.get("alternate_reason_counts") if isinstance(item.get("alternate_reason_counts"), dict) else {}
    )
    if status == "FAIL":
        label = "Fuente falla"
        tone = "avoid"
    elif auth_fallback_count and blocked_market_issue_count > 0 and operable_market_issue_count == 0:
        label = "Crypto operable"
        tone = "watch"
    elif auth_fallback_count:
        label = "Auth/permisos"
        tone = "avoid"
    elif status == "WARN":
        label = "Fuente revisar"
        tone = "watch"
    elif fallback_count:
        label = "Fallback"
        tone = "watch"
    else:
        label = "Fuente OK"
        tone = "buy"
    reason_text = ", ".join(f"{key} x{value}" for key, value in sorted(reason_counts.items())) if reason_counts else "-"
    alternate_text = (
        ", ".join(f"{key} x{value}" for key, value in sorted(alternate_counts.items())) if alternate_counts else "-"
    )
    detail = f"{checked or '-'} simbolos | fallback {fallback_count} | auth/perms {auth_fallback_count}"
    if route_focus_label and route_focus_label != "-":
        detail += f" | {route_focus_label}"
    if crypto_issue_count or stock_issue_count:
        detail += f" | issues crypto {crypto_issue_count}, stock {stock_issue_count}"
    if blocked_market_issue_count:
        detail += f" | bloqueado {blocked_market_issue_count}"
    if polygon_missing_count:
        detail += f" | Polygon falta {polygon_missing_count}"
    if reason_text != "-":
        detail += f" | {reason_text}"
    if alternate_text != "-":
        detail += f" | alterno {alternate_text}"
    recovery = text_display(item.get("premium_recovery_action"))
    if recovery and recovery != "-":
        detail += f" | accion {recovery}"
    raw_detail = text_display(item.get("detail"))
    if raw_detail and raw_detail != "-":
        detail += f" | {raw_detail}"
    return {
        "label": label,
        "tone": tone,
        "detail": detail,
        "checked_count": checked,
        "fallback_count": fallback_count,
        "auth_fallback_count": auth_fallback_count,
        "polygon_missing_count": polygon_missing_count,
        "operable_market_issue_count": operable_market_issue_count,
        "blocked_market_issue_count": blocked_market_issue_count,
        "crypto_issue_count": crypto_issue_count,
        "stock_issue_count": stock_issue_count,
        "route_focus_label": route_focus_label,
        "fallback_reason_counts": reason_counts,
        "alternate_reason_counts": alternate_counts,
        "premium_recovery_action": recovery,
    }


def chart_provider_effective_display_table(realtime_report: dict[str, Any] | None) -> pd.DataFrame:
    item = check_from_report(realtime_report, "chart_provider_effective")
    results = item.get("results") if isinstance(item.get("results"), list) else []
    rows: list[dict[str, Any]] = []
    for result in results:
        if not isinstance(result, dict):
            continue
        rows.append(
            {
                "Simbolo": text_display(result.get("symbol")),
                "Mercado": text_display(result.get("market")),
                "TF": text_display(result.get("timeframe")),
                "Estado": text_display(result.get("status")),
                "Proveedor": text_display(result.get("provider")),
                "Fuente": text_display(result.get("source")),
                "Modo": text_display(result.get("source_mode")),
                "Fallback": "Si" if bool(result.get("fallback")) else "No",
                "Motivo": text_display(result.get("fallback_reason")),
                "Alterno": text_display(result.get("polygon_fallback_reason")),
                "Accion": text_display(result.get("fallback_action") or result.get("fallback_detail")),
                "Recuperacion": text_display(
                    result.get("premium_recovery_action")
                    or result.get("polygon_fallback_action")
                    or result.get("fallback_action")
                    or result.get("fallback_detail")
                ),
            }
        )
    return pd.DataFrame(rows)


def provider_env_parity_dashboard_status(realtime_report: dict[str, Any] | None) -> dict[str, Any]:
    item = check_from_report(realtime_report, "provider_env_parity")
    if not item:
        return {"label": "Sin check", "tone": "watch", "detail": "No esta en el reporte RT"}
    alpaca_probe = check_from_report(realtime_report, "alpaca_account_probe")
    status = text_display(item.get("status")).upper()
    launchd_ok = bool(item.get("launchd_alpaca_configured"))
    process_ok = bool(item.get("process_alpaca_configured"))
    effective_ok = bool(item.get("effective_alpaca_configured"))
    launchd_premium_ok = bool(item.get("launchd_premium_configured", launchd_ok))
    process_premium_ok = bool(item.get("process_premium_configured", process_ok))
    effective_premium_ok = bool(item.get("effective_premium_configured", effective_ok))
    launchd_only = (
        item.get("launchd_only_provider_keys") if isinstance(item.get("launchd_only_provider_keys"), list) else []
    )
    process_only = (
        item.get("process_only_provider_keys") if isinstance(item.get("process_only_provider_keys"), list) else []
    )
    alpaca_auth_ok = alpaca_probe.get("auth_ok") if alpaca_probe else None
    alpaca_probe_status = text_display(alpaca_probe.get("status")) if alpaca_probe else ""
    alpaca_error_category = text_display(alpaca_probe.get("error_category")) if alpaca_probe else ""
    alpaca_mode = text_display(alpaca_probe.get("mode")) if alpaca_probe else ""
    alpaca_endpoint = text_display(alpaca_probe.get("expected_endpoint")) if alpaca_probe else ""
    if launchd_premium_ok and process_premium_ok:
        label = "Env alineado"
        tone = "buy"
    elif launchd_premium_ok and not process_premium_ok and effective_premium_ok:
        label = "Env efectivo"
        tone = "buy"
    elif launchd_premium_ok and not process_premium_ok:
        label = "Env servicio"
        tone = "watch"
    elif process_premium_ok and not launchd_premium_ok:
        label = "Env local"
        tone = "avoid"
    elif status == "WARN":
        label = "Env revisar"
        tone = "watch"
    else:
        label = "Sin premium"
        tone = "watch"
    detail = text_display(item.get("detail"))
    if launchd_only and "launchd-only" not in detail:
        detail += f" | launchd-only {', '.join(text_display(key) for key in launchd_only[:4])}"
    if process_only and "process-only" not in detail:
        detail += f" | process-only {', '.join(text_display(key) for key in process_only[:4])}"
    if alpaca_auth_ok is False:
        if tone == "buy":
            tone = "watch"
        detail += " | Alpaca auth no valida"
    elif alpaca_auth_ok is True:
        detail += " | Alpaca auth OK"
    if alpaca_probe_status and alpaca_probe_status != "-":
        detail += f" | probe {alpaca_probe_status}"
    if alpaca_error_category and alpaca_error_category != "-":
        detail += f" | error {alpaca_error_category}"
    if alpaca_mode and alpaca_mode != "-":
        detail += f" | modo {alpaca_mode}"
    if alpaca_endpoint and alpaca_endpoint != "-":
        detail += f" | endpoint {alpaca_endpoint}"
    return {
        "label": label,
        "tone": tone,
        "detail": detail,
        "launchd_alpaca_configured": launchd_ok,
        "process_alpaca_configured": process_ok,
        "effective_alpaca_configured": effective_ok,
        "launchd_premium_configured": launchd_premium_ok,
        "process_premium_configured": process_premium_ok,
        "effective_premium_configured": effective_premium_ok,
        "launchd_only_provider_keys": launchd_only,
        "process_only_provider_keys": process_only,
        "alpaca_account_auth_ok": alpaca_auth_ok,
        "alpaca_account_probe_status": alpaca_probe_status,
        "alpaca_account_error_category": alpaca_error_category,
        "alpaca_account_mode": alpaca_mode,
        "alpaca_expected_endpoint": alpaca_endpoint,
    }


def provider_recovery_dashboard_status(realtime_report: dict[str, Any] | None) -> dict[str, Any]:
    recovery = (
        realtime_report.get("provider_recovery")
        if isinstance(realtime_report, dict) and isinstance(realtime_report.get("provider_recovery"), dict)
        else {}
    )
    if not recovery:
        return {"label": "Sin plan", "tone": "watch", "detail": "No hay provider_recovery en el health"}
    label = text_display(recovery.get("label"))
    tone = text_display(recovery.get("tone")) or "watch"
    action = text_display(recovery.get("action"))
    detail = text_display(recovery.get("detail"))
    credential_scope = text_display(recovery.get("credential_scope"))
    credential_diagnosis = text_display(recovery.get("credential_diagnosis"))
    primary_issue = text_display(recovery.get("primary_provider_issue"))
    alternate_issue = text_display(recovery.get("alternate_provider_issue"))
    alpaca_auth_ok = recovery.get("alpaca_account_auth_ok")
    alpaca_probe_status = text_display(recovery.get("alpaca_account_probe_status"))
    alpaca_error_category = text_display(recovery.get("alpaca_account_error_category"))
    alpaca_mode = text_display(recovery.get("alpaca_account_mode"))
    alpaca_endpoint = text_display(recovery.get("alpaca_expected_endpoint"))
    recovery_priority = recovery.get("recovery_priority") if isinstance(recovery.get("recovery_priority"), list) else []
    polygon_missing = int(recovery.get("polygon_missing_count") or 0)
    auth_fallback = int(recovery.get("auth_fallback_count") or 0)
    impacted_markets = recovery.get("impacted_markets") if isinstance(recovery.get("impacted_markets"), list) else []
    safe_mode = text_display(recovery.get("safe_mode"))
    confirmation_gate = text_display(recovery.get("confirmation_gate"))
    if polygon_missing:
        detail += f" | Polygon falta {polygon_missing}"
    if auth_fallback:
        detail += f" | auth/perms {auth_fallback}"
    if primary_issue and primary_issue != "-":
        detail += f" | causa {primary_issue}"
    if alternate_issue and alternate_issue != "-":
        detail += f" | alterno {alternate_issue}"
    if alpaca_auth_ok is False:
        detail += " | Alpaca auth no valida"
    if alpaca_probe_status and alpaca_probe_status != "-":
        detail += f" | alpaca {alpaca_probe_status}"
    if alpaca_error_category and alpaca_error_category != "-":
        detail += f" | error {alpaca_error_category}"
    if alpaca_mode and alpaca_mode != "-":
        detail += f" | modo {alpaca_mode}"
    if alpaca_endpoint and alpaca_endpoint != "-":
        detail += f" | endpoint {alpaca_endpoint}"
    if recovery_priority:
        detail += " | prioridad " + ", ".join(text_display(item) for item in recovery_priority[:3])
    if credential_scope and credential_scope != "-":
        detail += f" | scope {credential_scope}"
    if credential_diagnosis and credential_diagnosis != "-":
        detail += f" | diagnostico {credential_diagnosis}"
    if impacted_markets:
        detail += " | mercados " + ", ".join(text_display(item) for item in impacted_markets)
    if safe_mode and safe_mode != "-":
        detail += f" | modo {safe_mode}"
    if confirmation_gate and confirmation_gate != "-":
        detail += f" | gate {confirmation_gate}"
    if action and action != "-":
        detail += f" | accion {action}"
    return {
        "label": label,
        "tone": tone if tone in {"buy", "watch", "avoid", "neutral"} else "watch",
        "detail": detail,
        "action": action,
        "premium_blocked": bool(recovery.get("premium_blocked")),
        "stock_alerts_allowed": bool(recovery.get("stock_alerts_allowed", True)),
        "polygon_missing_count": polygon_missing,
        "auth_fallback_count": auth_fallback,
        "impacted_markets": impacted_markets,
        "safe_mode": safe_mode,
        "confirmation_gate": confirmation_gate,
        "credential_scope": credential_scope,
        "credential_diagnosis": credential_diagnosis,
        "primary_provider_issue": primary_issue,
        "alternate_provider_issue": alternate_issue,
        "alpaca_account_auth_ok": alpaca_auth_ok,
        "alpaca_account_probe_status": alpaca_probe_status,
        "alpaca_account_error_category": alpaca_error_category,
        "alpaca_account_mode": alpaca_mode,
        "alpaca_expected_endpoint": alpaca_endpoint,
        "recovery_priority": recovery_priority,
    }


def provider_recovery_steps_table(realtime_report: dict[str, Any] | None) -> pd.DataFrame:
    recovery = (
        realtime_report.get("provider_recovery")
        if isinstance(realtime_report, dict) and isinstance(realtime_report.get("provider_recovery"), dict)
        else {}
    )
    if not recovery:
        return pd.DataFrame()
    premium_blocked = bool(recovery.get("premium_blocked"))
    status = text_display(recovery.get("status")).upper() or ("WARN" if premium_blocked else "OK")
    action = text_display(recovery.get("action"))
    credential_scope = text_display(recovery.get("credential_scope"))
    credential_diagnosis = text_display(recovery.get("credential_diagnosis"))
    safe_mode = text_display(recovery.get("safe_mode"))
    confirmation_gate = text_display(recovery.get("confirmation_gate"))
    impacted_markets = recovery.get("impacted_markets") if isinstance(recovery.get("impacted_markets"), list) else []
    missing_keys = (
        recovery.get("missing_provider_keys") if isinstance(recovery.get("missing_provider_keys"), list) else []
    )
    priority = recovery.get("recovery_priority") if isinstance(recovery.get("recovery_priority"), list) else []
    steps = recovery.get("recovery_steps") if isinstance(recovery.get("recovery_steps"), list) else []
    alpaca_auth_ok = recovery.get("alpaca_account_auth_ok")
    alpaca_probe_status = text_display(recovery.get("alpaca_account_probe_status"))
    alpaca_error_category = text_display(recovery.get("alpaca_account_error_category"))
    alpaca_mode = text_display(recovery.get("alpaca_account_mode"))
    alpaca_endpoint = text_display(recovery.get("alpaca_expected_endpoint"))

    rows: list[dict[str, Any]] = []
    if premium_blocked:
        rows.append(
            {
                "Prioridad": 1,
                "Bloque": "Proteccion",
                "Estado": "Activo",
                "Accion": "Mantener acciones/opciones bloqueadas hasta confirmar proveedor premium.",
                "Evidencia": f"modo {safe_mode or '-'} | gate {confirmation_gate or '-'}",
            }
        )
    elif status == "OK":
        rows.append(
            {
                "Prioridad": 1,
                "Bloque": "Proteccion",
                "Estado": "OK",
                "Accion": "Proveedor premium confirmado; alertas pueden seguir su compuerta normal.",
                "Evidencia": text_display(recovery.get("detail")),
            }
        )

    if credential_diagnosis and credential_diagnosis != "-":
        rows.append(
            {
                "Prioridad": 2,
                "Bloque": "Credenciales",
                "Estado": credential_scope or "-",
                "Accion": credential_diagnosis,
                "Evidencia": f"causa {text_display(recovery.get('primary_provider_issue'))}",
            }
        )
    if alpaca_auth_ok is False or alpaca_probe_status not in {"", "-"}:
        evidence_parts = []
        if alpaca_probe_status and alpaca_probe_status != "-":
            evidence_parts.append(f"probe {alpaca_probe_status}")
        if alpaca_error_category and alpaca_error_category != "-":
            evidence_parts.append(f"error {alpaca_error_category}")
        if alpaca_mode and alpaca_mode != "-":
            evidence_parts.append(f"modo {alpaca_mode}")
        if alpaca_endpoint and alpaca_endpoint != "-":
            evidence_parts.append(f"endpoint {alpaca_endpoint}")
        rows.append(
            {
                "Prioridad": 3,
                "Bloque": "Alpaca probe",
                "Estado": "AUTH_INVALID" if alpaca_auth_ok is False else (alpaca_probe_status or "Revisar"),
                "Accion": (
                    "Ejecutar el setup seguro `tools/provider_credential_setup.py alpaca` para capturar "
                    "ALPACA_API_KEY y ALPACA_SECRET_KEY; valida antes de guardar, sincroniza el entorno "
                    "administrado y mantiene ALPACA_PAPER alineado con el endpoint."
                ),
                "Evidencia": " | ".join(evidence_parts) if evidence_parts else "-",
            }
        )
    if missing_keys:
        rows.append(
            {
                "Prioridad": 4,
                "Bloque": "Alterno",
                "Estado": "Pendiente",
                "Accion": "Configurar proveedor alterno Polygon para validar velas premium.",
                "Evidencia": ", ".join(text_display(key) for key in missing_keys),
            }
        )
    for index, step in enumerate(steps, start=5):
        step_text = text_display(step)
        if not step_text or step_text == "-":
            continue
        priority_label = text_display(priority[index - 5]) if index - 5 < len(priority) else ""
        rows.append(
            {
                "Prioridad": index,
                "Bloque": "Plan",
                "Estado": priority_label or ("Pendiente" if premium_blocked else "Listo"),
                "Accion": step_text,
                "Evidencia": action if action and action != "-" else text_display(recovery.get("detail")),
            }
        )
    if premium_blocked:
        rows.append(
            {
                "Prioridad": len(rows) + 1,
                "Bloque": "Confirmacion externa",
                "Estado": "Manual",
                "Accion": "Usar Finviz/TradingView solo como confirmacion visual mientras se recupera la API premium.",
                "Evidencia": "No reemplaza proveedor realtime para disparar alertas de acciones/opciones.",
            }
        )
    if impacted_markets:
        rows.append(
            {
                "Prioridad": len(rows) + 1,
                "Bloque": "Mercados",
                "Estado": "Bloqueado" if premium_blocked else "Activo",
                "Accion": "Mercados afectados: " + ", ".join(text_display(item) for item in impacted_markets),
                "Evidencia": f"stock_alerts_allowed={bool(recovery.get('stock_alerts_allowed', True))}",
            }
        )
    return pd.DataFrame(rows)


def market_realtime_dashboard_rows(realtime_report: dict[str, Any] | None) -> list[dict[str, Any]]:
    market_realtime = (
        realtime_report.get("market_realtime")
        if isinstance(realtime_report, dict) and isinstance(realtime_report.get("market_realtime"), dict)
        else {}
    )
    rows = market_realtime.get("rows") if isinstance(market_realtime.get("rows"), list) else []
    cleaned: list[dict[str, Any]] = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        tone = text_display(row.get("tone")) or "watch"
        cleaned.append(
            {
                "market": text_display(row.get("market")).upper(),
                "label": text_display(row.get("label")),
                "tone": tone if tone in {"buy", "watch", "avoid", "neutral"} else "watch",
                "detail": text_display(row.get("detail")),
                "action": text_display(row.get("action")),
                "alerts_allowed": bool(row.get("alerts_allowed", True)),
            }
        )
    return cleaned


def market_realtime_route_summary(realtime_report: dict[str, Any] | None) -> dict[str, Any]:
    rows = market_realtime_dashboard_rows(realtime_report)
    recovery = (
        realtime_report.get("provider_recovery")
        if isinstance(realtime_report, dict) and isinstance(realtime_report.get("provider_recovery"), dict)
        else {}
    )
    operational = (
        realtime_report.get("operational_summary")
        if isinstance(realtime_report, dict) and isinstance(realtime_report.get("operational_summary"), dict)
        else {}
    )
    allowed = [
        row["market"] for row in rows if bool(row.get("alerts_allowed")) and text_display(row.get("tone")) != "avoid"
    ]
    blocked = [
        row["market"] for row in rows if not bool(row.get("alerts_allowed")) or text_display(row.get("tone")) == "avoid"
    ]
    if bool(recovery.get("premium_blocked")):
        impacted = (
            recovery.get("impacted_markets")
            if isinstance(recovery.get("impacted_markets"), list)
            else ["stock", "options"]
        )
        impacted_upper = {text_display(item).upper() for item in impacted if text_display(item) != "-"}
        if not impacted_upper:
            impacted_upper = {"STOCK", "OPTIONS"}
        allowed = [market for market in allowed if market not in impacted_upper]
        for market in ["STOCK", "OPTIONS", "CRYPTO"]:
            if market in impacted_upper and market not in blocked:
                blocked.append(market)
        if not allowed and "CRYPTO" not in impacted_upper:
            allowed = ["CRYPTO"]
    operational_allowed = [
        text_display(item).upper()
        for item in (operational.get("allowed_markets") if isinstance(operational.get("allowed_markets"), list) else [])
        if text_display(item) != "-"
    ]
    operational_blocked = [
        text_display(item).upper()
        for item in (operational.get("blocked_markets") if isinstance(operational.get("blocked_markets"), list) else [])
        if text_display(item) != "-"
    ]
    if operational_allowed or operational_blocked:
        allowed = operational_allowed
        blocked = operational_blocked

    def first_text(*values: Any) -> str:
        for value in values:
            text = text_display(value)
            if text and text != "-":
                return text
        return ""

    action = first_text(recovery.get("action"), operational.get("recommended_action"))
    safe_mode = first_text(operational.get("safe_mode"), recovery.get("safe_mode"))
    confirmation_gate = first_text(operational.get("confirmation_gate"), recovery.get("confirmation_gate"))
    operational_label = text_display(operational.get("active_route_label"))
    operational_detail = text_display(operational.get("active_route_detail"))
    auth_ok = recovery.get("alpaca_account_auth_ok")
    auth_probe_status = text_display(recovery.get("alpaca_account_probe_status"))
    auth_diagnosis = text_display(recovery.get("alpaca_account_probe_diagnosis"))
    auth_error_category = text_display(recovery.get("alpaca_account_error_category"))
    auth_mode = text_display(recovery.get("alpaca_account_mode"))
    auth_endpoint = text_display(recovery.get("alpaca_expected_endpoint"))

    if allowed and blocked:
        label = (
            operational_label if operational_label and operational_label != "-" else "Operar solo " + ", ".join(allowed)
        )
        tone = "watch"
        detail = (
            operational_detail
            if operational_detail and operational_detail != "-"
            else ("Realtime parcial: operable " + ", ".join(allowed) + "; bloqueado " + ", ".join(blocked) + ".")
        )
    elif allowed:
        label = operational_label if operational_label and operational_label != "-" else "Realtime completo"
        tone = "buy"
        detail = (
            operational_detail
            if operational_detail and operational_detail != "-"
            else ("Mercados operables: " + ", ".join(allowed) + ".")
        )
    elif blocked:
        label = operational_label if operational_label and operational_label != "-" else "Realtime bloqueado"
        tone = "avoid"
        detail = (
            operational_detail
            if operational_detail and operational_detail != "-"
            else ("Mercados bloqueados: " + ", ".join(blocked) + ".")
        )
    else:
        label = "Sin mapa RT"
        tone = "watch"
        detail = "Aun no hay market_realtime en el health."

    if safe_mode and safe_mode != "-":
        detail += f" Modo {safe_mode}."
    if confirmation_gate and confirmation_gate != "-":
        detail += f" Gate {confirmation_gate}."
    if auth_ok is False:
        detail += " Alpaca auth falla."
    elif auth_ok is True:
        detail += " Alpaca auth OK."
    if auth_probe_status and auth_probe_status != "-":
        detail += f" Probe {auth_probe_status}."
    if auth_diagnosis and auth_diagnosis != "-":
        detail += f" Diagnostico {auth_diagnosis}."
    if auth_error_category and auth_error_category != "-":
        detail += f" Error {auth_error_category}."
    if auth_mode and auth_mode != "-":
        detail += f" Modo cuenta {auth_mode}."
    if auth_endpoint and auth_endpoint != "-":
        detail += f" Endpoint {auth_endpoint}."
    if action and action != "-":
        detail += f" Accion: {action}"

    return {
        "label": label,
        "tone": tone,
        "detail": detail,
        "allowed_markets": allowed,
        "blocked_markets": blocked,
        "safe_mode": safe_mode,
        "confirmation_gate": confirmation_gate,
        "action": action,
        "alpaca_account_auth_ok": auth_ok,
        "alpaca_account_probe_status": auth_probe_status,
        "alpaca_account_probe_diagnosis": auth_diagnosis,
        "alpaca_account_error_category": auth_error_category,
        "alpaca_account_mode": auth_mode,
        "alpaca_expected_endpoint": auth_endpoint,
    }


def status_snapshot_route_summary(status: dict[str, Any] | None) -> dict[str, Any]:
    status = status or {}
    allowed = [
        text_display(item).upper()
        for item in (status.get("allowed_markets") if isinstance(status.get("allowed_markets"), list) else [])
        if text_display(item) != "-"
    ]
    blocked = [
        text_display(item).upper()
        for item in (status.get("blocked_markets") if isinstance(status.get("blocked_markets"), list) else [])
        if text_display(item) != "-"
    ]
    safe_mode = text_display(status.get("safe_mode"))
    route_label = text_display(status.get("active_route_label"))
    route_detail = text_display(status.get("active_route_detail"))
    recommended_action = text_display(status.get("recommended_action"))
    top_symbol = text_display(status.get("top_symbol"))
    top_gate = text_display(status.get("top_gate"))
    operational_focus_symbol = text_display(status.get("operational_focus_symbol")).upper()
    operational_focus_source = text_display(status.get("operational_focus_source")).upper()
    operational_focus_reason = text_display(status.get("operational_focus_reason"))
    operational_focus_overrides_top = bool(status.get("operational_focus_overrides_top", False))
    daily_plan_top_symbol = text_display(
        status.get("status_snapshot_daily_top_symbol") or status.get("daily_plan_top_symbol")
    ).upper()
    daily_plan_top_stage = text_display(
        status.get("status_snapshot_daily_top_stage") or status.get("daily_plan_top_stage")
    ).upper()
    daily_plan_top_probability = safe_float(
        first_present(status.get("status_snapshot_daily_top_probability"), status.get("daily_plan_top_probability"))
    )
    daily_plan_total = safe_float(
        first_present(status.get("daily_plan_total"), status.get("status_snapshot_daily_total"))
    )
    daily_plan_operar_ahora = safe_float(
        first_present(status.get("daily_plan_operar_ahora"), status.get("status_snapshot_daily_operar_ahora"))
    )
    daily_plan_proxima_entrada = safe_float(
        first_present(status.get("daily_plan_proxima_entrada"), status.get("status_snapshot_daily_proxima_entrada"))
    )
    daily_plan_vigilar = safe_float(
        first_present(status.get("daily_plan_vigilar"), status.get("status_snapshot_daily_vigilar"))
    )
    daily_plan_matches_top = (
        top_symbol != "-" and daily_plan_top_symbol != "-" and text_display(top_symbol).upper() == daily_plan_top_symbol
    )
    operational_focus_active = operational_focus_symbol != "-" and (
        operational_focus_overrides_top or operational_focus_symbol != text_display(top_symbol).upper()
    )
    daily_plan_matches_focus = (
        operational_focus_active and daily_plan_top_symbol != "-" and operational_focus_symbol == daily_plan_top_symbol
    )
    if route_label == "-":
        if allowed and blocked:
            route_label = "Operar solo " + ", ".join(allowed)
        elif allowed:
            route_label = "Realtime completo"
        elif blocked:
            route_label = "Realtime bloqueado"
        else:
            route_label = "Sin ruta"
    if route_detail == "-":
        if allowed and blocked:
            route_detail = "Operable " + ", ".join(allowed) + "; bloqueado " + ", ".join(blocked) + "."
        elif allowed:
            route_detail = "Mercados operables: " + ", ".join(allowed) + "."
        elif blocked:
            route_detail = "Mercados bloqueados: " + ", ".join(blocked) + "."
        else:
            route_detail = "Esperando snapshot realtime."
    if safe_mode != "-":
        route_detail += f" Modo {safe_mode}."
    if recommended_action != "-":
        route_detail += f" Accion: {recommended_action}"
    if top_symbol != "-":
        route_detail += f" Top {top_symbol}"
        if top_gate != "-":
            route_detail += f" | {top_gate}"
        route_detail += "."
    if operational_focus_active:
        route_detail += f" Foco {operational_focus_symbol}"
        if operational_focus_source != "-":
            route_detail += f" | {operational_focus_source}"
        if operational_focus_reason != "-":
            route_detail += f" | {operational_focus_reason.rstrip('. ')}"
        route_detail += "."
    if daily_plan_top_symbol != "-":
        route_detail += f" Plan {daily_plan_top_symbol}"
        if daily_plan_top_stage != "-":
            route_detail += f" | {daily_plan_top_stage}"
        if daily_plan_top_probability is not None:
            route_detail += f" | {daily_plan_top_probability:.0f}%"
        if operational_focus_active:
            route_detail += " | alineado al foco" if daily_plan_matches_focus else " | distinto al foco operativo"
        elif top_symbol != "-":
            route_detail += " | alineado" if daily_plan_matches_top else " | distinto al top snapshot"
        route_detail += "."
    daily_counts = []
    if daily_plan_operar_ahora is not None:
        daily_counts.append(f"operar {int(daily_plan_operar_ahora)}")
    if daily_plan_proxima_entrada is not None:
        daily_counts.append(f"proximas {int(daily_plan_proxima_entrada)}")
    if daily_plan_vigilar is not None:
        daily_counts.append(f"vigilar {int(daily_plan_vigilar)}")
    if daily_counts:
        route_detail += " Plan 24h " + ", ".join(daily_counts)
        if daily_plan_total is not None:
            route_detail += f" / total {int(daily_plan_total)}"
        route_detail += "."
    if not allowed and blocked:
        tone = "avoid"
    elif blocked:
        tone = "watch"
    elif allowed:
        tone = "buy"
    else:
        tone = "watch"
    return {
        "label": route_label,
        "tone": tone,
        "detail": route_detail,
        "allowed_markets": allowed,
        "blocked_markets": blocked,
        "safe_mode": safe_mode,
        "recommended_action": recommended_action,
        "top_symbol": top_symbol,
        "top_gate": top_gate,
        "operational_focus_symbol": operational_focus_symbol,
        "operational_focus_source": operational_focus_source,
        "operational_focus_reason": operational_focus_reason,
        "operational_focus_overrides_top": operational_focus_overrides_top,
        "daily_plan_top_symbol": daily_plan_top_symbol,
        "daily_plan_top_stage": daily_plan_top_stage,
        "daily_plan_top_probability": daily_plan_top_probability,
        "daily_plan_total": int(daily_plan_total) if daily_plan_total is not None else None,
        "daily_plan_operar_ahora": (int(daily_plan_operar_ahora) if daily_plan_operar_ahora is not None else None),
        "daily_plan_proxima_entrada": (
            int(daily_plan_proxima_entrada) if daily_plan_proxima_entrada is not None else None
        ),
        "daily_plan_vigilar": int(daily_plan_vigilar) if daily_plan_vigilar is not None else None,
        "daily_plan_matches_top": daily_plan_matches_top,
        "daily_plan_matches_focus": daily_plan_matches_focus,
    }


def status_snapshot_market_gate(status: dict[str, Any] | None, market: Any, symbol: Any = "") -> dict[str, Any]:
    route = status_snapshot_route_summary(status)
    normalized_market = normalize_command_market(market, symbol)
    market_label = normalized_market.upper()
    allowed = {text_display(item).upper() for item in route.get("allowed_markets", [])}
    blocked = {text_display(item).upper() for item in route.get("blocked_markets", [])}
    symbol_label = text_display(symbol).upper()
    if market_label in blocked:
        detail = (
            f"{symbol_label} esta en {market_label}, pero la ruta realtime actual bloquea ese mercado. "
            f"{text_display(route.get('detail'))}"
        )
        return {
            "label": "Mercado bloqueado",
            "tone": "avoid",
            "detail": detail,
            "blocked": True,
            "allowed": False,
            "market": market_label,
            "symbol": symbol_label,
            "route_label": route.get("label"),
        }
    if allowed and market_label not in allowed:
        detail = (
            f"{symbol_label} no esta dentro de los mercados permitidos ahora ({', '.join(sorted(allowed))}). "
            f"{text_display(route.get('detail'))}"
        )
        return {
            "label": "Fuera de ruta",
            "tone": "avoid",
            "detail": detail,
            "blocked": True,
            "allowed": False,
            "market": market_label,
            "symbol": symbol_label,
            "route_label": route.get("label"),
        }
    if allowed:
        return {
            "label": "Ruta permitida",
            "tone": "buy",
            "detail": f"{symbol_label} puede analizarse dentro de la ruta {text_display(route.get('label'))}.",
            "blocked": False,
            "allowed": True,
            "market": market_label,
            "symbol": symbol_label,
            "route_label": route.get("label"),
        }
    return {
        "label": "Ruta sin confirmar",
        "tone": "watch",
        "detail": "No hay snapshot de mercados permitido/bloqueado; confirmar realtime antes de operar.",
        "blocked": False,
        "allowed": False,
        "market": market_label,
        "symbol": symbol_label,
        "route_label": route.get("label"),
    }


def render_market_realtime_route(summary: dict[str, Any] | None) -> str:
    summary = summary or {}
    tone = text_display(summary.get("tone"))
    if tone not in {"buy", "watch", "avoid", "neutral"}:
        tone = "watch"
    allowed = summary.get("allowed_markets") if isinstance(summary.get("allowed_markets"), list) else []
    blocked = summary.get("blocked_markets") if isinstance(summary.get("blocked_markets"), list) else []

    def chips(values: list[Any], class_name: str) -> str:
        return "".join(
            f'<span class="{class_name}">{html.escape(text_display(value))}</span>'
            for value in values
            if text_display(value) != "-"
        )

    return (
        f'<section class="market-route market-route-{html.escape(tone)}">'
        '<div class="market-route-head">'
        '<span>Ruta realtime</span>'
        f'<strong>{html.escape(text_display(summary.get("label")))}</strong>'
        "</div>"
        f'<p>{html.escape(text_display(summary.get("detail")))}</p>'
        '<div class="market-route-chips">'
        f'{chips(allowed, "route-chip route-chip-buy")}'
        f'{chips(blocked, "route-chip route-chip-avoid")}'
        "</div>"
        "</section>"
    )


def realtime_data_readiness_status(
    freshness: dict[str, Any] | None,
    provider_status: dict[str, Any] | None,
    provider_env_status: dict[str, Any] | None = None,
) -> dict[str, Any]:
    freshness = dict(freshness or {})
    provider_status = dict(provider_status or {})
    provider_env_status = dict(provider_env_status or {})
    fresh_label = text_display(freshness.get("label"))
    fresh_tone = text_display(freshness.get("tone"))
    provider_label = text_display(provider_status.get("label"))
    provider_tone = text_display(provider_status.get("tone"))
    provider_detail = text_display(provider_status.get("detail"))
    env_label = text_display(provider_env_status.get("label"))
    alpaca_auth_ok = provider_env_status.get("alpaca_account_auth_ok")
    alpaca_probe_status = text_display(provider_env_status.get("alpaca_account_probe_status"))
    alpaca_error_category = text_display(provider_env_status.get("alpaca_account_error_category"))
    alpaca_mode = text_display(provider_env_status.get("alpaca_account_mode"))
    alpaca_endpoint = text_display(provider_env_status.get("alpaca_expected_endpoint"))
    fallback_count = int(provider_status.get("fallback_count") or 0)
    auth_fallback_count = int(provider_status.get("auth_fallback_count") or 0)
    checked_count = int(provider_status.get("checked_count") or 0)
    operable_market_issue_count = int(provider_status.get("operable_market_issue_count") or 0)
    route_focus_label = text_display(provider_status.get("route_focus_label"))

    if fresh_tone == "avoid" or fresh_label in {"Sin datos", "Estancados"}:
        return {
            "label": "Datos parados",
            "tone": "avoid",
            "detail": f"Archivos live no estan listos: {text_display(freshness.get('detail'))}",
        }

    blocked_market_issue_count = int(provider_status.get("blocked_market_issue_count") or 0)
    if auth_fallback_count and blocked_market_issue_count > 0 and operable_market_issue_count == 0:
        route_text = (
            route_focus_label
            if route_focus_label and route_focus_label != "-"
            else "Crypto operable; stock/options bloqueado"
        )
        return {
            "label": "Crypto operable",
            "tone": "watch",
            "detail": (
                f"Datos frescos y {route_text}; proveedor premium bloquea stock/options "
                f"({auth_fallback_count}/{checked_count or '-'})."
            ),
        }

    if auth_fallback_count:
        return {
            "label": "Premium bloqueado",
            "tone": "avoid",
            "detail": (
                f"Datos frescos, pero proveedor premium en auth/permisos "
                f"({auth_fallback_count}/{checked_count or '-'}); Roxy opera en fallback."
            ),
        }

    if fallback_count:
        return {
            "label": "Fallback live",
            "tone": "watch",
            "detail": (
                f"Datos frescos, pero {fallback_count}/{checked_count or '-'} graficas usan fallback. "
                "Validar fuente antes de operar."
            ),
        }

    if alpaca_auth_ok is False:
        detail = f"Datos frescos y fuente efectiva OK; premium requiere revisar Alpaca ({env_label})."
        if alpaca_probe_status and alpaca_probe_status != "-":
            detail += f" Probe {alpaca_probe_status}."
        if alpaca_error_category and alpaca_error_category != "-":
            detail += f" Error {alpaca_error_category}."
        if alpaca_mode and alpaca_mode != "-":
            detail += f" Modo {alpaca_mode}."
        if alpaca_endpoint and alpaca_endpoint != "-":
            detail += f" Endpoint {alpaca_endpoint}."
        return {
            "label": "Premium revisar",
            "tone": "watch",
            "detail": detail,
        }

    if provider_tone == "buy" and fresh_tone == "buy":
        return {
            "label": "Premium live",
            "tone": "buy",
            "detail": f"Frescura OK y fuente efectiva OK. Env: {env_label}.",
        }

    if provider_label == "Sin check" or not provider_status:
        return {
            "label": "Sin fuente RT",
            "tone": "watch" if fresh_tone == "buy" else "avoid",
            "detail": f"Datos {fresh_label}; falta check de fuente efectiva.",
        }

    return {
        "label": provider_label,
        "tone": provider_tone if provider_tone in {"buy", "watch", "avoid", "neutral"} else "watch",
        "detail": provider_detail,
    }


def chart_realtime_watch_rows(report: dict[str, Any] | None, *, limit: int = 6) -> list[dict[str, Any]]:
    report = report or {}
    charts = report.get("charts") if isinstance(report.get("charts"), list) else []
    rows: list[dict[str, Any]] = []
    for chart in charts:
        if not isinstance(chart, dict):
            continue
        status = text_display(chart.get("status")).upper()
        label = text_display(chart.get("label"))
        cadence_lag = safe_float(chart.get("cadence_lag_minutes"))
        health_lag = safe_float(chart.get("health_lag_minutes"))
        age = safe_float(chart.get("age_minutes"))
        next_update = safe_float(chart.get("next_expected_update_in_minutes"))
        symbol = text_display(chart.get("symbol"))
        timeframe = text_display(chart.get("timeframe"))
        if not symbol or symbol == "-":
            continue
        if not timeframe or timeframe == "-":
            timeframe = "?"
        priority = 0
        if status == "FAIL":
            priority += 500
        elif status == "WARN":
            priority += 200
        if label == "Estancada":
            priority += 80
        if cadence_lag is not None and cadence_lag > 0:
            priority += min(60, int(cadence_lag))
        if health_lag is not None and health_lag > 0:
            priority += min(40, int(health_lag))
        rows.append(
            {
                "symbol": symbol,
                "timeframe": timeframe,
                "estado": label,
                "status": status or "-",
                "edad_min": age,
                "proxima_vela_min": next_update,
                "lag_min": cadence_lag,
                "health_lag_min": health_lag,
                "detalle": text_display(chart.get("detail")),
                "tone": "avoid" if status == "FAIL" else "watch" if status == "WARN" else "buy",
                "_priority": priority,
            }
        )
    rows.sort(
        key=lambda row: (
            int(row.get("_priority") or 0),
            safe_float(row.get("edad_min")) or 0.0,
        ),
        reverse=True,
    )
    return [{key: value for key, value in row.items() if key != "_priority"} for row in rows[: max(1, int(limit))]]






def normalize_realtime_refresh_interval(value: Any, *, default: int = DEFAULT_REALTIME_REFRESH_SECONDS) -> int:
    try:
        interval = int(value)
    except (TypeError, ValueError):
        interval = int(default)
    allowed = sorted({int(item) for item in REALTIME_REFRESH_SECONDS})
    if interval in allowed:
        return interval
    return min(allowed, key=lambda item: abs(item - interval))


def build_realtime_refresh_script(interval_seconds: Any) -> str:
    interval = normalize_realtime_refresh_interval(interval_seconds)
    return f"""
    <script>
    (() => {{
        const legacyTimerKeys = [
            "__roxyRealtimeRefreshTimer",
            "__roxyRealtimeRefreshInterval",
            "__roxyAutoRefreshTimer",
            "__roxyAutoRefreshInterval",
            "__streamlitAutorefreshTimer",
            "__streamlitAutorefreshInterval"
        ];
        const getRoot = () => {{
            try {{
                return window.parent && window.parent !== window ? window.parent : window;
            }} catch (error) {{
                return window;
            }}
        }};
        const root = getRoot();
        try {{
            legacyTimerKeys.forEach((key) => {{
                const handle = root[key];
                if (handle) {{
                    root.clearTimeout(handle);
                    root.clearInterval(handle);
                }}
                root[key] = null;
            }});
            root.__roxyRealtimeRefreshMode = "streamlit-fragment";
            root.__roxyRealtimeRefreshSeconds = {interval};
            root.__roxyRealtimeRefreshReloadBlocked = true;
        }} catch (error) {{}}
    }})();
    </script>
    """


def realtime_refresh_dashboard_status(realtime: dict[str, Any] | None) -> dict[str, Any]:
    realtime = realtime or {}
    enabled = bool(realtime.get("enabled"))
    interval = normalize_realtime_refresh_interval(realtime.get("interval_seconds"))
    if enabled:
        mode = text_display(realtime.get("mode") or "streamlit_fragment")
        return {
            "label": "Live sin reload",
            "tone": "buy",
            "detail": f"{interval}s | {mode} | sin recargar pagina ni pantalla negra",
        }
    return {"label": "OFF", "tone": "watch", "detail": "manual sin auto-refresh"}


def live_ops_strip_rows(
    *,
    operational_mode_status: dict[str, Any],
    freshness_status: dict[str, Any],
    realtime_refresh_status: dict[str, Any],
    chart_health_status: dict[str, Any],
    chart_provider_status: dict[str, Any],
    alert_quality_status: dict[str, Any],
    operational_logs_status: dict[str, Any],
    check_status: dict[str, Any],
    dashboard_ui_status: dict[str, Any] | None = None,
    market_route_status: dict[str, Any] | None = None,
    generated_at: Any = None,
) -> list[dict[str, str]]:
    def row(label: str, value: Any, status: dict[str, Any] | None = None, detail: Any = None) -> dict[str, str]:
        status = status or {}
        tone = text_display(status.get("tone") or "neutral")
        return {
            "label": label,
            "value": text_display(value),
            "tone": tone if tone in {"buy", "watch", "avoid", "neutral"} else "neutral",
            "detail": text_display(detail if detail is not None else status.get("detail")),
        }

    rows = [
        row("Modo", operational_mode_status.get("label"), operational_mode_status),
        row("Datos", freshness_status.get("label"), freshness_status),
        row("Refresh", realtime_refresh_status.get("label"), realtime_refresh_status),
    ]
    if dashboard_ui_status:
        rows.append(row("UI live", dashboard_ui_status.get("label"), dashboard_ui_status))
    rows.extend(
        [
            row("Graficas", chart_health_status.get("label"), chart_health_status),
            row("Proveedor", chart_provider_status.get("label"), chart_provider_status),
        ]
    )
    if market_route_status:
        rows.append(row("Ruta", market_route_status.get("label"), market_route_status))
    rows.extend(
        [
            row("Alertas", alert_quality_status.get("label"), alert_quality_status),
            row("Logs", operational_logs_status.get("label"), operational_logs_status),
            row("Check", check_status.get("label"), check_status, generated_at or check_status.get("detail")),
        ]
    )
    return rows


def render_live_ops_strip(rows: list[dict[str, str]]) -> str:
    cards = []
    for item in rows:
        tone = text_display(item.get("tone") or "neutral")
        cards.append(
            f'<div class="live-ops-card live-ops-card-{html.escape(tone)}">'
            f'<span>{html.escape(text_display(item.get("label")))}</span>'
            f'<strong>{html.escape(text_display(item.get("value")))}</strong>'
            f'<small>{html.escape(text_display(item.get("detail")))}</small>'
            "</div>"
        )
    return (
        '<section class="live-ops-strip">'
        "<header><strong>Operacion en vivo</strong><span>Status recalculado por fragment refresh sin recargar pagina</span></header>"
        f'<div class="live-ops-grid">{"".join(cards)}</div>'
        "</section>"
    )


def configure_realtime_refresh() -> dict[str, Any]:
    st.sidebar.markdown("**Tiempo real**")
    enabled = st.sidebar.toggle("Live sin reload", value=True, key="roxy_realtime_enabled")
    interval = st.sidebar.selectbox(
        "Intervalo",
        REALTIME_REFRESH_SECONDS,
        index=REALTIME_REFRESH_SECONDS.index(DEFAULT_REALTIME_REFRESH_SECONDS),
        format_func=lambda value: f"{value}s",
        key="roxy_realtime_interval",
    )
    interval = normalize_realtime_refresh_interval(interval)
    st.sidebar.caption("Actualiza datos y graficas sin recargar el navegador, pantalla negra ni cambio de vista.")
    if enabled:
        st.components.v1.html(build_realtime_refresh_script(interval), height=0)
    return {"enabled": enabled, "interval_seconds": int(interval), "mode": "streamlit_fragment"}


def show_focused_sidebar() -> None:
    state = live_service_state()
    channels = notifier.configured_channels()
    st.sidebar.title("Roxy")
    st.sidebar.caption("SMA 20/40/100/200 + 15m/1h/2h/4h")
    st.sidebar.markdown("**Estado operativo**")
    st.sidebar.write(f"Escaner 24h: `{'ON' if state['loaded'] == 'yes' else 'OFF'}`")
    st.sidebar.write("Alertas: `" + (", ".join(channels) if channels else "archivo local") + "`")
    st.sidebar.write("Watchlist IA/dev: `data/watchlist_ai_core.txt`")
    st.sidebar.markdown("**Regla principal**")
    st.sidebar.write(
        "Solo alertar cuando 1h confirma, 15m da entrada, volumen acompana, riesgo <= 3.5% y target 2% es viable."
    )
    with st.sidebar.expander("Configuracion avanzada", expanded=False):
        st.write(f"Instalado: `{state['installed']}`")
        st.write(f"Activo: `{state['loaded']}`")
        st.write("Email: `SMTP_HOST` + `ALERT_EMAIL_TO`")
        st.write("Discord: `DISCORD_WEBHOOK_URL`")
        st.write("Pushover: `PUSHOVER_APP_TOKEN` + `PUSHOVER_USER_KEY`")
        st.write("Telegram: `TELEGRAM_BOT_TOKEN` + `TELEGRAM_CHAT_ID`")
        st.write("Slack: `SLACK_WEBHOOK_URL`")
        st.write("Webhook: `WEBHOOK_URL`")
        st.write("Mac: `MACOS_NOTIFICATIONS=1`")
        st.write("Estrategias: `" + "`, `".join(study_strategy_names()) + "`")
    username = text_display(st.session_state.get("user")).strip().lower()
    if username and username != "__roxy_diagnostic_probe__":
        with st.sidebar.expander("Seguridad de cuenta", expanded=False):
            security_message = str(st.session_state.pop("roxy_account_security_message", "") or "").strip()
            if security_message:
                st.success(security_message)
            with st.form("roxy_change_password_form", clear_on_submit=True):
                current_password = st.text_input(
                    "Contrasena actual",
                    type="password",
                    key="roxy_change_password_current",
                )
                new_password = st.text_input(
                    "Nueva contrasena",
                    type="password",
                    key="roxy_change_password_new",
                )
                confirmation = st.text_input(
                    "Confirmar nueva contrasena",
                    type="password",
                    key="roxy_change_password_confirmation",
                )
                change_submitted = st.form_submit_button("Actualizar contrasena")
                if change_submitted:
                    ok, message = roxy_change_password(
                        username,
                        current_password,
                        new_password,
                        confirmation,
                    )
                    if ok:
                        st.session_state["roxy_account_security_message"] = message
                        st.rerun()
                    st.error(message)


def show_ai_status_cards(
    *,
    scan_df: pd.DataFrame,
    confluence_df: pd.DataFrame,
    options_df: pd.DataFrame,
    daily_path: str | None,
    live_path: str | None,
    confluence_path: str | None,
    options_path: str | None,
    brief: dict,
    show_technical_reports: bool | None = None,
) -> None:
    state = live_service_state()
    alerts = int(brief.get("alert_count", 0) or 0)
    opportunities = brief.get("opportunities", [])
    best = opportunities[0] if opportunities else {}
    freshness = data_freshness_status([live_path, confluence_path], max_age_minutes=10.0)
    heartbeat = read_summary_json("alerts/ma_live_heartbeat.json")
    backend = live_backend_status(live_path, confluence_path, service_state=state, heartbeat=heartbeat)
    realtime_check = read_summary_json("alerts/roxy_realtime_check.json")
    check_status = realtime_check_status(realtime_check)
    autoheal_status = autoheal_dashboard_status(realtime_check)
    maintenance_report = read_summary_json("alerts/output_maintenance.json")
    maintenance_status = output_maintenance_dashboard_status(realtime_check, maintenance_report)
    runtime_backup_report = read_summary_json("alerts/runtime_backup.json")
    runtime_backup_daemon = read_summary_json("alerts/runtime_backup_daemon_heartbeat.json")
    runtime_backup_status = runtime_backup_dashboard_status(
        realtime_check, runtime_backup_report, runtime_backup_daemon
    )
    streamlit_service_status = realtime_report_check_card(
        realtime_check,
        "streamlit_service_24h",
        ok_label="24h ON",
        missing_label="Sin check",
    )
    daily_service_status = realtime_report_check_card(
        realtime_check,
        "daily_service",
        ok_label="Programado",
        missing_label="Sin check",
    )
    health_watchdog_status = realtime_report_check_card(
        realtime_check,
        "health_watchdog_service",
        ok_label="Vigilando",
        missing_label="Sin check",
    )
    lock_status = realtime_lock_dashboard_status(read_summary_json("alerts/roxy_realtime_lock.json"))
    health_notify_status = health_notify_dashboard_status(read_summary_json("alerts/roxy_health_notify_state.json"))
    health_history = load_health_history()
    health_history_status = (
        stability_summary_dashboard_status(realtime_check.get("stability_summary"))
        if isinstance(realtime_check.get("stability_summary"), dict)
        else health_history_dashboard_status(health_history, current_report=realtime_check)
    )
    mac_disk_status = disk_dashboard_status(Path.home())
    mac_storage_status = mac_storage_pressure_dashboard_status(realtime_check, mac_disk_status)
    local_media_status = local_training_media_dashboard_status(realtime_check)
    external_disk_status = disk_dashboard_status("/Volumes/RoxyData", warn_free_gb=100.0, fail_free_gb=20.0)
    gate_summary = brief.get("alert_gate_summary") or summarize_alert_gates(brief)
