def show_focused_controls() -> None:
    control_cols = st.columns([1, 1, 1, 1, 1.2, 1])
    with control_cols[0]:
        if st.button("Live completo", key="focused_run_full_live"):
            with st.spinner("Corriendo scan live y reconstruyendo brief IA..."):
                code_scan, output_scan = run_local_command(["tools/ma_live.py", "--once"])
                code_brief, output_brief = (
                    run_local_command(["tools/roxy_ai_watch.py", "--notify"]) if code_scan == 0 else (1, "")
                )
            if code_scan == 0 and code_brief == 0:
                st.success("Live completo actualizado")
            else:
                st.error("Live completo fallo")
            output = "\n".join(item for item in [output_scan, output_brief] if item)
            if output:
                st.code(output[-7000:])
    with control_cols[1]:
        if st.button("Escanear live ahora", key="focused_run_live"):
            with st.spinner("Corriendo scan intradia, confluencia, opciones y lectura IA..."):
                code, output = run_local_command(["tools/ma_live.py", "--once"])
            if code == 0:
                st.success("Scan live completado")
            else:
                st.error("Scan live fallo")
            if output:
                st.code(output[-5000:])
    with control_cols[2]:
        if st.button("Actualizar brief IA", key="focused_refresh_ai"):
            with st.spinner("Construyendo brief IA..."):
                code, output = run_local_command(["tools/roxy_ai_watch.py", "--notify"])
            if code == 0:
                st.success("Brief IA actualizado")
            else:
                st.error("Brief IA fallo")
            if output:
                st.code(output[-3000:])
    with control_cols[3]:
        if st.button("Activar 24h", key="focused_enable_24h"):
            with st.spinner("Instalando servicio 24h de macOS..."):
                code, output = run_local_command(
                    [
                        "tools/ma_live_launchd.py",
                        "install",
                        "--stock-intervals",
                        "15m,1h,2h,4h",
                        "--crypto-timeframes",
                        "15m,1h,2h,4h",
                        "--poll-seconds",
                        "300",
                        "--limit",
                        "30",
                        "--report-limit",
                        "12",
                        "--retention-count",
                        "96",
                        "--health-check",
                        "--health-app-url",
                        "http://127.0.0.1:3000",
                        "--health-chart-symbol",
                        "AAPL",
                        "--health-chart-timeframe",
                        "1h",
                    ]
                )
            if code == 0:
                st.success("Escaner 24h activado")
            else:
                st.error("No se pudo activar el escaner 24h")
            if output:
                st.code(output[-5000:])
    with control_cols[4]:
        if st.button("Detener 24h", key="focused_stop_24h"):
            with st.spinner("Deteniendo servicio 24h..."):
                code, output = run_local_command(["tools/ma_live_launchd.py", "uninstall"])
            if code == 0:
                st.success("Escaner 24h detenido")
            else:
                st.error("No se pudo detener el escaner 24h")
            if output:
                st.code(output[-3000:])
    with control_cols[5]:
        if st.button("Verificar RT", key="focused_realtime_check"):
            with st.spinner("Verificando pipeline realtime..."):
                code, output = run_local_command(
                    [
                        "tools/roxy_realtime_check.py",
                        "--app-url",
                        "http://127.0.0.1:3000",
                        "--chart-symbol",
                        "AAPL",
                        "--chart-timeframe",
                        "1h",
                        "--no-fail",
                    ]
                )
            if code == 0:
                st.success("Verificacion RT actualizada")
            else:
                st.error("Verificacion RT fallo antes de escribir reporte")
            if output:
                st.code(output[-5000:])


def watch_movement_label(row: dict) -> str:
    signal = str(row.get("signal") or "").upper()
    decision = str(row.get("trade_decision") or row.get("decision") or "").upper()
    trigger = str(row.get("trigger_setup") or row.get("trigger") or row.get("setup") or "").upper()
    trend = str(row.get("trend_setup") or row.get("trend") or "").upper()
    action = str(row.get("ai_action") or row.get("action") or "").upper()
    alert_movement = str(row.get("alert_movement") or row.get("movement") or "").strip()
    if action == "ALERT" or (signal == "BUY" and decision.startswith("TRADE_FOR")):
        return "BUY porque 15m/1h confirman, riesgo esta medido y target minimo es viable."
    if alert_movement:
        return alert_movement
    if "RISK_REWARD" in decision:
        return "Esperar mejor riesgo/beneficio: stop mas cerca o target minimo 2% viable."
    if "PULLBACK" in {trigger, trend}:
        return "Esperar rebote en SMA20/SMA40 con cierre verde y volumen."
    if "TREND_CONTINUATION" in {trigger, trend}:
        return "Esperar continuacion: cierre sobre SMA20 y ruptura del maximo reciente."
    if "EARLY_UPTREND" in {trigger, trend}:
        return "Esperar cruce confirmado: SMA20 sobre SMA40 y 1h sosteniendo tendencia."
    if "DOWNTREND" in {trigger, trend}:
        return "AVOID porque la estructura sigue bajista; esperar recuperacion sobre SMA200."
    if signal == "AVOID" or decision.startswith("NO_TRADE"):
        return "AVOID porque no hay confluencia BUY; esperar que vuelva a WATCH/BUY."
    if signal == "WATCH" or decision == "WAIT":
        return "Esperar 15m en BUY, 1h confirmando y volumen acompanando."
    return "Esperar setup mas claro antes de operar."


def opportunity_reason_label(row: dict) -> str:
    signal = str(row.get("signal") or "").upper()
    decision = str(row.get("trade_decision") or row.get("decision") or "").upper()
    trigger = str(row.get("trigger_setup") or row.get("trigger") or "").upper()
    trend = str(row.get("trend_setup") or row.get("trend") or "").upper()
    risk_pct = safe_float(row.get("risk_pct"))
    target_pct = safe_float(row.get("recommended_target_pct") or row.get("target_pct"))

    if opportunity_is_trade_ready(row):
        parts = ["BUY: confluencia activa"]
        if trigger:
            parts.append(trigger.replace("_", " ").title())
        if risk_pct is not None:
            parts.append(f"riesgo {risk_pct * 100:.2f}%")
        if target_pct is not None:
            parts.append(f"target {target_pct * 100:.0f}% viable")
        return " | ".join(parts[:4])

    if "RISK_REWARD" in decision:
        return "NO: el riesgo/beneficio no compensa el stop actual."
    if "DOWNTREND" in {trigger, trend}:
        return "AVOID: estructura bajista; primero debe recuperar medias largas."
    if signal == "AVOID" or decision.startswith("NO_TRADE"):
        return "AVOID: falta confluencia BUY entre tendencia, entrada y riesgo."
    if signal == "WATCH" or decision == "WAIT":
        return f"WATCH: {watch_movement_label(row)}"
    return "WAIT: falta un setup mas limpio."


def opportunity_change_label(row: dict) -> str:
    signal = str(row.get("signal") or "").upper()
    decision = str(row.get("trade_decision") or row.get("decision") or "").upper()
    trigger = str(row.get("trigger_setup") or row.get("trigger") or "").upper()
    trend = str(row.get("trend_setup") or row.get("trend") or "").upper()
    risk_pct = safe_float(row.get("risk_pct"))
    target_pct = safe_float(row.get("recommended_target_pct") or row.get("target_pct"))

    if opportunity_is_trade_ready(row):
        return "Mantener solo si respeta stop, 15m sigue BUY y volumen no se apaga."
    if "RISK_REWARD" in decision:
        return "Cambia si el stop queda mas cerca o el target minimo 2% vuelve a ser viable."
    if "DOWNTREND" in {trigger, trend}:
        return "Cambia si recupera SMA200 y 1h deja de marcar tendencia bajista."

    needed = []
    if signal != "BUY":
        needed.append("15m en BUY")
    if decision in {"", "WAIT"} or signal == "WATCH":
        needed.append("1h confirmando")
    if risk_pct is None or risk_pct > 0.035:
        needed.append("riesgo <= 3.5%")
    if target_pct is None or target_pct < 0.02:
        needed.append("target 2% viable")
    if not needed:
        needed.append("cierre fuerte con volumen")
    return "Necesita " + " + ".join(needed[:3]) + "."


def opportunity_confidence_label(row: dict) -> str:
    readiness = safe_float(row.get("alert_readiness_score") or row.get("readiness"))
    bias = str(row.get("learning_bias") or "").lower()
    memory_note = str(row.get("memory_note") or "")

    if bias == "positive" and readiness is not None and readiness >= 80:
        return "Alta: memoria positiva y checklist fuerte."
    if bias == "negative":
        return "Baja: memoria historica exige filtro extra."
    if bias == "shadow_positive":
        return "Media+: laboratorio WATCH mejora, falta muestra real."
    if bias == "shadow_negative":
        return "Baja: laboratorio WATCH exige filtro extra."
    if bias == "learning" or "no hay suficientes" in memory_note.lower():
        return "Aprendiendo: falta muestra cerrada."
    if readiness is not None and readiness >= 70:
        return "Media: checklist parcial, confirmar entrada."
    if readiness is not None:
        return "Baja: faltan condiciones del checklist."
    return "Sin memoria suficiente."


def focused_opportunity_source_rows(brief: dict) -> list[dict[str, Any]]:
    """Return candidate rows for the trade desk, even when the primary list is empty."""
    brief = brief if isinstance(brief, dict) else {}
    candidates: list[dict[str, Any]] = []
    primary = brief.get("opportunities")
    if isinstance(primary, list):
        candidates.extend(item for item in primary if isinstance(item, dict))

    plan = brief.get("daily_opportunity_plan") if isinstance(brief.get("daily_opportunity_plan"), dict) else {}
    for key in ("opportunities", "rows"):
        values = plan.get(key)
        if isinstance(values, list):
            candidates.extend(item for item in values if isinstance(item, dict))

    crypto_candidates = brief.get("crypto_scan_candidates")
    if isinstance(crypto_candidates, list):
        candidates.extend(item for item in crypto_candidates if isinstance(item, dict))

    source_files = brief.get("source_files") if isinstance(brief.get("source_files"), dict) else {}
    confluence_path = text_display(source_files.get("confluence"))
    if confluence_path != "-":
        try:
            confluence_file = Path(confluence_path)
            if confluence_file.exists():
                confluence = pd.read_csv(confluence_file)
                candidates.extend(confluence.head(80).to_dict("records"))
        except Exception:
            pass

    normalized: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str]] = set()
    for item in candidates:
        row = dict(item)
        symbol = text_display(row.get("symbol")).upper()
        if symbol == "-":
            continue
        market = normalize_command_market(row.get("market"), symbol)
        timeframe = text_display(row.get("timeframe") or row.get("tf") or row.get("entry_tf") or "1h")
        key = (symbol, market, timeframe)
        if key in seen:
            continue
        seen.add(key)
        action = text_display(row.get("action") or row.get("trade_decision")).upper()
        signal = text_display(row.get("signal") or row.get("raw_signal")).upper()
        if not row.get("ai_action"):
            if action.startswith("ENTER") or action.startswith("TRADE"):
                row["ai_action"] = "ALERT"
            elif action.startswith("NO_TRADE") or signal == "AVOID":
                row["ai_action"] = "WATCH"
            else:
                row["ai_action"] = "WATCH"
        row["action"] = row.get("ai_action") or row.get("action")
        row["market"] = market
        row["symbol"] = symbol
        row["timeframe"] = timeframe
        row["signal"] = "AVOID" if action.startswith("NO_TRADE") else (signal if signal != "-" else "WATCH")
        row["trade_decision"] = row.get("trade_decision") or ("NO_TRADE" if action.startswith("NO_TRADE") else action)
        row["ai_score"] = row.get("ai_score") or row.get("confluence_score") or row.get("score") or row.get("trend_score")
        row["current_price"] = (
            row.get("current_price")
            or row.get("latest_price")
            or row.get("close")
            or row.get("close_15m")
            or row.get("close_1h")
            or row.get("entry")
        )
        row["recommended_target_price"] = (
            row.get("recommended_target_price")
            or row.get("target_2pct_price")
            or row.get("target_2r")
            or row.get("target_price")
        )
        row["recommended_target_pct"] = row.get("recommended_target_pct") or row.get("target_pct") or 0.02
        row["alert_readiness_score"] = (
            row.get("alert_readiness_score")
            or row.get("readiness")
            or row.get("trigger_score")
            or row.get("confluence_score")
            or row.get("ai_score")
        )
        row["relative_volume_15m"] = row.get("relative_volume_15m") or row.get("relative_volume") or row.get("rel_volume")
        row["reason"] = row.get("reason") or row.get("reasons") or row.get("exit_plan")
        row["data_bucket"] = row.get("data_bucket") or "Fallback"
        row["data_source"] = row.get("data_source") or "scanner/confluence fallback"
        row["data_gate"] = row.get("data_gate") or "fallback_requires_confirmation"
        normalized.append(row)
    return normalized


def default_deploy_watch_symbols(selected_symbol: str = "", market_scope: str = "Todos", limit: int = 14) -> list[tuple[str, str]]:
    scope = text_display(market_scope).lower()
    symbols: list[tuple[str, str]] = []
    selected = text_display(selected_symbol).upper()
    if selected and selected != "-":
        symbols.append((selected, normalize_command_market("stock", selected)))
    if scope in {"-", "todos", "todo", "all", "acciones", "accion", "stocks", "stock"}:
        symbols.extend((str(symbol).upper(), "stock") for symbol in DEFAULT_STOCK_SYMBOLS)
    seen: set[tuple[str, str]] = set()
    unique: list[tuple[str, str]] = []
    for symbol, market in symbols:
        key = (symbol, market)
        if symbol and symbol != "-" and key not in seen:
            seen.add(key)
            unique.append(key)
    return unique[: max(1, int(limit or 14))]


@st.cache_data(ttl=cache_ttl("market_screen"), show_spinner=False)
def deploy_watchlist_opportunity_seed(
    selected_symbol: str = "",
    market_scope: str = "Todos",
    limit: int = 14,
) -> pd.DataFrame:
    """Build a real-data watch queue when Render has no local scan artifacts yet."""
    rows: list[dict[str, Any]] = []
    for symbol, market in default_deploy_watch_symbols(selected_symbol, market_scope, limit=limit):
        if market != "stock":
            continue
        history = fetch_direct_yfinance_ohlcv(symbol, "1h")
        if history.empty:
            continue
        data = add_central_indicators(
            history.tail(240).copy(),
            config=IndicatorConfig(
                sma_windows=(20, 40, 100, 200),
                ema_windows=(),
                volume_period=40,
            ),
        )
        closes = pd.to_numeric(data["close"], errors="coerce")
        highs = pd.to_numeric(data["high"], errors="coerce")
        lows = pd.to_numeric(data["low"], errors="coerce")
        volumes = pd.to_numeric(data["volume"], errors="coerce").fillna(0)
        current = safe_float(closes.iloc[-1])
        previous = safe_float(closes.iloc[-2]) if len(closes) > 1 else current
        if current is None or current <= 0:
            continue
        sma20 = safe_float(data["sma20"].iloc[-1])
        sma40 = safe_float(data["sma40"].iloc[-1])
        sma100 = safe_float(data["sma100"].iloc[-1])
        sma200 = safe_float(data["sma200"].iloc[-1])
        recent_low = safe_float(lows.tail(20).min()) or current * 0.98
        recent_high = safe_float(highs.tail(20).max()) or current * 1.02
        avg_volume = safe_float(data["volume_sma40"].iloc[-1]) or 0.0
        last_volume = safe_float(volumes.iloc[-1]) or 0.0
        rel_volume = last_volume / avg_volume if avg_volume > 0 else None
        change_pct = ((current - previous) / previous) if previous else 0.0

        above_fast = sma20 is not None and current >= sma20
        trend_up = bool(above_fast and sma40 is not None and sma20 >= sma40)
        long_trend_ok = sma100 is None or current >= sma100 * 0.985
        structure_ok = trend_up and long_trend_ok
        stop_buffer = 0.018 if structure_ok else 0.025
        stop = min(recent_low * 0.997, current * (1 - stop_buffer))
        if stop <= 0 or stop >= current:
            stop = current * (1 - stop_buffer)
        entry = current if structure_ok else min(current * 1.004, max(current, (sma20 or current) * 1.002))
        risk_pct = max(0.006, min(0.034, (entry - stop) / entry))
        stop = entry * (1 - risk_pct)
        target_2 = entry * 1.02
        target_5 = entry * 1.05
        target_10 = entry * 1.10
        readiness = 45.0
        readiness += 18.0 if structure_ok else 0.0
        readiness += 8.0 if change_pct >= 0 else 0.0
        readiness += 7.0 if rel_volume is not None and rel_volume >= 1 else 0.0
        readiness += 7.0 if recent_high and current >= recent_high * 0.985 else 0.0
        readiness = max(35.0, min(82.0, readiness))
        signal = "WATCH"
        decision = "WAIT"
        trend_label = "Canal alcista en vigilancia" if structure_ok else "Esperar recuperacion de medias"
        reason = (
            f"{symbol} tiene precio y niveles medibles; "
            f"{'SMA20/SMA40 alineadas' if structure_ok else 'todavia falta confirmacion de tendencia'}; "
            f"volumen relativo {rel_volume:.2f}x." if rel_volume is not None else
            f"{symbol} tiene precio y niveles medibles; falta confirmar volumen relativo."
        )
        rows.append(
            {
                "symbol": symbol,
                "market": "stock",
                "timeframe": "1h",
                "signal": signal,
                "decision": decision,
                "trade_decision": decision,
                "action": "WATCH",
                "ai_action": "WATCH",
                "ai_score": round(readiness, 2),
                "readiness": round(readiness, 2),
                "alert_readiness_score": round(readiness, 2),
                "current_price": current,
                "latest_price": current,
                "entry": round(entry, 4),
                "stop": round(stop, 4),
                "stop_loss": round(stop, 4),
                "target_2pct_price": round(target_2, 4),
                "target_5pct_price": round(target_5, 4),
                "target_10pct_price": round(target_10, 4),
                "recommended_target_price": round(target_2, 4),
                "recommended_target_pct": 0.02,
                "target_pct": 0.02,
                "risk_pct": round(risk_pct, 5),
                "relative_volume_15m": rel_volume,
                "rel_volume": rel_volume,
                "strategy_family": trend_label,
                "trigger": "WATCHLIST_SEED",
                "trend": "UPTREND_WATCH" if structure_ok else "WAIT_TREND_CONFIRMATION",
                "reason": reason,
                "por_que": reason,
                "raw_reason": reason,
                "waiting_for": "Confirmar 15m BUY, broker/TradingView y que el precio respete la zona antes de entrar.",
                "cambia_si": "Pasa a prioridad si el precio entra en zona con volumen y stop sigue medible.",
                "data_bucket": "Fallback",
                "data_state": "Seed live Render",
                "data_source": "yfinance direct deploy seed",
                "data_gate": "fallback_requires_confirmation",
                "source_memory_bias": "Sin memoria fuente",
                "strategy_source_memory_bias": "Sin memoria setup+fuente",
                "crypto_context_memory_bias": "No aplica",
                "backtest_memory_bias": "Sin backtest",
                "tradingview_confirmation": "Sin webhook",
                "market_event_state": "Sin evento FED/macro",
            }
        )
    if not rows:
        return pd.DataFrame()
    frame = pd.DataFrame(rows)
    frame["_sort"] = pd.to_numeric(frame["readiness"], errors="coerce").fillna(0)
    return frame.sort_values("_sort", ascending=False).drop(columns=["_sort"]).reset_index(drop=True)


def focused_opportunity_table(brief: dict) -> pd.DataFrame:
    rows = []
    memory_summary = (
        brief.get("source_memory_summary")
        or brief.get("paper_source_summary")
        or brief.get("paper_data_source_summary")
        or cached_source_memory_summary()
    )
    source_memory_lookup = source_memory_lookup_from_summary(memory_summary)
    strategy_source_summary = (
        brief.get("strategy_source_memory_summary")
        or brief.get("paper_strategy_source_summary")
        or cached_strategy_source_memory_summary()
    )
    strategy_source_memory_lookup = strategy_source_memory_lookup_from_summary(strategy_source_summary)
    crypto_context_summary = (
        brief.get("crypto_context_memory_summary")
        or brief.get("crypto_paper_context_summary")
        or cached_crypto_context_memory_summary()
    )
    crypto_context_memory_lookup = crypto_context_memory_lookup_from_summary(crypto_context_summary)
    backtest_memory_summary = (
        brief.get("backtest_memory_summary")
        or brief.get("backtest_performance_summary")
        or []
    )
    backtest_memory_lookup = backtest_memory_lookup_from_summary(backtest_memory_summary)
    tradingview_rows_source = brief.get("tradingview_webhooks") or brief.get("tradingview_webhook_rows")
    has_explicit_data_contract = any(
        isinstance(row, dict)
        and any(
            key in row
            for key in (
                "chart_data_contract",
                "live_price_contract",
                "price_data_contract",
                "chart_data_gate",
                "live_price_gate",
                "price_data_gate",
            )
        )
        for row in brief.get("opportunities", [])
    )
    if isinstance(tradingview_rows_source, pd.DataFrame):
        tradingview_rows = tradingview_rows_source
    elif isinstance(tradingview_rows_source, list):
        tradingview_rows = pd.DataFrame([item for item in tradingview_rows_source if isinstance(item, dict)])
    else:
        tradingview_rows = pd.DataFrame()
    macro_context = brief.get("macro_calendar") if isinstance(brief.get("macro_calendar"), dict) else macro_calendar_status()
    for row in focused_opportunity_source_rows(brief):
        option = row.get("option") or {}
        data_source = opportunity_data_source_bucket(row)
        source_memory = source_memory_bias_for_opportunity(row, source_memory_lookup)
        strategy_source_memory = strategy_source_memory_bias_for_opportunity(row, strategy_source_memory_lookup)
        crypto_context_memory = crypto_context_memory_bias_for_opportunity(row, crypto_context_memory_lookup)
        backtest_memory = backtest_memory_bias_for_opportunity(row, backtest_memory_lookup)
        tradingview_confirmation = tradingview_confirmation_bias_for_opportunity(row, rows=tradingview_rows)
        event_guard = market_event_guard(row, macro_context)
        signal = str(row.get("signal") or "").upper()
        decision = str(row.get("trade_decision") or "").upper()
        action = str(row.get("ai_action") or "").upper()
        is_trade = action == "ALERT" or (signal == "BUY" and decision.startswith("TRADE_FOR"))
        is_no_trade = signal == "AVOID" or decision.startswith("NO_TRADE")
        is_watch = not is_trade and not is_no_trade and (signal == "WATCH" or action == "WATCH" or decision == "WAIT")
        raw_focus_priority = 2 if is_trade else 1 if is_watch else 0
        priority_cap = int(data_source.get("priority_cap") or 0)
        if not has_explicit_data_contract and data_source.get("bucket") == "Sin contrato":
            priority_cap = 2
        focus_priority = min(raw_focus_priority, priority_cap)
        focus_priority = max(0, focus_priority + int(source_memory.get("priority_delta") or 0))
        focus_priority = max(0, focus_priority + int(strategy_source_memory.get("priority_delta") or 0))
        focus_priority = max(0, focus_priority + int(crypto_context_memory.get("priority_delta") or 0))
        focus_priority = max(0, focus_priority + int(backtest_memory.get("priority_delta") or 0))
        focus_priority = max(0, focus_priority + int(tradingview_confirmation.get("priority_delta") or 0))
        focus_priority = max(0, focus_priority + int(event_guard.get("priority_delta") or 0))
        rows.append(
            {
                "action": row.get("ai_action"),
                "symbol": row.get("symbol"),
                "market": row.get("market"),
                "ai_score": row.get("ai_score"),
                "signal": row.get("signal"),
                "decision": row.get("trade_decision"),
                "entry": row.get("entry"),
                "current_price": row.get("current_price") or row.get("latest_price") or row.get("last_price") or row.get("last") or row.get("price"),
                "stop": row.get("stop"),
                "risk_pct": row.get("risk_pct"),
                "target_pct": row.get("recommended_target_pct"),
                "target_price": row.get("recommended_target_price"),
                "timeframe": row.get("timeframe") or row.get("tf"),
                "rel_volume": row.get("relative_volume_15m") or row.get("relative_volume"),
                "strategy_family": dashboard_strategy_label(row),
                "trigger": row.get("trigger_setup"),
                "trend": row.get("trend_setup"),
                "option": option.get("contract"),
                "option_score": option.get("score"),
                "gate": alert_gate_label(row.get("alert_gate")),
                "data_state": data_source["state"],
                "data_gate": data_source["gate"],
                "data_source": data_source["source"],
                "data_source_action": data_source["action"],
                "data_bucket": data_source["bucket"],
                "source_memory_bias": source_memory["label"],
                "source_memory_detail": source_memory["detail"],
                "source_memory_action": source_memory["action"],
                "strategy_source_memory_bias": strategy_source_memory["label"],
                "strategy_source_memory_detail": strategy_source_memory["detail"],
                "strategy_source_memory_action": strategy_source_memory["action"],
                "crypto_context_memory_bias": crypto_context_memory["label"],
                "crypto_context_memory_detail": crypto_context_memory["detail"],
                "crypto_context_memory_action": crypto_context_memory["action"],
                "backtest_memory_bias": backtest_memory["label"],
                "backtest_memory_detail": backtest_memory["detail"],
                "backtest_memory_action": backtest_memory["action"],
                "tradingview_confirmation": tradingview_confirmation["label"],
                "tradingview_confirmation_detail": tradingview_confirmation["detail"],
                "tradingview_confirmation_action": tradingview_confirmation["action"],
                "market_event_state": event_guard["state"],
                "market_event_detail": event_guard["detail"],
                "market_event_action": event_guard["action"],
                "market_event_tone": event_guard["tone"],
                "market_event_severity": event_guard["severity"],
                "readiness": row.get("alert_readiness_score"),
                "confidence": opportunity_confidence_label(row),
                "learning_bias": row.get("learning_bias"),
                "raw_reason": row.get("reason"),
                "por_que": human_alert_reason(row) or opportunity_reason_label(row),
                "waiting_for": watch_movement_label(row),
                "cambia_si": opportunity_change_label(row),
                "focus_priority": focus_priority,
            }
        )
    table = pd.DataFrame(rows)
    if table.empty:
        return table
    if "ai_score" in table.columns:
        table["ai_score"] = pd.to_numeric(table["ai_score"], errors="coerce").fillna(0)
    return table.sort_values(["focus_priority", "ai_score"], ascending=[False, False]).reset_index(drop=True)


def market_pulse_rows(table: pd.DataFrame) -> pd.DataFrame:
    columns = [
        "bucket",
        "tone",
        "market",
        "symbol",
        "gate",
        "data_bucket",
        "data_state",
        "data_source",
        "readiness",
        "risk_pct",
        "ai_score",
    ]
    if table.empty:
        return pd.DataFrame(columns=columns)
    has_explicit_data_contract = any(
        text_display(row.get("data_bucket")) in {"Live real", "Fallback", "Bloqueadas"}
        or text_display(row.get("data_gate")) not in {"-", ""}
        or any(
            key in row
            for key in (
                "chart_data_contract",
                "live_price_contract",
                "price_data_contract",
                "chart_data_gate",
                "live_price_gate",
                "price_data_gate",
            )
        )
        for row in table.to_dict("records")
    )
    rows: list[dict[str, Any]] = []
    for _, item in table.iterrows():
        row = item.to_dict()
        action = str(row.get("action") or row.get("ai_action") or "").upper()
        signal = str(row.get("signal") or "").upper()
        decision = str(row.get("decision") or row.get("trade_decision") or "").upper()
        card_status = trade_decision_card_status(row)
        card_action = text_display(card_status.get("action"))
        if action == "ALERT" or opportunity_is_trade_ready(row):
            bucket = "Operar"
            tone = "buy"
        elif signal == "AVOID" or decision.startswith("NO_TRADE"):
            bucket = "Evitar"
            tone = "avoid"
        else:
            bucket = "Vigilar"
            tone = "watch"
        if card_action == "Entrar paper/manual":
            bucket = "Operar"
            tone = "buy"
        elif card_action == "No operar" and (signal == "AVOID" or decision.startswith("NO_TRADE")):
            bucket = "Evitar"
            tone = "avoid"
        elif card_action in {"Esperar confirmacion", "Esperar pullback", "Confirmar externo"}:
            bucket = "Vigilar"
            tone = "watch"
        data_bucket = text_display(row.get("data_bucket"))
        data_state = text_display(row.get("data_state"))
        if data_bucket == "-":
            data_bucket = text_display(opportunity_data_source_bucket(row).get("bucket"))
        if data_state == "-":
            data_state = text_display(opportunity_data_source_status(row).get("state"))
        if bucket == "Operar" and data_bucket == "Fallback":
            bucket = "Vigilar"
            tone = "watch"
        elif bucket == "Operar" and data_bucket == "Bloqueadas":
            bucket = "Evitar"
            tone = "avoid"
        elif bucket == "Operar" and data_bucket == "Sin contrato" and has_explicit_data_contract:
            bucket = "Evitar"
            tone = "avoid"
        rows.append(
            {
                "bucket": bucket,
                "tone": tone,
                "market": text_display(row.get("market")),
                "symbol": text_display(row.get("symbol")).upper(),
                "gate": text_display(row.get("gate")),
                "data_bucket": data_bucket,
                "data_state": data_state,
                "data_source": text_display(row.get("data_source")),
                "readiness": safe_float(row.get("readiness")),
                "risk_pct": safe_float(row.get("risk_pct")),
                "ai_score": safe_float(row.get("ai_score")),
            }
        )
    return pd.DataFrame(rows, columns=columns)


def market_pulse_summary(table: pd.DataFrame) -> dict[str, Any]:
    rows = market_pulse_rows(table)
    if rows.empty:
        return {
            "total": 0,
            "ready": 0,
            "watch": 0,
            "avoid": 0,
            "avg_readiness": None,
            "top_gate": "-",
            "top_market": "-",
            "risk_alerts": 0,
            "live_real": 0,
            "fallback": 0,
            "data_blocked": 0,
            "missing_contract": 0,
        }
    counts = rows["bucket"].value_counts()
    gate_counts = rows[rows["gate"].ne("-")]["gate"].value_counts()
    market_counts = rows[rows["market"].ne("-")]["market"].value_counts()
    data_counts = rows["data_bucket"].value_counts() if "data_bucket" in rows.columns else pd.Series(dtype=int)
    risk_values = pd.to_numeric(rows["risk_pct"], errors="coerce")
    return {
        "total": int(len(rows)),
        "ready": int(counts.get("Operar", 0)),
        "watch": int(counts.get("Vigilar", 0)),
        "avoid": int(counts.get("Evitar", 0)),
        "avg_readiness": safe_float(pd.to_numeric(rows["readiness"], errors="coerce").mean()),
        "top_gate": str(gate_counts.index[0]) if not gate_counts.empty else "-",
        "top_market": str(market_counts.index[0]) if not market_counts.empty else "-",
        "risk_alerts": int(risk_values.gt(0.035).sum()),
        "live_real": int(data_counts.get("Live real", 0)),
        "fallback": int(data_counts.get("Fallback", 0)),
        "data_blocked": int(data_counts.get("Bloqueadas", 0)),
        "missing_contract": int(data_counts.get("Sin contrato", 0)),
    }


def filter_focused_opportunities(
    table: pd.DataFrame,
    *,
    bucket: str = "Todos",
    market: str = "Todos",
    min_readiness: float = 0,
) -> pd.DataFrame:
    if table.empty:
        return table
    pulse = market_pulse_rows(table)
    mask = pd.Series(True, index=table.index)
    if bucket != "Todos":
        mask &= pulse["bucket"].eq(bucket).to_numpy()
    if market != "Todos":
        mask &= pulse["market"].astype(str).str.lower().eq(str(market).lower()).to_numpy()
    readiness = pd.to_numeric(pulse["readiness"], errors="coerce").fillna(0)
    mask &= readiness.ge(float(min_readiness)).to_numpy()
    return table.loc[mask].reset_index(drop=True)


def market_pulse_risk_map(table: pd.DataFrame) -> pd.DataFrame:
    rows = market_pulse_rows(table)
    if rows.empty:
        return pd.DataFrame()
    risk_map = rows.copy()
    risk_map["readiness"] = pd.to_numeric(risk_map["readiness"], errors="coerce")
    risk_map["risk_pct"] = pd.to_numeric(risk_map["risk_pct"], errors="coerce")
    risk_map = risk_map.dropna(subset=["readiness", "risk_pct"])
    if risk_map.empty:
        return risk_map
    risk_map["risk_pct_display"] = risk_map["risk_pct"] * 100.0
    return risk_map


def dashboard_now_reason(row: dict[str, Any], brief: dict[str, Any] | None = None) -> str:
    brief = brief or {}
    if not row:
        return text_display(brief.get("summary") or "Esperar el próximo scan con datos frescos.")
    for key in ("waiting_for", "next", "por_que", "reason", "raw_reason"):
        value = text_display(row.get(key))
        if value != "-":
            return value
    movement = watch_movement_label(row)
    if movement and movement != "-":
        return movement
    reason = opportunity_reason_label(row)
    if reason and reason != "-":
        return reason
    return text_display(brief.get("summary") or "Esperar confirmación de 15m, 1h, volumen y riesgo.")


def scanner_overview_summary(
    table: pd.DataFrame,
    confluence_df: pd.DataFrame,
    options_df: pd.DataFrame,
    brief: dict,
) -> dict[str, Any]:
    pulse = market_pulse_summary(table)
    top = table.iloc[0].to_dict() if not table.empty else {}
    score_values = (
        pd.to_numeric(table.get("ai_score", pd.Series(dtype=float)), errors="coerce")
        if not table.empty
        else pd.Series(dtype=float)
    )
    readiness_values = (
        pd.to_numeric(table.get("readiness", pd.Series(dtype=float)), errors="coerce")
        if not table.empty
        else pd.Series(dtype=float)
    )
    option_candidates = 0
    if not options_df.empty:
        if "option_decision" in options_df.columns:
            option_candidates = int(options_df["option_decision"].astype(str).str.upper().eq("OPTION_CANDIDATE").sum())
        else:
            option_candidates = int(len(options_df))
    session = brief.get("market_session") if isinstance(brief.get("market_session"), dict) else {}
    freshness = brief.get("source_freshness") if isinstance(brief.get("source_freshness"), dict) else {}
    return {
        "total": pulse["total"],
        "ready": pulse["ready"],
        "watch": pulse["watch"],
        "avoid": pulse["avoid"],
        "top_symbol": text_display(top.get("symbol")).upper(),
        "top_action": human_trade_action(top) if top else "Esperar",
        "top_strategy": dashboard_strategy_label(top) if top else "-",
        "top_gate": pulse["top_gate"],
        "avg_score": safe_float(score_values.mean()),
        "avg_readiness": safe_float(readiness_values.mean()),
        "confluence_rows": int(len(confluence_df)),
        "option_candidates": option_candidates,
        "session": text_display(session.get("stock_session") or session.get("crypto_session")),
        "freshness": text_display(freshness.get("label")),
    }


def scanner_heatmap_rows(table: pd.DataFrame) -> pd.DataFrame:
    if table.empty:
        return pd.DataFrame(columns=["strategy", "bucket", "tone", "count", "avg_score", "avg_readiness"])
    pulse = market_pulse_rows(table)
    rows: list[dict[str, Any]] = []
    for idx, item in table.iterrows():
        row = item.to_dict()
        status = pulse.iloc[idx].to_dict() if idx < len(pulse) else {}
        rows.append(
            {
                "strategy": dashboard_strategy_label(row),
                "bucket": status.get("bucket", "Vigilar"),
                "tone": status.get("tone", "watch"),
                "ai_score": safe_float(row.get("ai_score")),
                "readiness": safe_float(row.get("readiness")),
            }
        )
    data = pd.DataFrame(rows)
    grouped = (
        data.groupby(["strategy", "bucket", "tone"], as_index=False)
        .agg(count=("strategy", "size"), avg_score=("ai_score", "mean"), avg_readiness=("readiness", "mean"))
        .sort_values(["count", "avg_score"], ascending=[False, False])
    )
    return grouped.reset_index(drop=True)


def scanner_leaderboard_rows(table: pd.DataFrame, *, bucket: str = "Todos", limit: int = 12) -> pd.DataFrame:
    filtered = filter_focused_opportunities(table, bucket=bucket)
    if filtered.empty:
        return pd.DataFrame(
            columns=["symbol", "status", "market", "strategy", "score", "readiness", "risk", "gate", "data", "source", "next"]
        )
    pulse = market_pulse_rows(filtered)
    rows: list[dict[str, Any]] = []
    for idx, item in filtered.iterrows():
        row = item.to_dict()
        status = pulse.iloc[idx].to_dict() if idx < len(pulse) else {}
        rows.append(
            {
                "symbol": text_display(row.get("symbol")).upper(),
                "status": status.get("bucket", "-"),
                "market": text_display(row.get("market")),
                "strategy": dashboard_strategy_label(row),
                "score": safe_float(row.get("ai_score")),
                "readiness": safe_float(row.get("readiness")),
                "risk": safe_float(row.get("risk_pct")),
                "gate": text_display(row.get("gate")),
                "data": text_display(row.get("data_state")),
                "source": text_display(row.get("data_source")),
                "next": text_display(row.get("waiting_for")),
            }
        )
    display = pd.DataFrame(rows)
    display["score_sort"] = pd.to_numeric(display["score"], errors="coerce").fillna(0)
    display["readiness_sort"] = pd.to_numeric(display["readiness"], errors="coerce").fillna(0)
    display = display.sort_values(["score_sort", "readiness_sort"], ascending=[False, False]).head(limit)
    return display.drop(columns=["score_sort", "readiness_sort"]).reset_index(drop=True)


def opportunity_budget_fit(
    row: dict[str, Any],
    *,
    account_equity: float = 500.0,
    risk_pct: float = 0.01,
) -> dict[str, Any]:
    status = trade_decision_card_status(row)
    symbol = text_display(row.get("symbol") or status.get("symbol")).upper()
    market = normalize_command_market(row.get("market") or status.get("market"), symbol)
    entry = safe_float(status.get("entry") or row.get("entry") or row.get("current_price"))
    stop = safe_float(status.get("stop") or row.get("stop"))
    target_2 = safe_float(status.get("target_2") or row.get("target_2") or row.get("target_price"))
    option_value = row.get("option")
    option = option_value if isinstance(option_value, dict) else {}
    equity = max(1.0, safe_float(account_equity) or 500.0)
    risk_fraction = max(0.001, safe_float(risk_pct) or 0.01)
    plan = small_account_product_plan(
        account_equity=equity,
        risk_per_trade_pct=risk_fraction,
        market=market,
        entry=entry,
        stop=stop,
        option=option,
    )
    risk_budget = safe_float(plan.get("risk_budget")) or equity * risk_fraction
    units = safe_float(plan.get("units")) or 0.0
    risk_per_unit = safe_float(plan.get("risk_per_unit"))
    option_max_loss = safe_float(plan.get("option_max_loss"))
    recommendation = text_display(plan.get("recommendation"))
    allowed = bool(plan.get("allowed"))
    is_option = recommendation == "Opcion"
    if is_option:
        notional = (option_max_loss or 0.0) * units
        risk_dollars = notional
        rr_to_2 = safe_float(status.get("rr_to_2"))
        reward_dollars = max(0.0, rr_to_2 * risk_dollars) if rr_to_2 is not None and risk_dollars else None
    else:
        notional = (entry or 0.0) * units
        risk_dollars = (risk_per_unit or 0.0) * units if risk_per_unit is not None else 0.0
        reward_dollars = max(0.0, (target_2 or 0.0) - (entry or 0.0)) * units if entry and target_2 else None
    reward_to_r = None
    if reward_dollars is not None and risk_dollars and risk_dollars > 0:
        reward_to_r = reward_dollars / risk_dollars

    points = 0.0
    if allowed:
        points += 8.0
        if recommendation == "Accion":
            points += 8.0
        elif recommendation == "Accion fraccionada":
            points += 5.0
        elif recommendation.startswith("Crypto"):
            points += 6.0
        elif recommendation == "Opcion":
            points += 7.0
    else:
        points -= 30.0
    if reward_dollars is not None:
        points += min(18.0, max(0.0, reward_dollars / max(risk_budget, 0.01) * 4.0))
        if reward_dollars <= 0:
            points -= 8.0
    if reward_to_r is not None:
        points += min(8.0, max(0.0, reward_to_r * 2.0))
    if notional and notional > equity * 1.02 and not is_option:
        points -= 12.0
    if risk_dollars and risk_dollars > risk_budget * 1.05:
        points -= 25.0
    if entry is None or stop is None or target_2 is None:
        points -= 6.0

    return {
        "allowed": allowed,
        "recommendation": recommendation,
        "units": units,
        "whole_shares": safe_float(plan.get("whole_shares")),
        "notional": notional,
        "risk_budget": risk_budget,
        "risk_dollars": risk_dollars,
        "reward_2_dollars": reward_dollars,
        "reward_to_r": reward_to_r,
        "score_delta": round(points, 4),
        "message": text_display(plan.get("message")),
        "next_step": text_display(plan.get("next_step")),
    }


def opportunity_ranking_score(
    row: dict[str, Any],
    *,
    account_equity: float | None = None,
    risk_pct: float | None = None,
) -> float:
    status = trade_decision_card_status(row)
    score = safe_float(row.get("ai_score") or row.get("score")) or 0.0
    readiness = safe_float(row.get("readiness") or row.get("alert_readiness_score")) or 0.0
    risk = safe_float(row.get("risk_pct"))
    points = score * 0.45 + readiness * 0.35
    action = text_display(status.get("action"))
    data_bucket = text_display(row.get("data_bucket") or status.get("data_bucket"))
    source_memory = text_display(row.get("source_memory_bias"))
    strategy_source_memory = text_display(row.get("strategy_source_memory_bias"))
    crypto_context_memory = text_display(row.get("crypto_context_memory_bias"))
    backtest_memory = text_display(row.get("backtest_memory_bias"))
    tradingview_confirmation = text_display(row.get("tradingview_confirmation"))
    market_event_state = text_display(
        row.get("market_event_state")
        or row.get("event_state")
        or row.get("macro_event_state")
        or row.get("earnings_event_state")
    )
    data_confidence = opportunity_data_confidence_status(row)
    data_confidence_score = safe_float(data_confidence.get("score")) or 0.0
    if action == "Entrar paper/manual":
        points += 35
    elif action == "Confirmar externo":
        points += 8
    elif action == "No operar":
        points -= 45
    if data_bucket == "Live real":
        points += 15
    elif data_bucket == "Fallback":
        points -= 12
    elif data_bucket in {"Bloqueadas", "Sin contrato"}:
        points -= 35
    if data_confidence_score >= 90:
        points += 16
    elif data_confidence_score >= 70:
        points += 5
    elif data_confidence_score >= 45:
        points -= 16
    else:
        points -= 34
    if data_confidence.get("mixed_sources"):
        points -= 14
    if source_memory == "Memoria fuente positiva":
        points += 6
    elif source_memory == "Memoria fuente negativa":
        points -= 12
    if strategy_source_memory == "Memoria setup+fuente positiva":
        points += 10
    elif strategy_source_memory == "Memoria setup+fuente negativa":
        points -= 20
    if crypto_context_memory == "Memoria crypto positiva":
        points += 10
    elif crypto_context_memory == "Memoria crypto negativa":
        points -= 22
    if backtest_memory == "Backtest positivo":
        points += 12
    elif backtest_memory == "Backtest negativo":
        points -= 18
    if tradingview_confirmation == "TradingView confirma":
        points += 8
    elif tradingview_confirmation == "TradingView contradice":
        points -= 16
    if market_event_state in {"Evento macro activo", "Earnings cercanos"}:
        points -= 30
    elif market_event_state in {"Evento macro proximo", "Earnings revisar"}:
        points -= 14
    if risk is None:
        points -= 6
    elif risk <= 0.02:
        points += 8
    elif risk <= 0.035:
        points += 3
    else:
        points -= 18
    points += safe_float(status.get("entry_proximity_priority_delta")) or 0.0
    if status.get("entry") is None or status.get("stop") is None or status.get("target_2") is None:
        points -= 18
    if account_equity is not None:
        budget = opportunity_budget_fit(
            row,
            account_equity=account_equity,
            risk_pct=risk_pct if risk_pct is not None else 0.01,
        )
        points += safe_float(budget.get("score_delta")) or 0.0
    return round(points, 4)


def opportunity_ranking_rows(
    table: pd.DataFrame,
    *,
    limit: int = 8,
    account_equity: float | None = None,
    risk_pct: float | None = None,
) -> pd.DataFrame:
    include_budget = account_equity is not None
    columns = [
        "Rank",
        "Accion",
        "Ticker",
        "Estrategia",
        "Entrada",
        "Zona entrada",
        "Estado entrada",
        "Distancia entrada",
        "Stop",
        "Target 2%",
        "Target 5%",
        "Target 10%",
        "R:R 2%",
        "Confianza datos",
        "Detalle datos",
        "Riesgo",
        "Readiness",
        "Score ranking",
        *(
            [
                "Capital fit",
                "Producto",
                "Tamano",
                "Capital usado",
                "Riesgo $",
                "Ganancia 2% $",
                "R:R presupuesto",
            ]
            if include_budget
            else []
        ),
        "Fuente",
        "Evento",
        "Memoria setup+fuente",
        "Memoria crypto",
        "Backtest",
        "TV Webhook",
        "Por que",
        "Confirmacion",
        "Siguiente paso",
        "Activo",
        "TradingView",
        "_sort",
    ]
    if table.empty:
        return pd.DataFrame(columns=columns)
    rows: list[dict[str, Any]] = []
    for _, item in table.iterrows():
        row = item.to_dict()
        status = trade_decision_card_status(row)
        symbol = text_display(row.get("symbol")).upper()
        market = normalize_command_market(row.get("market"), symbol)
        tf = text_display(row.get("timeframe") or row.get("tf") or "1h")
        asset_href = f"?view=Activo&symbol={quote(symbol, safe='')}&market={quote(market, safe='')}&tf={quote(tf, safe='')}"
        rank_score = opportunity_ranking_score(row, account_equity=account_equity, risk_pct=risk_pct)
        data_confidence = opportunity_data_confidence_status(row)
        output_row = {
                "Rank": 0,
                "Accion": status["action"],
                "Ticker": symbol,
                "Estrategia": dashboard_strategy_label(row),
                "Entrada": safe_float(status.get("entry")),
                "Zona entrada": (
                    f"{price_display(status.get('entry_zone_low'))} - {price_display(status.get('entry_zone_high'))}"
                    if status.get("entry_zone_low") is not None and status.get("entry_zone_high") is not None
                    else "-"
                ),
                "Estado entrada": text_display(status.get("entry_proximity")),
                "Distancia entrada": safe_float(status.get("entry_distance_pct")),
                "Stop": safe_float(status.get("stop")),
                "Target 2%": safe_float(status.get("target_2")),
                "Target 5%": safe_float(status.get("target_5")),
                "Target 10%": safe_float(status.get("target_10")),
                "R:R 2%": safe_float(status.get("rr_to_2")),
                "Confianza datos": text_display(data_confidence.get("label")),
                "Detalle datos": text_display(data_confidence.get("detail")),
                "Riesgo": safe_float(status.get("risk_pct")),
                "Readiness": safe_float(status.get("readiness")),
                "Score ranking": rank_score,
                "Fuente": text_display(row.get("data_bucket") or status.get("data_bucket")),
                "Evento": text_display(row.get("market_event_state")),
                "Memoria setup+fuente": text_display(row.get("strategy_source_memory_bias")),
                "Memoria crypto": text_display(row.get("crypto_context_memory_bias")),
                "Backtest": text_display(row.get("backtest_memory_bias")),
                "TV Webhook": text_display(row.get("tradingview_confirmation")),
                "Por que": text_display(status.get("reason")),
                "Confirmacion": text_display(status.get("confirmation_rule")),
                "Siguiente paso": text_display(status.get("next_step")),
                "Activo": asset_href,
                "TradingView": alert_live_tradingview_url(symbol, market),
                "_sort": rank_score,
            }
        if include_budget:
            budget = opportunity_budget_fit(row, account_equity=account_equity or 500.0, risk_pct=risk_pct or 0.01)
            output_row.update(
                {
                    "Capital fit": "Cabe" if budget.get("allowed") else "No cabe",
                    "Producto": text_display(budget.get("recommendation")),
                    "Tamano": safe_float(budget.get("units")),
                    "Capital usado": safe_float(budget.get("notional")),
                    "Riesgo $": safe_float(budget.get("risk_dollars")),
                    "Ganancia 2% $": safe_float(budget.get("reward_2_dollars")),
                    "R:R presupuesto": safe_float(budget.get("reward_to_r")),
                }
            )
        rows.append(output_row)
    output = pd.DataFrame(rows, columns=columns)
    output = output.sort_values(["_sort", "Readiness"], ascending=[False, False], na_position="last").head(limit)
    output = output.reset_index(drop=True)
    output["Rank"] = range(1, len(output) + 1)
    return output


def budget_recommendation_rows(
    table: pd.DataFrame,
    *,
    account_equity: float = 100.0,
    risk_pct: float = 0.01,
    limit: int = 4,
) -> pd.DataFrame:
    columns = [
        "symbol",
        "bucket",
        "tone",
        "action",
        "product",
        "entry",
        "stop",
        "units",
        "capital_used",
        "risk_dollars",
        "reward_2_dollars",
        "reward_to_r",
        "score",
        "next_step",
        "href",
    ]
    if not isinstance(table, pd.DataFrame) or table.empty:
        return pd.DataFrame(columns=columns)
    rows: list[dict[str, Any]] = []
    for item in table.to_dict("records"):
        status = trade_decision_card_status(item)
        budget = opportunity_budget_fit(item, account_equity=account_equity, risk_pct=risk_pct)
        symbol = text_display(item.get("symbol")).upper()
        market = normalize_command_market(item.get("market"), symbol)
        tf = text_display(item.get("timeframe") or item.get("tf") or "1h")
        product = text_display(budget.get("recommendation"))
        allowed = bool(budget.get("allowed"))
        if allowed and product == "Accion":
            bucket = "Operable"
            tone = "buy"
        elif allowed and product in {"Accion fraccionada", "Crypto pequeno", "Opcion"}:
            bucket = "Presupuesto pequeño"
            tone = "watch"
        else:
            bucket = "Solo vigilar"
            tone = "avoid"
        rows.append(
            {
                "symbol": symbol,
                "bucket": bucket,
                "tone": tone,
                "action": text_display(status.get("action")),
                "product": product,
                "entry": safe_float(status.get("entry")),
                "stop": safe_float(status.get("stop")),
                "units": safe_float(budget.get("units")),
                "capital_used": safe_float(budget.get("notional")),
                "risk_dollars": safe_float(budget.get("risk_dollars")),
                "reward_2_dollars": safe_float(budget.get("reward_2_dollars")),
                "reward_to_r": safe_float(budget.get("reward_to_r")),
                "score": opportunity_ranking_score(item, account_equity=account_equity, risk_pct=risk_pct),
                "next_step": text_display(budget.get("next_step") or status.get("next_step")),
                "href": f"?view=Activo&symbol={quote(symbol, safe='')}&market={quote(market, safe='')}&tf={quote(tf, safe='')}",
            }
        )
    output = pd.DataFrame(rows, columns=columns)
    output["score_sort"] = pd.to_numeric(output["score"], errors="coerce").fillna(-999)
    output["reward_sort"] = pd.to_numeric(output["reward_2_dollars"], errors="coerce").fillna(-1)
    output["bucket_sort"] = output["bucket"].map({"Operable": 0, "Presupuesto pequeño": 1, "Solo vigilar": 2}).fillna(3)
    output = output.sort_values(["bucket_sort", "score_sort", "reward_sort"], ascending=[True, False, False]).head(limit)
    return output.drop(columns=["score_sort", "reward_sort", "bucket_sort"]).reset_index(drop=True)


def _nested_value(row: dict[str, Any], *paths: str) -> Any:
    for path in paths:
        cursor: Any = row
        ok = True
        for part in path.split("."):
            if isinstance(cursor, dict) and part in cursor:
                cursor = cursor.get(part)
            else:
                ok = False
                break
        if ok and cursor not in (None, ""):
            return cursor
    return None


def opportunity_relative_volume(row: dict[str, Any] | None) -> float | None:
    row = row if isinstance(row, dict) else {}
    value = _nested_value(
        row,
        "relative_volume_15m",
        "relative_volume",
        "rel_volume",
        "volume_ratio",
        "volume_vs_average",
        "indicators.relative_volume",
        "indicators.volume_ratio",
        "technical.relative_volume",
    )
    parsed = safe_float(value)
    if parsed is None:
        return None
    if parsed > 100:
        return parsed / 100.0
    return parsed


def opportunity_spread_pct(row: dict[str, Any] | None) -> float | None:
    row = row if isinstance(row, dict) else {}
    value = _nested_value(row, "spread_pct", "spread_percent", "option.spread_pct", "option.spread_percent")
    parsed = safe_float(value)
    if parsed is not None:
        return parsed / 100.0 if parsed > 1 else parsed
    bid = safe_float(_nested_value(row, "bid", "quote.bid", "option.bid", "option.bid_price"))
    ask = safe_float(_nested_value(row, "ask", "quote.ask", "option.ask", "option.ask_price"))
    if bid is None or ask is None or ask < bid:
        return None
    mid = (bid + ask) / 2.0
    if mid <= 0:
        return None
    return (ask - bid) / mid


def opportunity_freshness_label(row: dict[str, Any] | None, status: dict[str, Any] | None = None) -> str:
    row = row if isinstance(row, dict) else {}
    status = status if isinstance(status, dict) else {}
    value = _nested_value(
        row,
        "freshness",
        "freshness_status",
        "price_freshness",
        "live_price_contract.freshness",
        "live_price_contract.freshness_status",
        "chart_data_contract.freshness",
        "chart_data_contract.freshness_status",
        "data_bucket",
        "data_gate",
    )
    if value in (None, ""):
        value = status.get("data_bucket") or status.get("data_gate")
    return text_display(value)


def _normalized_data_source_name(value: Any) -> str:
    source = text_display(value).lower()
    if source in {"", "-"}:
        return ""
    for token in ("alpaca", "polygon", "binance", "coinbase", "finnhub", "twelve", "yfinance", "yahoo"):
        if token in source:
            return token
    return source.split()[0].replace("_", "-")


def opportunity_data_confidence_status(row: dict[str, Any] | None) -> dict[str, Any]:
    row = row if isinstance(row, dict) else {}
    status = opportunity_data_source_status(row)
    gate = text_display(status.get("gate")).upper()
    bucket = text_display(row.get("data_bucket") or opportunity_data_source_bucket(row).get("bucket"))
    freshness = text_display(row.get("freshness") or status.get("freshness")).upper()
    live_contract = row.get("live_price_contract") if isinstance(row.get("live_price_contract"), dict) else {}
    price_contract = row.get("price_data_contract") if isinstance(row.get("price_data_contract"), dict) else {}
    chart_contract = row.get("chart_data_contract") if isinstance(row.get("chart_data_contract"), dict) else {}
    price_source = text_display(
        row.get("price_source_label")
        or row.get("price_source")
        or live_contract.get("source_label")
        or live_contract.get("source")
        or price_contract.get("source_label")
        or price_contract.get("source")
        or status.get("source")
    )
    chart_source = text_display(
        row.get("chart_source_label")
        or row.get("chart_source")
        or chart_contract.get("source_label")
        or chart_contract.get("source")
        or status.get("source")
    )
    price_norm = _normalized_data_source_name(price_source)
    chart_norm = _normalized_data_source_name(chart_source)
    mixed_sources = bool(price_norm and chart_norm and price_norm != chart_norm)

    score = 78.0
    label = "Datos revisables"
    tone = "watch"
    reasons: list[str] = []
    sources_declared = bool(price_norm and chart_norm)
    if sources_declared and gate in {"LIVE_PRICE_OK", "LIVE_DATA_OK", "ANALYSIS_OK"} and bucket == "Live real":
        score = 96.0
        label = "Fuente alineada"
        tone = "buy"
        reasons.append("precio y analisis operables")
    elif bucket == "Live real":
        score = 74.0
        label = "Live sin fuente completa"
        tone = "watch"
        reasons.append("falta comparar precio y velas")
    elif bucket == "Fallback" or gate in {"NO_TRADE_FROM_PUBLIC_PRICE", "NO_TRADE_FROM_FALLBACK", "EXTERNAL_CONFIRM_REQUIRED"}:
        score = 42.0
        label = "Fallback"
        tone = "watch"
        reasons.append("confirmar en broker/TradingView")
    elif bucket in {"Bloqueadas", "Sin contrato"} or gate in {"NO_TRADE_PRICE_FAIL", "NO_TRADE_STALE_PRICE", "NO_TRADE_STALE_DATA"}:
        score = 12.0
        label = "Datos bloqueados"
        tone = "avoid"
        reasons.append("no usar para entrada")
    elif gate in {"WAIT_PRICE_CONFIRMATION", "WAIT_NEXT_CANDLE", "MARKET_CLOSED_RECHECK"}:
        score = 58.0
        label = "Esperar fuente"
        tone = "watch"
        reasons.append("esperar revalidacion")

    if freshness == "STALE" or "STALE" in gate:
        score = min(score, 24.0)
        label = "Stale"
        tone = "avoid"
        reasons.append("precio viejo")
    elif freshness in {"LIVE", "FRESH", "OK"} and tone == "buy":
        score = min(100.0, score + 2.0)

    if mixed_sources:
        score = min(score, 60.0)
        if tone == "buy":
            tone = "watch"
        label = "Fuentes mixtas"
        reasons.append(f"precio {price_source} / velas {chart_source}")

    if (not price_source or price_source == "-") and bucket != "Live real":
        score = min(score, 55.0)
        reasons.append("sin fuente de precio")
    elif (not price_source or price_source == "-") and bucket == "Live real":
        reasons.append("fuente live declarada")
    if (not chart_source or chart_source == "-") and bucket != "Live real":
        score = min(score, 60.0)
        reasons.append("sin fuente de velas")
    elif (not chart_source or chart_source == "-") and bucket == "Live real":
        reasons.append("velas live declaradas")

    detail_parts = [
        f"precio {price_source}",
        f"velas {chart_source}",
        f"gate {gate or '-'}",
        f"frescura {freshness or '-'}",
    ]
    if reasons:
        detail_parts.append(" · ".join(reasons[:3]))
    return {
        "label": label,
        "tone": tone,
        "score": round(max(0.0, min(100.0, score)), 2),
        "detail": " | ".join(detail_parts),
        "price_source": price_source,
        "chart_source": chart_source,
        "mixed_sources": mixed_sources,
        "gate": gate,
        "freshness": freshness,
    }


def budget_quality_adjustment(
    row: dict[str, Any] | None,
    *,
    relative_volume: float | None,
    spread_pct: float | None,
    stop_distance_pct: float | None,
    freshness: str,
) -> tuple[float, list[str]]:
    row = row if isinstance(row, dict) else {}
    score = 0.0
    reasons: list[str] = []
    if relative_volume is None:
        score -= 2.0
        reasons.append("volumen sin confirmar")
    elif relative_volume >= 1.5:
        score += 8.0
        reasons.append(f"volumen {relative_volume:.2f}x")
    elif relative_volume >= 1.0:
        score += 4.0
        reasons.append(f"volumen {relative_volume:.2f}x")
    elif relative_volume < 0.5:
        score -= 12.0
        reasons.append(f"volumen bajo {relative_volume:.2f}x")
    elif relative_volume < 0.8:
        score -= 7.0
        reasons.append(f"volumen flojo {relative_volume:.2f}x")

    if spread_pct is None:
        score -= 1.0
    elif spread_pct <= 0.02:
        score += 5.0
        reasons.append(f"spread {spread_pct:.2%}")
    elif spread_pct <= 0.06:
        score += 1.0
    elif spread_pct <= 0.12:
        score -= 7.0
        reasons.append(f"spread amplio {spread_pct:.2%}")
    else:
        score -= 14.0
        reasons.append(f"spread muy amplio {spread_pct:.2%}")

    if stop_distance_pct is None:
        score -= 10.0
        reasons.append("sin stop medible")
    elif 0.003 <= stop_distance_pct <= 0.025:
        score += 7.0
        reasons.append(f"stop {stop_distance_pct:.2%}")
    elif stop_distance_pct > 0.04:
        score -= 12.0
        reasons.append(f"stop ancho {stop_distance_pct:.2%}")
    elif stop_distance_pct < 0.0015:
        score -= 5.0
        reasons.append(f"stop demasiado ajustado {stop_distance_pct:.2%}")

    freshness_norm = text_display(freshness).lower()
    data_bucket = text_display(row.get("data_bucket")).lower()
    data_confidence = opportunity_data_confidence_status(row)
    data_confidence_score = safe_float(data_confidence.get("score")) or 0.0
    if data_confidence_score >= 90:
        score += 7.0
        reasons.append("fuente alineada")
    elif data_confidence_score < 35:
        score -= 18.0
        reasons.append(text_display(data_confidence.get("label")).lower())
    elif data_confidence_score < 65:
        score -= 8.0
        reasons.append(text_display(data_confidence.get("label")).lower())
    if "live real" in freshness_norm or data_bucket == "live real":
        score += 6.0
        reasons.append("precio live")
    elif any(token in freshness_norm for token in ["stale", "fallback", "bloquead", "sin contrato"]):
        score -= 12.0
        reasons.append(f"precio {text_display(freshness)}")
    elif any(token in data_bucket for token in ["fallback", "bloquead", "sin contrato"]):
        score -= 10.0
        reasons.append(f"datos {text_display(row.get('data_bucket'))}")

    strategy_bias = text_display(row.get("strategy_source_memory_bias"))
    backtest_bias = text_display(row.get("backtest_memory_bias"))
    crypto_bias = text_display(row.get("crypto_context_memory_bias"))
    if "positiva" in strategy_bias.lower() or "positivo" in backtest_bias.lower() or "positiva" in crypto_bias.lower():
        score += 6.0
        reasons.append("memoria favorece setup")
    if "negativa" in strategy_bias.lower() or "negativo" in backtest_bias.lower() or "negativa" in crypto_bias.lower():
        score -= 14.0
        reasons.append("memoria penaliza setup")

    return score, reasons[:5]


def budget_expectancy_status(
    row: dict[str, Any],
    *,
    account_equity: float = 100.0,
    risk_pct: float = 0.01,
) -> dict[str, Any]:
    status = trade_decision_card_status(row)
    budget = opportunity_budget_fit(row, account_equity=account_equity, risk_pct=risk_pct)
    readiness = safe_float(status.get("readiness") or row.get("readiness") or row.get("alert_readiness_score")) or 0.0
    rr = safe_float(budget.get("reward_to_r"))
    risk_dollars = safe_float(budget.get("risk_dollars"))
    reward_dollars = safe_float(budget.get("reward_2_dollars"))
    capital_used = safe_float(budget.get("notional"))
    probability = 0.30 + min(0.36, max(0.0, readiness) / 100.0 * 0.34)
    action = text_display(status.get("action"))
    data_bucket = text_display(row.get("data_bucket") or status.get("data_bucket"))
    strategy_source_memory = text_display(row.get("strategy_source_memory_bias"))
    backtest_memory = text_display(row.get("backtest_memory_bias"))
    tradingview_confirmation = text_display(row.get("tradingview_confirmation"))
    if action == "Entrar paper/manual":
        probability += 0.04
    elif action == "No operar":
        probability -= 0.10
    if data_bucket == "Live real":
        probability += 0.03
    elif data_bucket in {"Fallback", "Bloqueadas", "Sin contrato"}:
        probability -= 0.08
    if strategy_source_memory == "Memoria setup+fuente positiva":
        probability += 0.04
    elif strategy_source_memory == "Memoria setup+fuente negativa":
        probability -= 0.12
    if backtest_memory == "Backtest positivo":
        probability += 0.05
    elif backtest_memory == "Backtest negativo":
        probability -= 0.10
    if tradingview_confirmation == "TradingView confirma":
        probability += 0.04
    elif tradingview_confirmation == "TradingView contradice":
        probability -= 0.12
    entry = safe_float(status.get("entry"))
    stop = safe_float(status.get("stop"))
    relative_volume = opportunity_relative_volume(row)
    spread_pct = opportunity_spread_pct(row)
    freshness = opportunity_freshness_label(row, status)
    stop_distance_pct = None
    if entry and stop:
        stop_distance_pct = abs(entry - stop) / max(abs(entry), 0.0001)
    quality_score, quality_reasons = budget_quality_adjustment(
        row,
        relative_volume=relative_volume,
        spread_pct=spread_pct,
        stop_distance_pct=stop_distance_pct,
        freshness=freshness,
    )
    if risk_dollars is not None and risk_dollars > 0 and risk_dollars < (budget.get("risk_budget") or 0) * 0.25:
        quality_score -= 10.0
        quality_reasons.append("tamano capado por capital")
    probability += quality_score / 260.0
    win_probability = max(0.20, min(0.78, probability))

    expected_r = None
    expected_value = None
    if rr is not None and risk_dollars and risk_dollars > 0:
        effective_rr = min(rr, 6.0)
        if stop_distance_pct is not None and stop_distance_pct < 0.0015:
            effective_rr = min(effective_rr, 2.0)
        expected_r = win_probability * effective_rr - (1.0 - win_probability)
        expected_value = expected_r * risk_dollars
    capital_efficiency = None
    if expected_value is not None and capital_used and capital_used > 0:
        capital_efficiency = expected_value / capital_used
    budget_score = opportunity_ranking_score(row, account_equity=account_equity, risk_pct=risk_pct)
    if expected_r is not None:
        budget_score += expected_r * 28.0
    if capital_efficiency is not None:
        budget_score += min(18.0, max(-18.0, capital_efficiency * 500.0))
    budget_score += quality_score
    if not budget.get("allowed"):
        budget_score -= 20.0

    quality_label = "Alta" if quality_score >= 10 else "Media" if quality_score >= -4 else "Baja"
    if not budget.get("allowed"):
        lane = "Solo vigilar"
        tone = "avoid"
    elif quality_score <= -14:
        lane = "Baja expectativa"
        tone = "avoid"
    elif expected_r is not None and expected_r >= 0.35 and action != "No operar":
        lane = "Mejor uso"
        tone = "buy"
    elif expected_r is not None and expected_r >= 0.05:
        lane = "Puede esperar"
        tone = "watch"
    else:
        lane = "Baja expectativa"
        tone = "avoid"
    return {
        "lane": lane,
        "tone": tone,
        "win_probability": round(win_probability, 4),
        "expected_r": None if expected_r is None else round(expected_r, 4),
        "expected_value": None if expected_value is None else round(expected_value, 4),
        "capital_efficiency": None if capital_efficiency is None else round(capital_efficiency, 6),
        "budget_score": round(budget_score, 4),
        "quality_score": round(quality_score, 4),
        "quality_label": quality_label,
        "quality_reasons": quality_reasons,
        "relative_volume": None if relative_volume is None else round(relative_volume, 4),
        "spread_pct": None if spread_pct is None else round(spread_pct, 6),
        "stop_distance_pct": None if stop_distance_pct is None else round(stop_distance_pct, 6),
        "freshness": freshness,
        "budget": budget,
        "status": status,
    }


BUDGET_STAGE_ORDER = {
    "OPERAR_AHORA": 0,
    "ESPERAR_CONFIRMACION": 1,
    "SOLO_VIGILAR": 2,
    "NO_OPERAR": 3,
}


def budget_execution_stage(expectancy: dict[str, Any]) -> dict[str, Any]:
    status = expectancy.get("status") if isinstance(expectancy.get("status"), dict) else {}
    budget = expectancy.get("budget") if isinstance(expectancy.get("budget"), dict) else {}
    action = text_display(status.get("action"))
    data_bucket = text_display(status.get("data_bucket") or status.get("data_state"))
    entry_proximity = text_display(status.get("entry_proximity"))
    lane = text_display(expectancy.get("lane"))
    expected_r = safe_float(expectancy.get("expected_r"))
    readiness = safe_float(status.get("readiness")) or 0.0
    allowed = bool(budget.get("allowed"))
    blocked_data = data_bucket in {"Bloqueadas", "Sin contrato"} or "bloquead" in data_bucket.lower()
    weak_expectancy = expected_r is not None and expected_r < -0.05
    quality_score = safe_float(expectancy.get("quality_score")) or 0.0
    spread_pct = safe_float(expectancy.get("spread_pct"))
    stop_distance_pct = safe_float(expectancy.get("stop_distance_pct"))
    bad_structure = (
        quality_score <= -45
        or (spread_pct is not None and spread_pct > 0.12)
        or (stop_distance_pct is not None and stop_distance_pct > 0.08)
    )

    if action == "No operar" and blocked_data and readiness >= 50 and lane != "Baja expectativa":
        code = "SOLO_VIGILAR"
        label = "Solo vigilar"
        tone = "watch"
        reason = "La senal existe, pero falta fuente operable/live antes de arriesgar capital."
    elif (
        lane == "Baja expectativa"
        and allowed
        and action in {"Esperar confirmacion", "Esperar pullback", "Confirmar externo"}
        and readiness >= 45
        and not bad_structure
    ):
        code = "SOLO_VIGILAR"
        label = "Solo vigilar"
        tone = "watch"
        reason = "Cabe en presupuesto y tiene niveles medibles, pero aun necesita confirmacion live/externa."
    elif action == "No operar" or lane == "Baja expectativa" or weak_expectancy:
        code = "NO_OPERAR"
        label = "No operar"
        tone = "avoid"
        reason = "No vale la pena con este capital ahora."
    elif action == "Entrar paper/manual" and allowed and not blocked_data and (expected_r is None or expected_r >= 0.05):
        code = "OPERAR_AHORA"
        label = "Operar ahora"
        tone = "buy"
        reason = "Plan listo: cabe en presupuesto, tiene entrada/stop/target y expectativa positiva."
    elif allowed and action in {"Esperar confirmacion", "Esperar pullback", "Confirmar externo"} and readiness >= 60:
        code = "ESPERAR_CONFIRMACION"
        label = "Esperar confirmacion"
        tone = "watch"
        if action == "Confirmar externo" or blocked_data:
            reason = "Cabe en presupuesto, pero requiere confirmacion externa/live antes de entrar."
        elif entry_proximity in {"Antes de entrada", "No perseguir"}:
            reason = "Cabe en presupuesto, pero hay que esperar precio/zona de entrada."
        else:
            reason = "Cabe en presupuesto, pero falta confirmacion de entrada."
    elif allowed:
        code = "SOLO_VIGILAR"
        label = "Solo vigilar"
        tone = "watch"
        reason = "Cabe en presupuesto, pero todavia no tiene suficiente calidad para priorizar entrada."
    else:
        code = "SOLO_VIGILAR"
        label = "Solo vigilar"
        tone = "avoid"
        reason = "No cabe bien con este presupuesto o el riesgo por trade queda mal ajustado."

    return {
        "code": code,
        "label": label,
        "tone": tone,
        "reason": reason,
        "sort": BUDGET_STAGE_ORDER.get(code, 9),
    }


def budget_strategy_allocation_rows(
    table: pd.DataFrame,
    *,
    account_equity: float = 100.0,
    risk_pct: float = 0.01,
    limit: int = 5,
) -> pd.DataFrame:
    columns = [
        "symbol",
        "market",
        "strategy",
        "lane",
        "tone",
        "stage",
        "stage_label",
        "stage_tone",
        "stage_reason",
        "stage_sort",
        "budget_allowed",
        "product",
        "action",
        "capital_used",
        "risk_dollars",
        "reward_2_dollars",
        "win_probability",
        "expected_r",
        "expected_value",
        "capital_efficiency",
        "budget_score",
        "quality_label",
        "quality_reasons",
        "next_step",
        "href",
    ]
    if not isinstance(table, pd.DataFrame) or table.empty:
        return pd.DataFrame(columns=columns)
    rows: list[dict[str, Any]] = []
    for item in table.to_dict("records"):
        symbol = text_display(item.get("symbol")).upper()
        if not symbol or symbol == "-":
            continue
        market = normalize_command_market(item.get("market"), symbol)
        tf = text_display(item.get("timeframe") or item.get("tf") or "1h")
        expectation = budget_expectancy_status(item, account_equity=account_equity, risk_pct=risk_pct)
        stage = budget_execution_stage(expectation)
        budget = expectation["budget"]
        status = expectation["status"]
        rows.append(
            {
                "symbol": symbol,
                "market": market,
                "strategy": dashboard_strategy_label(item),
                "lane": expectation["lane"],
                "tone": expectation["tone"],
                "stage": stage["code"],
                "stage_label": stage["label"],
                "stage_tone": stage["tone"],
                "stage_reason": stage["reason"],
                "stage_sort": stage["sort"],
                "budget_allowed": bool(budget.get("allowed")),
                "product": text_display(budget.get("recommendation")),
                "action": text_display(status.get("action")),
                "capital_used": safe_float(budget.get("notional")),
                "risk_dollars": safe_float(budget.get("risk_dollars")),
                "reward_2_dollars": safe_float(budget.get("reward_2_dollars")),
                "win_probability": safe_float(expectation.get("win_probability")),
                "expected_r": safe_float(expectation.get("expected_r")),
                "expected_value": safe_float(expectation.get("expected_value")),
                "capital_efficiency": safe_float(expectation.get("capital_efficiency")),
                "budget_score": safe_float(expectation.get("budget_score")),
                "quality_label": text_display(expectation.get("quality_label")),
                "quality_reasons": " · ".join(text_display(item) for item in expectation.get("quality_reasons") or []),
                "next_step": text_display(budget.get("next_step") or status.get("next_step")),
                "href": f"?view=Activo&symbol={quote(symbol, safe='')}&market={quote(market, safe='')}&tf={quote(tf, safe='')}",
            }
        )
    output = pd.DataFrame(rows, columns=columns)
    if output.empty:
        return output
    output["lane_sort"] = output["lane"].map(
        {"Mejor uso": 0, "Puede esperar": 1, "Baja expectativa": 2, "Solo vigilar": 3}
    ).fillna(4)
    if "stage_sort" not in output.columns:
        output["stage_sort"] = 9
    output["score_sort"] = pd.to_numeric(output["budget_score"], errors="coerce").fillna(-999)
    output["expected_sort"] = pd.to_numeric(output["expected_value"], errors="coerce").fillna(-999)
    return (
        output.sort_values(["stage_sort", "lane_sort", "score_sort", "expected_sort"], ascending=[True, True, False, False])
        .head(limit)
        .drop(columns=["lane_sort", "stage_sort", "score_sort", "expected_sort"])
        .reset_index(drop=True)
    )


def budget_market_scope_matches(row: dict[str, Any], scope: str) -> bool:
    normalized = text_display(scope).lower()
    if normalized in {"-", "todos", "todo", "all"}:
        return True
    symbol = text_display(row.get("symbol")).upper()
    market = normalize_command_market(row.get("market"), symbol)
    product = text_display(row.get("product") or row.get("recommendation"))
    has_option = product == "Opcion" or isinstance(row.get("option"), dict)
    if normalized in {"acciones", "accion", "stocks", "stock"}:
        return market == "stock" and not has_option
    if normalized in {"crypto", "criptomonedas"}:
        return market == "crypto"
    if normalized in {"opciones", "opcion", "options"}:
        return has_option
    return True


def budget_filtered_opportunity_table(
    table: pd.DataFrame,
    *,
    account_equity: float = 100.0,
    risk_pct: float = 0.01,
    market_scope: str = "Todos",
    max_trades: int = 3,
) -> pd.DataFrame:
    if not isinstance(table, pd.DataFrame) or table.empty:
        return pd.DataFrame()
    candidates = table.copy().reset_index(drop=True)
    scoped_records = [
        record for record in candidates.to_dict("records") if budget_market_scope_matches(record, market_scope)
    ]
    if not scoped_records:
        return pd.DataFrame(columns=table.columns)
    scoped = pd.DataFrame(scoped_records)
    allocation = budget_strategy_allocation_rows(
        scoped,
        account_equity=account_equity,
        risk_pct=risk_pct,
        limit=max(12, int(max_trades or 3) * 4),
    )
    if allocation.empty:
        return scoped.head(max(1, int(max_trades or 3))).reset_index(drop=True)
    allocation = allocation[
        allocation["lane"].isin(["Mejor uso", "Puede esperar", "Baja expectativa", "Solo vigilar"])
    ].copy()
    if allocation.empty:
        return scoped.head(max(1, int(max_trades or 3))).reset_index(drop=True)
    budget_allowed = allocation["budget_allowed"].astype(bool) if "budget_allowed" in allocation.columns else True
    actionable_allocation = allocation[budget_allowed & ~allocation["stage"].astype(str).eq("NO_OPERAR")].copy()
    if actionable_allocation.empty:
        return pd.DataFrame(columns=table.columns)
    allocation = actionable_allocation
    ordered_symbols = [text_display(symbol).upper() for symbol in allocation["symbol"].tolist()]
    scoped["_budget_order"] = scoped["symbol"].astype(str).str.upper().map(
        {symbol: idx for idx, symbol in enumerate(ordered_symbols)}
    )
    filtered = scoped[scoped["_budget_order"].notna()].sort_values("_budget_order")
    return filtered.drop(columns=["_budget_order"]).head(max(1, int(max_trades or 3))).reset_index(drop=True)


def budget_wide_search_rows(
    table: pd.DataFrame,
    *,
    account_equity: float = 100.0,
    risk_pct: float = 0.01,
    market_scope: str = "Todos",
    limit: int = 10,
) -> pd.DataFrame:
    columns = [
        "symbol",
        "market",
        "strategy",
        "lane",
        "tone",
        "stage",
        "stage_label",
        "stage_tone",
        "stage_reason",
        "budget_allowed",
        "product",
        "action",
        "capital_used",
        "risk_dollars",
        "reward_2_dollars",
        "win_probability",
        "expected_r",
        "expected_value",
        "capital_efficiency",
        "budget_score",
        "quality_label",
        "quality_reasons",
        "next_step",
        "href",
    ]
    if not isinstance(table, pd.DataFrame) or table.empty:
        return pd.DataFrame(columns=columns)
    scoped_records = [
        record for record in table.copy().reset_index(drop=True).to_dict("records") if budget_market_scope_matches(record, market_scope)
    ]
    if not scoped_records:
        return pd.DataFrame(columns=columns)
    allocation = budget_strategy_allocation_rows(
        pd.DataFrame(scoped_records),
        account_equity=account_equity,
        risk_pct=risk_pct,
        limit=max(24, int(limit or 10) * 5),
    )
    if allocation.empty:
        return pd.DataFrame(columns=columns)
    candidates = allocation.copy()
    actionable_watch = candidates[~candidates["stage"].astype(str).eq("NO_OPERAR")].copy()
    if not actionable_watch.empty:
        candidates = actionable_watch
    candidates["_budget_ok_sort"] = (~candidates["budget_allowed"].astype(bool)).astype(int)
    candidates["_stage_sort"] = candidates["stage"].map(BUDGET_STAGE_ORDER).fillna(9)
    candidates["_score_sort"] = pd.to_numeric(candidates["budget_score"], errors="coerce").fillna(-999)
    candidates["_expected_sort"] = pd.to_numeric(candidates["expected_value"], errors="coerce").fillna(-999)
    candidates = candidates.sort_values(
        ["_budget_ok_sort", "_stage_sort", "_score_sort", "_expected_sort"],
        ascending=[True, True, False, False],
    )
    if text_display(market_scope).lower() in {"-", "todos", "todo", "all"}:
        picked_indexes: list[int] = []
        for market in ("stock", "crypto", "options"):
            market_rows = candidates[candidates["market"].astype(str).str.lower().eq(market)]
            if not market_rows.empty:
                picked_indexes.append(int(market_rows.index[0]))
        remaining_indexes = [int(idx) for idx in candidates.index if int(idx) not in picked_indexes]
        ordered_indexes = (picked_indexes + remaining_indexes)[: max(1, int(limit or 10))]
        candidates = candidates.loc[ordered_indexes]
    else:
        candidates = candidates.head(max(1, int(limit or 10)))
    return (
        candidates.drop(columns=["_budget_ok_sort", "_stage_sort", "_score_sort", "_expected_sort"], errors="ignore")
        .reindex(columns=columns)
        .reset_index(drop=True)
    )


def _crypto_budget_operational_plan(
    symbol: str,
    setup: str,
    *,
    account_equity: float,
    risk_pct: float,
) -> dict[str, Any]:
    risk_budget = max(1.0, safe_float(account_equity) or 100.0) * max(0.001, safe_float(risk_pct) or 0.01)
    source_label = "crypto_ohlcv_1h"
    try:
        history = roxy_crypto_history_for_signal(symbol, timeframe="1h", limit=120)
    except Exception as exc:
        return {
            "stage": "SOLO_VIGILAR",
            "stage_label": "Sin precio crypto",
            "stage_tone": "watch",
            "stage_reason": f"No hay velas crypto suficientes para calcular entrada/stop ahora: {type(exc).__name__}.",
            "tone": "watch",
            "action": "Conectar fuente crypto",
            "capital_used": None,
            "risk_dollars": risk_budget,
            "reward_1_dollars": None,
            "reward_2_dollars": None,
            "quality_label": "Sin precio",
            "quality_reasons": "Falta OHLCV crypto",
            "next_step": "Cargar grafica y esperar precio/velas crypto antes de calcular una operacion.",
            "verdict": "Sin operacion calculable",
            "price_source": "sin_fuente_crypto",
        }
    if not isinstance(history, pd.DataFrame) or history.empty or "close" not in history.columns:
        return {
            "stage": "SOLO_VIGILAR",
            "stage_label": "Sin velas crypto",
            "stage_tone": "watch",
            "stage_reason": "La fuente crypto no entrego velas 1h suficientes para calcular entrada, stop y target.",
            "tone": "watch",
            "action": "Esperar velas crypto",
            "capital_used": None,
            "risk_dollars": risk_budget,
            "reward_1_dollars": None,
            "reward_2_dollars": None,
            "quality_label": "Sin velas",
            "quality_reasons": "Falta historial OHLCV",
            "next_step": "Esperar velas frescas antes de operar crypto.",
            "verdict": "Sin operacion calculable",
            "price_source": source_label,
        }

    frame = history.copy().tail(120)
    for column in ("open", "high", "low", "close", "volume"):
        if column in frame.columns:
            frame[column] = pd.to_numeric(frame[column], errors="coerce")
    frame = frame.dropna(subset=["close"])
    if frame.empty:
        return {
            "stage": "SOLO_VIGILAR",
            "stage_label": "Precio invalido",
            "stage_tone": "watch",
            "stage_reason": "Las velas crypto llegaron sin cierre valido.",
            "tone": "watch",
            "action": "Esperar precio crypto",
            "capital_used": None,
            "risk_dollars": risk_budget,
            "reward_1_dollars": None,
            "reward_2_dollars": None,
            "quality_label": "Precio invalido",
            "quality_reasons": "Close vacio",
            "next_step": "Esperar precio valido antes de operar crypto.",
            "verdict": "Sin operacion calculable",
            "price_source": source_label,
        }

    price = safe_float(frame["close"].iloc[-1])
    if price is None or price <= 0:
        return {
            "stage": "SOLO_VIGILAR",
            "stage_label": "Precio invalido",
            "stage_tone": "watch",
            "stage_reason": "La fuente crypto no entrego precio positivo.",
            "tone": "watch",
            "action": "Esperar precio crypto",
            "capital_used": None,
            "risk_dollars": risk_budget,
            "reward_1_dollars": None,
            "reward_2_dollars": None,
            "quality_label": "Precio invalido",
            "quality_reasons": "Close <= 0",
            "next_step": "Esperar precio valido antes de operar crypto.",
            "verdict": "Sin operacion calculable",
            "price_source": source_label,
        }

    if {"high", "low"}.issubset(frame.columns):
        ranges = ((frame["high"] - frame["low"]) / frame["close"]).replace([float("inf"), float("-inf")], pd.NA).dropna()
        median_range = safe_float(ranges.tail(36).median()) if not ranges.empty else None
    else:
        median_range = None
    stop_pct = min(0.055, max(0.012, (median_range or 0.022) * 1.25))
    recent_high = safe_float(frame["high"].tail(24).max()) if "high" in frame.columns else price
    recent_low = safe_float(frame["low"].tail(24).min()) if "low" in frame.columns else price * (1 - stop_pct)
    setup_lower = setup.lower()
    if "breakout" in setup_lower and recent_high is not None and recent_high > 0:
        entry = max(price, recent_high * 1.001)
        stop = min(price * (1 - stop_pct), entry * (1 - stop_pct * 0.8))
    elif "pullback" in setup_lower and recent_low is not None and recent_low > 0:
        entry = price
        stop = min(recent_low * 0.998, price * (1 - stop_pct))
    elif "lateral" in setup_lower and recent_low is not None and recent_high is not None:
        entry = price
        stop = min(recent_low * 0.998, price * (1 - stop_pct))
    else:
        entry = price
        stop = price * (1 - stop_pct)
    if stop >= entry:
        stop = entry * (1 - stop_pct)
    risk_per_unit = max(0.00000001, entry - stop)
    target_1 = entry + (risk_per_unit * 2.0)
    target_2 = entry + (risk_per_unit * 3.0)
    sizing = small_account_product_plan(
        account_equity=account_equity,
        risk_per_trade_pct=risk_pct,
        market="crypto",
        entry=entry,
        stop=stop,
    )
    qty = safe_float(sizing.get("units")) or 0.0
    capital_used = qty * entry if qty > 0 else None
    risk_used = min(risk_budget, risk_per_unit * qty) if qty > 0 else risk_budget
    reward_1 = max(0.0, (target_1 - entry) * qty) if qty > 0 else None
    reward_2 = max(0.0, (target_2 - entry) * qty) if qty > 0 else None
    rr = (reward_1 / risk_used) if reward_1 is not None and risk_used else None
    stage_tone = "buy" if rr is not None and rr >= 1.8 and qty > 0 else "watch"
    stage = "PROXIMA_ENTRADA" if stage_tone == "buy" else "SOLO_VIGILAR"
    verdict = (
        f"Plan paper/manual: entrada {price_display(entry)}, stop {price_display(stop)}, T1 {price_display(target_1)}."
        if qty > 0
        else "Sin tamano calculable con este presupuesto."
    )
    return {
        "stage": stage,
        "stage_label": "Plan crypto" if stage_tone == "buy" else "Vigilar crypto",
        "stage_tone": stage_tone,
        "stage_reason": f"Crypto 24/7 con operacion fraccionada calculada desde velas 1h ({source_label}).",
        "tone": stage_tone,
        "action": "Plan paper/manual",
        "capital_used": capital_used,
        "qty": qty,
        "entry": entry,
        "stop": stop,
        "target_1": target_1,
        "target_2": target_2,
        "risk_dollars": risk_used,
        "reward_1_dollars": reward_1,
        "reward_2_dollars": reward_2,
        "expected_r": rr,
        "expected_value": reward_1,
        "capital_efficiency": (reward_1 / capital_used) if reward_1 is not None and capital_used else None,
        "budget_score": 55.0 + min(25.0, (rr or 0.0) * 8.0),
        "quality_label": "Plan operativo",
        "quality_reasons": f"Entrada/stop/targets desde {len(frame)} velas 1h",
        "next_step": text_display(sizing.get("next_step")) or "Confirmar 15m/1h antes de entrar.",
        "verdict": verdict,
        "price_source": source_label,
    }


def default_crypto_budget_watch_rows(
    *,
    account_equity: float = 100.0,
    risk_pct: float = 0.01,
    limit: int = 6,
) -> pd.DataFrame:
    columns = [
        "symbol",
        "market",
        "strategy",
        "lane",
        "tone",
        "stage",
        "stage_label",
        "stage_tone",
        "stage_reason",
        "budget_allowed",
        "product",
        "action",
        "qty",
        "entry",
        "stop",
        "target_1",
        "target_2",
        "capital_used",
        "risk_dollars",
        "reward_1_dollars",
        "reward_2_dollars",
        "win_probability",
        "expected_r",
        "expected_value",
        "capital_efficiency",
        "budget_score",
        "quality_label",
        "quality_reasons",
        "next_step",
        "href",
        "verdict",
        "price_source",
        "watch_seed",
    ]
    risk_budget = max(1.0, safe_float(account_equity) or 100.0) * max(0.001, safe_float(risk_pct) or 0.01)
    symbols = list(dict.fromkeys([*DEFAULT_CRYPTO_SYMBOLS, "XRP/USD", "ADA/USD", "AVAX/USD"]))
    setups = [
        "Canal alcista crypto",
        "Pullback crypto",
        "Cruce de medias crypto",
        "Breakout crypto",
        "Canal lateral crypto",
    ]
    rows: list[dict[str, Any]] = []
    for idx, symbol in enumerate(symbols[: max(1, int(limit or 6))]):
        setup = setups[idx % len(setups)]
        plan = _crypto_budget_operational_plan(
            symbol,
            setup,
            account_equity=account_equity,
            risk_pct=risk_pct,
        )
        rows.append(
            {
                "symbol": symbol.upper(),
                "market": "crypto",
                "strategy": setup,
                "lane": "Solo vigilar",
                "budget_allowed": True,
                "product": "Crypto fraccionada",
                "win_probability": None,
                "href": f"?view=Activo&symbol={quote(symbol.upper(), safe='')}&market=crypto&tf=1h",
                "watch_seed": True,
                **plan,
            }
        )
    return pd.DataFrame(rows, columns=columns)


def crypto_twenty_min_strike_rows(
    *,
    account_equity: float = 100.0,
    risk_pct: float = 0.01,
    symbols: list[str] | tuple[str, ...] | None = None,
    limit: int = 4,
    now: datetime | None = None,
) -> pd.DataFrame:
    columns = [
        "symbol",
        "price",
        "direction",
        "strike",
        "distance_pct",
        "momentum_20m",
        "momentum_5m",
        "confidence",
        "action",
        "risk_dollars",
        "source",
        "expires_at",
        "minutes_to_expiry",
        "timer_state",
        "next_step",
        "tone",
        "signal",
        "contract_side",
        "decision_state",
        "probability_roxy",
        "edge",
        "risk_reward",
        "recommended_entry",
        "reasons",
        "warning_flags",
        "href",
    ]
    risk_budget = max(1.0, safe_float(account_equity) or 100.0) * max(0.001, safe_float(risk_pct) or 0.01)
    selected_symbols = list(dict.fromkeys(symbols or DEFAULT_CRYPTO_SYMBOLS))[: max(1, int(limit or 4))]
    current_time = (now or datetime.now(timezone.utc)).astimezone(timezone.utc)
    minute_block = (current_time.minute // 20 + 1) * 20
    expires_at = current_time.replace(second=0, microsecond=0)
    if minute_block >= 60:
        expires_at = expires_at.replace(minute=0) + timedelta(hours=1)
    else:
        expires_at = expires_at.replace(minute=minute_block)
    minutes_to_expiry = max(0.0, (expires_at - current_time).total_seconds() / 60.0)
    timer_state = "Ventana valida" if 8.0 <= minutes_to_expiry <= 18.5 else "Esperar proxima ronda"
    rows: list[dict[str, Any]] = []
    for symbol in selected_symbols:
        href = f"?view=Activo&symbol={quote(str(symbol).upper(), safe='')}&market=crypto&tf=1m"
        try:
            frame = roxy_crypto_history_for_signal(str(symbol), timeframe="1m", limit=80)
        except Exception as exc:
            rows.append(
                {
                    "symbol": str(symbol).upper(),
                    "price": None,
                    "direction": "Esperar",
                    "strike": None,
                    "distance_pct": None,
                    "momentum_20m": None,
                    "momentum_5m": None,
                    "confidence": 0,
                    "action": "Sin datos 1m",
                    "risk_dollars": risk_budget,
                    "source": f"crypto_1m_error:{type(exc).__name__}",
                    "expires_at": expires_at.strftime("%H:%M UTC"),
                    "minutes_to_expiry": minutes_to_expiry,
                    "timer_state": timer_state,
                    "next_step": "No operar 20m hasta recibir velas 1m frescas.",
                    "tone": "avoid",
                    "signal": SIGNAL_NO_TRADE,
                    "contract_side": "WAIT",
                    "decision_state": "NO OPERAR",
                    "probability_roxy": 0,
                    "edge": None,
                    "risk_reward": None,
                    "recommended_entry": "Sin datos live.",
                    "reasons": ["No hay velas 1m frescas para validar BTC/crypto tipo strike."],
                    "warning_flags": ["data_unavailable"],
                    "href": href,
                }
            )
            continue
        if not isinstance(frame, pd.DataFrame) or frame.empty or "close" not in frame.columns:
            rows.append(
                {
                    "symbol": str(symbol).upper(),
                    "price": None,
                    "direction": "Esperar",
                    "strike": None,
                    "distance_pct": None,
                    "momentum_20m": None,
                    "momentum_5m": None,
                    "confidence": 0,
                    "action": "Sin velas 1m",
                    "risk_dollars": risk_budget,
                    "source": "crypto_1m_empty",
                    "expires_at": expires_at.strftime("%H:%M UTC"),
                    "minutes_to_expiry": minutes_to_expiry,
                    "timer_state": timer_state,
                    "next_step": "No operar 20m hasta tener precio y velas 1m.",
                    "tone": "avoid",
                    "signal": SIGNAL_NO_TRADE,
                    "contract_side": "WAIT",
                    "decision_state": "NO OPERAR",
                    "probability_roxy": 0,
                    "edge": None,
                    "risk_reward": None,
                    "recommended_entry": "Sin precio/velas live.",
                    "reasons": ["La fuente no devolvio velas 1m legibles."],
                    "warning_flags": ["empty_candles"],
                    "href": href,
                }
            )
            continue

        data = frame.copy().tail(80)
        for column in ("open", "high", "low", "close", "volume"):
            if column in data.columns:
                data[column] = pd.to_numeric(data[column], errors="coerce")
        data = data.dropna(subset=["close"])
        price = safe_float(data["close"].iloc[-1]) if not data.empty else None
        if price is None or price <= 0 or len(data) < 24:
            rows.append(
                {
                    "symbol": str(symbol).upper(),
                    "price": price,
                    "direction": "Esperar",
                    "strike": None,
                    "distance_pct": None,
                    "momentum_20m": None,
                    "momentum_5m": None,
                    "confidence": 0,
                    "action": "Historial corto",
                    "risk_dollars": risk_budget,
                    "source": "crypto_1m_insufficient",
                    "expires_at": expires_at.strftime("%H:%M UTC"),
                    "minutes_to_expiry": minutes_to_expiry,
                    "timer_state": timer_state,
                    "next_step": "Esperar mas velas 1m antes de decidir arriba/abajo.",
                    "tone": "watch",
                    "signal": SIGNAL_NO_TRADE,
                    "contract_side": "WAIT",
                    "decision_state": "ESPERAR CONFIRMACION",
                    "probability_roxy": 0,
                    "edge": None,
                    "risk_reward": None,
                    "recommended_entry": "Esperar mas historial 1m.",
                    "reasons": ["Historial insuficiente para validar momentum, EMAs y rechazo cerca del strike."],
                    "warning_flags": ["short_history"],
                    "href": href,
                }
            )
            continue

        close = data["close"]
        prior = safe_float(close.iloc[-21]) if len(close) >= 21 else safe_float(close.iloc[0])
        prior_5m = safe_float(close.iloc[-6]) if len(close) >= 6 else safe_float(close.iloc[0])
        momentum_20m = ((price / prior) - 1.0) if prior else 0.0
        momentum_5m = ((price / prior_5m) - 1.0) if prior_5m else 0.0
        sma9 = safe_float(close.tail(9).mean()) or price
        sma20 = safe_float(close.tail(20).mean()) or price
        returns = close.pct_change().replace([float("inf"), float("-inf")], pd.NA).dropna()
        minute_vol = safe_float(returns.tail(20).std()) or 0.001
        expected_move_pct = min(0.018, max(0.0015, minute_vol * math.sqrt(20)))
        strike_gap = min(0.012, max(0.0015, expected_move_pct * 0.55))
        bullish_confirmed = momentum_20m > 0.0005 and momentum_5m > 0.0002 and price >= sma9 >= sma20
        bearish_confirmed = momentum_20m < -0.0005 and momentum_5m < -0.0002 and price <= sma9 <= sma20
        if bullish_confirmed:
            direction = "Arriba"
        elif bearish_confirmed:
            direction = "Abajo"
        else:
            direction = "Esperar"
        preliminary_direction = direction
        if direction == "Arriba":
            strike = price * (1.0 + strike_gap)
            trend_ok = bullish_confirmed
        elif direction == "Abajo":
            strike = price * (1.0 - strike_gap)
            trend_ok = bearish_confirmed
        else:
            strike = price * (1.0 + strike_gap if momentum_5m >= 0 else 1.0 - strike_gap)
            trend_ok = False
        distance_pct = abs(strike - price) / price
        momentum_aligned = (direction == "Arriba" and momentum_20m > 0) or (direction == "Abajo" and momentum_20m < 0)
        edge_ratio = expected_move_pct / distance_pct if distance_pct else 0.0
        confidence = 35
        confidence += 20 if trend_ok else 0
        confidence += 16 if momentum_aligned and direction != "Esperar" else 0
        confidence += 14 if edge_ratio >= 1.35 else (6 if edge_ratio >= 1.0 else 0)
        confidence += min(12, abs(momentum_20m) * 1200)
        confidence += 6 if 8.0 <= minutes_to_expiry <= 18.5 else -18
        confidence = int(min(92, max(0, round(confidence))))
        timer_ok = timer_state == "Ventana valida"
        strike_engine_signal = analyze_strike_option(
            asset=roxy_crypto_base_symbol(str(symbol)),
            current_price=price,
            strike=strike,
            time_remaining_seconds=int(max(0, round(minutes_to_expiry * 60.0))),
            expiration_label="20 minutos",
            candles=roxy_candles_for_strike_engine(data, limit=80),
            stake=risk_budget,
        )
        engine_signal = strike_engine_signal.signal
        display_signal = engine_signal
        if engine_signal == SIGNAL_YES:
            direction = "Arriba"
            contract_side = "YES"
        elif engine_signal == SIGNAL_NO:
            direction = "Abajo"
            contract_side = "NO"
        else:
            direction = "Esperar"
            contract_side = "WAIT"
        confidence = int(strike_engine_signal.confidence)
        edge = strike_engine_signal.edge
        risk_reward = strike_engine_signal.risk_reward
        if not timer_ok:
            confidence = min(confidence, 57)
            action = "Esperar timer"
            tone = "watch"
            decision_state = "ESPERAR CONFIRMACION"
            display_signal = SIGNAL_NO_TRADE
            direction = "Esperar"
            contract_side = "WAIT"
            next_step = (
                f"No entrar ahora: quedan {num_display(minutes_to_expiry, 1)} min para el cierre. "
                "Evaluar al inicio de la proxima ronda :00/:20/:40."
            )
        elif preliminary_direction == "Esperar":
            confidence = min(confidence, 57)
            tone = "watch"
            action = "NO TRADE 20m"
            decision_state = "ESPERAR CONFIRMACION"
            display_signal = SIGNAL_NO_TRADE
            direction = "Esperar"
            contract_side = "WAIT"
            next_step = "No operar 20m: 20m y 5m no estan alineados con medias; esperar confirmacion clara."
        elif engine_signal == SIGNAL_NO_TRADE:
            tone = "avoid" if strike_engine_signal.color == "red" else "watch"
            action = "NO TRADE 20m"
            decision_state = "NO OPERAR" if tone == "avoid" else "ESPERAR CONFIRMACION"
            next_step = strike_engine_signal.recommended_entry
        elif strike_engine_signal.color == "green" and confidence >= 76:
            tone = "buy"
            action = f"{engine_signal} 20m"
            decision_state = "OPERAR AHORA"
            next_step = strike_engine_signal.recommended_entry
        else:
            tone = "watch"
            action = f"Vigilar {engine_signal} 20m"
            decision_state = "ESPERAR CONFIRMACION"
            next_step = strike_engine_signal.recommended_entry
        rows.append(
            {
                "symbol": str(symbol).upper(),
                "price": price,
                "direction": direction,
                "strike": strike_engine_signal.strike,
                "distance_pct": abs(strike_engine_signal.strike - price) / price if price else distance_pct,
                "momentum_20m": momentum_20m,
                "momentum_5m": momentum_5m,
                "confidence": confidence,
                "action": action,
                "risk_dollars": risk_budget,
                "source": "crypto_1m_ohlcv",
                "expires_at": expires_at.strftime("%H:%M UTC"),
                "minutes_to_expiry": minutes_to_expiry,
                "timer_state": timer_state,
                "next_step": next_step,
                "tone": tone,
                "signal": display_signal,
                "contract_side": contract_side,
                "decision_state": decision_state,
                "probability_roxy": strike_engine_signal.probability_roxy,
                "edge": edge,
                "risk_reward": risk_reward,
                "recommended_entry": strike_engine_signal.recommended_entry,
                "reasons": strike_engine_signal.reasons,
                "warning_flags": strike_engine_signal.warning_flags,
                "href": href,
            }
        )
    return pd.DataFrame(rows, columns=columns).sort_values("confidence", ascending=False).reset_index(drop=True)


def render_crypto_twenty_min_strike_panel(
    *,
    account_equity: float,
    risk_pct: float,
    symbols: list[str] | tuple[str, ...] | None = None,
) -> None:
    rows = crypto_twenty_min_strike_rows(
        account_equity=account_equity,
        risk_pct=risk_pct,
        symbols=symbols,
        limit=4,
    )
    if rows.empty:
        return
    cards: list[str] = []
    for row in rows.to_dict("records"):
        tone = text_display(row.get("tone"))
        if tone not in {"buy", "watch", "avoid"}:
            tone = "watch"
        reasons_value = row.get("reasons")
        reasons = reasons_value if isinstance(reasons_value, list) else []
        warning_value = row.get("warning_flags")
        warnings = warning_value if isinstance(warning_value, list) else []
        why_html = "".join(
            f"<li>{html.escape(text_display(reason))}</li>"
            for reason in reasons[:4]
            if text_display(reason)
        )
        warning_html = "".join(
            f"<li>{html.escape(text_display(flag).replace('_', ' '))}</li>"
            for flag in warnings[:3]
            if text_display(flag)
        )
        why_block = (
            f'<details><summary>Por que?</summary><ul>{why_html}</ul></details>'
            if why_html
            else ""
        )
        warning_block = (
            f'<details class="strike20-warnings"><summary>Riesgo</summary><ul>{warning_html}</ul></details>'
            if warning_html
            else ""
        )
        signal_label = text_display(row.get("signal") or SIGNAL_NO_TRADE)
        decision_state = text_display(row.get("decision_state") or "ESPERAR CONFIRMACION")
        cards.append(
            f'<article class="strike20-card strike20-{html.escape(tone)}">'
            f'<header><a href="{html.escape(text_display(row.get("href")))}">{html.escape(text_display(row.get("symbol")))}</a>'
            f'<span>{html.escape(text_display(row.get("expires_at")))}</span></header>'
            f'<strong>{html.escape(signal_label)} · {html.escape(decision_state)}</strong>'
            f'<p>{html.escape(text_display(row.get("action")))} · {html.escape(text_display(row.get("direction")))} de <b>{html.escape(price_display(row.get("strike")))}</b></p>'
            '<div class="strike20-metrics">'
            f'<b><small>Ahora</small>{html.escape(price_display(row.get("price")))}</b>'
            f'<b><small>Roxy</small>{html.escape(pct_display(row.get("probability_roxy")))}</b>'
            f'<b><small>Distancia</small>{html.escape(pct_display(row.get("distance_pct")))}</b>'
            f'<b><small>Edge</small>{html.escape(pct_display(row.get("edge")))}</b>'
            f'<b><small>R/R</small>{html.escape(num_display(row.get("risk_reward"), 2))}</b>'
            f'<b><small>Timer</small>{html.escape(num_display(row.get("minutes_to_expiry"), 1))}m</b>'
            f'<b><small>Conf.</small>{html.escape(num_display(row.get("confidence"), 0))}/100</b>'
            "</div>"
            f'<small>{html.escape(text_display(row.get("timer_state")))}</small>'
            f'<em>{html.escape(text_display(row.get("next_step"))[:160])}</em>'
            f"{why_block}{warning_block}"
            f'<a class="budget-chart-link" href="{html.escape(text_display(row.get("href")))}">Cargar en graficas</a>'
            "</article>"
        )
    st.markdown(
        '<section class="strike20-panel">'
        '<header><strong>Crypto 20min</strong><span>Simulacion paper/manual · no coloca orden real · no es garantia</span></header>'
        f'<div class="strike20-grid">{"".join(cards)}</div>'
        "</section>",
        unsafe_allow_html=True,
    )


def budget_trade_plan_rows(
    table: pd.DataFrame,
    *,
    account_equity: float = 100.0,
    risk_pct: float = 0.01,
    market_scope: str = "Todos",
    max_trades: int = 3,
) -> pd.DataFrame:
    columns = [
        "symbol",
        "stage",
        "stage_label",
        "stage_tone",
        "stage_reason",
        "action",
        "product",
        "qty",
        "entry",
        "stop",
        "target_1",
        "target_2",
        "risk_dollars",
        "reward_1_dollars",
        "reward_2_dollars",
        "win_probability",
        "expected_r",
        "expected_value",
        "quality_label",
        "quality_reasons",
        "verdict",
        "next_step",
        "href",
    ]
    filtered = budget_filtered_opportunity_table(
        table,
        account_equity=account_equity,
        risk_pct=risk_pct,
        market_scope=market_scope,
        max_trades=max_trades,
    )
    if filtered.empty:
        return pd.DataFrame(columns=columns)
    rows: list[dict[str, Any]] = []
    for item in filtered.to_dict("records"):
        symbol = text_display(item.get("symbol")).upper()
        market = normalize_command_market(item.get("market"), symbol)
        tf = text_display(item.get("timeframe") or item.get("tf") or "1h")
        status = trade_decision_card_status(item)
        budget = opportunity_budget_fit(item, account_equity=account_equity, risk_pct=risk_pct)
        expectancy = budget_expectancy_status(item, account_equity=account_equity, risk_pct=risk_pct)
        stage = budget_execution_stage(expectancy)
        entry = safe_float(status.get("entry"))
        target_1 = safe_float(status.get("target_2"))
        target_2 = safe_float(status.get("target_5") or status.get("target_10"))
        units = safe_float(budget.get("units"))
        reward_1 = safe_float(budget.get("reward_2_dollars"))
        reward_2 = None
        if entry and target_2 and units:
            reward_2 = max(0.0, target_2 - entry) * units
        expected_r = safe_float(expectancy.get("expected_r"))
        allowed = bool(budget.get("allowed"))
        if allowed and expected_r is not None and expected_r > 0.35 and status.get("action") != "No operar":
            verdict = "Vale la pena vigilar/ejecutar paper si confirma."
        elif allowed and expected_r is not None and expected_r > 0:
            verdict = "Solo si mejora entrada o confirma volumen."
        else:
            verdict = "No vale la pena con este capital ahora."
        rows.append(
            {
                "symbol": symbol,
                "stage": stage["code"],
                "stage_label": stage["label"],
                "stage_tone": stage["tone"],
                "stage_reason": stage["reason"],
                "action": text_display(status.get("action")),
                "product": text_display(budget.get("recommendation")),
                "qty": units,
                "entry": entry,
                "stop": safe_float(status.get("stop")),
                "target_1": target_1,
                "target_2": target_2,
                "risk_dollars": safe_float(budget.get("risk_dollars")),
                "reward_1_dollars": reward_1,
                "reward_2_dollars": reward_2,
                "win_probability": safe_float(expectancy.get("win_probability")),
                "expected_r": expected_r,
                "expected_value": safe_float(expectancy.get("expected_value")),
                "quality_label": text_display(expectancy.get("quality_label")),
                "quality_reasons": " · ".join(text_display(reason) for reason in expectancy.get("quality_reasons") or []),
                "verdict": verdict,
                "next_step": text_display(budget.get("next_step") or status.get("next_step")),
                "href": f"?view=Activo&symbol={quote(symbol, safe='')}&market={quote(market, safe='')}&tf={quote(tf, safe='')}",
            }
        )
    return pd.DataFrame(rows, columns=columns)


def budget_top_trade_rows(
    table: pd.DataFrame,
    *,
    account_equity: float = 100.0,
    risk_pct: float = 0.01,
    market_scope: str = "Todos",
    max_trades: int = 3,
) -> pd.DataFrame:
    columns = [
        "rank",
        "rank_label",
        "symbol",
        "stage",
        "stage_label",
        "stage_tone",
        "stage_reason",
        "action",
        "product",
        "qty",
        "entry",
        "stop",
        "target_1",
        "risk_dollars",
        "reward_1_dollars",
        "win_probability",
        "expected_r",
        "expected_value",
        "quality_label",
        "quality_reasons",
        "verdict",
        "next_step",
        "href",
    ]
    rows = budget_trade_plan_rows(
        table,
        account_equity=account_equity,
        risk_pct=risk_pct,
        market_scope=market_scope,
        max_trades=max_trades,
    )
    if rows.empty:
        return pd.DataFrame(columns=columns)
    rows = rows.copy()
    rows["_stage_sort"] = rows["stage"].map(BUDGET_STAGE_ORDER).fillna(9)
    rows["_expected_sort"] = pd.to_numeric(rows["expected_value"], errors="coerce").fillna(-999)
    rows["_prob_sort"] = pd.to_numeric(rows["win_probability"], errors="coerce").fillna(0)
    output = (
        rows.sort_values(["_stage_sort", "_expected_sort", "_prob_sort"], ascending=[True, False, False])
        .drop(columns=["_stage_sort", "_expected_sort", "_prob_sort"])
        .head(max(1, int(max_trades or 3)))
        .copy()
    )
    labels = ["Mejor oportunidad", "Alternativa", "Solo si confirma"]
    output.insert(0, "rank", range(1, len(output) + 1))
    output.insert(1, "rank_label", [labels[idx] if idx < len(labels) else "Vigilar" for idx in range(len(output))])
    return output.reindex(columns=columns)


def render_budget_top_trades_panel(
    table: pd.DataFrame,
    *,
    account_equity: float,
    risk_pct: float,
    market_scope: str,
    max_trades: int,
) -> None:
    rows = budget_top_trade_rows(
        table,
        account_equity=account_equity,
        risk_pct=risk_pct,
        market_scope=market_scope,
        max_trades=min(3, max(1, int(max_trades or 3))),
    )
    risk_budget = max(1.0, safe_float(account_equity) or 100.0) * max(0.001, safe_float(risk_pct) or 0.01)
    if rows.empty:
        st.markdown(
            '<section class="budget-top-panel budget-top-empty compact-empty-budget">'
            f'<header><strong>Sin entrada lista para tu presupuesto</strong><span>${account_equity:,.0f} capital · 1R ${risk_budget:,.2f} · paper/manual</span></header>'
            '<div><article class="budget-empty-card">'
            '<b>Esperar</b>'
            '<p>No hay setup con precio, stop, target, liquidez y frescura suficientes ahora.</p>'
            '<small>Roxy sigue escaneando. No arriesga capital hasta tener entrada y stop medibles.</small>'
            '</article></div>'
            "</section>",
            unsafe_allow_html=True,
        )
        return
    cards = []
    for row in rows.to_dict("records"):
        rank = int(row.get("rank") or 0)
        tone = text_display(row.get("stage_tone"))
        if tone == "-":
            tone = "buy" if rank == 1 and safe_float(row.get("expected_r")) and safe_float(row.get("expected_r")) > 0 else "watch"
        if "No vale" in text_display(row.get("verdict")):
            tone = "avoid"
        qty = safe_float(row.get("qty"))
        qty_text = f"{qty:.4f}" if qty is not None and qty < 1 else num_display(qty, 0)
        reasons = text_display(row.get("quality_reasons"))
        stage_label = text_display(row.get("stage_label"))
        stage_reason = text_display(row.get("stage_reason"))
        size_prefix = "Comprar" if stage_label == "Operar ahora" else "Plan"
        cards.append(
            f'<article class="budget-top-card budget-top-{html.escape(tone)}">'
            f'<span>#{rank} · {html.escape(text_display(row.get("rank_label")))}</span>'
            f'<a href="{html.escape(text_display(row.get("href")))}">{html.escape(text_display(row.get("symbol")).upper())}</a>'
            f'<b>{html.escape(stage_label)} · {html.escape(text_display(row.get("quality_label")))}</b>'
            f'<p>{html.escape(size_prefix)} {html.escape(qty_text)} · Entrada {html.escape(price_display(row.get("entry")))} · Stop {html.escape(price_display(row.get("stop")))} · T1 {html.escape(price_display(row.get("target_1")))}</p>'
            f'<em>Riesgo ${html.escape(num_display(row.get("risk_dollars"), 2))} · Gana T1 ${html.escape(num_display(row.get("reward_1_dollars"), 2))} · EV {html.escape(num_display(row.get("expected_value"), 2))} · Prob. {html.escape(pct_display(row.get("win_probability")))}</em>'
            f'<i>{html.escape((stage_reason if stage_reason != "-" else reasons if reasons != "-" else text_display(row.get("next_step")))[:128])}</i>'
            "</article>"
        )
    st.markdown(
        '<section class="budget-top-panel">'
        f'<header><strong>Top 3 para tu presupuesto</strong><span>${account_equity:,.0f} capital · 1R ${risk_budget:,.2f} · {html.escape(text_display(market_scope))} · paper/manual</span></header>'
        f'<div>{"".join(cards)}</div></section>',
        unsafe_allow_html=True,
    )


def record_budget_filtered_paper_candidates(
    table: pd.DataFrame,
    *,
    account_equity: float = 100.0,
    risk_pct: float = 0.01,
    market_scope: str = "Todos",
    max_trades: int = 3,
) -> dict[str, int]:
    result = {"stock": 0, "crypto": 0}
    filtered = budget_filtered_opportunity_table(
        table,
        account_equity=account_equity,
        risk_pct=risk_pct,
        market_scope=market_scope,
        max_trades=max_trades,
    )
    if not isinstance(filtered, pd.DataFrame) or filtered.empty:
        return result
    records = filtered.to_dict("records")
    stock_rows = [
        row
        for row in records
        if normalize_command_market(row.get("market"), text_display(row.get("symbol")).upper()) == "stock"
    ]
    crypto_rows = [
        row
        for row in records
        if normalize_command_market(row.get("market"), text_display(row.get("symbol")).upper()) == "crypto"
    ]
    if stock_rows:
        try:
            candidates = build_alpaca_paper_practice_candidates(
                pd.DataFrame(stock_rows),
                account_equity=account_equity,
                risk_pct=risk_pct,
                limit=len(stock_rows),
            )
            if not candidates.empty and "status" in candidates.columns:
                candidates = candidates[candidates["status"].astype(str).eq("READY_FOR_PAPER")].reset_index(drop=True)
            if not candidates.empty:
                record_alpaca_paper_practice_candidates(candidates)
                result["stock"] = len(candidates)
        except Exception:
            pass
    if crypto_rows:
        try:
            candidates = build_crypto_paper_practice_candidates(
                pd.DataFrame(crypto_rows),
                account_equity=account_equity,
                risk_pct=risk_pct,
                limit=len(crypto_rows),
            )
            if not candidates.empty and "status" in candidates.columns:
                candidates = candidates[candidates["status"].astype(str).eq("READY_FOR_PAPER")].reset_index(drop=True)
            if not candidates.empty:
                record_crypto_paper_practice_candidates(candidates)
                result["crypto"] = len(candidates)
        except Exception:
            pass
    return result


