def option_side_from_row(row: dict) -> str:
    explicit = str(row.get("option_type") or row.get("side") or row.get("type") or "").upper()
    if explicit in {"CALL", "PUT"}:
        return explicit
    contract = str(row.get("contractSymbol") or "")
    if len(contract) >= 9 and contract[-9] in {"C", "P"}:
        return "CALL" if contract[-9] == "C" else "PUT"
    return "CALL" if "C" in contract[-10:] else "PUT" if "P" in contract[-10:] else "-"


def prepare_options_view(options_df: pd.DataFrame) -> pd.DataFrame:
    if options_df.empty:
        return pd.DataFrame()
    data = options_df.copy()
    for column in [
        "option_score",
        "dte",
        "strike",
        "delta",
        "gamma",
        "theta",
        "vega",
        "bid",
        "ask",
        "spread_pct",
        "volume",
        "openInterest",
        "breakeven_price",
        "breakeven_pct",
        "max_loss_per_contract",
        "risk_reward_at_target",
    ]:
        if column in data.columns:
            data[column] = pd.to_numeric(data[column], errors="coerce")
    data["side"] = data.apply(lambda row: option_side_from_row(row.to_dict()), axis=1)
    if "option_decision" in data.columns:
        data["candidate_rank"] = data["option_decision"].astype(str).str.upper().eq("OPTION_CANDIDATE").astype(int)
    else:
        data["candidate_rank"] = 0
    if "volume" in data.columns and "openInterest" in data.columns:
        data["liquidity"] = data["volume"].fillna(0) + data["openInterest"].fillna(0)
    else:
        data["liquidity"] = 0
    if "spread_pct" in data.columns:
        data["spread_pct_display"] = data["spread_pct"] * 100.0
    if "breakeven_pct" in data.columns:
        data["breakeven_pct_display"] = data["breakeven_pct"] * 100.0
    data = annotate_option_greek_quality(data)
    sort_cols = [
        col for col in ["candidate_rank", "option_score", "spread_pct", "liquidity", "dte"] if col in data.columns
    ]
    ascending = [False, False, True, False, True][: len(sort_cols)]
    if sort_cols:
        data = data.sort_values(sort_cols, ascending=ascending)
    return data.reset_index(drop=True)


def annotate_options_risk_budget(
    options_df: pd.DataFrame,
    *,
    account_equity: float = 500.0,
    risk_per_trade_pct: float = 0.01,
) -> pd.DataFrame:
    if options_df.empty:
        return options_df
    data = options_df.copy()
    risk_budget = max(1.0, float(account_equity or 500.0)) * max(0.001, float(risk_per_trade_pct or 0.01))
    if "max_loss_per_contract" in data.columns:
        data["max_loss_per_contract"] = pd.to_numeric(data["max_loss_per_contract"], errors="coerce")
        data["risk_budget"] = risk_budget
        data["risk_multiple"] = data["max_loss_per_contract"] / risk_budget
        data["fits_1r"] = data["max_loss_per_contract"].le(risk_budget)
        data["small_account_label"] = data["fits_1r"].map({True: "Cabe en 1R", False: "Solo paper / reducir riesgo"})
        data.loc[data["max_loss_per_contract"].isna(), "small_account_label"] = "Sin max loss"
    else:
        data["risk_budget"] = risk_budget
        data["risk_multiple"] = pd.NA
        data["fits_1r"] = False
        data["small_account_label"] = "Sin max loss"
    return data


def options_quality_chart_frame(view: pd.DataFrame) -> pd.DataFrame:
    required = ["spread_pct_display", "option_score", "liquidity"]
    if view.empty or not set(required).issubset(view.columns):
        return pd.DataFrame(columns=list(view.columns))
    frame = view.copy()
    for column in required:
        frame[column] = pd.to_numeric(frame[column], errors="coerce")
        frame[column] = frame[column].map(
            lambda value: value if pd.notna(value) and math.isfinite(float(value)) else None
        )
    frame = frame.dropna(subset=required)
    frame = frame[frame["liquidity"] > 0]
    return frame.reset_index(drop=True)


def options_liquidity_chart_frame(view: pd.DataFrame, *, limit: int = 12) -> pd.DataFrame:
    required = ["contractSymbol", "volume", "openInterest"]
    if view.empty or not set(required).issubset(view.columns):
        return pd.DataFrame(columns=["contractSymbol", "metric", "value"])
    frame = view.head(max(1, int(limit)))[required].copy()
    for column in ["volume", "openInterest"]:
        frame[column] = pd.to_numeric(frame[column], errors="coerce")
    liquidity = frame.melt("contractSymbol", var_name="metric", value_name="value")
    liquidity["value"] = pd.to_numeric(liquidity["value"], errors="coerce")
    liquidity["value"] = liquidity["value"].map(
        lambda value: value if pd.notna(value) and math.isfinite(float(value)) else None
    )
    liquidity = liquidity.dropna(subset=["contractSymbol", "value"])
    liquidity = liquidity[liquidity["value"] > 0]
    return liquidity.reset_index(drop=True)


def options_symbol_filter_contract(
    options_df: pd.DataFrame,
    active_symbol: str,
    active_market: str,
) -> dict[str, Any]:
    """Bind the options universe to the shared selected-underlying contract."""
    symbol = text_display(active_symbol).upper()
    market = normalize_command_market(active_market, symbol)
    available: list[str] = []
    if isinstance(options_df, pd.DataFrame) and not options_df.empty and "symbol" in options_df.columns:
        available = sorted(
            {
                text_display(value).upper()
                for value in options_df["symbol"].dropna().tolist()
                if text_display(value) != "-"
            }
        )
    if market != "stock":
        return {
            "active_symbol": symbol,
            "active_market": market,
            "values": ["Todos"],
            "default": "Todos",
            "applicable": False,
            "has_contracts": False,
        }
    values = ["Todos"] + available
    if symbol and symbol != "-" and symbol not in available:
        values.insert(1, symbol)
    return {
        "active_symbol": symbol,
        "active_market": market,
        "values": values,
        "default": symbol if symbol and symbol != "-" else "Todos",
        "applicable": True,
        "has_contracts": symbol in available,
    }


def persist_options_symbol_filter() -> None:
    selected = text_display(st.session_state.get("options_symbol_filter")).upper()
    if not selected or selected in {"-", "TODOS"}:
        return
    st.session_state["command_symbol"] = selected
    st.session_state["command_market"] = "stock"
    st.query_params["symbol"] = selected
    st.query_params["market"] = "stock"
    if not first_query_param_value(st.query_params, "tf"):
        st.query_params["tf"] = st.session_state.get("command_timeframe", "1h")


def show_options_screen(confluence_df: pd.DataFrame, options_df: pd.DataFrame, brief: dict) -> None:
    operational = resolve_roxy_operational_context(st.query_params, st.session_state)
    active_symbol = operational["symbol"]
    active_market = operational["market"]
    active_timeframe = operational["timeframe"]
    st.session_state["command_symbol"] = active_symbol
    st.session_state["command_market"] = active_market
    st.session_state["command_timeframe"] = active_timeframe
    st.subheader(f"Opciones · {active_symbol}")
    st.caption(
        f"Subyacente central: {active_symbol} · mercado {active_market.upper()} · marco {active_timeframe}. "
        "Cambiar el símbolo aquí actualiza el mismo contexto usado por gráficas, voz, watchlists y alertas."
    )
    options_route = options_route_status()
    feed = professional_options_feed_status()
    feed_cols = st.columns(3)
    with feed_cols[0]:
        render_kpi_card("Fuente Greeks", feed["label"], tone=feed["tone"], detail=feed["source"])
    with feed_cols[1]:
        render_kpi_card("Datos requeridos", "Delta / DTE / Spread / OI", tone="watch")
    with feed_cols[2]:
        usage_label = "Solo lectura" if options_route["blocked"] else "Manual / paper"
        render_kpi_card("Uso permitido", usage_label, tone=options_route["tone"], detail=options_route["detail"])

    data = prepare_options_view(options_df)
    symbol_contract = options_symbol_filter_contract(data, active_symbol, active_market)
    if not symbol_contract["applicable"]:
        st.info(
            f"El panel de opciones sobre acciones no aplica a {active_symbol} ({active_market.upper()}). "
            "Roxy conserva el activo seleccionado y no muestra contratos bursátiles de otro subyacente."
        )
        return
    if data.empty:
        if options_route["blocked"]:
            st.info("Opciones bloqueadas por ruta/proveedor. Los candidatos se mantienen solo como contexto historico.")
        else:
            st.info(
                "Todavia no hay candidatos de opciones. Roxy solo escanea contratos cuando la accion base tiene setup calificado."
            )
        empty_cols = st.columns(3)
        with empty_cols[0]:
            render_kpi_card("1R cuenta", num_display(float(DEFAULT_ACCOUNT_EQUITY) * 0.01), tone="watch")
        with empty_cols[1]:
            render_kpi_card("Regla opciones", "Solo paper", tone="avoid")
        with empty_cols[2]:
            render_kpi_card("Esperar", "Setup base BUY", tone="watch")
        st.caption(
            "Con $500 y riesgo 1%, un contrato solo pasa si su max loss cabe cerca de $5. Si no cabe, Roxy debe priorizar accion/fraccionada o paper."
        )
        table = focused_opportunity_table(brief)
        if not table.empty and "symbol" in table.columns:
            table = table[table["symbol"].astype(str).str.upper().eq(active_symbol)]
        if not table.empty:
            st.markdown(f"**{active_symbol} esperando escaneo de opciones**")
            st.dataframe(
                table[["symbol", "signal", "decision", "entry", "stop", "target_pct"]], width="stretch", hide_index=True
            )
        return

    symbols = list(symbol_contract["values"])
    signature = (active_symbol, active_market, tuple(symbols))
    if st.session_state.get("options_symbol_context_signature") != signature:
        st.session_state["options_symbol_filter"] = symbol_contract["default"]
        st.session_state["options_symbol_context_signature"] = signature
    controls = st.columns([1, 1, 1, 1, 1])
    with controls[0]:
        selected_symbol = st.selectbox(
            "Simbolo",
            symbols,
            key="options_symbol_filter",
            on_change=persist_options_symbol_filter,
        )
    with controls[1]:
        selected_side = st.selectbox("Tipo", ["Todos", "CALL", "PUT"], key="options_side_filter")
    with controls[2]:
        min_score = st.slider("Score minimo", 0, 100, 0, key="options_min_score")
    with controls[3]:
        option_equity = st.number_input(
            "Cuenta", min_value=100.0, value=float(DEFAULT_ACCOUNT_EQUITY), step=50.0, key="options_equity"
        )
    with controls[4]:
        option_risk_pct = st.number_input(
            "Riesgo %", min_value=0.1, max_value=5.0, value=1.0, step=0.1, key="options_risk_pct"
        )

    view = data.copy()
    if selected_symbol != "Todos" and "symbol" in view.columns:
        view = view[view["symbol"].astype(str).str.upper().eq(selected_symbol)]
    if selected_side != "Todos":
        view = view[view["side"].eq(selected_side)]
    if "option_score" in view.columns:
        view = view[view["option_score"].fillna(0) >= min_score]
    view = annotate_options_risk_budget(
        view,
        account_equity=float(option_equity),
        risk_per_trade_pct=float(option_risk_pct) / 100.0,
    )
    view = annotate_professional_options_contracts(view)

    if view.empty:
        if selected_symbol == active_symbol and not symbol_contract["has_contracts"]:
            st.warning(
                f"Sin contratos verificables para {active_symbol} en el snapshot actual. "
                "Roxy no sustituye el subyacente por otro símbolo."
            )
        else:
            st.warning("Ningun contrato coincide con esos filtros.")
        return

    if options_route["blocked"]:
        st.warning("Ruta de opciones bloqueada: revisar solo como contexto; no usar como entrada operable.")

    best = view.iloc[0].to_dict()
    best_cols = st.columns(8)
    with best_cols[0]:
        pro_decision = text_display(best.get("professional_decision"))
        render_kpi_card(
            "Mejor contrato",
            best.get("contractSymbol", "-"),
            tone="buy" if pro_decision in {"MIRAR_CALL", "MIRAR_PUT"} else "watch",
            detail=text_display(best.get("human_decision")),
        )
    with best_cols[1]:
        render_kpi_card("Tipo", best.get("side", "-"))
    with best_cols[2]:
        render_kpi_card("DTE", num_display(best.get("dte"), 0))
    with best_cols[3]:
        render_kpi_card("Delta", num_display(best.get("delta"), 2))
    with best_cols[4]:
        render_kpi_card("Spread", pct_display(best.get("spread_pct")))
    with best_cols[5]:
        render_kpi_card("Volumen", num_display(best.get("volume"), 0))
    with best_cols[6]:
        render_kpi_card("Open interest", num_display(best.get("openInterest"), 0))
    with best_cols[7]:
        render_kpi_card(
            "Riesgo max",
            num_display(best.get("max_loss_per_contract")),
            tone="buy" if bool(best.get("fits_1r")) else "avoid",
        )

    readiness_cols = st.columns([1, 1, 1.2, 1])
    with readiness_cols[0]:
        readiness = text_display(best.get("professional_readiness"))
        readiness_tone = (
            "buy" if readiness == "Listo para revisar" else "avoid" if readiness == "Faltan Greeks" else "watch"
        )
        render_kpi_card("Calidad contrato", readiness, tone=readiness_tone)
    with readiness_cols[1]:
        render_kpi_card("Fuente", text_display(best.get("data_source") or feed["source"]), tone=feed["tone"])
    with readiness_cols[2]:
        render_kpi_card("Bloqueos", text_display(best.get("professional_blockers")), tone=readiness_tone)
    with readiness_cols[3]:
        render_kpi_card(
            "Prima / max loss", f"{num_display(best.get('ask'))} / {num_display(best.get('max_loss_per_contract'))}"
        )

    risk_cols = st.columns(4)
    with risk_cols[0]:
        render_kpi_card("Break-even", num_display(best.get("breakeven_price")))
    with risk_cols[1]:
        render_kpi_card("Break-even %", pct_display(best.get("breakeven_pct")))
    with risk_cols[2]:
        render_kpi_card("Bid / Ask", f"{num_display(best.get('bid'))} / {num_display(best.get('ask'))}")
    with risk_cols[3]:
        render_kpi_card(
            "Score opcion",
            num_display(best.get("option_score"), 0),
            tone="buy" if (safe_float(best.get("option_score")) or 0) >= 70 else "watch",
        )

    greek_label, greek_tone, greek_note = greek_quality_label(best)
    greek_cols = st.columns(4)
    with greek_cols[0]:
        render_kpi_card("Greeks", greek_label, tone=greek_tone, detail=greek_note)
    with greek_cols[1]:
        render_kpi_card("Gamma", num_display(best.get("gamma"), 4))
    with greek_cols[2]:
        render_kpi_card(
            "Theta",
            num_display(best.get("theta"), 4),
            tone="avoid" if safe_float(best.get("theta")) and safe_float(best.get("theta")) < 0 else "neutral",
        )
    with greek_cols[3]:
        render_kpi_card("Vega", num_display(best.get("vega"), 4))

    account_cols = st.columns(4)
    with account_cols[0]:
        render_kpi_card("1R cuenta", num_display(best.get("risk_budget")), tone="watch")
    with account_cols[1]:
        fits = bool(best.get("fits_1r"))
        render_kpi_card("Cabe en 1R", "SI" if fits else "NO", tone="buy" if fits else "avoid")
    with account_cols[2]:
        render_kpi_card(
            "Veces 1R",
            num_display(best.get("risk_multiple"), 2),
            tone="avoid" if (safe_float(best.get("risk_multiple")) or 0) > 1 else "buy",
        )
    with account_cols[3]:
        render_kpi_card(
            "Contratos por riesgo",
            num_display(best.get("contracts_by_risk"), 0),
            tone="buy" if (safe_float(best.get("contracts_by_risk")) or 0) >= 1 else "avoid",
            detail=best.get("small_account_label", "-"),
        )
    summary_text = text_display(best.get("professional_summary"))
    if summary_text != "-":
        st.info(summary_text)

    chart_cols = st.columns([1, 1])
    with chart_cols[0]:
        quality_view = options_quality_chart_frame(view)
        if not quality_view.empty:
            quality_spread_max = safe_float(quality_view["spread_pct_display"].max()) or 1.0
            quality_liquidity_max = safe_float(quality_view["liquidity"].max()) or 1.0
