def render_smart_alert_gate(brief: dict) -> None:
    rows = []
    for row in brief.get("opportunities") or []:
        blockers = row.get("alert_blockers") or []
        if isinstance(blockers, str):
            blockers = [blockers]
        checks = (row.get("smart_alert") or {}).get("checks") or []
        rows.append(
            {
                "symbol": row.get("symbol"),
                "market": row.get("market"),
                "action": human_trade_action(row),
                "quality": row.get("alert_quality") or (row.get("smart_alert") or {}).get("quality"),
                "gate": alert_gate_label(row.get("alert_gate")),
                "readiness": row.get("alert_readiness_score"),
                "passed": f"{(row.get('smart_alert') or {}).get('passed_count', 0)}/{(row.get('smart_alert') or {}).get('total_checks', 0)}",
                "primary_blocker": row.get("alert_primary_blocker")
                or (row.get("smart_alert") or {}).get("primary_blocker"),
                "next_action": row.get("alert_next_action") or (row.get("smart_alert") or {}).get("next_action"),
                "reason": human_alert_reason(row),
                "missing": " | ".join(str(item) for item in blockers[:3]) if blockers else "Listo",
                "movement": row.get("alert_movement"),
                "signal": row.get("signal"),
                "decision": row.get("trade_decision"),
                "entry": row.get("entry"),
                "stop": row.get("stop"),
                "checks": " | ".join(
                    f"{check.get('rule')}: {'OK' if check.get('passed') else 'NO'}" for check in checks[:5]
                ),
            }
        )
    st.markdown("**Filtro inteligente de alertas**")
    if not rows:
        st.caption("No hay oportunidades ordenadas por IA en el brief actual.")
        return
    gate_df = pd.DataFrame(rows).sort_values(["action", "readiness"], ascending=[True, False])
    chart_df = gate_df.copy()
    chart_df["readiness"] = pd.to_numeric(chart_df["readiness"], errors="coerce")
    chart_df["readiness"] = chart_df["readiness"].map(
        lambda value: value if pd.notna(value) and math.isfinite(float(value)) else None
    )
    chart_df = chart_df.dropna(subset=["symbol", "readiness"]).head(12)
    chart = (
        alt.Chart(chart_df)
        .mark_bar()
        .encode(
            # A color encoding makes Vega-Lite stack bars by default and creates
            # synthetic readiness_start/end fields.  Disabling that needless
            # stack prevents an empty extent in the mobile iframe.
            x=alt.X(
                "readiness:Q",
                title="Checklist %",
                stack=None,
                scale=alt.Scale(domain=[0, 100]),
            ),
            y=alt.Y("symbol:N", title="Simbolo", sort="-x"),
            color=alt.Color(
                "gate:N",
                title="Filtro",
                scale=alt.Scale(
                    range=["#22c55e", "#f59e0b", "#38bdf8", "#ef4444", "#a78bfa", "#94a3b8"],
                ),
            ),
            tooltip=[
                alt.Tooltip("symbol:N", title="Simbolo"),
                alt.Tooltip("quality:N", title="Calidad"),
                alt.Tooltip("gate:N", title="Filtro"),
                alt.Tooltip("passed:N", title="Pasa"),
                alt.Tooltip("primary_blocker:N", title="Bloqueo principal"),
                alt.Tooltip("next_action:N", title="Proximo paso"),
            ],
        )
    )
    st.altair_chart(chart.properties(height=280), use_container_width=True)
    display_cols = [
        "symbol",
        "action",
        "quality",
        "gate",
        "readiness",
        "passed",
        "primary_blocker",
        "next_action",
        "reason",
        "entry",
        "stop",
    ]
    gate_display = gate_df[[col for col in display_cols if col in gate_df.columns]].rename(
        columns={
            "symbol": "Simbolo",
            "action": "Accion",
            "quality": "Calidad",
            "gate": "Filtro",
            "readiness": "Checklist %",
            "passed": "Pasa",
            "primary_blocker": "Bloqueo principal",
            "next_action": "Proximo paso",
            "reason": "Razon",
            "entry": "Entrada",
            "stop": "Stop",
        }
    )
    st.dataframe(gate_display, width="stretch", hide_index=True)


def roxy_lab_evidence_chart_frame(lab_df: pd.DataFrame) -> pd.DataFrame:
    if lab_df.empty or not {"evidence_score", "strategy_family", "lab_state"}.issubset(lab_df.columns):
        return pd.DataFrame()
    frame = lab_df.copy()
    frame["evidence_score_pct"] = pd.to_numeric(frame["evidence_score"], errors="coerce") * 100.0
    frame["evidence_score_pct"] = frame["evidence_score_pct"].map(
        lambda value: value if pd.notna(value) and math.isfinite(float(value)) else None
    )
    return frame.dropna(subset=["strategy_family", "evidence_score_pct"]).reset_index(drop=True)


def roxy_learning_readiness_chart_frame(journal_df: pd.DataFrame) -> pd.DataFrame:
    if journal_df.empty or not {"generated_at", "top_readiness"}.issubset(journal_df.columns):
        return pd.DataFrame()
    frame = journal_df.copy()
    frame["generated_at"] = pd.to_datetime(frame["generated_at"], errors="coerce", utc=True, format="mixed")
    frame["generated_at"] = frame["generated_at"].dt.tz_convert(None)
    frame["top_readiness"] = pd.to_numeric(frame["top_readiness"], errors="coerce")
    frame["top_readiness"] = frame["top_readiness"].map(
        lambda value: value if pd.notna(value) and math.isfinite(float(value)) else None
    )
    frame = frame.dropna(subset=["generated_at", "top_readiness"]).reset_index(drop=True)
    if frame.empty:
        return frame
    # Vega's temporal extent inference can emit empty-domain warnings in narrow
    # iframes even when pandas contains valid datetimes.  A finite epoch domain
    # makes the rendering contract deterministic while retaining a readable
    # timestamp in the tooltip.
    frame["generated_epoch_ms"] = frame["generated_at"].astype("int64") / 1_000_000.0
    frame["generated_label"] = frame["generated_at"].dt.strftime("%Y-%m-%d %H:%M UTC")
    return frame


def render_roxy_lab_visual(brief: dict, memory: dict) -> None:
    trades_path, trades_df = latest_backtest_trades()
    backtest_summary = summarize_backtest_by_strategy(trades_df)
    lab_rows = build_strategy_lab(memory, backtest_summary=backtest_summary)

    st.subheader("Roxy Lab")
    if not lab_rows:
        st.info("Roxy Lab is waiting for strategy memory or backtest results.")
        return

    lab_df = pd.DataFrame(lab_rows)
    state_labels = {
        "Promote": "Promover",
        "Watch": "Vigilar",
        "Collect data": "Recolectar datos",
        "Tighten filter": "Ajustar filtro",
    }
    state_counts = lab_df["lab_state"].value_counts()
    kpi_cols = st.columns(4)
    with kpi_cols[0]:
        render_kpi_card("Promover", int(state_counts.get("Promote", 0)), tone="buy")
    with kpi_cols[1]:
        render_kpi_card("Vigilar", int(state_counts.get("Watch", 0)), tone="watch")
    with kpi_cols[2]:
        render_kpi_card("Ajustar", int(state_counts.get("Tighten filter", 0)), tone="avoid")
    with kpi_cols[3]:
        render_kpi_card("Datos", int(state_counts.get("Collect data", 0)))

    shadow_observed = int(pd.to_numeric(lab_df.get("shadow_observed", 0), errors="coerce").fillna(0).sum())
    shadow_target_weighted = 0.0
    shadow_stop_weighted = 0.0
    if shadow_observed:
        shadow_target_weighted = (
            pd.to_numeric(lab_df.get("shadow_target_rate", 0), errors="coerce").fillna(0)
            * pd.to_numeric(lab_df.get("shadow_observed", 0), errors="coerce").fillna(0)
        ).sum() / shadow_observed
        shadow_stop_weighted = (
            pd.to_numeric(lab_df.get("shadow_stop_pressure", 0), errors="coerce").fillna(0)
            * pd.to_numeric(lab_df.get("shadow_observed", 0), errors="coerce").fillna(0)
        ).sum() / shadow_observed
    shadow_cols = st.columns(3)
    with shadow_cols[0]:
        render_kpi_card("WATCH medidos", shadow_observed, tone="watch")
    with shadow_cols[1]:
        render_kpi_card(
            "WATCH cerca 2%",
            pct_display(shadow_target_weighted),
            tone="buy" if shadow_target_weighted >= 0.55 else "neutral",
        )
    with shadow_cols[2]:
        render_kpi_card(
            "WATCH hacia stop",
            pct_display(shadow_stop_weighted),
            tone="avoid" if shadow_stop_weighted >= 0.45 else "neutral",
        )

    render_lab_daily_summary(lab_rows)

    chart_df = roxy_lab_evidence_chart_frame(lab_df)
    chart_df["lab_state_label"] = chart_df["lab_state"].map(state_labels).fillna(chart_df["lab_state"])
    state_domain = ["Promote", "Watch", "Collect data", "Tighten filter"]
    state_label_domain = [state_labels[item] for item in state_domain]
    state_range = ["#22c55e", "#f59e0b", "#38bdf8", "#ef4444"]
    if not chart_df.empty:
        lab_chart = (
            alt.Chart(chart_df)
            .mark_bar()
            .encode(
            x=alt.X("evidence_score_pct:Q", title="Evidencia %", scale=alt.Scale(domain=[0, 100])),
            y=alt.Y("strategy_family:N", title="Estrategia", sort="-x"),
            color=alt.Color(
                "lab_state_label:N", title="Estado lab", scale=alt.Scale(domain=state_label_domain, range=state_range)
            ),
            tooltip=[
                alt.Tooltip("strategy_family:N", title="Estrategia"),
                alt.Tooltip("lab_state_label:N", title="Estado"),
                alt.Tooltip("evidence_score_pct:Q", title="Evidencia %", format=".1f"),
                alt.Tooltip("alerts:Q", title="Alertas"),
                alt.Tooltip("shadow_observed:Q", title="WATCH medidos"),
                alt.Tooltip("shadow_target_rate:Q", title="WATCH cerca 2%", format=".1%"),
                alt.Tooltip("shadow_stop_pressure:Q", title="WATCH hacia stop", format=".1%"),
                alt.Tooltip("backtest_trades:Q", title="Backtest trades"),
            ],
            )
        )
        st.altair_chart(lab_chart.properties(height=320), use_container_width=True)
    else:
        st.caption("Evidencia cuantitativa pendiente; Roxy no dibuja una escala vacia.")

    journal_df = load_learning_journal(limit=40)
    if not journal_df.empty:
        st.markdown("**Bitacora diaria de aprendizaje**")
        chart_rows = roxy_learning_readiness_chart_frame(journal_df)
        if not chart_rows.empty and chart_rows["top_readiness"].nunique(dropna=True) > 1:
            epoch_min = float(chart_rows["generated_epoch_ms"].min())
            epoch_max = float(chart_rows["generated_epoch_ms"].max())
            epoch_padding = max((epoch_max - epoch_min) * 0.02, 60_000.0)
            readiness_chart = (
                alt.Chart(chart_rows)
                .mark_line(point=True)
                .encode(
                    x=alt.X(
                        "generated_epoch_ms:Q",
                        title="Tiempo",
                        scale=alt.Scale(domain=[epoch_min - epoch_padding, epoch_max + epoch_padding]),
                        axis=alt.Axis(format=".0f", labels=False, ticks=False),
                    ),
                    y=alt.Y("top_readiness:Q", title="Checklist %", scale=alt.Scale(domain=[0, 100])),
                    color=alt.Color("top_action:N", title="Accion"),
                    tooltip=[
                        alt.Tooltip("generated_label:N", title="Tiempo"),
                        alt.Tooltip("top_symbol:N", title="Simbolo"),
                        alt.Tooltip("top_action:N", title="Accion"),
                        alt.Tooltip("top_gate:N", title="Filtro"),
                        alt.Tooltip("top_quality:N", title="Calidad"),
                        alt.Tooltip("top_readiness:Q", title="Checklist %", format=".0f"),
                        alt.Tooltip("learning_bias:N", title="Memoria"),
                    ],
                )
            )
            st.altair_chart(readiness_chart.properties(height=180), use_container_width=True)
        elif not chart_rows.empty:
            st.caption("Readiness sin variacion en la ventana actual; no se dibuja una serie plana.")

        display_cols = [
            "generated_at",
            "top_symbol",
            "top_market",
            "top_action",
            "top_strategy",
            "top_gate",
            "top_quality",
            "top_readiness",
            "top_next_action",
            "learning_bias",
            "learning_lesson",
            "next_experiment",
        ]
        journal_display = journal_df[[col for col in display_cols if col in journal_df.columns]].copy()
        if "top_action" in journal_display.columns:
            journal_display["top_action"] = journal_display["top_action"].map(action_label)
        if "top_readiness" in journal_display.columns:
            journal_display["top_readiness"] = journal_display["top_readiness"].map(
                lambda value: num_display(value, 0) if pd.notna(value) else "-"
            )
        if "generated_at" in journal_display.columns:
            journal_display["generated_at"] = (
                journal_display["generated_at"].astype(str).str.replace("T", " ", regex=False).str.slice(0, 16)
            )
        journal_display = journal_display.rename(
            columns={
                "generated_at": "Fecha",
                "top_symbol": "Simbolo",
                "top_market": "Mercado",
                "top_action": "Decision",
                "top_strategy": "Estrategia",
                "top_gate": "Filtro",
                "top_quality": "Calidad",
                "top_readiness": "Checklist",
                "top_next_action": "Que espera",
                "learning_bias": "Memoria",
                "learning_lesson": "Leccion",
                "next_experiment": "Siguiente experimento",
            }
        )
        st.dataframe(journal_display.tail(15), width="stretch", hide_index=True, height=320)

    learning_plan = brief.get("learning_plan") or autonomous_learning_plan(memory, backtest_summary=backtest_summary)
    if learning_plan:
        st.markdown("**Plan autonomo de aprendizaje**")
        plan_df = pd.DataFrame(learning_plan)
        display_cols = [
            "strategy_family",
            "action",
            "safety_mode",
            "evidence_score",
            "proposed_rule",
            "activation_rule",
            "why",
        ]
        plan_display = plan_df[[col for col in display_cols if col in plan_df.columns]].rename(
            columns={
                "strategy_family": "Estrategia",
                "action": "Accion",
                "safety_mode": "Modo",
                "evidence_score": "Evidencia",
                "proposed_rule": "Regla propuesta",
                "activation_rule": "Activacion",
                "why": "Por que",
            }
        )
        if "Accion" in plan_display.columns:
            plan_display["Accion"] = plan_display["Accion"].map(learning_action_label)
        if "Modo" in plan_display.columns:
            plan_display["Modo"] = plan_display["Modo"].map(safety_mode_label)
        st.dataframe(plan_display, width="stretch", hide_index=True)

    experiment_registry = brief.get("experiment_registry") or (
        memory.get("experiment_registry") if isinstance(memory, dict) else []
    )
    if experiment_registry:
        st.markdown("**Registro de experimentos Roxy**")
        experiments_df = pd.DataFrame(experiment_registry)
        measured_total = int(pd.to_numeric(experiments_df.get("measured_count", 0), errors="coerce").fillna(0).sum())
        hit_2_total = int(pd.to_numeric(experiments_df.get("hit_2_count", 0), errors="coerce").fillna(0).sum())
        stop_total = int(pd.to_numeric(experiments_df.get("stop_count", 0), errors="coerce").fillna(0).sum())
        exp_cols = st.columns(4)
        with exp_cols[0]:
            render_kpi_card("Experimentos", len(experiments_df), tone="watch")
        with exp_cols[1]:
            render_kpi_card("Senales medidas", measured_total, tone="buy" if measured_total >= 3 else "watch")
        with exp_cols[2]:
            render_kpi_card(
                "Hit 2% lab", pct_display(hit_2_total / measured_total if measured_total else 0.0), tone="buy"
            )
        with exp_cols[3]:
            render_kpi_card(
                "Stop lab",
                pct_display(stop_total / measured_total if measured_total else 0.0),
                tone="avoid" if stop_total else "neutral",
            )
        display_cols = [
            "strategy_family",
            "status",
            "outcome_state",
            "action",
            "safety_mode",
            "evidence_score",
            "measured_count",
            "hit_2_rate",
            "stop_rate",
            "seen_count",
            "proposed_rule",
            "activation_rule",
        ]
        for col in ["hit_2_rate", "stop_rate", "evidence_score"]:
            if col in experiments_df.columns:
                experiments_df[col] = experiments_df[col].map(
                    lambda value: pct_display(value) if pd.notna(value) else "-"
                )
        experiment_display = experiments_df[[col for col in display_cols if col in experiments_df.columns]].rename(
            columns={
                "strategy_family": "Estrategia",
                "status": "Estado",
                "outcome_state": "Resultado",
                "action": "Accion",
                "safety_mode": "Modo",
                "evidence_score": "Evidencia",
                "measured_count": "Medidas",
                "hit_2_rate": "Hit 2%",
                "stop_rate": "Stop",
                "seen_count": "Visto",
                "proposed_rule": "Regla propuesta",
                "activation_rule": "Activacion",
            }
        )
        if "Estado" in experiment_display.columns:
            experiment_display["Estado"] = experiment_display["Estado"].map(experiment_status_label)
        if "Accion" in experiment_display.columns:
            experiment_display["Accion"] = experiment_display["Accion"].map(learning_action_label)
        if "Modo" in experiment_display.columns:
            experiment_display["Modo"] = experiment_display["Modo"].map(safety_mode_label)
        st.dataframe(
            experiment_display,
            width="stretch",
            hide_index=True,
            height=260,
        )

    display_cols = [
        "strategy_family",
        "lab_state",
        "evidence_score",
        "memory_bias",
        "adaptive_weight",
        "alerts",
        "hit_2_rate",
        "hit_5_rate",
        "stop_rate",
        "shadow_observed",
        "shadow_target_rate",
        "shadow_stop_pressure",
        "backtest_trades",
        "backtest_win_rate",
        "backtest_profit_factor",
        "lab_decision",
        "experiment_rule",
    ]
    display = lab_df[[col for col in display_cols if col in lab_df.columns]].copy()
    for col in [
        "evidence_score",
        "hit_2_rate",
        "hit_5_rate",
        "stop_rate",
        "shadow_target_rate",
        "shadow_stop_pressure",
        "backtest_win_rate",
    ]:
        if col in display.columns:
            display[col] = display[col].map(lambda value: pct_display(value) if pd.notna(value) else "-")
    if "adaptive_weight" in display.columns:
        display["adaptive_weight"] = display["adaptive_weight"].map(lambda value: f"{float(value):.2f}x")
    if "backtest_profit_factor" in display.columns:
        display["backtest_profit_factor"] = display["backtest_profit_factor"].map(
            lambda value: "inf" if value == float("inf") else num_display(value)
        )
    display = display.rename(
        columns={
            "strategy_family": "Estrategia",
            "lab_state": "Estado lab",
            "evidence_score": "Evidencia",
            "memory_bias": "Memoria",
            "adaptive_weight": "Peso",
            "alerts": "Alertas",
            "hit_2_rate": "Hit 2%",
            "hit_5_rate": "Hit 5%",
            "stop_rate": "Stop",
            "shadow_observed": "WATCH medidos",
            "shadow_target_rate": "WATCH cerca 2%",
            "shadow_stop_pressure": "WATCH hacia stop",
            "backtest_trades": "Backtest trades",
            "backtest_win_rate": "Win rate",
            "backtest_profit_factor": "Profit factor",
            "lab_decision": "Decision lab",
            "experiment_rule": "Regla experimento",
        }
    )
    if "Estado lab" in display.columns:
        display["Estado lab"] = display["Estado lab"].map(lambda value: state_labels.get(str(value), value))
    with st.expander("Detalle: panel de control de estrategias", expanded=False):
        st.dataframe(display, width="stretch", hide_index=True, height=360)

    promote_rows = [row for row in lab_rows if row.get("lab_state") == "Promote"]
    tighten_rows = [row for row in lab_rows if row.get("lab_state") == "Tighten filter"]
    next_rows = promote_rows[:2] + tighten_rows[:2]
    if next_rows:
        st.markdown("**Decisiones de Roxy**")
        cols = st.columns(min(3, len(next_rows)))
        for idx, row in enumerate(next_rows[:3]):
            tone = "buy" if row.get("lab_state") == "Promote" else "avoid"
            strategy_name = text_display(row.get("strategy_family"))
            row_key = f"{idx}_{safe_key(strategy_name)}"
            with cols[idx]:
                render_kpi_card(
                    strategy_name,
                    state_labels.get(str(row.get("lab_state")), row.get("lab_state")),
                    tone=tone,
                    detail=row.get("production_action"),
                )
                st.caption(str(row.get("experiment_rule") or ""))
                if st.button("Mini estudio", key=f"lab_inline_study_{row_key}", use_container_width=True):
                    st.session_state["lab_inline_study_strategy"] = strategy_name
                if st.button("Cargar en Estudios", key=f"lab_load_study_{row_key}", use_container_width=True):
                    st.session_state["study_strategy_request"] = strategy_name
                    st.session_state["study_focus_message"] = (
                        f"Roxy Lab cargo {strategy_name}. Abre la pestana Estudios para verlo completo."
                    )
                    st.success("Listo. Abre Estudios para ver el playbook completo con grafica.")

    inline_strategy = st.session_state.get("lab_inline_study_strategy")
    if inline_strategy:
        st.markdown("**Mini estudio conectado al laboratorio**")
        inline_row = next((row for row in lab_rows if row.get("strategy_family") == inline_strategy), {})
        render_strategy_study_preview(str(inline_strategy), inline_row)

    if trades_path:
        st.caption(f"Fuente backtest: `{trades_path}`")
    st.caption(
        "Los cambios del laboratorio afectan ranking y alertas paper. Las ordenes reales siguen manuales hasta conectar un broker explicitamente."
    )


def roxy_clean_html_fragment(fragment: str) -> str:
    return re.sub(r"\n[ \t]+<", "\n<", textwrap.dedent(fragment).strip())


def roxy_home_live_chart_html(*, symbol: str, market: str, timeframe: str) -> str:
    normalized_symbol = text_display(symbol or "AAPL").upper()
    normalized_market = normalize_command_market(market, normalized_symbol)
    normalized_timeframe = normalize_command_timeframe(timeframe or "1h")
    safe_symbol = html.escape(normalized_symbol)
    timeframe_html = "".join(
        f'<a class="{"active" if item == normalized_timeframe else ""}" '
        f'href="?view=Dashboard&amp;symbol={quote(normalized_symbol, safe="")}&amp;market={quote(normalized_market, safe="")}&amp;tf={quote(item, safe="")}">'
        f"{html.escape(item.upper())}</a>"
        for item in TIMEFRAME_OPTIONS
    )
    try:
        chart_df = cached_trade_desk_chart_df(normalized_symbol, normalized_market, normalized_timeframe)
    except Exception:
        chart_df = pd.DataFrame()
    if not isinstance(chart_df, pd.DataFrame) or chart_df.empty:
        return roxy_clean_html_fragment(f"""
            <div class="roxy-ref-panel roxy-ref-chart roxy-real-chart-card" data-live-chart="loading">
              <header><span>Grafica principal</span><strong>{safe_symbol}</strong><b>Datos live...</b></header>
              <div class="roxy-ref-timeframes roxy-real-timeframes">{timeframe_html}</div>
              <div class="roxy-ref-candle-chart roxy-real-candle-chart roxy-real-chart-empty">
                <strong>Roxy esta cargando velas reales</strong>
                <small>Conectando historial, precio e indicadores del proveedor.</small>
              </div>
              <div class="roxy-chart-indicators"><i>EMA 9</i><i>SMA 20</i><i>SMA 40</i><i>BB 20 2</i><i>VOL</i></div>
            </div>
        """)

    payload = live_candle_chart_payload(
        chart_df,
        symbol=normalized_symbol,
        market=normalized_market,
        timeframe=normalized_timeframe,
        max_candles=90,
    )
    candles = list(payload.get("candles") or [])[-42:]
    if len(candles) < 2:
        return roxy_clean_html_fragment(f"""
            <div class="roxy-ref-panel roxy-ref-chart roxy-real-chart-card" data-live-chart="loading">
              <header><span>Grafica principal</span><strong>{safe_symbol}</strong><b>Esperando velas</b></header>
              <div class="roxy-ref-timeframes roxy-real-timeframes">{timeframe_html}</div>
              <div class="roxy-ref-candle-chart roxy-real-candle-chart roxy-real-chart-empty">
                <strong>Roxy necesita mas historial</strong>
                <small>El proveedor devolvio menos de dos velas para esta vista.</small>
              </div>
              <div class="roxy-chart-indicators"><i>EMA 9</i><i>SMA 20</i><i>SMA 40</i><i>BB 20 2</i><i>VOL</i></div>
            </div>
        """)

    line_items = payload.get("lines") if isinstance(payload.get("lines"), dict) else {}
    time_index = {int(candle["time"]): idx for idx, candle in enumerate(candles)}
    visible_times = set(time_index)
    visible_values: list[float] = []
    for candle in candles:
        visible_values.extend(
            [
                float(candle.get("high") or candle.get("close") or 0),
                float(candle.get("low") or candle.get("close") or 0),
            ]
        )
    for line_name in ["EMA9", "SMA20", "SMA40", "BB Upper", "BB Lower"]:
        for point in line_items.get(line_name, []) or []:
            if int(point.get("time") or 0) in visible_times:
                value = safe_float(point.get("value"))
                if value is not None:
                    visible_values.append(value)
    price_low = min(visible_values)
    price_high = max(visible_values)
    if price_high <= price_low:
        price_high = price_low + max(abs(price_low) * 0.01, 1.0)
    pad = (price_high - price_low) * 0.08
    price_low -= pad
    price_high += pad
    price_range = price_high - price_low

    def y_pct(value: Any) -> float:
        number = safe_float(value)
        if number is None:
            number = price_low
        return max(3.0, min(97.0, 100.0 - ((number - price_low) / price_range * 100.0)))

    def x_pct(index: int) -> float:
        if len(candles) <= 1:
            return 50.0
        return 7.0 + (index / (len(candles) - 1)) * 82.0

    candle_html: list[str] = []
    volume_values = [max(0.0, float(candle.get("volume") or 0)) for candle in candles]
    max_volume = max(volume_values) if any(volume_values) else 1.0
    volume_html: list[str] = []
    for idx, candle in enumerate(candles):
        open_price = float(candle.get("open") or candle.get("close") or 0)
        close_price = float(candle.get("close") or open_price)
        high_price = float(candle.get("high") or max(open_price, close_price))
        low_price = float(candle.get("low") or min(open_price, close_price))
        wick_top = y_pct(high_price)
        wick_bottom = y_pct(low_price)
        body_top = y_pct(max(open_price, close_price))
        body_bottom = y_pct(min(open_price, close_price))
        body_height = max(body_bottom - body_top, 1.6)
        color_class = "up" if close_price >= open_price else "down"
        x_value = x_pct(idx)
        candle_html.append(
            (
                f'<span class="roxy-real-candle {color_class}" '
                f'style="--x:{x_value:.2f}%;--wick-top:{wick_top:.2f}%;'
                f'--wick-h:{max(wick_bottom - wick_top, 2.0):.2f}%;'
                f'--body-top:{body_top:.2f}%;--body-h:{body_height:.2f}%"></span>'
            )
        )
        volume_height = 10.0 + (max(0.0, float(candle.get("volume") or 0)) / max_volume) * 55.0
        volume_html.append(f'<u style="--x:{x_value:.2f}%;--h:{volume_height:.2f}%"></u>')

    def line_points(line_name: str) -> str:
        points: list[str] = []
        for point in line_items.get(line_name, []) or []:
            point_time = int(point.get("time") or 0)
            if point_time not in time_index:
                continue
            value = safe_float(point.get("value"))
            if value is None:
                continue
            points.append(f"{x_pct(time_index[point_time]):.2f},{y_pct(value):.2f}")
        return " ".join(points)

    ema9_points = line_points("EMA9")
    sma20_points = line_points("SMA20")
    sma40_points = line_points("SMA40")
    bb_upper_points = line_points("BB Upper")
    bb_lower_points = line_points("BB Lower")
    lines_svg = f"""
        <svg class="roxy-real-lines" viewBox="0 0 100 100" preserveAspectRatio="none" aria-hidden="true">
          <polyline class="bb upper" points="{html.escape(bb_upper_points)}"></polyline>
          <polyline class="bb lower" points="{html.escape(bb_lower_points)}"></polyline>
          <polyline class="ema fast" points="{html.escape(ema9_points)}"></polyline>
          <polyline class="ema mid" points="{html.escape(sma20_points)}"></polyline>
          <polyline class="ema slow" points="{html.escape(sma40_points)}"></polyline>
        </svg>
    """
    latest = candles[-1]
    previous = candles[-2]
    latest_close = float(latest.get("close") or 0)
    previous_close = float(previous.get("close") or latest_close)
    change_pct = ((latest_close / previous_close) - 1.0) if previous_close else 0.0
    change_class = "positive" if change_pct >= 0 else "negative"
    last_top = y_pct(latest_close)
    axis_values = [
        price_high - price_range * 0.08,
        price_high - price_range * 0.32,
        price_high - price_range * 0.56,
        price_low + price_range * 0.08,
    ]
    price_axis_html = "".join(
        f'<span class="roxy-chart-price" style="top:{y_pct(value):.2f}%">{html.escape(price_display(value))}</span>'
        for value in axis_values
    )

    def time_label(candle: dict[str, Any]) -> str:
        ts = pd.to_datetime(candle.get("time"), unit="s", utc=True, errors="coerce")
        if pd.isna(ts):
            return ""
        if normalized_timeframe in {"1d", "1w"}:
            return ts.strftime("%d")
        return ts.strftime("%H:%M")

    label_indices = [0, max(0, len(candles) // 3), max(0, (len(candles) * 2) // 3), len(candles) - 1]
    x_axis_html = "".join(
        f'<span style="left:{x_pct(idx):.2f}%">{html.escape(time_label(candles[idx]))}</span>'
        for idx in dict.fromkeys(label_indices)
    )
    safe_price = html.escape(price_display(latest_close))
    safe_change = html.escape(pct_display(change_pct))
    source = text_display(payload.get("stream", {}).get("provider") or "historial real")
    try:
        freshness = shared_chart_freshness_status(
            chart_df,
            market=normalized_market,
            timeframe=normalized_timeframe,
        )
    except Exception:
        freshness = {"label": "Revisar", "tone": "watch", "detail": "frescura no disponible", "status": "WARN"}
    freshness_tone = re.sub(r"[^a-z0-9_-]+", "", text_display(freshness.get("tone") or "watch").lower()) or "watch"
    freshness_label = text_display(freshness.get("label") or "Datos reales")
    freshness_detail = text_display(freshness.get("detail") or "")
    latest_ts = pd.to_datetime(latest.get("time"), unit="s", utc=True, errors="coerce")
    latest_stamp = "Ultima vela real"
    if pd.notna(latest_ts):
        try:
            latest_stamp = latest_ts.tz_convert("America/New_York").strftime("%m/%d %I:%M %p ET")
        except Exception:
            latest_stamp = latest_ts.strftime("%m/%d %H:%M UTC")
    latest_open = float(latest.get("open") or latest_close)
    latest_high = float(latest.get("high") or latest_close)
    latest_low = float(latest.get("low") or latest_close)
    latest_volume = float(latest.get("volume") or 0)
    ohlc_html = "".join(
        [
            f"<span>O <b>{html.escape(price_display(latest_open))}</b></span>",
            f"<span>H <b>{html.escape(price_display(latest_high))}</b></span>",
            f"<span>L <b>{html.escape(price_display(latest_low))}</b></span>",
            f"<span>V <b>{html.escape(compact_large_number(latest_volume))}</b></span>",
        ]
    )
    return roxy_clean_html_fragment(f"""
        <div class="roxy-ref-panel roxy-ref-chart roxy-real-chart-card" data-live-chart="real" data-symbol="{safe_symbol}" data-freshness="{html.escape(freshness_tone)}">
          <header>
            <span>Grafica principal</span>
            <strong>{safe_symbol}</strong>
            <b class="{change_class}">{safe_price} · {safe_change}</b>
          </header>
          <div class="roxy-real-chart-meta">
            <em class="roxy-fresh-{html.escape(freshness_tone)}"><i></i>{html.escape(freshness_label)}</em>
            <small>{html.escape(latest_stamp)}</small>
          </div>
          <div class="roxy-ref-timeframes roxy-real-timeframes">{timeframe_html}</div>
          <div class="roxy-real-ohlc">{ohlc_html}</div>
          <div class="roxy-ref-candle-chart roxy-real-candle-chart">
            {price_axis_html}
            {lines_svg}
            {''.join(candle_html)}
            <span class="roxy-chart-last-line" style="top:{last_top:.2f}%"></span>
            <small class="roxy-chart-last" style="top:{last_top:.2f}%">{safe_price}</small>
            <div class="roxy-chart-volume">{''.join(volume_html)}</div>
            <div class="roxy-chart-x-axis">{x_axis_html}</div>
          </div>
          <div class="roxy-chart-indicators"><i>EMA 9</i><i>SMA 20</i><i>SMA 40</i><i>BB 20 2</i><i>VOL</i></div>
          <small class="roxy-real-source"><span><b>Datos reales</b> {html.escape(source)}</span><span>{html.escape(freshness_detail)}</span><span>{html.escape(normalized_timeframe.upper())} · sin velas simuladas</span></small>
        </div>
    """)


def render_roxy_opening_stage(
    symbol: str,
    market: str,
    timeframe: str,
    equity: float,
    risk_pct: float,
    risk_cash: float,
    ready_now: int,
    watch_now: int,
    opportunities: pd.DataFrame | None = None,
) -> None:
    safe_symbol = html.escape(text_display(symbol).upper())
    safe_market = html.escape(text_display(market).upper())
    safe_timeframe = html.escape(text_display(timeframe))
    safe_user_name = html.escape(roxy_user_display_name())
    home_chart_html = roxy_home_live_chart_html(symbol=symbol, market=market, timeframe=timeframe)
    opportunity_table = opportunities if isinstance(opportunities, pd.DataFrame) else pd.DataFrame()
    all_opportunity_rows = opportunity_table.to_dict(orient="records") if not opportunity_table.empty else []
    opportunity_rows = all_opportunity_rows[:3]

    def _opening_opportunity_html(row: dict[str, Any]) -> str:
        row_symbol = text_display(row.get("symbol")).upper() or "-"
        row_name = text_display(row.get("strategy_family") or row.get("data_source") or "Sin estrategia confirmada")
        status = trade_decision_card_status(row)
        action = text_display(status.get("action") or row.get("action") or row.get("signal") or "Vigilar")
        price = price_display(row.get("current_price"))
        data_state = text_display(row.get("data_state") or row.get("data_bucket") or "Estado no disponible")
        return (
            f'<div><i class="material-symbols-outlined" aria-hidden="true">monitoring</i>'
            f'<p><strong>{html.escape(row_symbol)}</strong><small>{html.escape(row_name)}</small></p>'
            f'<b>{html.escape(action)} · {html.escape(price)}</b>'
            f'<em>{html.escape(data_state)}</em></div>'
        )

    movers_html = "".join(_opening_opportunity_html(row) for row in opportunity_rows)
    if not movers_html:
        movers_html = (
            '<div><i class="material-symbols-outlined" aria-hidden="true">database_off</i>'
            '<p><strong>Sin oportunidades</strong><small>El escaner no entrego filas verificables.</small></p>'
            '<b>Sin datos</b></div>'
        )

    selected_row: dict[str, Any] = {}
    for row in all_opportunity_rows:
        if text_display(row.get("symbol")).upper() == text_display(symbol).upper():
            selected_row = row
            break
    selected_status = trade_decision_card_status(selected_row) if selected_row else {}
    selected_action = text_display(selected_status.get("action") or "Sin señal operativa")
    selected_entry = price_display(selected_row.get("entry")) if selected_row else "-"
    selected_stop = price_display(selected_row.get("stop")) if selected_row else "-"
    selected_target = price_display(selected_row.get("target_price")) if selected_row else "-"
    selected_source = (
        text_display(selected_row.get("data_source") or "Fuente de señal no disponible")
        if selected_row
        else "Sin oportunidad para este activo"
    )
    selected_plan_ready = bool(
        selected_row
        and safe_float(selected_row.get("entry")) is not None
        and safe_float(selected_row.get("stop")) is not None
        and safe_float(selected_row.get("target_price")) is not None
    )
    selected_plan_detail = (
        f"Entrada {selected_entry} · Stop {selected_stop} · Objetivo {selected_target} · Riesgo {risk_pct:.1f}%"
        if selected_plan_ready
        else "Esperando entrada, stop y objetivo verificables."
    )

    macro_context = macro_calendar_status()
    macro_events = list(macro_context.get("active_events") or []) + list(macro_context.get("upcoming_events") or [])
    event_rows = []
    for event in macro_events[:3]:
        event_time = pd.to_datetime(event.get("event_time"), utc=True, errors="coerce")
