def render_roxy_first_screen_launchpad(
    table: pd.DataFrame,
    *,
    symbol: str,
    market: str,
    timeframe: str,
) -> None:
    message = st.session_state.pop("roxy_launch_message", "")
    if message:
        st.success(message)
    module_from_query = first_query_param_value(st.query_params, "module")
    if not module_from_query:
        return
    st.session_state["roxy_active_module"] = normalize_roxy_module(module_from_query)
    active_module = normalize_roxy_module(module_from_query)
    active_info = roxy_module_by_slug(active_module)

    if active_module == "classroom":
        render_roxy_module_workspace(table, active_module=active_module, timeframe=timeframe)
        return
    if active_module == "acciones-operar":
        render_roxy_module_workspace(table, active_module=active_module, timeframe=timeframe)
        return

    st.markdown(
        f"""
        <section class="roxy-folder-head">
          <a href="?view=Dashboard&symbol={quote(str(symbol or 'AAPL'), safe='')}&market={quote(str(market or 'stock'), safe='')}&tf={quote(str(timeframe or '1h'), safe='')}">Cerrar carpeta</a>
          <div><span>Carpeta Roxy</span><strong>{html.escape(active_info["label"])}</strong></div>
          <small>{html.escape(active_info["detail"])} Toca una card para cargar la grafica.</small>
        </section>
        """,
        unsafe_allow_html=True,
    )
    render_roxy_module_workspace(table, active_module=active_module, timeframe=timeframe)
    return

    if not isinstance(table, pd.DataFrame) or table.empty:
        return

    pulse = market_pulse_rows(table)
    launch_rows: list[dict[str, Any]] = []
    for idx, (_, item) in enumerate(table.head(4).iterrows()):
        row = item.to_dict()
        pulse_row = pulse.iloc[idx].to_dict() if idx < len(pulse) else {}
        status = trade_decision_card_status(row)
        row_symbol = text_display(row.get("symbol")).upper()
        row_market = normalize_command_market(row.get("market"), row_symbol)
        launch_rows.append(
            {
                "symbol": row_symbol,
                "market": row_market,
                "action": text_display(status.get("action") or human_trade_action(row)),
                "tone": text_display(status.get("tone") or pulse_row.get("tone") or "watch"),
                "readiness": num_display(row.get("readiness"), 0),
                "strategy": strategy_family_for_row(row),
                "why": text_display(row.get("waiting_for") or row.get("por_que") or row.get("gate")),
            }
        )
    if not launch_rows:
        return

    st.markdown('<div class="roxy-launchpad-opps">', unsafe_allow_html=True)
    opp_cols = st.columns(len(launch_rows), gap="small")
    for idx, item in enumerate(launch_rows):
        tone = item["tone"] if item["tone"] in {"buy", "watch", "avoid"} else "watch"
        with opp_cols[idx]:
            st.markdown(
                f"""
                <div class="roxy-launch-opp roxy-launch-opp-{html.escape(tone)}">
                  <span>{html.escape(item["market"].upper())}</span>
                  <strong>{html.escape(item["symbol"])}</strong>
                  <small>{html.escape(item["action"])} · Readiness {html.escape(item["readiness"])}</small>
                  <p>{html.escape(item["strategy"])}</p>
                  <em>{html.escape(item["why"][:90])}</em>
                </div>
                """,
                unsafe_allow_html=True,
            )
            if st.button(
                "Abrir grafica",
                key=f"roxy_launch_opp_{idx}_{safe_key(item['symbol'])}",
            ):
                apply_roxy_navigation_target(
                    page="Activo",
                    symbol=item["symbol"],
                    market=item["market"],
                    timeframe=timeframe,
                    message=f"Roxy cargo {item['symbol']} en la grafica.",
                )
                st.rerun()
    st.markdown("</div>", unsafe_allow_html=True)


def roxy_selected_asset_row(symbol: str, market: str) -> dict[str, Any]:
    selected_symbol = text_display(symbol).upper()
    selected_market = normalize_command_market(market, selected_symbol)
    return {
        "symbol": selected_symbol,
        "market": selected_market,
        "current_price": None,
        "entry": None,
        "stop": None,
        "target_price": None,
        "risk_pct": None,
        "signal": "WATCH",
        "action": "Vigilar",
        "decision": "WAIT",
        "strategy_family": "Esperando datos del proveedor",
        "por_que": "Activo seleccionado por el usuario; Roxy carga velas e indicadores sin completar el universo con símbolos estáticos.",
        "readiness": 0,
        "data_bucket": "User selection",
        "data_state": "Esperando cotización verificada",
        "data_source": "Contexto visible de URL/sesión",
        "data_gate": "NO_DATA",
    }


def roxy_asset_rows_for_market(table: pd.DataFrame, market: str, *, limit: int = 8) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    seen: set[str] = set()
    priority = {"stock": ["AAPL", "MSFT", "NVDA", "TSLA"], "crypto": ["BTC/USD", "ETH/USD", "SOL/USD", "XRP/USD"]}.get(
        market, []
    )
    if isinstance(table, pd.DataFrame) and not table.empty and "symbol" in table.columns:
        data = table.copy()
        if "market" in data.columns:
            data = data[data["market"].astype(str).str.lower().map(lambda value: normalize_command_market(value, "")) == market]
        else:
            data = data[data["symbol"].astype(str).map(lambda value: normalize_command_market(None, value)) == market]
        if not data.empty and priority:
            data["_roxy_priority"] = data["symbol"].astype(str).str.upper().map(
                lambda value: priority.index(value) if value in priority else len(priority)
            )
            data = data.sort_values("_roxy_priority", kind="stable").drop(columns=["_roxy_priority"], errors="ignore")
        for _, item in data.head(limit).iterrows():
            row = item.to_dict()
            symbol = text_display(row.get("symbol")).upper()
            if symbol and symbol not in seen:
                row["symbol"] = symbol
                row["market"] = market
                rows.append(row)
                seen.add(symbol)
    return rows[:limit]


def roxy_row_recommendation(row: dict[str, Any]) -> tuple[str, str]:
    status = trade_decision_card_status(row)
    action = text_display(status.get("action") or human_trade_action(row) or row.get("signal") or "Vigilar")
    tone = text_display(status.get("tone") or "watch")
    if tone not in {"buy", "watch", "avoid"}:
        tone = "watch"
    return action, tone


def selected_roxy_asset_row(
    rows: list[dict[str, Any]], *, default_market: str, default_timeframe: str
) -> tuple[dict[str, Any], str, str, str]:
    selected_symbol = text_display(first_query_param_value(st.query_params, "symbol")).upper()
    selected_timeframe = normalize_command_timeframe(first_query_param_value(st.query_params, "tf"), default=default_timeframe)
    if not selected_symbol and rows:
        selected_symbol = text_display(rows[0].get("symbol")).upper()
    selected_market = normalize_command_market(
        first_query_param_value(st.query_params, "market") or default_market,
        selected_symbol,
    )
    selected_row: dict[str, Any] = {}
    for row in rows:
        row_symbol = text_display(row.get("symbol")).upper()
        if row_symbol == selected_symbol:
            selected_row = row
            break
    if not selected_row and rows:
        selected_row = rows[0]
        selected_symbol = text_display(selected_row.get("symbol")).upper()
        selected_market = normalize_command_market(selected_row.get("market") or default_market, selected_symbol)
    st.session_state["command_symbol"] = selected_symbol
    st.session_state["command_market"] = selected_market
    st.session_state["command_timeframe"] = selected_timeframe
    return selected_row, selected_symbol, selected_market, selected_timeframe


