                f'<p><i class="material-symbols-outlined">verified</i><span>Validacion<br><b>{html.escape(text_display(top.get("roxy_validation") or "Pendiente"))}</b></span><em>{int(safe_float(top.get("readiness")) or 0)}/100</em></p>'
