def render_roxy_alerts_panel(*, selected_symbol: str, selected_market: str, selected_timeframe: str) -> None:
    store = WatchlistStore(project_path("data/roxy_watchlists.json"))
    user_id = roxy_os_user_id()
    selected_list = roxy_mutable_watchlist_name(
        store, user_id, st.session_state.get("roxy_watchlist_selected") or "Principal"
    )
    durable_alerts = store.alerts_snapshot(user_id)
    monitor_report = read_summary_json("alerts/price_alert_monitor.json")

    st.markdown("## Alertas conectadas")
    st.caption("Reglas durables por usuario, evaluadas solo con precios positivos y fuente declarada.")
    monitor_status = text_display(monitor_report.get("status") or "NO_DATA").upper()
    monitor_detail = text_display(monitor_report.get("detail") or "El monitor background aun no ha publicado estado.")
    if monitor_status in {"OK", "NO_DATA"}:
        st.success(f"Monitor background {monitor_status} · {monitor_detail}")
    else:
        st.warning(f"Monitor background {monitor_status} · {monitor_detail}")
    if durable_alerts:
        selected_rules = [
            row for row in durable_alerts if text_display(row.get("symbol")).upper() == selected_symbol.upper()
        ]
        visible_rules = selected_rules or durable_alerts[:3]
        st.markdown("**Estado durable disponible**")
        for rule in visible_rules[:4]:
            direction = roxy_durable_alert_rule_label(rule)
            st.caption(
                f"{text_display(rule.get('symbol')).upper()} · {direction} · "
                f"{text_display(rule.get('status') or 'Activa')} · "
                f"{text_display(rule.get('last_source') or 'esperando evaluacion')}"
            )
    else:
        st.info("No hay alertas activas. Roxy no crea reglas ni niveles de demostracion.")

    current_snapshot = cached_live_price_snapshot(selected_symbol, selected_market)
    current_price = safe_float(current_snapshot.get("price"))
    current_source = text_display(current_snapshot.get("source") or "No disponible")
    current_freshness = text_display(current_snapshot.get("freshness") or current_snapshot.get("latency_note") or "")

    state_cols = st.columns(4)
    state_cols[0].metric("Activo", selected_symbol)
    state_cols[1].metric("Precio", price_display(current_price) if current_price and current_price > 0 else "Sin dato")
    state_cols[2].metric("Fuente", current_source[:28])
    state_cols[3].metric("Estado", current_freshness[:28] or "Sin lectura")

    lifetime_label = st.selectbox(
        "Vigencia de la regla",
        ("24 horas", "7 días", "30 días", "90 días"),
        index=2,
        key=f"roxy_alert_lifetime_{selected_symbol}",
        help="Si la condición no ocurre dentro de esta vigencia, Roxy la marca Expirada y deja de evaluarla.",
    )
    lifetime_hours = {"24 horas": 24, "7 días": 168, "30 días": 720, "90 días": 2160}[lifetime_label]

    threshold_value = st.number_input(
        "Nivel de alerta",
        min_value=0.000001,
        value=float(current_price) if current_price and current_price > 0 else None,
        format="%.6f",
        help="Roxy usa este nivel exacto; no lo reemplaza con un precio simulado.",
        key=f"roxy_alert_threshold_{selected_symbol}",
    )
    above_col, below_col = st.columns(2)

    def create_rule(alert_type: str) -> None:
        threshold = safe_float(threshold_value)
        if threshold is None or threshold <= 0:
            st.error("La alerta requiere un precio positivo verificable.")
            return
        store.add_asset(user_id, selected_list, selected_symbol, selected_market)
        result = store.create_price_alert(
            user_id,
            symbol=selected_symbol,
            market=selected_market,
            alert_type=alert_type,
            threshold=threshold,
            timeframe=selected_timeframe,
            watchlist_name=selected_list,
            source="manual_ui",
            ttl_hours=lifetime_hours,
        )
        sync_roxy_watchlist_session(store, user_id, selected_list)
        if result.get("created"):
            st.session_state["roxy_launch_message"] = f"Alerta creada para {selected_symbol}."
            st.rerun()
        elif result.get("reason") == "duplicate":
            st.warning("Esa alerta ya existe y permanece activa.")
        else:
            st.error("No se pudo crear la alerta; revisa activo, tipo y nivel.")

    with above_col:
        if st.button(f"Avisar si {selected_symbol} sube al nivel", key=f"roxy_alert_above_{selected_symbol}", width="stretch"):
            create_rule("price_above")
    with below_col:
        if st.button(f"Avisar si {selected_symbol} baja al nivel", key=f"roxy_alert_below_{selected_symbol}", width="stretch"):
            create_rule("price_below")

    st.markdown("**Alertas técnicas desde indicadores centrales**")
    technical_cols = st.columns([1.2, 1, 0.8, 0.8])
    technical_timeframe = technical_cols[0].selectbox(
        "Temporalidad técnica",
        TIMEFRAME_OPTIONS,
        index=(
            TIMEFRAME_OPTIONS.index(normalize_command_timeframe(selected_timeframe))
            if normalize_command_timeframe(selected_timeframe) in TIMEFRAME_OPTIONS
            else TIMEFRAME_OPTIONS.index("15m")
        ),
        key=f"roxy_alert_technical_tf_{selected_symbol}",
    )
    volume_threshold = technical_cols[1].number_input(
        "RVol mínimo",
        min_value=0.1,
        max_value=20.0,
        value=1.5,
        step=0.1,
        key=f"roxy_alert_rvol_{selected_symbol}",
    )
    fast_period = technical_cols[2].number_input(
        "EMA rápida", min_value=2, max_value=200, value=9, step=1,
        key=f"roxy_alert_fast_ema_{selected_symbol}",
    )
    slow_period = technical_cols[3].number_input(
        "EMA lenta", min_value=3, max_value=400, value=21, step=1,
        key=f"roxy_alert_slow_ema_{selected_symbol}",
    )

    def create_technical_rule(alert_type: str) -> None:
        store.add_asset(user_id, selected_list, selected_symbol, selected_market)
        result = store.create_technical_alert(
            user_id,
            symbol=selected_symbol,
            market=selected_market,
            alert_type=alert_type,
            timeframe=technical_timeframe,
            threshold=volume_threshold,
            fast_period=int(fast_period),
            slow_period=int(slow_period),
            watchlist_name=selected_list,
            source="manual_ui",
            ttl_hours=lifetime_hours,
        )
        sync_roxy_watchlist_session(store, user_id, selected_list)
        if result.get("created"):
            st.session_state["roxy_launch_message"] = f"Alerta técnica creada para {selected_symbol}."
            st.rerun()
        elif result.get("reason") == "duplicate":
            st.warning("Esa alerta técnica ya existe y permanece activa.")
        else:
            st.error("No se pudo crear la alerta técnica; revisa temporalidad y parámetros.")

    cross_up, cross_down, volume_col = st.columns(3)
    if cross_up.button(f"EMA{int(fast_period)} cruza sobre EMA{int(slow_period)}", key=f"roxy_alert_ema_up_{selected_symbol}", width="stretch"):
        create_technical_rule("ema_cross_above")
    if cross_down.button(f"EMA{int(fast_period)} cruza debajo de EMA{int(slow_period)}", key=f"roxy_alert_ema_down_{selected_symbol}", width="stretch"):
        create_technical_rule("ema_cross_below")
    if volume_col.button("Volumen supera RVol", key=f"roxy_alert_volume_{selected_symbol}", width="stretch"):
        create_technical_rule("relative_volume_above")

    alerts = store.alerts_snapshot(user_id)
    # The visible asset is already quoted above. Reuse that snapshot instead of
    # performing up to twenty sequential network calls on every Streamlit rerun.
    # Background monitoring owns the remaining symbols; opening one evaluates it
    # immediately with the same central alert engine and declared source.
    quote_payloads: dict[str, dict[str, Any]] = {}
    visible_gate = alert_quote_gate(current_snapshot, market=selected_market)
    if visible_gate.get("accepted"):
        quote_payloads[selected_symbol] = {
            "price": visible_gate.get("price"),
            "source": visible_gate.get("source") or current_source,
            "freshness": visible_gate.get("freshness") or current_freshness,
        }
    elif any(
        text_display(alert.get("symbol")).upper() == selected_symbol.upper()
        and text_display(alert.get("status")) == "Activa"
        for alert in durable_alerts
    ):
        store.record_alert_monitor_state(
            user_id,
            symbol=selected_symbol,
            market=selected_market,
            status=text_display(visible_gate.get("status") or "SIN_DATOS"),
            detail=text_display(visible_gate.get("detail") or "Precio visible no apto para disparar alertas."),
            source=text_display(visible_gate.get("source") or current_source),
            freshness=text_display(visible_gate.get("freshness") or current_freshness),
        )
    if quote_payloads:
        store.evaluate_price_alerts(user_id, quote_payloads)
        alerts = store.alerts_snapshot(user_id)

    if not alerts:
        st.info("No hay alertas activas. Roxy no crea reglas ni niveles de demostracion.")
        return
    st.caption("El activo visible se evalua ahora; los demas permanecen a cargo del monitor operativo.")
    for index, alert in enumerate(alerts):
        symbol = text_display(alert.get("symbol")).upper()
        alert_type = text_display(alert.get("type"))
        rule = roxy_durable_alert_rule_label(alert)
        status = text_display(alert.get("status") or "Activa")
        row = st.columns([1.1, 1.4, 1, 1.6, 0.7])
        row[0].markdown(f"**{symbol}**")
        row[1].write(rule)
        row[2].write(status)
        row[3].caption(
            f"{text_display(alert.get('last_source') or 'Esperando precio')} · "
            f"{text_display(alert.get('last_freshness') or 'sin evaluar')} · "
            f"{text_display(alert.get('monitor_status') or 'monitor pendiente')}"
        )
        row[3].caption(f"Vence: {text_display(alert.get('expires_at') or 'sin vigencia legacy')[:25]}")
        if status == "Activada":
            row[3].caption(
                f"Entrega: {text_display(alert.get('notification_status') or 'PENDING')} · "
                f"intentos {int(safe_float(alert.get('notification_attempts')) or 0)}"
            )
        monitor_reason = text_display(alert.get("monitor_detail"))
        if monitor_reason:
            row[3].caption(monitor_reason[:180])
        if row[4].button("Archivar", key=f"roxy_alert_archive_{alert.get('id')}_{index}"):
            store.archive_alert(user_id, alert.get("id"))
            st.rerun()


def show_alerts_screen() -> None:
    context = resolve_roxy_operational_context(st.query_params, st.session_state)
    render_roxy_alerts_panel(
        selected_symbol=context["symbol"],
        selected_market=context["market"],
        selected_timeframe=context["timeframe"],
    )


def show_notifications_screen() -> None:
    context = resolve_roxy_operational_context(st.query_params, st.session_state)
    render_selected_asset_banner(context["symbol"], context["market"], context["timeframe"])
    st.subheader("Notificaciones")
    st.caption(
        "Estado real de entrega para el usuario activo. La telemetría global muestra salud agregada; "
        "los mensajes de otros usuarios no se exponen."
    )
    store = WatchlistStore(project_path("data/roxy_watchlists.json"))
    user_id = roxy_os_user_id()
    alerts = [dict(row) for row in store.alerts_snapshot(user_id) if isinstance(row, dict)]
    delivery_counts: dict[str, int] = {}
    for row in alerts:
        if text_display(row.get("status")) != "Activada":
            continue
        state = text_display(row.get("notification_status") or "LEGACY_UNKNOWN").upper()
        delivery_counts[state] = delivery_counts.get(state, 0) + 1
    channels = notifier.notification_channel_status()
    configured = [row for row in channels if bool(row.get("configured"))]
    history = notifier.notification_history_summary(limit=50)
    cols = st.columns(4)
    with cols[0]:
        render_kpi_card("Canales externos", len(configured), detail="Configurados", tone="buy" if configured else "watch")
    with cols[1]:
        render_kpi_card("Entregadas", delivery_counts.get("DELIVERED", 0), detail="Alertas de este usuario")
    with cols[2]:
        pending = delivery_counts.get("PENDING", 0) + delivery_counts.get("RETRY_PENDING", 0)
        render_kpi_card("Pendientes", pending, detail="Reintento durable", tone="watch" if pending else "neutral")
    with cols[3]:
        failed = delivery_counts.get("DELIVERY_FAILED", 0)
        render_kpi_card("Fallidas", failed, detail="Máximo de intentos", tone="avoid" if failed else "neutral")
    st.caption(
        f"Modo global de entrega: {text_display(history.get('delivery_mode'))} · "
        f"última actividad agregada: {text_display(history.get('last_ts') or 'sin historial')} · "
        "sin contenido de mensajes en esta vista."
    )
    channel_frame = pd.DataFrame(channels)
    if not channel_frame.empty:
        st.dataframe(channel_frame, width="stretch", hide_index=True)
    user_rows = []
    for row in alerts:
        if text_display(row.get("status")) != "Activada":
            continue
        user_rows.append(
            {
                "symbol": text_display(row.get("symbol")).upper(),
                "rule": roxy_durable_alert_rule_label(row),
                "delivery": text_display(row.get("notification_status") or "LEGACY_UNKNOWN"),
                "attempts": int(safe_float(row.get("notification_attempts")) or 0),
                "last_attempt": text_display(row.get("last_notification_attempt_at")),
                "channels": ", ".join(str(item) for item in (row.get("notification_channels") or [])),
                "detail": text_display(row.get("notification_detail")),
            }
        )
    if user_rows:
        st.dataframe(pd.DataFrame(user_rows), width="stretch", hide_index=True)
    else:
        st.info("Este usuario no tiene alertas activadas con entrega pendiente o completada.")


def show_activity_screen() -> None:
    context = resolve_roxy_operational_context(st.query_params, st.session_state)
    render_selected_asset_banner(context["symbol"], context["market"], context["timeframe"])
    st.subheader("Actividad")
    user_id = roxy_os_user_id()
    store = WatchlistStore(project_path("data/roxy_watchlists.json"))
    alerts = [dict(row) for row in store.alerts_snapshot(user_id) if isinstance(row, dict)]
    archive = [dict(row) for row in store.opportunity_archive_snapshot(user_id) if isinstance(row, dict)]
    trades = storage.get_simulated_trades(limit=100, user=user_id)
    st.caption(
        f"Registro local aislado para {user_id}: alertas durables, oportunidades archivadas y fills simulados. "
        "No incluye órdenes reales ni actividad de otros perfiles."
    )
    cols = st.columns(3)
    with cols[0]:
        render_kpi_card("Alertas", len(alerts), detail="Todos los estados")
    with cols[1]:
        render_kpi_card("Oportunidades archivadas", len(archive), detail="Sistema por usuario")
    with cols[2]:
        render_kpi_card("Fills locales", len(trades), detail="PAPER_ONLY")
    if alerts:
        alert_rows = [
            {
                "timestamp": text_display(row.get("triggered_at") or row.get("expired_at") or row.get("updated_at") or row.get("created_at")),
                "type": "alert",
                "symbol": text_display(row.get("symbol")).upper(),
                "status": text_display(row.get("status")),
                "detail": text_display(row.get("monitor_detail") or roxy_durable_alert_rule_label(row)),
            }
            for row in alerts
        ]
    else:
        alert_rows = []
    archive_rows = [
        {
            "timestamp": text_display(row.get("archived_at")),
            "type": "opportunity_archive",
            "symbol": text_display(row.get("symbol")).upper(),
            "status": text_display(row.get("status")),
            "detail": text_display(row.get("archive_reason")),
        }
        for row in archive
    ]
    trade_rows = [
        {
            "timestamp": text_display(row[1]),
            "type": "local_paper_fill",
            "symbol": text_display(row[3]).upper(),
            "status": text_display(row[4]),
            "detail": f"qty={num_display(row[5], 6)} · price={num_display(row[6], 4)} · {text_display(row[7])}",
        }
        for row in trades
    ]
    activity = sorted(alert_rows + archive_rows + trade_rows, key=lambda row: row["timestamp"], reverse=True)
    if activity:
        st.dataframe(pd.DataFrame(activity[:100]), width="stretch", hide_index=True)
    else:
        st.info("Todavía no existe actividad durable para este usuario.")


def _personal_task_due_label(value: Any) -> str:
    if not value:
        return "Sin fecha limite"
    try:
        stamp = pd.Timestamp(value)
        if stamp.tzinfo is None:
            stamp = stamp.tz_localize("UTC")
        return stamp.tz_convert("America/New_York").strftime("%m/%d/%Y %I:%M %p ET")
    except (TypeError, ValueError):
        return "Fecha no disponible"


def show_personal_tasks_screen() -> None:
    user_id = roxy_os_user_id()
    store = roxy_personal_task_store()
    snapshot = store.snapshot(user_id, limit=500)
    tasks = list(snapshot.get("tasks") or [])
    st.subheader("Tareas personales")
    st.caption(
        f"Fuente local durable aislada para {user_id} · sincronizacion remota: LOCAL_ONLY · "
        f"ultima escritura: {text_display(snapshot.get('updated_at'))}. "
        "La misma fuente es utilizada por los recordatorios de voz y texto de Roxy."
    )
    metric_cols = st.columns(3)
    metric_cols[0].metric("Activas", int(snapshot.get("active_count") or 0))
    metric_cols[1].metric("Vencidas", int(snapshot.get("overdue_count") or 0))
    metric_cols[2].metric("Completadas visibles", sum(task.get("status") == "DONE" for task in tasks))

    with st.expander("Nueva tarea", expanded=not tasks):
        with st.form("roxy_personal_task_create", clear_on_submit=True):
            title = st.text_input("Titulo", max_chars=180, placeholder="Ej. Llamar al contador")
            notes = st.text_area("Notas", max_chars=2000, placeholder="Contexto opcional")
            priority = st.selectbox(
                "Prioridad",
                ["NORMAL", "HIGH", "URGENT", "LOW"],
                format_func=lambda value: {
                    "NORMAL": "Normal",
                    "HIGH": "Alta",
                    "URGENT": "Urgente",
                    "LOW": "Baja",
                }[value],
            )
            has_due_at = st.checkbox("Agregar fecha limite")
            due_cols = st.columns(2)
            due_date = due_cols[0].date_input("Fecha", disabled=not has_due_at)
            due_time = due_cols[1].time_input("Hora (ET)", disabled=not has_due_at)
            submitted = st.form_submit_button("Guardar tarea", type="primary", width="stretch")
        if submitted:
            try:
                due_at = None
                if has_due_at:
                    due_at = datetime.combine(due_date, due_time, tzinfo=ZoneInfo("America/New_York")).astimezone(
                        timezone.utc
                    )
                created = store.create(
                    user_id,
                    title,
                    notes=notes,
                    due_at=due_at,
                    priority=priority,
                    source="streamlit_ui",
                )
                st.success(f"Tarea guardada: {created['title']}")
                st.rerun()
            except ValueError as exc:
                st.error(str(exc))

    status_filter = st.selectbox(
        "Mostrar",
        ["ACTIVE", "PENDING", "IN_PROGRESS", "DONE", "ARCHIVED", "ALL"],
        format_func=lambda value: {
            "ACTIVE": "Pendientes y en progreso",
            "PENDING": "Pendientes",
            "IN_PROGRESS": "En progreso",
            "DONE": "Completadas",
            "ARCHIVED": "Archivadas",
            "ALL": "Todas",
        }[value],
        key="roxy_personal_task_filter",
    )
    statuses = ACTIVE_TASK_STATUSES if status_filter == "ACTIVE" else (
        None if status_filter == "ALL" else {status_filter}
    )
    visible_tasks = store.list_tasks(
        user_id,
        statuses=statuses,
        include_archived=status_filter in {"ARCHIVED", "ALL"},
        limit=500,
    )
    if not visible_tasks:
        st.info("No hay tareas en este estado. Roxy no agrega tareas simuladas para llenar esta vista.")
        return

    status_labels = {
        "PENDING": "Pendiente",
        "IN_PROGRESS": "En progreso",
        "DONE": "Completada",
        "ARCHIVED": "Archivada",
    }
    priority_labels = {"LOW": "Baja", "NORMAL": "Normal", "HIGH": "Alta", "URGENT": "Urgente"}
    for task in visible_tasks:
        task_id = text_display(task.get("id"))
        with st.container(border=True):
            title_col, status_col = st.columns([4, 1])
            title_col.markdown(f"**{text_display(task.get('title'))}**")
            status_col.caption(status_labels.get(text_display(task.get("status")), "Estado desconocido"))
            details = [
                f"Prioridad: {priority_labels.get(text_display(task.get('priority')), 'No disponible')}",
                f"Limite: {_personal_task_due_label(task.get('due_at'))}",
                f"Fuente: {text_display(task.get('source'))}",
            ]
            if task.get("overdue"):
                details.append("VENCIDA")
            st.caption(" · ".join(details))
            if text_display(task.get("notes")) not in {"", "-"}:
                st.write(text_display(task.get("notes")))
            actions = st.columns(4)
            status = text_display(task.get("status"))
            if status == "PENDING" and actions[0].button("Iniciar", key=f"task_start_{task_id}", width="stretch"):
                store.transition(user_id, task_id, "IN_PROGRESS")
                st.rerun()
            if status in ACTIVE_TASK_STATUSES and actions[1].button(
                "Completar", key=f"task_done_{task_id}", width="stretch"
            ):
                store.transition(user_id, task_id, "DONE")
                st.rerun()
            if status in {"DONE", "ARCHIVED"} and actions[2].button(
                "Restaurar", key=f"task_restore_{task_id}", width="stretch"
            ):
                store.transition(user_id, task_id, "PENDING")
                st.rerun()
            if status != "ARCHIVED" and actions[3].button(
                "Archivar", key=f"task_archive_{task_id}", width="stretch"
            ):
                store.transition(user_id, task_id, "ARCHIVED")
                st.rerun()


def show_shopping_list_screen() -> None:
    user_id = roxy_os_user_id()
    store = roxy_shopping_list_store()
    snapshot = store.snapshot(user_id, limit=500)
    st.subheader("Lista de compras")
    st.caption(
        f"Fuente local durable aislada para {user_id} · sincronizacion remota: LOCAL_ONLY · "
        f"ultima escritura: {text_display(snapshot.get('updated_at'))}. "
        "Voz, texto y esta pantalla utilizan la misma lista."
    )
    metrics = st.columns(2)
    metrics[0].metric("Pendientes", int(snapshot.get("pending_count") or 0))
    metrics[1].metric("Comprados visibles", int(snapshot.get("purchased_count") or 0))

    category_labels = {
        "GENERAL": "General",
        "FOOD": "Alimentos",
        "HOUSEHOLD": "Hogar",
        "HEALTH": "Salud",
        "PERSONAL": "Cuidado personal",
        "OTHER": "Otro",
    }
    with st.expander("Agregar articulo", expanded=not bool(snapshot.get("items"))):
        with st.form("roxy_shopping_add", clear_on_submit=True):
            name = st.text_input("Articulo", max_chars=120, placeholder="Ej. Cafe")
            input_cols = st.columns(3)
            quantity = input_cols[0].number_input("Cantidad", min_value=0.01, max_value=100000.0, value=1.0)
            unit = input_cols[1].text_input("Unidad", value="unidad", max_chars=32)
            category = input_cols[2].selectbox(
                "Categoria",
                list(category_labels),
                format_func=lambda value: category_labels[value],
            )
            notes = st.text_input("Notas", max_chars=1000, placeholder="Marca o detalle opcional")
            submitted = st.form_submit_button("Agregar a la lista", type="primary", width="stretch")
        if submitted:
            try:
                saved = store.add(
                    user_id,
                    name,
                    quantity=quantity,
                    unit=unit,
                    category=category,
                    notes=notes,
                    source="streamlit_ui",
                )
                st.success(f"Articulo guardado: {saved['name']}")
                st.rerun()
            except ValueError as exc:
                st.error(str(exc))

    status_filter = st.selectbox(
        "Mostrar",
        ["PENDING", "PURCHASED", "ARCHIVED", "ALL"],
        format_func=lambda value: {
            "PENDING": "Pendientes",
            "PURCHASED": "Comprados",
            "ARCHIVED": "Archivados",
            "ALL": "Todos",
        }[value],
        key="roxy_shopping_filter",
    )
    statuses = None if status_filter == "ALL" else {status_filter}
    items = store.list_items(
        user_id,
        statuses=statuses,
        include_archived=status_filter in {"ARCHIVED", "ALL"},
        limit=500,
    )
    if not items:
        st.info("No hay articulos en este estado. Roxy no agrega compras simuladas para llenar la vista.")
        return
    status_labels = {"PENDING": "Pendiente", "PURCHASED": "Comprado", "ARCHIVED": "Archivado"}
    for item in items:
        item_id = text_display(item.get("id"))
        status = text_display(item.get("status"))
        with st.container(border=True):
            title_col, state_col = st.columns([4, 1])
            title_col.markdown(f"**{text_display(item.get('name'))}**")
            state_col.caption(status_labels.get(status, "Estado desconocido"))
            st.caption(
                f"Cantidad: {num_display(item.get('quantity'), 4)} {text_display(item.get('unit'))} · "
                f"Categoria: {category_labels.get(text_display(item.get('category')), 'No disponible')} · "
                f"Fuente: {text_display(item.get('source'))}"
            )
            if text_display(item.get("notes")) not in {"", "-"}:
                st.write(text_display(item.get("notes")))
            actions = st.columns(3)
            if status == "PENDING" and actions[0].button(
                "Marcar comprado", key=f"shopping_buy_{item_id}", width="stretch"
            ):
                store.transition(user_id, item_id, "PURCHASED")
                st.rerun()
            if status in {"PURCHASED", "ARCHIVED"} and actions[1].button(
                "Volver a pendientes", key=f"shopping_restore_{item_id}", width="stretch"
            ):
                store.transition(user_id, item_id, "PENDING")
                st.rerun()
            if status != "ARCHIVED" and actions[2].button(
                "Archivar", key=f"shopping_archive_{item_id}", width="stretch"
            ):
                store.transition(user_id, item_id, "ARCHIVED")
                st.rerun()


def show_roxy_home_screen() -> None:
    client = roxy_home_assistant_client()
    snapshot = client.entities()
    st.session_state["roxy_home_assistant_snapshot"] = snapshot
    status = text_display(snapshot.get("status"))
    st.subheader("Roxy Home")
    st.caption(
        f"Proveedor: Home Assistant · estado: {status} · comprobado: {text_display(snapshot.get('checked_at'))}. "
        "Las credenciales y atributos sensibles nunca se muestran."
    )
    if status != "CONNECTED":
        message = text_display(snapshot.get("detail"))
        if status == "SERVICE_NOT_CONFIGURED":
            st.info(f"Servicio no configurado. {message}")
        elif status == "AUTH_INVALID":
            st.error(f"Token rechazado. {message}")
        elif status == "CONFIGURATION_ERROR":
            st.error(f"Configuracion insegura o invalida. {message}")
        else:
            st.warning(f"Home Assistant no esta disponible. {message}")
        st.markdown(
            "- `ROXY_HOME_ASSISTANT_URL`: URL base del servidor.\n"
            "- `ROXY_HOME_ASSISTANT_TOKEN`: token de larga duracion; nunca se renderiza.\n"
            "- `ROXY_HOME_CONTROL_ENABLED=0`: mantiene toda escritura desactivada."
        )
        st.caption(
            "HTTP sin TLS sólo se acepta para localhost, IP privada o dominios .local. "
            "Activa control únicamente después de validar lectura y permisos."
        )
        return

    entities = [dict(item) for item in snapshot.get("entities", []) if isinstance(item, dict)]
    metrics = st.columns(3)
    metrics[0].metric("Entidades", len(entities))
    metrics[1].metric("Controlables", sum(bool(item.get("writable")) for item in entities))
    metrics[2].metric("Control externo", "ACTIVO" if snapshot.get("control_enabled") else "DESACTIVADO")
    rows = [
        {
            "Nombre": text_display(item.get("name")),
            "Entidad": text_display(item.get("entity_id")),
            "Tipo": text_display(item.get("domain")),
            "Estado": text_display(item.get("state")),
            "Unidad": text_display(item.get("unit")),
            "Actualizado": text_display(item.get("updated_at")),
            "Modo": "Solo lectura" if item.get("sensitive") or not item.get("writable") else "Control permitido",
        }
        for item in entities
    ]
    if rows:
        st.dataframe(pd.DataFrame(rows), width="stretch", hide_index=True)
    else:
        st.info("Home Assistant respondio, pero no devolvio entidades compatibles.")

    writable = [item for item in entities if item.get("writable")]
    if not writable:
        return
    st.markdown("**Control seguro de luces e interruptores**")
    if not snapshot.get("control_enabled"):
        st.warning("Lectura conectada; escritura desactivada por ROXY_HOME_CONTROL_ENABLED=0.")
        return
    permission_checked = st.checkbox(
        "Autorizar smart_home durante esta sesion",
        value="smart_home" in set(st.session_state.get("roxy_os_allowed_permissions") or []),
        key="roxy_home_permission_checkbox",
    )
    permissions = set(st.session_state.get("roxy_os_allowed_permissions") or [])
    if permission_checked:
        permissions.add("smart_home")
    else:
        permissions.discard("smart_home")
    st.session_state["roxy_os_allowed_permissions"] = sorted(permissions)
    lookup = {text_display(item.get("entity_id")): item for item in writable}
    selected_entity = st.selectbox(
        "Entidad exacta",
        list(lookup),
        format_func=lambda entity_id: f"{text_display(lookup[entity_id].get('name'))} · {entity_id}",
        key="roxy_home_entity",
    )
    selected_service = st.radio(
        "Accion",
        ["turn_on", "turn_off"],
        format_func=lambda value: "Encender" if value == "turn_on" else "Apagar",
        horizontal=True,
        key="roxy_home_service",
    )
    domain = text_display(lookup[selected_entity].get("domain"))
    preview = {"domain": domain, "service": selected_service, "entity_id": selected_entity}
    if st.button("Preparar accion", key="roxy_home_prepare", width="stretch"):
        st.session_state["roxy_home_pending_action"] = preview
    pending = st.session_state.get("roxy_home_pending_action")
    if pending != preview:
        return
    st.warning(f"Confirmacion pendiente: {selected_service} sobre {selected_entity}.")
    confirmed = st.checkbox(
        "Confirmo esta entidad y accion exactas",
        key=f"roxy_home_confirm_{selected_entity}_{selected_service}",
    )
    if st.button("Ejecutar en Home Assistant", type="primary", disabled=not confirmed, width="stretch"):
        result = client.call_service(
            domain=domain,
            service=selected_service,
            entity_id=selected_entity,
            confirmed=confirmed,
            permission_granted="smart_home" in permissions,
        )
        if result.get("executed"):
            st.success(f"Accion ejecutada: {selected_service} · {selected_entity}")
            st.session_state.pop("roxy_home_pending_action", None)
        else:
            st.error(f"Accion no ejecutada: {text_display(result.get('status'))} · {text_display(result.get('detail'))}")


def show_document_vault_screen() -> None:
    user_id = roxy_os_user_id()
    vault = roxy_document_vault()
    snapshot = vault.snapshot(user_id, limit=500)
    st.subheader("Documentos")
    st.caption(
        f"Repositorio privado local para {user_id} · estado: {text_display(snapshot.get('sync_state'))} · "
        f"ultima escritura: {text_display(snapshot.get('updated_at'))}."
    )
    if snapshot.get("at_rest_encryption"):
        st.success(
            f"Contenido protegido con AES-256-GCM · clave: {text_display(snapshot.get('encryption_key_status'))}. "
            "La clave privada se almacena fuera del repositorio de documentos."
        )
    else:
        st.warning(
            f"Cifrado incompleto · objetos sin cifrar: {int(snapshot.get('unencrypted_count') or 0)} · "
            f"clave: {text_display(snapshot.get('encryption_key_status'))}."
        )
        if st.button("Cifrar contenido existente", type="primary", width="stretch", key="roxy_document_migrate"):
            try:
                result = vault.migrate_plaintext_objects()
                st.success(f"Migracion terminada: {int(result.get('encrypted') or 0)} objetos cifrados.")
                st.rerun()
            except (ValueError, RuntimeError, OSError) as exc:
                st.error(str(exc))
    st.metric("Documentos activos", int(snapshot.get("active_count") or 0))
    with st.expander("Importar documento", expanded=not bool(snapshot.get("documents"))):
        uploaded = st.file_uploader(
            "Selecciona un archivo",
            type=["txt", "md", "csv", "json", "pdf", "docx", "xlsx"],
            accept_multiple_files=False,
            key="roxy_document_upload",
            help="Maximo 10 MB. Importar crea una copia privada local; no modifica el archivo original.",
        )
        if st.button("Guardar copia privada", type="primary", disabled=uploaded is None, width="stretch"):
            try:
                saved = vault.ingest(
                    user_id,
                    uploaded.name,
                    uploaded.getvalue(),
                    content_type=getattr(uploaded, "type", "application/octet-stream"),
                    source="streamlit_upload",
                )
                st.success(f"Documento guardado: {saved['name']}")
                st.rerun()
            except (ValueError, OSError) as exc:
                st.error(str(exc))

    include_archived = st.checkbox("Mostrar archivados", key="roxy_documents_include_archived")
    documents = vault.list_documents(user_id, include_archived=include_archived, limit=500)
    if not documents:
        st.info("No hay documentos en este estado. Roxy no crea archivos de demostracion.")
        return
    for row in documents:
        document_id = text_display(row.get("id"))
        status = text_display(row.get("status"))
        with st.container(border=True):
            title_col, state_col = st.columns([4, 1])
            title_col.markdown(f"**{text_display(row.get('name'))}**")
            state_col.caption("Activo" if status == "ACTIVE" else "Archivado")
            st.caption(
                f"Tipo: {text_display(row.get('suffix'))} · Tamano: {int(row.get('size_bytes') or 0):,} bytes · "
                f"SHA-256: {text_display(row.get('sha256'))[:12]}… · Fuente: {text_display(row.get('source'))}"
            )
            actions = st.columns(3)
            if status == "ACTIVE" and actions[0].button(
                "Preparar contenido", key=f"doc_prepare_{document_id}", width="stretch"
            ):
                try:
                    metadata, content = vault.read(user_id, document_id)
                    st.session_state["roxy_document_prepared"] = {
                        "id": document_id,
                        "metadata": metadata,
                        "content": content,
                    }
                except (KeyError, ValueError, RuntimeError, FileNotFoundError) as exc:
                    st.error(str(exc))
            if status == "ACTIVE" and actions[2].button(
                "Archivar", key=f"doc_archive_{document_id}", width="stretch"
            ):
                vault.archive(user_id, document_id)
                if (st.session_state.get("roxy_document_prepared") or {}).get("id") == document_id:
                    st.session_state.pop("roxy_document_prepared", None)
                st.rerun()
            if status == "ARCHIVED" and actions[1].button(
                "Restaurar", key=f"doc_restore_{document_id}", width="stretch"
            ):
                vault.archive(user_id, document_id, restore=True)
                st.rerun()
            prepared = st.session_state.get("roxy_document_prepared")
            if not isinstance(prepared, dict) or prepared.get("id") != document_id:
                continue
            content = prepared.get("content") if isinstance(prepared.get("content"), bytes) else b""
            metadata = prepared.get("metadata") if isinstance(prepared.get("metadata"), dict) else row
            if text_display(metadata.get("suffix")) in TEXT_PREVIEW_SUFFIXES:
                preview = content[:20_000].decode("utf-8", errors="replace")
                st.text_area("Vista previa local", value=preview, height=220, disabled=True, key=f"doc_preview_{document_id}")
            else:
                st.info("Vista previa no disponible para este formato; la descarga conserva el archivo original verificado.")
            st.download_button(
                "Descargar copia verificada",
                data=content,
                file_name=text_display(metadata.get("name")),
                mime=text_display(metadata.get("content_type")),
                key=f"doc_download_{document_id}",
                width="stretch",
            )


def show_email_screen() -> None:
    configured = configured_email_provider()
    provider = st.selectbox(
        "Proveedor de correo",
        ["gmail", "outlook"],
        index=0 if configured == "gmail" else 1,
        format_func=lambda value: "Gmail API" if value == "gmail" else "Outlook · Microsoft Graph",
        key="roxy_email_provider",
    )
    snapshot = roxy_email_snapshot(provider)
    st.session_state["roxy_email_snapshot"] = snapshot
    status = text_display(snapshot.get("status"))
    st.subheader("Correo")
    st.caption(
        f"Proveedor: {'Gmail API' if provider == 'gmail' else 'Outlook · Microsoft Graph'} · estado: {status} · modo: READ_ONLY · "
        f"comprobado: {text_display(snapshot.get('checked_at'))}."
    )
    st.warning(
        "Envio deshabilitado. Roxy no redacta ni envia correo desde este adaptador; "
        "los cuerpos tampoco se descargan durante la lista de mensajes."
    )
    if status != "CONNECTED":
        detail = text_display(snapshot.get("detail"))
        if status == "SERVICE_NOT_CONFIGURED":
            st.info(f"Servicio no configurado. {detail}")
            st.markdown(
                "- `ROXY_GMAIL_ACCESS_TOKEN`: token OAuth efimero con alcance `gmail.readonly`.\n"
                "- `ROXY_OUTLOOK_ACCESS_TOKEN`: token OAuth efimero Microsoft Graph con alcance `Mail.Read`.\n"
                "- Renovacion OAuth y envio: pendientes antes de uso remoto continuo."
            )
        elif status == "AUTH_INVALID":
            st.error(f"Token OAuth rechazado o sin alcance. {detail}")
        elif status == "RATE_LIMITED":
            st.warning(detail)
        else:
            st.warning(f"El proveedor no esta disponible. {detail}")
        return
    messages = [dict(row) for row in snapshot.get("messages", []) if isinstance(row, dict)]
    metrics = st.columns(3)
    metrics[0].metric("Mensajes mostrados", len(messages))
    metrics[1].metric("No leidos", sum(bool(row.get("unread")) for row in messages))
    metrics[2].metric("Envio", "DESACTIVADO")
    if not messages:
        st.info("El proveedor esta conectado, pero INBOX no devolvio mensajes en esta consulta.")
        return
    rows = [
        {
            "No leido": "Si" if row.get("unread") else "No",
            "De": text_display(row.get("from")),
            "Asunto": text_display(row.get("subject")),
            "Fecha": text_display(row.get("date")),
            "Etiquetas": ", ".join(str(value) for value in row.get("labels", [])),
            "Cuerpo": "No cargado",
        }
        for row in messages
    ]
    st.dataframe(pd.DataFrame(rows), width="stretch", hide_index=True)
    st.caption("Máximo cinco mensajes por consulta; cache 30 segundos; cuerpos y adjuntos fuera de alcance.")


def show_memory_screen() -> None:
    context = resolve_roxy_operational_context(st.query_params, st.session_state)
    render_selected_asset_banner(context["symbol"], context["market"], context["timeframe"])
    st.subheader("Memoria")
