def roxy_trade_plan_from_row(
    row: dict[str, Any],
    *,
    symbol: str,
    market: str,
    timeframe: str,
    action: str,
) -> dict[str, Any]:
    entry = safe_float(row.get("entry") or row.get("current_price") or row.get("price") or row.get("last_price"))
    stop = safe_float(row.get("stop") or row.get("stop_loss"))
    target = safe_float(row.get("target_price") or row.get("target") or row.get("recommended_target_price"))
    target_2 = safe_float(row.get("target_2") or row.get("target_2pct_price") or target)
    target_5 = safe_float(row.get("target_5") or row.get("target_5pct_price"))
    target_10 = safe_float(row.get("target_10") or row.get("target_10pct_price"))
    normalized_market = normalize_command_market(market, symbol)
    normalized_timeframe = normalize_command_timeframe(timeframe)
    values = (entry, stop, target_2)
    plan_ready = all(value is not None and value > 0 for value in values)
    plan_ready = bool(plan_ready and stop != entry and target_2 != entry)
    if not plan_ready:
        stop = None
        target = None
        target_2 = None
        target_5 = None
        target_10 = None
    rr_to_2 = None
    if plan_ready and entry is not None and stop is not None and target_2 is not None and abs(entry - stop) > 0:
        rr_to_2 = abs(target_2 - entry) / abs(entry - stop)
    computed_risk_pct = safe_float(row.get("risk_pct"))
    if plan_ready and computed_risk_pct is None and entry not in (None, 0) and stop is not None:
        computed_risk_pct = abs(entry - stop) / entry
    if not plan_ready:
        computed_risk_pct = None
    entry_zone_low = safe_float(row.get("entry_zone_low"))
    entry_zone_high = safe_float(row.get("entry_zone_high"))
    if not plan_ready:
        entry_zone_low = None
        entry_zone_high = None
    return {
        "symbol": symbol,
        "market": normalized_market,
        "timeframe": normalized_timeframe,
        "action": action if plan_ready else "Esperar confirmacion",
        "plan_status": "Plan operativo listo" if plan_ready else "Plan pendiente: faltan niveles verificables",
        "plan_ready": plan_ready,
        "plan_source": text_display(row.get("roxy_plan_source") or row.get("data_source") or "Fuente no disponible"),
        "entry": entry,
        "stop": stop,
        "target": target,
        "target_price": target,
        "target_2": target_2,
        "target_5": target_5,
        "target_10": target_10,
        "entry_zone_low": entry_zone_low,
        "entry_zone_high": entry_zone_high,
        "rr_to_2": rr_to_2,
        "risk_pct": computed_risk_pct,
    }


def clean_roxy_operational_chart_df(
    chart_df: pd.DataFrame,
    *,
    timeframe: str,
    max_points: int = 140,
    anchor_price: float | None = None,
) -> pd.DataFrame:
    """Return a display-safe OHLCV window without split/provider spike artifacts.

    This does not synthesize prices. It only removes candles whose OHLC values
    are structurally invalid or far outside the local price regime, which makes
    the operational chart readable without letting one bad provider candle flatten
    the whole setup.
    """
    if not isinstance(chart_df, pd.DataFrame) or chart_df.empty:
        return pd.DataFrame()
    required = {"ts", "open", "high", "low", "close"}
    if not required.issubset(set(chart_df.columns)):
        return pd.DataFrame()
    df = chart_df.copy()
    df["ts"] = pd.to_datetime(df["ts"], errors="coerce")
    numeric_columns = [
        "open",
        "high",
        "low",
        "close",
        "volume",
        "ema9",
        "ema20",
        "ema21",
        "sma20",
        "sma40",
        "sma100",
        "sma200",
        "bb_upper",
        "bb_mid",
        "bb_lower",
    ]
    for column in numeric_columns:
        if column in df.columns:
            df[column] = pd.to_numeric(df[column], errors="coerce")
    df = df.dropna(subset=["ts", "open", "high", "low", "close"])
    df = df.sort_values("ts").drop_duplicates(subset=["ts"], keep="last")
    df = df[(df["open"] > 0) & (df["high"] > 0) & (df["low"] > 0) & (df["close"] > 0)]
    df = df[(df["high"] >= df["low"]) & (df["high"] >= df["open"]) & (df["high"] >= df["close"])]
    df = df[(df["low"] <= df["open"]) & (df["low"] <= df["close"])]
    if df.empty:
        return df

    raw_count = len(df)
    tf = normalize_command_timeframe(timeframe)
    close = pd.to_numeric(df["close"], errors="coerce")
    local_ref = close.rolling(31, min_periods=6, center=True).median()
    median_close = safe_float(close.median())
    if median_close not in (None, 0):
        local_ref = local_ref.fillna(median_close)
    valid_ref = local_ref > 0
    body_deviation = pd.concat(
        [
            ((pd.to_numeric(df["open"], errors="coerce") - local_ref).abs() / local_ref).where(valid_ref),
            ((pd.to_numeric(df["close"], errors="coerce") - local_ref).abs() / local_ref).where(valid_ref),
        ],
        axis=1,
    ).max(axis=1)
    wick_deviation = pd.concat(
        [
            ((pd.to_numeric(df["high"], errors="coerce") - local_ref).abs() / local_ref).where(valid_ref),
            ((pd.to_numeric(df["low"], errors="coerce") - local_ref).abs() / local_ref).where(valid_ref),
        ],
        axis=1,
    ).max(axis=1)
    candle_range_pct = (pd.to_numeric(df["high"], errors="coerce") - pd.to_numeric(df["low"], errors="coerce")) / close
    typical_range = safe_float(candle_range_pct[(candle_range_pct > 0) & (candle_range_pct < 0.18)].median()) or 0.012
    if tf in {"1m", "5m", "15m"}:
        max_range_pct = max(0.055, min(0.18, typical_range * 7.0))
        body_limit = 0.16
        wick_limit = 0.24
    elif tf in {"1h", "2h", "4h"}:
        max_range_pct = max(0.075, min(0.22, typical_range * 7.5))
        body_limit = 0.22
        wick_limit = 0.32
    else:
        max_range_pct = max(0.12, min(0.38, typical_range * 8.0))
        body_limit = 0.34
        wick_limit = 0.48
    clean_mask = (
        body_deviation.fillna(0) <= body_limit
    ) & (
        wick_deviation.fillna(0) <= wick_limit
    ) & (
        candle_range_pct.fillna(0) <= max_range_pct
    )
    # Intraday stock providers can occasionally deliver one isolated bad bar
    # after a split/session boundary. Removing only structurally isolated jumps
    # keeps the operational scale readable without synthesizing replacement data.
    close_return_pct = close.pct_change().abs()
    open_gap_pct = ((pd.to_numeric(df["open"], errors="coerce") - close.shift(1)).abs() / close.shift(1)).replace(
        [float("inf"), float("-inf")],
        pd.NA,
    )
    typical_return = safe_float(close_return_pct[(close_return_pct > 0) & (close_return_pct < 0.12)].median()) or 0.0035
    if tf in {"1m", "5m", "15m"}:
        max_jump_pct = max(0.026, min(0.070, typical_return * 11.0))
        max_gap_pct = max(0.032, min(0.085, typical_return * 13.0))
    elif tf in {"1h", "2h", "4h"}:
        max_jump_pct = max(0.040, min(0.110, typical_return * 12.5))
        max_gap_pct = max(0.050, min(0.135, typical_return * 14.0))
    else:
        max_jump_pct = max(0.070, min(0.220, typical_return * 16.0))
        max_gap_pct = max(0.085, min(0.260, typical_return * 18.0))
    jump_mask = (close_return_pct.fillna(0) <= max_jump_pct) | (close_return_pct.isna())
    gap_mask = (open_gap_pct.fillna(0) <= max_gap_pct) | (open_gap_pct.isna())
    clean_mask = clean_mask & jump_mask & gap_mask
    cleaned = df[clean_mask].copy()
    if len(cleaned) < min(12, len(df)):
        relaxed_mask = (
            body_deviation.fillna(0) <= body_limit * 2.2
        ) & (
            wick_deviation.fillna(0) <= wick_limit * 2.2
        ) & (
            candle_range_pct.fillna(0) <= max_range_pct * 1.8
        )
        cleaned = df[relaxed_mask].copy()
    if cleaned.empty:
        cleaned = df.copy()
    anchor = safe_float(anchor_price)
    if anchor is not None and anchor > 0:
        anchor_band = 0.18 if tf in {"1m", "5m", "15m", "1h", "2h", "4h"} else 0.38
        anchor_low = anchor * (1 - anchor_band)
        anchor_high = anchor * (1 + anchor_band)
        anchored = cleaned[
            (pd.to_numeric(cleaned["open"], errors="coerce").between(anchor_low, anchor_high))
            & (pd.to_numeric(cleaned["close"], errors="coerce").between(anchor_low, anchor_high))
            & (pd.to_numeric(cleaned["high"], errors="coerce") <= anchor_high)
            & (pd.to_numeric(cleaned["low"], errors="coerce") >= anchor_low)
        ].copy()
        if len(anchored) >= min(18, len(cleaned)):
            cleaned = anchored
    cleaned = cleaned.tail(max(40, int(max_points or 140))).reset_index(drop=True)
    cleaned.attrs["roxy_removed_anomalies"] = max(0, raw_count - len(cleaned))
    return cleaned


def roxy_actions_plotly_chart_panel(
    chart_df: pd.DataFrame,
    *,
    symbol: str,
    timeframe: str,
    trade_plan: dict[str, Any],
    title: str,
    height: int = 470,
) -> bool:
    if go is None or make_subplots is None:
        return False
    if not isinstance(chart_df, pd.DataFrame) or chart_df.empty:
        return False
    normalized_tf = normalize_command_timeframe(timeframe)
    max_candles = 96 if normalized_tf in {"15m", "15min"} else 86
    df = clean_roxy_operational_chart_df(chart_df, timeframe=normalized_tf, max_points=max_candles)
    if df.empty or len(df) < 8:
        st.markdown(
            f"""
            <section class="roxy-actions-chart-empty">
              <strong>{html.escape(title)} · {html.escape(text_display(symbol).upper())}</strong>
              <span>El proveedor no entrego suficientes velas limpias para pintar una grafica operativa en {html.escape(timeframe)}. Roxy mantiene la accion en vigilancia y conserva entrada/stop/target desde quote real.</span>
            </section>
            """,
            unsafe_allow_html=True,
        )
        return False
    removed_anomalies = int(df.attrs.get("roxy_removed_anomalies") or 0)
    latest_close = safe_float(df["close"].iloc[-1])
    close_series = pd.to_numeric(df["close"], errors="coerce").dropna()
    open_series = pd.to_numeric(df["open"], errors="coerce").dropna()
    body_prices = pd.concat([close_series, open_series], ignore_index=True).dropna()
    domain_low: float | None = None
    domain_high: float | None = None
    if not body_prices.empty:
        domain_low = float(body_prices.quantile(0.04))
        domain_high = float(body_prices.quantile(0.96))
    if latest_close not in (None, 0):
        domain_low = latest_close * 0.985 if domain_low is None else min(domain_low, latest_close * 0.996)
        domain_high = latest_close * 1.015 if domain_high is None else max(domain_high, latest_close * 1.004)
    for level_value in [
        safe_float(trade_plan.get("entry")),
        safe_float(trade_plan.get("stop")),
        safe_float(trade_plan.get("target_2") or trade_plan.get("target_price") or trade_plan.get("target")),
    ]:
        if level_value is None:
            continue
        if latest_close not in (None, 0) and not (latest_close * 0.90 <= level_value <= latest_close * 1.10):
            continue
        domain_low = level_value if domain_low is None else min(domain_low, level_value)
        domain_high = level_value if domain_high is None else max(domain_high, level_value)
    if domain_low is None or domain_high is None or domain_high <= domain_low:
        lows = pd.to_numeric(df["low"], errors="coerce").dropna()
        highs = pd.to_numeric(df["high"], errors="coerce").dropna()
        if not lows.empty and not highs.empty:
            domain_low = float(lows.quantile(0.08))
            domain_high = float(highs.quantile(0.92))
    if domain_low is not None and domain_high is not None and domain_high > domain_low:
        span = max(domain_high - domain_low, abs(domain_high) * 0.004, 0.01)
        domain_low -= span * 0.22
        domain_high += span * 0.22
        df["high"] = pd.to_numeric(df["high"], errors="coerce").clip(upper=domain_high)
        df["low"] = pd.to_numeric(df["low"], errors="coerce").clip(lower=domain_low)

    fig = make_subplots(
        rows=2,
        cols=1,
        shared_xaxes=True,
        vertical_spacing=0.025,
        row_heights=[0.80, 0.20],
    )
    fig.add_trace(
        go.Candlestick(
            x=df["ts"],
            open=df["open"],
            high=df["high"],
            low=df["low"],
            close=df["close"],
            name=f"{text_display(symbol).upper()} velas",
            increasing_line_color="#22c55e",
            increasing_fillcolor="#22c55e",
            decreasing_line_color="#ef4444",
            decreasing_fillcolor="#ef4444",
            whiskerwidth=0.80,
        ),
        row=1,
        col=1,
    )
    line_specs = [
        ("ema9", "EMA 9", "#ec4899", 2.6),
        ("ema21", "EMA 21", "#a855f7", 2.2),
        ("sma20", "AVG 20", "#38bdf8", 2.2),
        ("sma40", "AVG 40", "#f97316", 2.2),
        ("bb_upper", "BB Upper", "rgba(226,232,240,.58)", 1.3),
        ("bb_lower", "BB Lower", "rgba(226,232,240,.58)", 1.3),
    ]
    for column, label, color, width in line_specs:
        if column in df.columns and df[column].notna().any():
            fig.add_trace(
                go.Scatter(
                    x=df["ts"],
                    y=df[column],
                    mode="lines",
                    name=label,
                    line={"color": color, "width": width, "dash": "dot" if column.startswith("bb_") else "solid"},
                    hovertemplate=f"{label}: %{{y:.2f}}<extra></extra>",
                ),
                row=1,
                col=1,
            )
    if "volume" in df.columns:
        volume_colors = ["rgba(34,197,94,.42)" if close >= open_ else "rgba(239,68,68,.42)" for open_, close in zip(df["open"], df["close"])]
        fig.add_trace(
            go.Bar(
                x=df["ts"],
                y=df["volume"].fillna(0),
                name="Volumen",
                marker_color=volume_colors,
                hovertemplate="Volumen: %{y:,.0f}<extra></extra>",
            ),
            row=2,
            col=1,
        )
    if {"bb_upper", "bb_lower"}.issubset(df.columns) and df["bb_upper"].notna().any() and df["bb_lower"].notna().any():
        fig.add_trace(
            go.Scatter(
                x=list(df["ts"]) + list(df["ts"])[::-1],
                y=list(df["bb_upper"]) + list(df["bb_lower"])[::-1],
                fill="toself",
                fillcolor="rgba(148,163,184,.08)",
                line={"color": "rgba(148,163,184,0)", "width": 0},
                hoverinfo="skip",
                name="Bollinger area",
                showlegend=False,
            ),
            row=1,
            col=1,
        )
    level_specs = [
        ("Entrada", safe_float(trade_plan.get("entry")), "#22c55e"),
        ("Stop", safe_float(trade_plan.get("stop")), "#ef4444"),
        ("Target", safe_float(trade_plan.get("target_2") or trade_plan.get("target_price") or trade_plan.get("target")), "#38bdf8"),
    ]
    for label, value, color in level_specs:
        if value is None:
            continue
        fig.add_hline(
            y=value,
            line_color=color,
            line_width=1.8,
            line_dash="dash",
            annotation_text=f"{label} {price_display(value)}",
            annotation_position="right",
            annotation_font_color=color,
            row=1,
            col=1,
        )
    if domain_low is not None and domain_high is not None and domain_high > domain_low:
        fig.update_yaxes(range=[domain_low, domain_high], row=1, col=1)
    fig.update_layout(
        title={
            "text": f"{title} · {text_display(symbol).upper()} · {normalized_tf}"
            + (f" · {removed_anomalies} velas anomalas filtradas" if removed_anomalies else ""),
            "font": {"size": 13, "color": "#e0f2fe"},
        },
        height=height,
        margin={"l": 6, "r": 64, "t": 34, "b": 24},
        paper_bgcolor="rgba(2,6,23,0)",
        plot_bgcolor="rgba(2,6,23,.72)",
        font={"color": "#dbeafe", "size": 10},
        hovermode="x unified",
        dragmode="pan",
        showlegend=False,
        xaxis_rangeslider_visible=False,
        transition={"duration": 250, "easing": "cubic-in-out"},
    )
    fig.update_xaxes(
        showgrid=True,
        gridcolor="rgba(148,163,184,.14)",
        rangeslider_visible=False,
        showspikes=True,
        spikemode="across",
        spikecolor="rgba(248,250,252,.45)",
        spikethickness=1,
        row=1,
        col=1,
    )
    fig.update_xaxes(showgrid=True, gridcolor="rgba(148,163,184,.10)", row=2, col=1)
    fig.update_yaxes(
        side="right",
        showgrid=True,
        gridcolor="rgba(148,163,184,.14)",
        tickfont={"color": "#bbf7d0"},
        row=1,
        col=1,
    )
    fig.update_yaxes(side="right", showgrid=False, tickfont={"color": "#7dd3fc"}, row=2, col=1)
    if latest_close is not None:
        fig.add_annotation(
            x=df["ts"].iloc[-1],
            y=latest_close,
            text=price_display(latest_close),
            showarrow=False,
            xshift=34,
            bgcolor="#22c55e",
            bordercolor="rgba(187,247,208,.55)",
            font={"color": "#052e16", "size": 10},
            row=1,
            col=1,
        )
    st.plotly_chart(
        fig,
        use_container_width=True,
        config={
            "displayModeBar": False,
            "scrollZoom": True,
            "responsive": True,
            "displaylogo": False,
        },
    )
    return True


def roxy_dual_chart_strategy_plan(
    trade_plan: dict[str, Any],
    pane_data: list[tuple[str, str, pd.DataFrame]],
    *,
    symbol: str,
    market: str,
    provider: str = "roxy-market-data",
) -> dict[str, Any]:
    plan = dict(trade_plan or {})
    frames = {tf: frame for tf, _label, frame in pane_data if isinstance(frame, pd.DataFrame)}
    candles_15m = frames.get("15m", pd.DataFrame())
    candles_1h = frames.get("1h", pd.DataFrame())
    if candles_15m.empty or candles_1h.empty:
        return plan
    try:
        signal = evaluate_uptrend_pullback_to_ema21(
            symbol=symbol,
            candles_1h=candles_1h,
            candles_15m=candles_15m,
            provider=provider,
            provider_timestamp=(
                pd.to_datetime(candles_15m["ts"], utc=True, errors="coerce").dropna().iloc[-1].isoformat()
                if "ts" in candles_15m.columns and not pd.to_datetime(candles_15m["ts"], utc=True, errors="coerce").dropna().empty
                else None
            ),
        )
    except Exception as exc:
        plan["strategy_status"] = "ERROR"
        plan["strategy_detail"] = f"No se pudo evaluar la estrategia visual: {type(exc).__name__}."
        return plan
    plan["strategy_signal"] = signal
    plan["strategy_annotations"] = list(signal.get("chartAnnotations") or [])
    plan["strategy_name"] = text_display(signal.get("strategy") or "Estrategia no disponible")
    plan["strategy_status"] = text_display(signal.get("status") or "DATA_INSUFFICIENT")
    plan["strategy_reasons"] = list(signal.get("reasons") or [])
    plan["strategy_warnings"] = list(signal.get("warnings") or [])
    visual_structures: list[dict[str, Any]] = []
    drawable_types = {
        "BREAKOUT",
        "BREAKDOWN",
        "ASCENDING_TRIANGLE",
        "DESCENDING_TRIANGLE",
        "SYMMETRIC_TRIANGLE",
        "RISING_WEDGE",
        "FALLING_WEDGE",
        "CONSOLIDATION",
        "BULLISH_RETEST",
        "BEARISH_RETEST",
        "EMA_BULLISH_CROSS",
        "EMA_BEARISH_CROSS",
        "BULLISH_RSI_DIVERGENCE",
        "BEARISH_RSI_DIVERGENCE",
        "VOLUME_SURGE",
        "RSI_OVERBOUGHT",
        "RSI_OVERSOLD",
        "SUPPORT_RESISTANCE",
    }
    for pane_tf, _pane_label, pane_frame in pane_data:
        if not isinstance(pane_frame, pd.DataFrame) or pane_frame.empty:
            continue
        detected = detect_visual_price_structures(
            symbol=symbol,
            candles=pane_frame,
            timeframe=pane_tf,
            provider=provider,
        )
        if not detected:
            continue
        pane_structures = [dict(item) for item in detected[:3] if isinstance(item, dict)]
        visual_structures.extend(pane_structures)
        for structure in pane_structures[:2]:
            if text_display(structure.get("setupType")) not in drawable_types:
                continue
            plan["strategy_annotations"].extend(
                dict(annotation)
                for annotation in (structure.get("chartAnnotations") or [])
                if isinstance(annotation, dict)
            )
    plan["visual_structures"] = visual_structures
    if plan["strategy_status"] == "DATA_INSUFFICIENT" and visual_structures:
        primary_structure = visual_structures[0]
        plan["strategy_name"] = text_display(primary_structure.get("strategy") or plan["strategy_name"])
        plan["strategy_status"] = text_display(primary_structure.get("status") or plan["strategy_status"])
        plan["strategy_reasons"] = list(primary_structure.get("reasons") or [])
        plan["strategy_warnings"] = list(primary_structure.get("warnings") or [])
    status = plan["strategy_status"]
    actionable_statuses = {"READY", "NEAR_ENTRY", "WAITING_CONFIRMATION"}
    levels = {
        "entry": safe_float(signal.get("confirmationPrice")),
        "entry_zone_low": safe_float(signal.get("entryZoneLow")),
        "entry_zone_high": safe_float(signal.get("entryZoneHigh")),
        "stop": safe_float(signal.get("stopPrice")),
        "target": safe_float(signal.get("primaryTarget")),
        "target_2": safe_float(signal.get("primaryTarget")),
        "rr_to_2": safe_float(signal.get("riskReward")),
    }
    complete_levels = all((levels[key] or 0) > 0 for key in ("entry", "stop", "target"))
    existing_complete = all((safe_float(plan.get(key)) or 0) > 0 for key in ("entry", "stop")) and (
        safe_float(plan.get("target_2") or plan.get("target")) or 0
    ) > 0
    if status in actionable_statuses and complete_levels and not existing_complete:
        plan.update(levels)
        plan["target_price"] = levels["target"]
        plan["plan_ready"] = True
        plan["plan_status"] = status
        plan["plan_source"] = provider
        plan["action"] = "Preparar entrada" if status == "READY" else "Esperar confirmacion"
    elif not existing_complete:
        plan["plan_ready"] = False
        plan["plan_status"] = status
    return plan


def roxy_actions_pro_chart_payload(
    chart_df: pd.DataFrame,
    *,
    symbol: str,
    market: str,
    timeframe: str,
    trade_plan: dict[str, Any],
    panel_label: str,
    max_points: int = 132,
) -> dict[str, Any]:
    def verified_level(value: Any) -> float | None:
        parsed = safe_float(value)
        return parsed if parsed is not None and math.isfinite(parsed) and parsed > 0 else None

    anchor_price = safe_float(
        trade_plan.get("entry")
        or trade_plan.get("current_price")
        or trade_plan.get("latest")
        or trade_plan.get("target_price")
    )
    clean_chart_df = clean_roxy_operational_chart_df(
        chart_df,
        timeframe=timeframe,
        max_points=max(260, max_points + 90),
        anchor_price=anchor_price,
    )
    payload = live_candle_chart_payload(
        clean_chart_df if isinstance(clean_chart_df, pd.DataFrame) and not clean_chart_df.empty else chart_df,
        symbol=symbol,
        market=market,
        timeframe=timeframe,
        live_price={"price": trade_plan.get("entry"), "source": "quote + historial"},
        trade_plan=trade_plan,
        strategy_profile="acciones_15m_1h",
        max_candles=max(260, max_points + 90),
    )
    candles = list(payload.get("candles") or [])
    if not candles:
        return {}
    candles = candles[-max_points:]
    times = {int(item.get("time")) for item in candles if item.get("time") is not None}
    candle_values: list[float] = []
    candle_body_values: list[float] = []
    candle_wick_values: list[float] = []
    for candle in candles:
        if not isinstance(candle, dict):
            continue
        for key in ("open", "high", "low", "close"):
            value = safe_float(candle.get(key))
            if value is not None and math.isfinite(value) and value > 0:
                candle_values.append(value)
                if key in {"open", "close"}:
                    candle_body_values.append(value)
                else:
                    candle_wick_values.append(value)
    line_low: float | None = None
    line_high: float | None = None
    operative_window = candles[-min(len(candles), 86):]
    operative_body_values: list[float] = []
    operative_wick_values: list[float] = []
    for candle in operative_window:
        if not isinstance(candle, dict):
            continue
        for key in ("open", "close"):
            value = safe_float(candle.get(key))
            if value is not None and math.isfinite(value) and value > 0:
                operative_body_values.append(value)
        for key in ("high", "low"):
            value = safe_float(candle.get(key))
            if value is not None and math.isfinite(value) and value > 0:
                operative_wick_values.append(value)
    if operative_body_values or candle_body_values or candle_values:
        body_series = pd.Series(operative_body_values or candle_body_values or candle_values, dtype="float64")
        line_low = safe_float(body_series.quantile(0.03))
        line_high = safe_float(body_series.quantile(0.97))
        if operative_wick_values or candle_wick_values:
            wick_series = pd.Series(operative_wick_values or candle_wick_values, dtype="float64")
            wick_low = safe_float(wick_series.quantile(0.08))
            wick_high = safe_float(wick_series.quantile(0.92))
            if wick_low is not None:
                line_low = wick_low if line_low is None else min(line_low, wick_low)
            if wick_high is not None:
                line_high = wick_high if line_high is None else max(line_high, wick_high)
        latest_close = safe_float((candles[-1] or {}).get("close")) if candles else None
        if latest_close is not None:
            line_low = latest_close if line_low is None else min(line_low, latest_close)
            line_high = latest_close if line_high is None else max(line_high, latest_close)
        for level_value in [
            verified_level(trade_plan.get("entry")),
            verified_level(trade_plan.get("stop")),
            verified_level(trade_plan.get("target_2") or trade_plan.get("target_price") or trade_plan.get("target")),
        ]:
            if level_value is None:
                continue
            if line_low is not None and line_high is not None:
                center = (line_low + line_high) / 2
                if center > 0 and abs(level_value - center) / center > 0.18:
                    continue
            line_low = level_value if line_low is None else min(line_low, level_value)
            line_high = level_value if line_high is None else max(line_high, level_value)
        if line_low is not None and line_high is not None and line_high > line_low:
            span = max(line_high - line_low, abs(line_high) * 0.004, 0.01)
            line_low -= span * 0.22
            line_high += span * 0.22

    def trim_line(points: Any) -> list[dict[str, Any]]:
        out: list[dict[str, Any]] = []
        if not isinstance(points, list):
            return out
        for point in points:
            if not isinstance(point, dict):
                continue
            ts = point.get("time")
            value = safe_float(point.get("value"))
            if (
                ts in times
                and value is not None
                and math.isfinite(value)
                and (line_low is None or value >= line_low)
                and (line_high is None or value <= line_high)
            ):
                out.append({"time": int(ts), "value": float(value)})
        return out

    cleaned_lines: dict[str, list[dict[str, Any]]] = {}
    for name, points in dict(payload.get("lines") or {}).items():
        cleaned_lines[text_display(name)] = trim_line(points)
    payload["candles"] = candles
    payload["lines"] = cleaned_lines
    payload["displayRange"] = {"minValue": line_low, "maxValue": line_high} if line_low is not None and line_high is not None and line_high > line_low else None
    payload["suggestedVisibleCandles"] = 48
    payload["panelLabel"] = panel_label
    payload["levels"] = [
        {"key": "entry", "label": "Entrada", "value": verified_level(trade_plan.get("entry")), "color": "#22c55e"},
        {"key": "stop", "label": "Stop", "value": verified_level(trade_plan.get("stop")), "color": "#ef4444"},
        {
            "key": "target",
            "label": "Target",
            "value": verified_level(trade_plan.get("target_2") or trade_plan.get("target_price") or trade_plan.get("target")),
            "color": "#38bdf8",
        },
    ]
    payload["levels"] = [
        level
        for level in payload["levels"]
        if verified_level(level.get("value")) is not None
    ]
    payload["chartQuality"] = {
        "removedAnomalies": int(getattr(clean_chart_df, "attrs", {}).get("roxy_removed_anomalies") or 0)
        if isinstance(clean_chart_df, pd.DataFrame)
        else 0,
        "lineDomainLow": line_low,
        "lineDomainHigh": line_high,
    }
    payload["roxySummary"] = {
        "action": text_display(trade_plan.get("action") or "Esperar confirmacion"),
        "status": text_display(trade_plan.get("plan_status") or "Plan operativo de Roxy"),
        "entry": verified_level(trade_plan.get("entry")),
        "entryZoneLow": verified_level(trade_plan.get("entry_zone_low")),
        "entryZoneHigh": verified_level(trade_plan.get("entry_zone_high")),
        "stop": verified_level(trade_plan.get("stop")),
        "target": verified_level(trade_plan.get("target_2") or trade_plan.get("target_price") or trade_plan.get("target")),
        "rr": verified_level(trade_plan.get("rr_to_2")),
    }
    payload["strategyAnnotations"] = [
        dict(annotation)
        for annotation in (trade_plan.get("strategy_annotations") or [])
        if isinstance(annotation, dict) and text_display(annotation.get("timeframe")) in {"", timeframe}
    ]
    payload["strategySummary"] = {
        "name": text_display(trade_plan.get("strategy_name") or "Sin estrategia validada"),
        "status": text_display(trade_plan.get("strategy_status") or "DATA_INSUFFICIENT"),
        "reasons": list(trade_plan.get("strategy_reasons") or [])[:4],
        "warnings": list(trade_plan.get("strategy_warnings") or [])[:4],
        "structures": [
            {
                "setupType": text_display(item.get("setupType")),
                "strategy": text_display(item.get("strategy")),
                "status": text_display(item.get("status")),
                "confidence": int(safe_float(item.get("confidence")) or 0),
                "timeframe": text_display(item.get("timeframe")),
            }
            for item in (trade_plan.get("visual_structures") or [])[:4]
            if isinstance(item, dict)
        ],
    }
    return payload


ROXY_ACTIONS_PRO_CHART_RUNTIME_TEMPLATE_PATH = project_path("assets/runtime/roxy_actions_pro_chart.html")
ROXY_ACTIONS_PRO_CHART_PAYLOAD_MARKER = "__PAYLOAD__"
ROXY_ACTIONS_PRO_CHART_VENDOR_MARKER = "__LIGHTWEIGHT_INLINE__"
ROXY_ACTIONS_PRO_CHART_ID_MARKER = "__CHART_ID__"


@lru_cache(maxsize=1)
def roxy_actions_pro_chart_runtime_template() -> str:
    try:
        template = ROXY_ACTIONS_PRO_CHART_RUNTIME_TEMPLATE_PATH.read_text(encoding="utf-8")
    except OSError as exc:
        raise RuntimeError(f"Roxy actions pro chart runtime resource unavailable: {exc}") from exc
    expected = {
        ROXY_ACTIONS_PRO_CHART_PAYLOAD_MARKER: 1,
        ROXY_ACTIONS_PRO_CHART_VENDOR_MARKER: 1,
        ROXY_ACTIONS_PRO_CHART_ID_MARKER: 2,
    }
    if any(template.count(marker) != count for marker, count in expected.items()):
        raise RuntimeError("Roxy actions pro chart runtime has an invalid marker contract")
    required = (
        'class="roxy-pro-chart"',
        "LightweightCharts.createChart",
        "chart.subscribeCrosshairMove",
        "roxy-stock-quote",
        "</script>",
    )
    if len(template) < 45_000 or any(marker not in template for marker in required):
        raise RuntimeError("Roxy actions pro chart runtime is incomplete")
    return template


def roxy_actions_pro_chart_runtime_markup(
    *,
    payload: Mapping[str, Any],
    lightweight_inline_source: str,
    chart_id: str,
) -> str:
    safe_chart_id = str(chart_id or "").strip()
    if not re.fullmatch(r"[A-Za-z0-9_-]{1,80}", safe_chart_id):
        raise ValueError("Roxy actions pro chart id is invalid")
    replacements = {
        ROXY_ACTIONS_PRO_CHART_PAYLOAD_MARKER: roxy_json_for_inline_script(dict(payload)),
        ROXY_ACTIONS_PRO_CHART_VENDOR_MARKER: roxy_json_for_inline_script(lightweight_inline_source),
        ROXY_ACTIONS_PRO_CHART_ID_MARKER: safe_chart_id,
    }
    marker_pattern = "|".join(re.escape(marker) for marker in replacements)
    return re.sub(
        marker_pattern,
        lambda match: replacements[match.group(0)],
        roxy_actions_pro_chart_runtime_template(),
    )


def render_roxy_actions_pro_chart_panel(
    chart_df: pd.DataFrame,
    *,
    symbol: str,
    market: str,
    timeframe: str,
    trade_plan: dict[str, Any],
    panel_label: str,
    height: int = 620,
) -> bool:
    payload = roxy_actions_pro_chart_payload(
        chart_df,
        symbol=symbol,
        market=market,
        timeframe=timeframe,
        trade_plan=trade_plan,
        panel_label=panel_label,
    )
    if not payload.get("candles"):
        return False
    chart_id = "roxy-pro-" + hashlib.sha1(
        f"{symbol}-{market}-{timeframe}-{panel_label}-{len(payload.get('candles') or [])}".encode("utf-8")
    ).hexdigest()[:12]
    components.html(
        roxy_actions_pro_chart_runtime_markup(
            payload=payload,
            lightweight_inline_source=roxy_vendor_js_source("lightweight-charts.4.2.3.min.js"),
            chart_id=chart_id,
        ),
        height=height,
        scrolling=False,
    )
    return True


