@st.cache_data(ttl=cache_ttl("chart"), show_spinner=False)
def cached_roxy_crypto_chart_df(symbol: str, timeframe: str, limit: int = 260) -> pd.DataFrame:
    """Exchange-only chart data; never stalls on unrelated stock fallbacks."""
    try:
        frame = roxy_crypto_history_for_signal(symbol, timeframe, limit)
    except Exception:
        frame = pd.DataFrame()
    return prepare_symbol_chart_data(frame) if isinstance(frame, pd.DataFrame) and not frame.empty else pd.DataFrame()


