def render_roxy_module_workspace(table: pd.DataFrame, *, active_module: str, timeframe: str) -> None:
    active_module = normalize_roxy_module(active_module)
    remember_roxy_voice_opportunities(
        table,
        source=f"module:{active_module}",
        module=active_module,
        timeframe=timeframe,
    )
    if active_module in {"acciones-operar", "acciones", "accion", "stock", "stocks", "acciones-disponibles"}:
        render_roxy_actions_operating_route(timeframe="1h")
        return
    if active_module == "crypto-trabajar":
        rows = roxy_asset_rows_for_market(table, "crypto")
        render_roxy_folder_trade_chart(rows, market="crypto", timeframe="1h", key_prefix="crypto-trabajar")
        render_roxy_asset_cards(rows, market="crypto", timeframe="1h", key_prefix="crypto-trabajar")
        return
    if active_module == "crypto-20m":
        render_roxy_crypto20_folder(table, timeframe=timeframe or "20m")
        return
    if active_module == "crypto-2h":
        render_roxy_crypto2h_folder(table, timeframe="2h")
        return
    if active_module == "crypto-daily":
        render_roxy_crypto_daily_folder(table, timeframe="1d")
        return
    if active_module == "classroom":
        render_roxy_classroom_module()
        return
    st.markdown(
        """
        <div class="roxy-module-empty">
          <strong>Carpeta en preparacion</strong>
          <span>Roxy esta preparando esta seccion.</span>
        </div>
        """,
        unsafe_allow_html=True,
    )


def render_command_center_controls(confluence_df: pd.DataFrame, brief: dict) -> dict[str, Any]:
    # Contract kept for compact controls: label_visibility="collapsed",
    # on_change=persist_command_symbol_query_params, on_change=persist_command_query_params.
    best = focused_opportunity_table(brief)
    sync_roxy_operational_watchlist(best)
    default_symbol = default_trade_plan_symbol(confluence_df, brief)
    remember_roxy_voice_opportunities(
        best,
        source="command_center",
        module=first_query_param_value(st.query_params, "module") or "home",
        symbol=st.session_state.get("command_symbol") or default_symbol,
        market=st.session_state.get("command_market") or first_query_param_value(st.query_params, "market") or "",
        timeframe=st.session_state.get("command_timeframe") or first_query_param_value(st.query_params, "tf") or "",
    )
    hydrate_command_state_from_query_params(st.query_params, st.session_state, default_symbol)
    apply_pending_command_state()

    current_symbol = st.session_state.get("command_symbol", default_symbol)
    current_market = normalize_command_market(st.session_state.get("command_market"), current_symbol)
    current_timeframe = normalize_command_timeframe(st.session_state.get("command_timeframe"))
    current_equity = float(st.session_state.get("command_equity", 100.0) or 100.0)
    current_risk = float(st.session_state.get("command_risk", 1.0) or 1.0)
    current_1r = current_equity * (current_risk / 100.0)
    table = best if isinstance(best, pd.DataFrame) else pd.DataFrame()
    ready_now = 0
    watch_now = 0
    if not table.empty:
        pulse = market_pulse_summary(table)
        ready_now = int(pulse.get("ready") or 0)
        watch_now = int(pulse.get("watch") or 0)
    module_is_open = bool(first_query_param_value(st.query_params, "module"))
    if module_is_open:
        render_roxy_first_screen_launchpad(
            table,
            symbol=text_display(current_symbol).upper(),
            market=current_market,
            timeframe=current_timeframe,
        )
    else:
        render_roxy_opening_stage(
            current_symbol,
            current_market,
            current_timeframe,
            current_equity,
            current_risk,
            current_1r,
            ready_now,
            watch_now,
            opportunities=table,
        )
    return {
        "best": best,
        "default_symbol": default_symbol,
        "symbol_input": current_symbol,
        "market": current_market,
        "timeframe": current_timeframe,
        "account_equity": float(current_equity),
        "risk_pct": float(current_risk) / 100.0,
        "budget_market_scope": st.session_state.get("command_budget_market_scope", "Todos"),
        "max_daily_trades": int(st.session_state.get("command_max_daily_trades", 3) or 3),
        "realtime_report": read_summary_json("alerts/roxy_realtime_check.json"),
        "clean_mode": True,
        "command_center_only": True,
        "roxy_folder_open": module_is_open,
    }
    st.markdown(
        f"""
        <section class="trade-desk-control-panel">
          <div class="trade-desk-control-brand">
            {brand_logo_html()}
            <div>
              <span>Roxy Trade Desk</span>
              <strong>{html.escape(text_display(current_symbol).upper())}</strong>
              <small>{html.escape(current_market.upper())} · {html.escape(current_timeframe)} · Capital ${current_equity:,.0f} · 1R ${current_1r:,.2f}</small>
            </div>
          </div>
          <div class="trade-desk-control-status">
            <strong>Paper/manual</strong>
            <span>Ordenes reales OFF</span>
          </div>
        </section>
        """,
        unsafe_allow_html=True,
    )
    quick_cols = st.columns([1.0, 0.42], gap="small")
    with quick_cols[0]:
        symbol_input_kwargs: dict[str, Any] = {
            "key": "command_symbol",
            "on_change": persist_command_symbol_query_params,
            "label_visibility": "collapsed",
            "placeholder": "Ticker o crypto: AAPL, TSLA, BTC/USD",
        }
        if "command_symbol" not in st.session_state:
            symbol_input_kwargs["value"] = current_symbol
        symbol_input = st.text_input(
            "Cambiar activo",
            **symbol_input_kwargs,
        )
    with quick_cols[1]:
        st.markdown(
            f"""
            <div class="trade-desk-quick-metrics">
              <span>Riesgo</span>
              <strong>{current_risk:.1f}%</strong>
              <small>1R ${current_1r:,.2f}</small>
            </div>
            """,
            unsafe_allow_html=True,
        )

    with st.expander("Cambiar mercado, timeframe, capital y riesgo", expanded=False):
        control_cols = st.columns([0.62, 0.56, 0.72, 0.50], gap="small")
        inferred_market = normalize_command_market(current_market, symbol_input)
        with control_cols[0]:
            market_index = 1 if inferred_market == "crypto" else 0
            market_kwargs: dict[str, Any] = {
            }
            if "command_market" not in st.session_state:
                market_kwargs["index"] = market_index
            market = st.selectbox(
                "Mercado",
                ["stock", "crypto"],
                key="command_market",
                on_change=persist_command_query_params,
                **market_kwargs,
            )
        with control_cols[1]:
            timeframe_kwargs: dict[str, Any] = {
            }
            if "command_timeframe" not in st.session_state:
                timeframe_kwargs["index"] = (
                    TIMEFRAME_OPTIONS.index(current_timeframe)
                    if current_timeframe in TIMEFRAME_OPTIONS
                    else DEFAULT_TIMEFRAME_INDEX
                )
            timeframe = st.selectbox(
                "Marco",
                TIMEFRAME_OPTIONS,
                key="command_timeframe",
                on_change=persist_command_query_params,
                **timeframe_kwargs,
            )
        with control_cols[2]:
            equity_kwargs: dict[str, Any] = {
                "min_value": 50.0,
                "step": 50.0,
                "key": "command_equity",
                "help": "Roxy calcula tamaño, riesgo y potencial según este capital; no usa un riesgo fijo.",
            }
            if "command_equity" not in st.session_state:
                equity_kwargs["value"] = current_equity
            account_equity = st.number_input(
                "Capital disponible",
                **equity_kwargs,
            )
        with control_cols[3]:
            risk_kwargs: dict[str, Any] = {
                "min_value": 0.1,
                "max_value": 5.0,
                "step": 0.1,
                "key": "command_risk",
            }
            if "command_risk" not in st.session_state:
                risk_kwargs["value"] = current_risk
            risk_pct_ui = st.number_input(
                "Riesgo %",
                **risk_kwargs,
            )
        extra_cols = st.columns([0.75, 0.55, 0.48], gap="small")
        with extra_cols[0]:
            budget_market_scope = st.selectbox(
                "Mercado presupuesto",
                ["Todos", "Acciones", "Crypto", "Opciones"],
                key="command_budget_market_scope",
                help="Modo Tengo $X hoy: Roxy filtra oportunidades antes de mostrarlas como candidatas principales.",
            )
        with extra_cols[1]:
            max_trades_kwargs: dict[str, Any] = {
                "min_value": 1,
                "max_value": 5,
                "step": 1,
                "key": "command_max_daily_trades",
                "help": "Roxy devuelve solo las mejores oportunidades que caben en este limite diario.",
            }
            if "command_max_daily_trades" not in st.session_state:
                max_trades_kwargs["value"] = 3
            max_daily_trades = st.number_input(
                "Max trades/dia",
                **max_trades_kwargs,
            )
        with extra_cols[2]:
            clean_mode_kwargs: dict[str, Any] = {
                "key": "command_clean_mode",
                "help": "Muestra primero oportunidades accionables y oculta paneles secundarios del Dashboard.",
            }
            if "command_clean_mode" not in st.session_state:
                clean_mode_kwargs["value"] = True
            clean_mode = st.toggle(
                "Modo limpio",
                **clean_mode_kwargs,
            )
    market = normalize_command_market(st.session_state.get("command_market", current_market), symbol_input)
    timeframe = normalize_command_timeframe(st.session_state.get("command_timeframe", current_timeframe))
    account_equity = float(st.session_state.get("command_equity", current_equity) or current_equity)
    risk_pct_ui = float(st.session_state.get("command_risk", current_risk) or current_risk)
    budget_market_scope = st.session_state.get("command_budget_market_scope", "Todos")
    max_daily_trades = int(st.session_state.get("command_max_daily_trades", 3) or 3)
    clean_mode = bool(st.session_state.get("command_clean_mode", True))
    if "/" in str(symbol_input) and market != "crypto":
        market = "crypto"
        st.session_state["command_market"] = market
        persist_command_query_params()
    realtime_report = read_summary_json("alerts/roxy_realtime_check.json")
    sync_dashboard_query_params(
        st.query_params,
        symbol=symbol_input,
        market=market,
        timeframe=timeframe,
        page=st.session_state.get("roxy_focused_page", "Dashboard"),
    )
    write_dashboard_ui_state(
        symbol=symbol_input,
        market=market,
        timeframe=timeframe,
        page=st.session_state.get("roxy_focused_page", "Dashboard"),
    )
    return {
        "best": best,
        "default_symbol": default_symbol,
        "symbol_input": symbol_input,
        "market": market,
        "timeframe": timeframe,
        "account_equity": float(account_equity),
        "risk_pct": float(risk_pct_ui) / 100.0,
        "budget_market_scope": budget_market_scope,
        "max_daily_trades": int(max_daily_trades),
        "realtime_report": realtime_report,
        "clean_mode": bool(clean_mode),
    }


def render_launch_operator_shell(brief: dict, controls: dict[str, Any], realtime: dict[str, Any]) -> None:
    table = controls.get("best")
    if not isinstance(table, pd.DataFrame):
        table = focused_opportunity_table(brief)
    query_state = command_state_from_query_params(
        st.query_params,
        text_display(controls.get("default_symbol") or "AAPL"),
        persisted_state=read_dashboard_ui_state(),
    )
    selected_symbol = text_display(
        controls.get("symbol_input") or query_state.get("symbol") or controls.get("default_symbol") or "-"
    ).upper()
    selected_market = normalize_command_market(
        controls.get("market") or query_state.get("market"),
        selected_symbol,
    ).upper()
    timeframe = normalize_command_timeframe(controls.get("timeframe") or query_state.get("timeframe"))
    best_row: dict[str, Any] = {}
    if isinstance(table, pd.DataFrame) and not table.empty:
        if selected_symbol != "-" and "symbol" in table.columns:
            selected_rows = table[table["symbol"].astype(str).str.upper().eq(selected_symbol)]
            if not selected_rows.empty:
                best_row = selected_rows.iloc[0].to_dict()
        if not best_row:
            best_row = {
                "symbol": selected_symbol,
                "market": selected_market.lower(),
                "timeframe": timeframe,
                "action": "Esperar confirmacion",
                "reason": "Roxy mantiene la grafica seleccionada; operar solo si 15m/1h confirman tendencia, volumen y stop medible.",
                "next_step": "Confirmar la grafica actual antes de entrar.",
            }
    status = trade_decision_card_status(best_row)
    action = text_display(status.get("action") or "Esperar")
    tone = text_display(status.get("tone"))
    if tone not in {"buy", "watch", "avoid", "neutral"}:
        tone = "watch"
    if action.lower().startswith("esperar"):
        tone = "watch"
    symbol = text_display(status.get("symbol") or selected_symbol or "-").upper()
    market = normalize_command_market(status.get("market") or selected_market, symbol).upper()
    account_equity = safe_float(controls.get("account_equity")) or 100.0
    risk_pct = safe_float(controls.get("risk_pct")) or 0.01
    risk_budget = account_equity * risk_pct
    reason = text_display(status.get("reason") or dashboard_now_reason(best_row, brief))
    next_step = text_display(status.get("next_step") or status.get("confirmation_rule"))
    live_state = "Live ON" if realtime.get("enabled") else "Live manual"
    refresh = normalize_realtime_refresh_interval(realtime.get("interval_seconds"))
    pulse = market_pulse_summary(table if isinstance(table, pd.DataFrame) else pd.DataFrame())
    ready_count = int(pulse.get("ready") or 0)
    watch_count = int(pulse.get("watch") or 0)
    avoid_count = int(pulse.get("avoid") or 0)
    launch_rows = budget_top_trade_rows(
        table if isinstance(table, pd.DataFrame) else pd.DataFrame(),
        account_equity=account_equity,
        risk_pct=risk_pct,
        market_scope=text_display(controls.get("budget_market_scope") or "Todos"),
        max_trades=int(safe_float(controls.get("max_daily_trades")) or 3),
    )
    top_symbols = ", ".join(launch_rows["symbol"].astype(str).str.upper().head(3).tolist()) if not launch_rows.empty else "-"
    st.markdown(
        f"""
        <section class="launch-operator-shell launch-operator-{html.escape(tone)}">
          <div class="launch-operator-brand">
            {brand_logo_html()}
            <div><span>Roxy Trade Desk</span><strong>Modo operador</strong><small>Paper/manual · ordenes reales OFF</small></div>
          </div>
          <div class="launch-operator-main">
            <span>Decision ahora</span>
            <strong>{html.escape(action)}</strong>
            <p>{html.escape(reason[:190])}</p>
          </div>
          <div class="launch-operator-metrics">
            <div><span>Activo</span><strong>{html.escape(symbol)}</strong><small>{html.escape(market)} · {html.escape(timeframe)}</small></div>
            <div><span>Entrada</span><strong>{html.escape(price_display(status.get("entry")))}</strong><small>Stop {html.escape(price_display(status.get("stop")))}</small></div>
            <div><span>1R</span><strong>${risk_budget:,.2f}</strong><small>Capital ${account_equity:,.0f}</small></div>
            <div><span>Live</span><strong>{html.escape(live_state)}</strong><small>Refresh {int(refresh)}s</small></div>
          </div>
          <div class="launch-operator-bottom">
            <span>Top presupuesto: {html.escape(top_symbols)}</span>
            <span>Scan: operar {ready_count} · vigilar {watch_count} · evitar {avoid_count}</span>
            <span>{html.escape(next_step[:120])}</span>
          </div>
        </section>
        """,
        unsafe_allow_html=True,
    )


def render_focused_home_live(
    scan_df: pd.DataFrame,
    confluence_df: pd.DataFrame,
    options_df: pd.DataFrame,
    brief: dict,
    controls: dict[str, Any],
) -> None:
    best = controls.get("best")
    if not isinstance(best, pd.DataFrame):
        best = focused_opportunity_table(brief)
    default_symbol = text_display(controls.get("default_symbol") or default_trade_plan_symbol(confluence_df, brief))
    symbol_input = text_display(controls.get("symbol_input") or default_symbol)
    market = normalize_command_market(controls.get("market"), symbol_input)
    timeframe = normalize_command_timeframe(controls.get("timeframe"))
    account_equity = float(controls.get("account_equity") or 500.0)
    risk_pct = float(controls.get("risk_pct") or 0.01)
    budget_market_scope = text_display(controls.get("budget_market_scope") or "Todos")
    max_daily_trades = int(safe_float(controls.get("max_daily_trades")) or 3)
    budget_best = budget_filtered_opportunity_table(
        best,
        account_equity=account_equity,
        risk_pct=risk_pct,
        market_scope=budget_market_scope,
        max_trades=max_daily_trades,
    )
    display_best = budget_best if isinstance(budget_best, pd.DataFrame) and not budget_best.empty else best.head(max_daily_trades)
    realtime_report = controls.get("realtime_report")
    if not isinstance(realtime_report, dict):
        realtime_report = read_summary_json("alerts/roxy_realtime_check.json")
    clean_mode = bool(controls.get("clean_mode", False))
    defer_command_analysis = bool(controls.get("defer_command_analysis"))
    suppress_budget_summary = bool(controls.get("suppress_budget_summary"))
    top_symbol = selected_dashboard_symbol(display_best if isinstance(display_best, pd.DataFrame) else best)
    active_symbol = text_display(symbol_input).upper()
    selected_symbol_changed = bool(active_symbol and top_symbol and active_symbol != top_symbol)
    paper_risk_state = paper_journal_operational_risk_state(
        load_alpaca_paper_practice_journal(),
        load_crypto_paper_practice_journal(),
        account_equity=account_equity,
        risk_per_trade_pct=risk_pct,
    )
    macro_context = brief.get("macro_calendar") if isinstance(brief.get("macro_calendar"), dict) else macro_calendar_status()

    render_selected_asset_banner(symbol_input, market, timeframe, top_symbol=top_symbol)
    if clean_mode:
        if not defer_command_analysis:
            render_command_center_live_panel(confluence_df, options_df, brief, controls, render_side_panel=False)
        render_market_discovery_deck(display_best, confluence_df, scan_df, controls)
        render_top_opportunity_cards(display_best, confluence_df)
        if not suppress_budget_summary:
            record_budget_filtered_paper_candidates(
                display_best,
                account_equity=account_equity,
                risk_pct=risk_pct,
                market_scope=budget_market_scope,
                max_trades=max_daily_trades,
            )
            render_budget_split_opportunities_panel(
                best,
                account_equity=account_equity,
                risk_pct=risk_pct,
                max_trades=max_daily_trades,
            )
            with st.expander("Panel avanzado: ranking, memoria y diagnostico", expanded=False):
                render_budget_strategy_allocation_panel(display_best, account_equity=account_equity, risk_pct=risk_pct)
                render_opportunity_ranking_panel(display_best, account_equity=account_equity, risk_pct=risk_pct)
                render_budget_wide_search_panel(
                    best,
                    account_equity=account_equity,
                    risk_pct=risk_pct,
                    market_scope=budget_market_scope,
                    max_trades=max_daily_trades,
                )
        with st.expander("Plan detallado: confirmaciones, vigilancia y salidas", expanded=False):
            render_paper_readiness_gap_panel(best)
            render_trading_desk_table(best, confluence_df, scan_df)
            render_confirmation_radar(confluence_df)
            render_buy_readiness_gap_panel(confluence_df)
            render_exit_plan_board(best, confluence_df)
        with st.expander("Paper labs y medicion", expanded=False):
            paper_journal_snapshot = alpaca_paper_journal_snapshot(limit=8)
            st.session_state["alpaca_paper_journal_snapshot"] = paper_journal_snapshot
            render_alpaca_paper_practice_lab(best, paper_journal_snapshot, account_equity=account_equity, risk_pct=risk_pct)
            render_crypto_paper_practice_lab(best)
            render_small_account_learning_panel()
        with st.expander("Riesgo, broker y guardrails paper", expanded=False):
            render_broker_status_hub(best, account_equity=float(account_equity), risk_pct=float(risk_pct))
            render_paper_operational_risk_panel(paper_risk_state)
            render_market_event_guard_panel(best, macro_context)
    else:
        render_broker_status_hub(best, account_equity=float(account_equity), risk_pct=float(risk_pct))
        render_paper_operational_risk_panel(paper_risk_state)
        render_market_event_guard_panel(best, macro_context)
        render_ticker_intel_strip(best, confluence_df, symbol_input)
        render_company_research_hub(symbol_input, market)
        render_live_provider_center(symbol=symbol_input, market=market, realtime_report=realtime_report)
        st.markdown(
            render_market_realtime_route(market_realtime_route_summary(realtime_report)),
            unsafe_allow_html=True,
        )
        render_alpaca_paper_execution_panel(
            best,
            account_equity=account_equity,
            risk_pct=risk_pct,
            risk_state=paper_risk_state,
        )
        paper_journal_snapshot = render_alpaca_paper_journal_panel()
        render_alpaca_paper_practice_lab(best, paper_journal_snapshot, account_equity=account_equity, risk_pct=risk_pct)
        render_crypto_paper_practice_lab(best)
        render_alpaca_paper_open_positions_panel(paper_journal_snapshot, best)
        render_alpaca_paper_strategy_ranking(paper_journal_snapshot, best)
        render_screener_preset_deck(best, confluence_df)
        render_exit_plan_board(best, confluence_df)
        render_executive_cockpit(best, confluence_df, scan_df, brief)
        render_top_opportunity_cards(display_best, confluence_df)
        if not suppress_budget_summary:
            record_budget_filtered_paper_candidates(
                display_best,
                account_equity=account_equity,
                risk_pct=risk_pct,
                market_scope=budget_market_scope,
                max_trades=max_daily_trades,
            )
            render_budget_split_opportunities_panel(
                best,
                account_equity=account_equity,
                risk_pct=risk_pct,
                max_trades=max_daily_trades,
            )
            with st.expander("Panel avanzado: ranking, memoria y diagnostico", expanded=False):
                render_budget_strategy_allocation_panel(display_best, account_equity=account_equity, risk_pct=risk_pct)
                render_opportunity_ranking_panel(display_best, account_equity=account_equity, risk_pct=risk_pct)
                render_budget_wide_search_panel(
                    best,
                    account_equity=account_equity,
                    risk_pct=risk_pct,
                    market_scope=budget_market_scope,
                    max_trades=max_daily_trades,
                )
        render_paper_readiness_gap_panel(best)
        render_market_discovery_deck(display_best, confluence_df, scan_df, controls)
        render_market_movers_tape(best, confluence_df)
        render_opportunity_compare_board(best, confluence_df)
        render_opportunity_edge_heatmap(best, confluence_df)
        render_trading_desk_table(best, confluence_df, scan_df)
        render_confirmation_radar(confluence_df)
        render_buy_readiness_gap_panel(confluence_df)
        render_daily_opportunity_plan(brief)
        render_finviz_style_wallboard(best, confluence_df, brief)
        render_opportunity_matrix(best, confluence_df)
        render_confluence_validation_board(confluence_df)
        render_market_breadth_strip(scan_df, confluence_df)
        render_market_index_strip(scan_df, confluence_df)
        render_technical_movers_strip(scan_df)
        render_scanner_cockpit(best, confluence_df, options_df, brief)
        render_market_pulse_dashboard(best)

    if defer_command_analysis:
        return
    if not clean_mode:
        render_command_center_live_panel(confluence_df, options_df, brief, controls)


def render_command_center_live_panel(
    confluence_df: pd.DataFrame,
    options_df: pd.DataFrame,
    brief: dict,
    controls: dict[str, Any],
    *,
    show_spinner: bool = True,
    render_side_panel: bool = True,
    chart_interactive: bool = True,
    render_secondary_charts: bool = True,
    render_decision_panel: bool = True,
) -> None:
    best = controls.get("best")
    if not isinstance(best, pd.DataFrame):
        best = focused_opportunity_table(brief)
    default_symbol = text_display(controls.get("default_symbol") or default_trade_plan_symbol(confluence_df, brief))
    symbol_input = text_display(controls.get("symbol_input") or default_symbol)
    market = normalize_command_market(controls.get("market"), symbol_input)
    timeframe = normalize_command_timeframe(controls.get("timeframe"))
    account_equity = float(controls.get("account_equity") or 500.0)
    risk_pct = float(controls.get("risk_pct") or 0.01)
    status_snapshot = read_summary_json("alerts/roxy_status.json")
    market_gate = status_snapshot_market_gate(status_snapshot, market, symbol_input)
    symbol = str(symbol_input or default_symbol or "AAPL").strip().upper()
    if not symbol:
        symbol = "AAPL"

    top_symbol = selected_dashboard_symbol(best) or text_display(status_snapshot.get("top_symbol")).upper()
    selected_symbol_changed = bool(symbol and top_symbol and symbol != top_symbol)

    def render_symbol_context(symbol_value: str, market_value: str) -> None:
        status_cm = st.spinner(f"Leyendo {symbol_value} en {timeframe}...") if show_spinner else nullcontext()
        with status_cm:
            try:
                context = load_symbol_trade_context(
                    symbol=symbol_value,
                    market=market_value,
                    timeframe=timeframe,
                    confluence_df=confluence_df,
                    options_df=options_df,
                    account_equity=account_equity,
                    risk_per_trade_pct=risk_pct,
                    memory=load_memory(),
                )
            except Exception as exc:
                st.error(f"No se pudo construir el Command Center para {symbol_value}: {exc}")
                context = {}
        if context:
            render_command_center_analysis(
                context,
                app_brief=brief,
                account_equity=account_equity,
                risk_per_trade_pct=risk_pct,
                chart_interactive=chart_interactive,
                render_secondary_charts=render_secondary_charts,
                render_decision_panel=render_decision_panel,
            )

    if not render_side_panel:
        if market_gate.get("blocked") and not selected_symbol_changed:
            fallback_symbol = text_display(status_snapshot.get("top_symbol")).upper()
            fallback_market = normalize_command_market(status_snapshot.get("top_market"), fallback_symbol)
            fallback_gate = status_snapshot_market_gate(status_snapshot, fallback_market, fallback_symbol)
            if fallback_symbol and fallback_symbol != "-" and not fallback_gate.get("blocked"):
                st.caption(
                    f"{symbol} está bloqueado por la ruta realtime; Roxy cambia la gráfica al foco operable "
                    f"{fallback_symbol} ({fallback_market.upper()})."
                )
                render_symbol_context(fallback_symbol, fallback_market)
            else:
                st.warning(market_gate["detail"])
                render_kpi_card(
                    "Ruta operativa",
                    market_gate["label"],
                    tone=market_gate["tone"],
                    detail=f"{market_gate['market']} bloqueado | {market_gate.get('route_label') or '-'}",
                )
        else:
            if market_gate.get("blocked"):
                st.caption(
                    f"{symbol} fue seleccionado manualmente; Roxy mantiene esa gráfica aunque el scanner global tenga otro foco."
                )
            render_symbol_context(symbol, market)
        return

    left, right = st.columns([1.6, 0.72])
    with left:
        if market_gate.get("blocked") and not selected_symbol_changed:
            fallback_symbol = text_display(status_snapshot.get("top_symbol")).upper()
            fallback_market = normalize_command_market(status_snapshot.get("top_market"), fallback_symbol)
            fallback_gate = status_snapshot_market_gate(status_snapshot, fallback_market, fallback_symbol)
            if fallback_symbol and fallback_symbol != "-" and not fallback_gate.get("blocked"):
                st.caption(
                    f"{symbol} está bloqueado por la ruta realtime; Roxy cambia la gráfica al foco operable "
                    f"{fallback_symbol} ({fallback_market.upper()})."
                )
                render_symbol_context(fallback_symbol, fallback_market)
            else:
                st.warning(market_gate["detail"])
                render_kpi_card(
                    "Ruta operativa",
                    market_gate["label"],
                    tone=market_gate["tone"],
                    detail=f"{market_gate['market']} bloqueado | {market_gate.get('route_label') or '-'}",
                )
        else:
            if market_gate.get("blocked"):
                st.caption(
                    f"{symbol} fue seleccionado manualmente; Roxy mantiene esa gráfica aunque el scanner global tenga otro foco."
                )
            render_symbol_context(symbol, market)
    with right:
        if not render_side_panel:
            st.caption("Panel de busqueda estable durante live refresh.")
            return
        render_company_profile_card(symbol, market)
        st.subheader("Carga rapida")
        quick_rows = best.head(7).to_dict("records") if not best.empty else []
        if quick_rows:
            for idx, row in enumerate(quick_rows):
                label = (
                    f"{text_display(row.get('symbol')).upper()} | "
                    f"{human_trade_action(row)} | "
                    f"{strategy_family_for_row(row)}"
                )
                if st.button(label, key=f"command_load_{idx}_{safe_key(row.get('symbol'))}", use_container_width=True):
                    st.session_state["command_symbol_pending"] = text_display(row.get("symbol")).upper()
                    st.session_state["command_market_pending"] = (
                        "crypto" if str(row.get("market") or "").lower().startswith("crypto") else "stock"
                    )
                    st.rerun()
        else:
            st.info("No hay oportunidades ordenadas. Puedes escribir un simbolo manualmente.")

        st.markdown("**Simbolos clave**")
        for symbol_label in ["AAPL", "NVDA", "AMD", "MSFT", "PLTR", "QQQ", "BTC/USD", "SOL/USD"]:
            if st.button(symbol_label, key=f"command_key_symbol_{safe_key(symbol_label)}", use_container_width=True):
                st.session_state["command_symbol_pending"] = symbol_label
                st.session_state["command_market_pending"] = "crypto" if "/" in symbol_label else "stock"
                st.rerun()

        status = status_snapshot
        if status:
            st.subheader("Estado Roxy")
            route_status = status_snapshot_route_summary(status)
            status_cols = st.columns(3)
            with status_cols[0]:
                alert_count = int(status.get("notifications_ready", 0) or 0)
                render_kpi_card("Alertas listas", alert_count, tone="buy" if alert_count else "neutral")
            with status_cols[1]:
                render_kpi_card(
                    "Datos",
                    status.get("data_label", "-"),
                    tone="buy" if status.get("data_label") == "Frescos" else "avoid",
                )
            with status_cols[2]:
                render_kpi_card(
                    "Macro",
                    status.get("macro_label", "-"),
                    tone="avoid" if status.get("macro_active") else "neutral",
                    detail=status.get("macro_detail"),
                )
            render_kpi_card(
                "Ruta RT",
                route_status["label"],
                tone=route_status["tone"],
                detail=route_status["detail"],
            )
            render_kpi_card(
                "Top watch",
                f"{status.get('top_market', '-')} {status.get('top_symbol', '-')}",
                tone="buy" if status.get("top_action") == "ALERT" else "watch",
                detail=f"{status.get('top_gate', '-')} | {status.get('top_quality', '-')}",
            )
            next_action = text_display(status.get("top_next_action"))
            if next_action != "-":
                st.caption(next_action)
            blockers = status.get("top_blockers") or []
            if blockers:
                st.caption("Bloquea: " + " | ".join(str(item) for item in blockers[:2]))
        st.subheader("Lectura IA")
        lessons = brief.get("lessons", [])[-6:]
        if lessons:
            for lesson in lessons:
                st.write(f"- {lesson}")
        else:
            st.write("La memoria IA se llenara despues del proximo escaneo live.")
        lines = build_notification_lines(brief)
        if lines:
            st.markdown("**Vista previa de alerta**")
            st.code("\n".join(lines))
        if not best.empty:
            with st.expander("Watchlist priorizada", expanded=False):
                watch_controls = st.columns([1, 1, 1])
                with watch_controls[0]:
                    watch_bucket = st.selectbox(
                        "Estado",
                        ["Todos", "Operar", "Vigilar", "Evitar"],
                        key="watchlist_bucket_filter",
                    )
                with watch_controls[1]:
                    markets = ["Todos"] + sorted(
                        market
                        for market in market_pulse_rows(best)["market"].dropna().astype(str).unique().tolist()
                        if market != "-"
                    )
                    watch_market = st.selectbox("Mercado", markets, key="watchlist_market_filter")
                with watch_controls[2]:
                    watch_min_readiness = st.slider(
                        "Readiness minimo", 0, 100, 0, step=5, key="watchlist_min_readiness"
                    )
                filtered_watchlist = filter_focused_opportunities(
                    best,
                    bucket=watch_bucket,
                    market=watch_market,
                    min_readiness=float(watch_min_readiness),
                )
                if filtered_watchlist.empty:
                    st.info("Ninguna oportunidad coincide con esos filtros.")
                else:
                    st.caption(
                        f"Mostrando {min(len(filtered_watchlist), 15)} de {len(best)} oportunidades priorizadas."
                    )
                    st.dataframe(focused_display_table_es(filtered_watchlist).head(15), width="stretch", height=320)


def show_focused_home(
    scan_df: pd.DataFrame, confluence_df: pd.DataFrame, options_df: pd.DataFrame, brief: dict
) -> None:
    controls = render_command_center_controls(confluence_df, brief)
    render_focused_home_live(scan_df, confluence_df, options_df, brief, controls)


def show_focused_opportunities(confluence_df: pd.DataFrame, options_df: pd.DataFrame, brief: dict) -> None:
    table = focused_opportunity_table(brief)
    st.subheader("Solo lo importante")
    if table.empty:
        st.info("Todavia no hay oportunidades ordenadas por IA.")
    else:
        st.dataframe(focused_display_table_es(table), width="stretch", height=360)

    with st.expander("Confluencia tecnica completa"):
        if confluence_df.empty:
            st.write("No hay datos de confluencia.")
        else:
            cols = [
                "market",
                "symbol",
                "signal",
                "trade_decision",
                "confluence_score",
                "entry",
                "stop",
                "risk_pct",
                "recommended_target_pct",
                "recommended_target_price",
                "trigger_setup",
                "trend_setup",
                "backtest_eligible",
                "reasons",
            ]
            st.dataframe(confluence_df[[col for col in cols if col in confluence_df.columns]], use_container_width=True)

    options_route = options_route_status()
    expander_label = "Candidatos de opciones (solo info)" if options_route["blocked"] else "Candidatos de opciones"
    with st.expander(expander_label):
        if options_df.empty:
            if options_route["blocked"]:
                st.write("Opciones bloqueadas por ruta/proveedor; no hay candidatos informativos activos.")
            else:
                st.write("No hay candidatos de opciones.")
        else:
            if options_route["blocked"]:
                st.info("Opciones bloqueadas por ruta/proveedor. Tabla informativa, sin accion operable.")
            cols = [
                "symbol",
                "contractSymbol",
                "option_decision",
                "option_score",
                "expiry",
                "dte",
                "strike",
                "delta",
                "bid",
                "ask",
                "spread_pct",
                "breakeven_price",
                "breakeven_pct",
                "max_loss_per_contract",
                "volume",
                "openInterest",
            ]
            st.dataframe(options_df[[col for col in cols if col in options_df.columns]], use_container_width=True)

    with st.expander("Backtest by strategy", expanded=True):
        render_backtest_strategy_visual()


def show_focused_ai_24h(brief: dict) -> None:
    memory = load_memory()
    render_roxy_lab_visual(brief, memory)
    st.divider()
    autopilot = load_autopilot_status()
    st.subheader("Roxy Autopilot")
    autopilot_buttons = st.columns(4)
    with autopilot_buttons[0]:
        if st.button("Ejecutar Autopilot ahora", key="run_roxy_autopilot_now", use_container_width=True):
            autopilot = run_autopilot(apply=False)
            st.success("Autopilot actualizo salud y propuestas.")
    with autopilot_buttons[1]:
        if st.button("Reparar datos ahora", key="repair_roxy_autopilot_data_now", use_container_width=True):
            autopilot = run_autopilot(apply=False)
            repaired = autopilot.get("autoheal_actions") if isinstance(autopilot.get("autoheal_actions"), list) else []
            ok_count = sum(1 for item in repaired if item.get("ok"))
            if repaired:
                st.success(f"Auto-healing ejecuto {len(repaired)} accion(es); OK {ok_count}.")
            else:
                st.info("No habia reportes stale/missing que reparar.")
    with autopilot_buttons[2]:
        if st.button("Aplicar propuestas seguras", key="apply_roxy_autopilot_now", use_container_width=True):
            autopilot = run_autopilot(apply=True)
            applied_count = sum(1 for item in autopilot.get("applied", []) if item.get("applied"))
            if applied_count:
                st.success(f"Autopilot aplico {applied_count} override(s) paper-only.")
            else:
                st.warning(f"No se aplicaron cambios. Requiere {CODE_WRITE_ENV}=1 en el entorno del servicio.")
    with autopilot_buttons[3]:
        if st.button("Activar servicio continuo", key="install_roxy_autopilot_launchd", use_container_width=True):
            code, output = run_local_command(["tools/roxy_autopilot_launchd.py", "install"])
            if code == 0:
                st.success("Servicio Autopilot continuo instalado en launchd.")
            else:
                st.error(output or "No se pudo instalar el servicio Autopilot.")
            autopilot = load_autopilot_status()
    auto_cols = st.columns(4)
    with auto_cols[0]:
        render_kpi_card("Estado", autopilot.get("status", "SIN CORRER"), tone="buy" if autopilot.get("status") == "ACTIVE" else "watch")
    with auto_cols[1]:
        render_kpi_card("Code write", "ON" if autopilot.get("code_write_enabled") else "OFF", tone="watch", detail="Requiere ROXY_AUTOPILOT_CODE_WRITE=1")
    with auto_cols[2]:
        render_kpi_card("Propuestas", autopilot.get("proposal_count", 0), tone="buy" if autopilot.get("proposal_count") else "neutral")
    with auto_cols[3]:
        applied = autopilot.get("applied") if isinstance(autopilot.get("applied"), list) else []
        render_kpi_card("Aplicadas", sum(1 for item in applied if item.get("applied")), tone="buy" if applied else "neutral")
    if autopilot:
        proposals = autopilot.get("proposals") if isinstance(autopilot.get("proposals"), list) else []
        if proposals:
            with st.expander("Propuestas autonomas de mejora", expanded=False):
                st.dataframe(
                    pd.DataFrame(
                        [
                            {
                                "Tipo": item.get("type"),
                                "Titulo": item.get("title"),
                                "Riesgo": item.get("risk"),
                                "Modo": item.get("safety_mode"),
                                "Target": item.get("target_path"),
                            }
                            for item in proposals[:12]
                        ]
                    ),
                    width="stretch",
                    hide_index=True,
                )
        autoheal_actions = (
            autopilot.get("autoheal_actions") if isinstance(autopilot.get("autoheal_actions"), list) else []
        )
        if autoheal_actions:
            with st.expander("Auto-healing de datos", expanded=False):
                st.dataframe(
                    pd.DataFrame(
                        [
                            {
                                "Reporte": item.get("name"),
                                "Estado": item.get("status"),
                                "OK": item.get("ok"),
                                "Duracion s": item.get("duration_seconds"),
                                "Comando": " ".join(str(part) for part in item.get("command", [])[-3:]),
                                "Salida": item.get("output"),
                            }
                            for item in autoheal_actions
                        ]
                    ),
                    width="stretch",
                    hide_index=True,
                )
        reviews = autopilot.get("override_reviews") if isinstance(autopilot.get("override_reviews"), list) else []
        rollbacks = autopilot.get("rollback_applied") if isinstance(autopilot.get("rollback_applied"), list) else []
        if reviews or rollbacks:
            with st.expander("Tracking y rollback de overrides", expanded=False):
                if reviews:
                    st.dataframe(
                        pd.DataFrame(
                            [
                                {
                                    "Estrategia": item.get("strategy_family"),
                                    "Accion": item.get("action"),
                                    "Estado": item.get("status"),
                                    "Recomendacion": item.get("recommendation"),
                                    "Medidas": (item.get("metrics") or {}).get("measured"),
                                    "Target 2%": pct_display((item.get("metrics") or {}).get("hit_2_rate")),
                                    "Stops": pct_display((item.get("metrics") or {}).get("stop_rate")),
                                    "Razon": item.get("reason"),
                                }
                                for item in reviews
                            ]
                        ),
                        width="stretch",
                        hide_index=True,
                    )
                if rollbacks:
                    st.markdown("**Rollbacks aplicados/bloqueados**")
                    st.dataframe(pd.DataFrame(rollbacks), width="stretch", hide_index=True)
        health = autopilot.get("health") if isinstance(autopilot.get("health"), dict) else {}
        st.caption(
            "Autopilot solo puede escribir configuraciones allowlist y mantiene trading real bloqueado. "
            f"Health: {health.get('status', '-')}"
        )
    else:
        st.caption("Ejecuta `.venv/bin/python tools/roxy_autopilot.py --json` para generar el primer estado autonomo.")

    st.subheader("Alertas IA 24h")
    state = live_service_state()
    cols = st.columns(3)
    with cols[0]:
        render_kpi_card("LaunchAgent", state["loaded"], tone="buy" if state["loaded"] == "yes" else "watch")
    with cols[1]:
        render_kpi_card("Memory symbols", brief.get("memory_symbols", 0))
    with cols[2]:
        render_kpi_card("Modo", brief.get("mode", "AI_WATCH_24H"))

    render_daily_opportunity_plan(brief)
    render_smart_alert_gate(brief)

    with st.expander("Configuracion de notificaciones", expanded=False):
        st.code(
            "ALERT_EMAIL_TO=you@example.com\n"
            "SMTP_HOST=smtp.gmail.com\n"
            "SMTP_PORT=587\n"
            "SMTP_USERNAME=you@example.com\n"
            "SMTP_PASSWORD=app_password\n"
            "# alternativas opcionales\n"
            "DISCORD_WEBHOOK_URL=...\n"
            "PUSHOVER_APP_TOKEN=...\n"
            "PUSHOVER_USER_KEY=...\n"
            "TELEGRAM_BOT_TOKEN=...\n"
            "TELEGRAM_CHAT_ID=...\n"
            "SLACK_WEBHOOK_URL=...\n"
            "WEBHOOK_URL=...\n"
            "MACOS_NOTIFICATIONS=1\n"
            "ALERT_COOLDOWN_MINUTES=60"
        )
        st.caption(
            "El escaner puede correr cada 5 minutos. Crypto es 24h; acciones usan 15m/1h/2h/4h y extended-hours cuando el proveedor lo permita."
        )

    st.markdown("**Centro de alertas**")
    gate_summary = brief.get("alert_gate_summary") or summarize_alert_gates(brief)
    delivery_summary = notifier.notification_history_summary(limit=50)
    gate_status = alert_gate_summary_dashboard_status(gate_summary)
    delivery_status = notification_history_dashboard_status(delivery_summary)
    quality_cols = st.columns(4)
    with quality_cols[0]:
        render_kpi_card("Compuerta", gate_status["label"], tone=gate_status["tone"], detail=gate_status["detail"])
    with quality_cols[1]:
        render_kpi_card(
            "Readiness prom.",
            num_display(gate_summary.get("avg_readiness"), 0) if gate_summary.get("avg_readiness") is not None else "-",
            tone=gate_status["tone"],
            detail=f"Listas {gate_summary.get('notifications_ready', 0)} / {gate_summary.get('total_opportunities', 0)}",
        )
    with quality_cols[2]:
        render_kpi_card(
            "Delivery", delivery_status["label"], tone=delivery_status["tone"], detail=delivery_status["detail"]
        )
    with quality_cols[3]:
        top_blocker = text_display(gate_summary.get("top_blocker"))
        render_kpi_card("Bloqueo top", gate_summary.get("top_gate_label", "-"), tone="watch", detail=top_blocker)

    status_df = notification_channel_display(notifier.notification_channel_status())
    if not status_df.empty:
        st.table(status_df)

    alert_cols = st.columns([1, 2])
    with alert_cols[0]:
        if st.button("Probar notificacion Mac", use_container_width=True):
            result = notifier.send_test_macos_notification()
            if result.get("sent"):
                st.success("Notificacion Mac enviada.")
            else:
                st.warning("La notificacion Mac no se envio.")
    with alert_cols[1]:
        active_channels = notifier.configured_channels()
        active_labels = [NOTIFICATION_CHANNEL_LABELS.get(channel, channel) for channel in active_channels]
        st.metric("Canales activos", ", ".join(active_labels) if active_labels else "solo archivos locales")
        lines = build_notification_lines(brief)
        st.metric("Alertas listas", len(lines))
        st.caption(f"Cooldown: {notifier.ALERT_COOLDOWN_MINUTES} minutos por mercado/simbolo.")

    preview_df = alert_preview_table(brief)
    lines = build_notification_lines(brief)
    if not preview_df.empty:
        with st.expander("Vista previa de alerta actual", expanded=True):
            display_df = preview_df.copy()
            for col in ["entry", "stop", "target_2", "target_5", "target_10"]:
                if col in display_df.columns:
                    display_df[col] = display_df[col].map(lambda value: num_display(value) if pd.notna(value) else "-")
            if "risk" in display_df.columns:
                display_df["risk"] = display_df["risk"].map(
                    lambda value: pct_display(value) if pd.notna(value) else "-"
                )
            if "readiness" in display_df.columns:
                display_df["readiness"] = display_df["readiness"].map(
                    lambda value: num_display(value, 0) if pd.notna(value) else "-"
                )
            st.dataframe(display_df, width="stretch", hide_index=True)
            if lines:
                st.caption("Texto exacto que se enviaria por los canales activos:")
                st.text("\n".join(lines))
    else:
        st.caption(
            "No hay alertas limpias ahora. Roxy seguira observando hasta que 1h, 15m, volumen, riesgo y target coincidan."
        )

    history = notifier.read_notification_history(limit=25)
    st.markdown("**Historial de notificaciones**")
    if history:
        history_df = notification_history_display_table(history)
        cols = ["ts", "effective_sent", "sent", "reason", "cooldown_skipped", "channels", "message"]
        st.dataframe(history_df[[col for col in cols if col in history_df.columns]], width="stretch", hide_index=True)
    else:
        st.caption("Todavia no hay historial de notificaciones.")

    brief_text = Path("alerts/roxy_ai_brief.txt")
    if brief_text.exists():
        st.markdown("**Ultimo brief IA**")
        st.text(brief_text.read_text())
    learning_profiles = brief.get("learning_profiles") or summarize_strategy_learning(memory)
    if learning_profiles:
        learning_df = pd.DataFrame(learning_profiles)
        display_cols = [
            "strategy_family",
            "bias",
            "adaptive_weight",
            "alerts",
            "hit_2_rate",
            "hit_5_rate",
            "hit_10_rate",
            "stop_rate",
            "lesson",
            "recommendation",
        ]
        learning_display = learning_df[[col for col in display_cols if col in learning_df.columns]].copy()
        for col in ["hit_2_rate", "hit_5_rate", "hit_10_rate", "stop_rate"]:
            if col in learning_display.columns:
                learning_display[col] = learning_display[col].map(
                    lambda value: pct_display(value) if pd.notna(value) else "-"
                )
        if "adaptive_weight" in learning_display.columns:
            learning_display["adaptive_weight"] = learning_display["adaptive_weight"].map(
                lambda value: f"{float(value):.2f}x"
            )
        st.markdown("**Aprendizaje Roxy**")
        st.dataframe(learning_display, width="stretch", hide_index=True)
        if st.button("Speak learning summary", key="speak_learning_summary"):
            voice_lines = []
            for profile in learning_profiles[:4]:
                lesson = str(profile.get("lesson") or "")
                recommendation = str(profile.get("recommendation") or "")
                if lesson:
                    voice_lines.append(lesson)
                if recommendation:
                    voice_lines.append(recommendation)
            speak_in_browser(" ".join(voice_lines), key="learning-summary")

    research_rows = brief.get("research_queue") or learning_research_queue(memory)
    if research_rows:
        st.markdown("**Lo proximo que Roxy debe probar**")
        st.dataframe(pd.DataFrame(research_rows), width="stretch", hide_index=True)

    gate_research = brief.get("gate_research") or []
    if gate_research:
        st.markdown("**Investigacion de filtros**")
        st.caption("Patrones de WATCH bloqueados. Esto le dice a Roxy que filtro debe mejorar.")
        st.dataframe(pd.DataFrame(gate_research), width="stretch", hide_index=True)

    strategy_stats = memory.get("strategy_stats") or {}
    if strategy_stats:
        rows = []
        for family, stats in strategy_stats.items():
            alerts = int(stats.get("alerts", 0) or 0)
            hit_2 = int(stats.get("hit_2pct", 0) or 0)
            stops = int(stats.get("stops", 0) or 0)
            rows.append(
                {
                    "strategy": family,
                    "seen": stats.get("seen", 0),
                    "alerts": alerts,
                    "hit_2pct": hit_2,
                    "hit_5pct": stats.get("hit_5pct", 0),
                    "hit_10pct": stats.get("hit_10pct", 0),
                    "stops": stops,
                    "hit_2_rate": hit_2 / alerts if alerts else None,
                    "stop_rate": stops / alerts if alerts else None,
                }
            )
        memory_df = pd.DataFrame(rows).sort_values(["hit_2_rate", "alerts"], ascending=[False, False])
        display = memory_df.copy()
        display["hit_2_rate"] = display["hit_2_rate"].map(lambda value: pct_display(value) if pd.notna(value) else "-")
        display["stop_rate"] = display["stop_rate"].map(lambda value: pct_display(value) if pd.notna(value) else "-")
        st.markdown("**Strategy memory**")
        st.dataframe(display, width="stretch", hide_index=True)
    with st.expander("Raw AI memory"):
        st.json(memory)


def show_strategy_study_center(
    scan_df: pd.DataFrame,
    confluence_df: pd.DataFrame,
    options_df: pd.DataFrame,
    brief: dict,
) -> None:
    st.subheader("Estudios")
    memory = load_memory()
    trades_path, trades_df = latest_backtest_trades()
    backtest_summary = summarize_backtest_by_strategy(trades_df)
    lab_rows = build_strategy_lab(memory, backtest_summary=backtest_summary)
    guides = study_guides_with_lab(lab_rows)
    if not guides:
        st.info("Roxy todavia no tiene guias de estudio cargadas.")
        return

    state_labels = {
        "Promote": "Promover",
        "Watch": "Vigilar",
        "Collect data": "Recolectar datos",
        "Tighten filter": "Ajustar filtro",
    }
    tone_by_state = {
        "Promote": "buy",
        "Watch": "watch",
        "Collect data": "neutral",
        "Tighten filter": "avoid",
    }
    strategy_names = [row["strategy"] for row in guides]
    preferred = next((row["strategy"] for row in guides if row.get("lab_state") == "Promote"), strategy_names[0])
    requested = st.session_state.pop("study_strategy_request", None)
    selected_default = resolve_study_strategy_choice(
        strategy_names,
        preferred,
        requested=requested,
        current=st.session_state.get("study_strategy_select"),
    )
    if selected_default in strategy_names:
        st.session_state["study_strategy_select"] = selected_default
    focus_message = st.session_state.pop("study_focus_message", None)
    if focus_message:
        st.success(str(focus_message))
    selected = st.selectbox(
        "Estrategia para estudiar",
        strategy_names,
        index=strategy_names.index(selected_default) if selected_default in strategy_names else 0,
        key="study_strategy_select",
    )
    guide = next(row for row in guides if row["strategy"] == selected)
    lab_state = str(guide.get("lab_state") or "Collect data")
    lab_tone = tone_by_state.get(lab_state, "neutral")

    st.markdown(
        f"""
        <div class="study-hero study-hero-{lab_tone}">
            <div>
                <div class="study-kicker">Playbook Roxy</div>
                <h2>{html.escape(selected)}</h2>
                <p>{html.escape(text_display(guide.get("headline")))}</p>
            </div>
            <div class="study-status">
                <span>Lab</span>
                <strong>{html.escape(state_labels.get(lab_state, lab_state))}</strong>
            </div>
        </div>
        """,
        unsafe_allow_html=True,
    )

    metric_cols = st.columns(4)
    with metric_cols[0]:
        render_kpi_card("Evidencia", pct_display(guide.get("evidence_score")), tone=lab_tone)
    with metric_cols[1]:
        render_kpi_card("Win rate", pct_display(guide.get("backtest_win_rate")), tone="buy")
    with metric_cols[2]:
        profit_factor = guide.get("backtest_profit_factor")
        render_kpi_card(
            "Profit factor",
            "inf" if profit_factor == float("inf") else num_display(profit_factor),
            tone="buy" if safe_float(profit_factor) and safe_float(profit_factor) >= 1.25 else "watch",
        )
    with metric_cols[3]:
        weight = safe_float(guide.get("adaptive_weight"))
        render_kpi_card("Peso IA", f"{weight:.2f}x" if weight is not None else "-", tone=lab_tone)

    selected_study_page = st.radio(
        "Seccion de estudio",
        STUDY_PAGE_LABELS,
        horizontal=True,
        label_visibility="collapsed",
        key="roxy_study_page",
    )
    if selected_study_page == "Manual":
        cards = [
            ("Cuando funciona", guide.get("works_when"), "buy"),
            ("Requisitos", guide.get("requirements_text") or "-", "buy"),
            ("Entrada", guide.get("entry"), "watch"),
            ("No operar si", guide.get("avoid"), "avoid"),
            ("Opciones", guide.get("option_note"), "watch"),
            ("Practica", guide.get("practice"), "neutral"),
        ]
        for start in range(0, len(cards), 3):
            cols = st.columns(min(3, len(cards) - start))
            for col, (label, value, tone) in zip(cols, cards[start : start + 3]):
                with col:
                    st.markdown(
                        f"""
                        <div class="study-card study-card-{tone}">
                            <div class="study-card-label">{html.escape(label)}</div>
                            <div class="study-card-text">{html.escape(text_display(value))}</div>
                        </div>
                        """,
                        unsafe_allow_html=True,
                    )

    elif selected_study_page == "Ejemplo con grafica":
        examples = study_example_rows(confluence_df, brief, selected)
        example_symbols = (
            examples["symbol"].dropna().astype(str).str.upper().unique().tolist() if not examples.empty else []
        )
        fallback_symbols = ["AAPL", "NVDA", "AMD", "MSFT", "PLTR", "QQQ"]
        symbols = sorted(dict.fromkeys(example_symbols + fallback_symbols))
        control_cols = st.columns([1, 0.8, 0.8])
        with control_cols[0]:
            symbol_choice = st.selectbox("Simbolo de ejemplo", symbols, key=f"study_symbol_{selected}")
        with control_cols[1]:
            default_market = "crypto" if "/" in symbol_choice else "stock"
            market = st.selectbox(
                "Mercado",
                ["stock", "crypto"],
                index=1 if default_market == "crypto" else 0,
                key=f"study_market_{selected}",
            )
        with control_cols[2]:
            timeframe = st.selectbox("Marco", TIMEFRAME_OPTIONS, index=DEFAULT_TIMEFRAME_INDEX, key=f"study_tf_{selected}")

        resolved_symbol = resolve_symbol_query(symbol_choice, market)
        with st.spinner(f"Estudiando {resolved_symbol} en {timeframe}..."):
            try:
                history = fetch_symbol_history(resolved_symbol, market=market, timeframe=timeframe)
                chart_df = prepare_symbol_chart_data(history)
                setup = analyze_moving_average_setup(history) if not history.empty else {}
                setup = apply_learned_strategy_brain(chart_df, setup) if setup else setup
            except Exception as exc:
                st.warning(f"No se pudo cargar la grafica de estudio para {resolved_symbol}: {exc}")
                setup = {}
                chart_df = pd.DataFrame()

        if chart_df.empty or not setup:
            st.info("No hay suficiente historial para graficar este ejemplo ahora.")
        else:
            confluence = latest_confluence_row(confluence_df, resolved_symbol)
            trade_brief = build_symbol_trade_brief(
                symbol=resolved_symbol,
                market=market,
                timeframe=timeframe,
                setup=setup,
                confluence=confluence,
                options_df=options_df,
                account_equity=float(DEFAULT_ACCOUNT_EQUITY),
                account_risk_pct=0.01,
                memory=memory,
            )
            render_ai_trade_brief(trade_brief)
            render_chart_readout(setup, confluence, trade_brief, chart_df)
            render_chart_strategy_summary(setup, confluence, trade_brief, chart_df)
            render_strategy_event_panel(chart_df, setup)
            render_chart_level_plan(chart_df, setup, confluence, trade_brief)
            price_chart = build_professional_price_chart(
                chart_df,
                setup,
                confluence,
                trade_brief,
                paper_snapshot=st.session_state.get("alpaca_paper_journal_snapshot"),
                symbol=resolved_symbol,
            ).properties(height=440)
            volume_chart = build_professional_volume_chart(chart_df)
            oscillator_chart = build_professional_oscillator_chart(chart_df)
            chart_panels = [price_chart]
            if volume_chart is not None:
                chart_panels.append(volume_chart.properties(height=120))
            if oscillator_chart is not None:
                chart_panels.append(oscillator_chart.properties(height=110))
            if len(chart_panels) > 1:
                combined_chart = alt.vconcat(*chart_panels).resolve_scale(x="shared")
                st.altair_chart(style_trading_chart(combined_chart), use_container_width=True)
            else:
                st.altair_chart(style_trading_chart(price_chart), use_container_width=True)

        if not examples.empty:
            display_cols = [
                "symbol",
                "source",
                "signal",
                "trade_decision",
                "ai_action",
                "confluence_score",
                "entry",
                "stop",
                "risk_pct",
                "recommended_target_pct",
                "trigger_setup",
                "trend_setup",
            ]
            display = examples[[col for col in display_cols if col in examples.columns]].copy()
            for col in ["entry", "stop"]:
                if col in display.columns:
                    display[col] = display[col].map(lambda value: num_display(value) if pd.notna(value) else "-")
            for col in ["risk_pct", "recommended_target_pct"]:
                if col in display.columns:
                    display[col] = display[col].map(lambda value: pct_display(value) if pd.notna(value) else "-")
            st.markdown("**Ejemplos detectados por Roxy**")
            st.dataframe(display.head(12), width="stretch", hide_index=True)

    elif selected_study_page == "Laboratorio":
        lab_display = pd.DataFrame(guides)
        lab_display = lab_display[
            [
                "strategy",
                "lab_state",
                "evidence_score",
                "memory_bias",
                "adaptive_weight",
                "backtest_win_rate",
                "backtest_profit_factor",
                "lab_decision",
                "experiment_rule",
            ]
        ].copy()
        lab_display["lab_state"] = lab_display["lab_state"].map(lambda value: state_labels.get(str(value), value))
        for col in ["evidence_score", "backtest_win_rate"]:
            lab_display[col] = lab_display[col].map(lambda value: pct_display(value) if pd.notna(value) else "-")
        lab_display["adaptive_weight"] = lab_display["adaptive_weight"].map(
            lambda value: f"{float(value):.2f}x" if pd.notna(value) else "-"
        )
        lab_display["backtest_profit_factor"] = lab_display["backtest_profit_factor"].map(
            lambda value: "inf" if value == float("inf") else num_display(value)
        )
        lab_display = lab_display.rename(
            columns={
                "strategy": "Estrategia",
                "lab_state": "Estado lab",
                "evidence_score": "Evidencia",
                "memory_bias": "Memoria",
                "adaptive_weight": "Peso IA",
                "backtest_win_rate": "Win rate",
                "backtest_profit_factor": "Profit factor",
                "lab_decision": "Decision lab",
                "experiment_rule": "Regla experimento",
            }
        )
        st.dataframe(lab_display, width="stretch", hide_index=True, height=300)
        selected_rule = text_display(guide.get("experiment_rule"))
        selected_decision = text_display(guide.get("lab_decision"))
        if selected_rule != "-" or selected_decision != "-":
            st.markdown("**Lectura del laboratorio para esta estrategia**")
            if selected_decision != "-":
                st.info(selected_decision)
            if selected_rule != "-":
                st.caption(selected_rule)
        if trades_path:
            st.caption(f"Fuente backtest: `{trades_path}`")

    idle_review = read_idle_video_learning_review()
    with st.expander("Revision automatica cada 35 minutos", expanded=False):
        st.caption(
            "Roxy busca videos nuevos cada 35 minutos. Si no encuentra videos nuevos, estudia lo ya procesado y genera mejoras candidatas para Roxy Lab."
        )
        if idle_review:
            st.markdown(idle_review)
        else:
            st.info(
                "Todavia no hay revision automatica guardada. El LaunchAgent la crea en la proxima corrida o al usar Escanear videos ahora."
            )

    teacher_playbook = load_roxy_teacher_playbook()
    with st.expander("Cerebro operativo aprendido de clases y materiales", expanded=False):
        if not teacher_playbook:
            st.info("Todavia no hay playbook operativo. Ejecuta el escaneo de materiales para generarlo.")
        else:
            counts = teacher_playbook.get("source_counts") or {}
            cols = st.columns(3)
            cols[0].metric("Videos estudiados", int(counts.get("videos") or 0))
            cols[1].metric("Materiales", int(counts.get("materials") or 0))
            cols[2].metric("Reglas activas", len(teacher_playbook.get("strategy_rules") or []))
            st.caption(f"Actualizado: {text_display(teacher_playbook.get('generated_at'))}")
            rules = []
            for rule in teacher_playbook.get("strategy_rules") or []:
                rules.append(
                    {
                        "regla": rule.get("name"),
                        "uso": rule.get("use_when"),
                        "criterio": rule.get("rule"),
                        "fuentes": ", ".join((rule.get("sources") or [])[:4]),
                    }
                )
            if rules:
                st.dataframe(pd.DataFrame(rules), width="stretch", hide_index=True, height=260)
            checklist = teacher_playbook.get("opportunity_checklist") or []
            if checklist:
                st.markdown("**Checklist que Roxy debe completar antes de mostrar una oportunidad**")
                st.markdown("\n".join(f"- {item}" for item in checklist))
            anti_patterns = teacher_playbook.get("anti_patterns") or []
            if anti_patterns:
                st.markdown("**Errores que Roxy debe bloquear**")
                st.markdown(
                    "\n".join(
                        f"- **{item.get('name')}**: {item.get('avoid')} -> {item.get('roxy_response')}"
                        for item in anti_patterns
                    )
                )

    material_library = load_study_material_library()
    with st.expander("Materiales de estudio analizados por Roxy", expanded=False):
        if not material_library:
            st.info(
                "Todavia no hay PDFs, imagenes o documentos indexados. El escaneo automatico los agregara al encontrarlos."
            )
        else:
            material_rows = []
            for item in material_library:
                metadata = item.get("metadata") or {}
                material_rows.append(
                    {
                        "archivo": Path(text_display(item.get("source_path"))).name,
                        "tipo": item.get("material_type") or metadata.get("kind"),
                        "temas": ", ".join(item.get("topics") or []),
                        "texto": item.get("text_chars"),
                        "procesado": item.get("processed_at"),
                        "notas": item.get("notes_path"),
                    }
                )
            st.dataframe(pd.DataFrame(material_rows), width="stretch", hide_index=True, height=240)
            material_names = [row["archivo"] for row in material_rows]
            selected_material = st.selectbox(
                "Abrir nota de material",
                material_names,
                key="study_material_library_select",
            )
            selected_item = next(
                (
                    item
                    for item in material_library
                    if Path(text_display(item.get("source_path"))).name == selected_material
                ),
                material_library[0],
            )
            note_text = read_video_learning_note(selected_item)
            if note_text:
                st.markdown(note_text)
            else:
                st.warning("Este material todavia no tiene nota legible generada.")

    video_library = load_video_learning_library()
    with st.expander("Biblioteca de videos estudiados por Roxy", expanded=False):
        scan_cols = st.columns([1, 1, 2])
        with scan_cols[0]:
            scan_limit = st.number_input(
                "Videos nuevos",
                min_value=1,
                max_value=5,
                value=1,
                step=1,
                key="video_learning_scan_limit",
            )
        with scan_cols[1]:
            transcribe_video = st.checkbox(
                "Transcribir audio",
                value=False,
                help="Mas lento, pero extrae conocimiento hablado si el video no tiene texto claro.",
                key="video_learning_transcribe_audio",
            )
        with scan_cols[2]:
            st.write("")
            st.write("")
            if st.button("Escanear videos ahora", key="scan_training_videos_now"):
                with st.spinner("Roxy esta revisando videos nuevos..."):
                    ok, output = run_video_learning_ingest(limit=int(scan_limit), transcribe=bool(transcribe_video))
                if ok:
                    st.success("Escaneo completado. La biblioteca se actualizara con los videos encontrados.")
                    if output:
                        st.code(output[-4000:])
                    st.rerun()
                else:
                    st.error("No se pudo completar el escaneo de videos.")
                    if output:
                        st.code(output[-4000:])
        if not video_library:
            st.info("Todavia no hay indice de videos. Usa el boton de escaneo para procesar el primer video nuevo.")
        else:
            rows = []
            for item in video_library:
                metadata = item.get("metadata") or {}
                rows.append(
                    {
                        "video": Path(text_display(item.get("source_path"))).name,
                        "duracion_min": metadata.get("duration_minutes"),
                        "temas": ", ".join(item.get("topics") or []),
                        "frames": item.get("frames_count"),
                        "ocr": item.get("ocr_count"),
                        "procesado": item.get("processed_at"),
                        "notas": item.get("notes_path"),
                    }
                )
            st.dataframe(pd.DataFrame(rows), width="stretch", hide_index=True, height=240)
            video_names = [row["video"] for row in rows]
            selected_video = st.selectbox("Abrir nota de video", video_names, key="study_video_library_select")
            selected_item = next(
                (item for item in video_library if Path(text_display(item.get("source_path"))).name == selected_video),
                video_library[0],
            )
            note_text = read_video_learning_note(selected_item)
            if note_text:
                st.markdown(note_text)
            else:
                st.warning("Este video todavia no tiene nota legible generada.")


def show_focused_voice(brief: dict) -> None:
    st.markdown(
        f"""
        <div class="voice-desk-title">
          {roxy_avatar_html("speaking", "mini", "Roxy Voice Desk")}
          <div>
            <h3>Roxy Voice Desk</h3>
            <p>Respuesta operativa limpia: oportunidad actual, que falta y proximo paso.</p>
          </div>
        </div>
        """,
        unsafe_allow_html=True,
    )
    st.caption(
        "Respuesta operativa limpia: oportunidad actual, que falta y proximo paso. Los detalles tecnicos quedan ocultos."
    )
    try:
        from tools import voice_assistant as va
    except Exception as exc:
        st.error(f"Voice assistant unavailable: {exc}")
        return

    user = st.session_state.get("user")
    opportunity = (brief.get("opportunities") or [{}])[0] if brief.get("opportunities") else {}
    if opportunity:
        symbol = html.escape(text_display(opportunity.get("symbol") or opportunity.get("ticker") or "-"))
        decision = html.escape(text_display(opportunity.get("decision") or opportunity.get("action") or "Esperar"))
        setup = html.escape(text_display(opportunity.get("setup") or opportunity.get("strategy") or "-"))
        score = html.escape(text_display(opportunity.get("score") or opportunity.get("ai_score") or "-"))
        reason = html.escape(_summarize_voice_context(opportunity))
        st.markdown(
            f"""
            <div style="border:1px solid rgba(96,165,250,.34);border-radius:18px;padding:16px 18px;
                        background:linear-gradient(135deg,rgba(15,23,42,.94),rgba(30,41,59,.78));margin:10px 0 14px;">
              <div style="font-size:11px;text-transform:uppercase;letter-spacing:.08em;color:#93c5fd;font-weight:900;">Roxy esta mirando</div>
              <div style="display:flex;gap:12px;flex-wrap:wrap;align-items:flex-end;margin-top:8px;">
                <div style="font-size:30px;font-weight:950;color:#f8fafc;line-height:1;">{symbol}</div>
                <div style="padding:5px 10px;border-radius:999px;background:rgba(251,191,36,.18);color:#fde68a;font-weight:900;">{decision}</div>
                <div style="padding:5px 10px;border-radius:999px;background:rgba(59,130,246,.16);color:#bfdbfe;font-weight:800;">{setup}</div>
                <div style="padding:5px 10px;border-radius:999px;background:rgba(16,185,129,.14);color:#bbf7d0;font-weight:800;">Score {score}</div>
              </div>
              <div style="margin-top:10px;color:#cbd5e1;font-size:13px;line-height:1.35;">{reason}</div>
            </div>
            """,
            unsafe_allow_html=True,
        )
    quick_cols = st.columns(4)
    quick_prompts = [
        ("Ahora", "resumen de oportunidad"),
        ("Que falta", "que falta para operar la mejor oportunidad"),
        ("Salida", "como salgo a tiempo de la oportunidad actual"),
        ("Cuenta", "como esta mi cuenta"),
    ]
    for idx, (label, prompt) in enumerate(quick_prompts):
        with quick_cols[idx]:
            if st.button(label, key=f"voice_quick_{idx}", use_container_width=True):
                state = va.generate_reply_state(prompt, user=user, session_id=f"streamlit:{user or 'local'}")
                reply = state.get("reply", "")
                st.session_state["voice_last_state"] = state
                st.session_state["voice_last_reply"] = reply
                st.session_state["voice_last_query"] = prompt

    query = st.text_input(
        "Preguntar a Roxy",
        value=st.session_state.get("voice_last_query", ""),
        placeholder="Ejemplo: Roxy, explicame AAPL o que estas aprendiendo",
        key="focused_voice_query",
    )
    ask_cols = st.columns([1, 1, 2])
    with ask_cols[0]:
        if st.button("Preguntar", key="focused_voice_ask", use_container_width=True):
            state = va.generate_reply_state(query, user=user, session_id=f"streamlit:{user or 'local'}")
            reply = state.get("reply", "")
            st.session_state["voice_last_state"] = state
            st.session_state["voice_last_reply"] = reply
            st.session_state["voice_last_query"] = query
    with ask_cols[1]:
        auto_speak = st.toggle("Leer respuesta", value=True, key="focused_voice_auto_speak")

    reply = st.session_state.get("voice_last_reply")
    if reply:
        st.markdown("**Respuesta operativa de Roxy**")
        state = st.session_state.get("voice_last_state") or {}
        if isinstance(state, dict):
            with st.expander("Detalles tecnicos de voz", expanded=False):
                status_cols = st.columns(6)
                status_cols[0].metric("Intent", str(state.get("intent") or "-"))
                status_cols[1].metric("Voice", str(state.get("voice_style") or "-"))
                status_cols[2].metric("Avatar", str(state.get("avatar_state") or "-"))
                status_cols[3].metric("Emotion", str(state.get("emotion") or "-"))
                status_cols[4].metric("Safety", str(state.get("safety_level") or "-"))
                status_cols[5].metric("Live source", "Needed" if state.get("needs_live_source") else "OK")
                events = state.get("events") or []
                if isinstance(events, list) and events:
                    event_labels = [str(event.get("type") or "-") for event in events if isinstance(event, dict)]
                    st.caption("Voice events: " + " -> ".join(event_labels[:6]))
        st.info(reply)
        if auto_speak:
            speak_in_browser(str(reply), key="voice-panel")
        elif st.button("Leer ultima respuesta", key="focused_voice_speak_last"):
            speak_in_browser(str(reply), key="voice-panel-manual")

    with st.expander("Captura de voz"):
        st.caption(
            "Chrome puede transcribir tu voz aqui. Copia el texto a Preguntar a Roxy si Streamlit no lo llena automaticamente."
        )
        st.components.v1.html(
            """
            <div style="font-family: system-ui; color: #f8fafc;">
              <button id="roxy-start" style="padding:8px 12px;border-radius:8px;border:1px solid #64748b;background:#111827;color:#f8fafc;">Escuchar</button>
              <button id="roxy-stop" style="padding:8px 12px;border-radius:8px;border:1px solid #64748b;background:#111827;color:#f8fafc;">Parar</button>
              <div id="roxy-transcript" style="margin-top:10px;padding:10px;border:1px solid #334155;border-radius:8px;background:#0f172a;min-height:42px;">
                La transcripcion aparecera aqui.
              </div>
              <script>
                let recognition = null;
                const out = document.getElementById('roxy-transcript');
                const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
                if (SpeechRecognition) {
                  recognition = new SpeechRecognition();
                  recognition.lang = 'es-US';
                  recognition.interimResults = false;
                  recognition.continuous = false;
                  recognition.onresult = (event) => {
                    out.innerText = event.results[0][0].transcript;
                    navigator.clipboard?.writeText(event.results[0][0].transcript).catch(() => {});
                  };
                  recognition.onerror = (event) => {
                    out.innerText = 'Error: ' + event.error;
                  };
                } else {
                  out.innerText = 'El reconocimiento de voz no esta disponible en este navegador.';
                }
                document.getElementById('roxy-start').onclick = () => { if (recognition) recognition.start(); };
                document.getElementById('roxy-stop').onclick = () => { if (recognition) recognition.stop(); };
              </script>
            </div>
            """,
            height=170,
        )

    if opportunity:
        with st.expander("Contexto completo que esta leyendo Roxy", expanded=False):
            st.write(_summarize_voice_context(opportunity))


def portfolio_milestone_chart_frame(milestones: pd.DataFrame) -> pd.DataFrame:
    if milestones.empty or not {"stage", "target"}.issubset(milestones.columns):
        return pd.DataFrame()
    frame = milestones[["stage", "target"]].copy()
    frame["target"] = pd.to_numeric(frame["target"], errors="coerce")
    frame["target"] = frame["target"].map(
        lambda value: value if pd.notna(value) and math.isfinite(float(value)) else None
    )
    return frame.dropna(subset=["stage", "target"]).reset_index(drop=True)


def render_million_growth_plan_screen() -> None:
    st.subheader("Plan de capital 500 a 1M")
    st.warning(
        "Esto es un marco de riesgo, no una promesa. Con $500, la primera meta es proteger capital y probar el setup."
    )

    controls = st.columns([1, 1, 1])
    with controls[0]:
        starting_capital = st.number_input(
            "Capital inicial", min_value=100.0, max_value=100_000.0, value=500.0, step=50.0
        )
    with controls[1]:
        target_capital = st.number_input(
            "Meta de capital", min_value=1_000.0, max_value=5_000_000.0, value=1_000_000.0, step=10_000.0
        )
    with controls[2]:
        risk_pct_ui = st.slider("Riesgo por trade %", min_value=0.25, max_value=2.00, value=1.00, step=0.25)

    plan = build_million_growth_plan(
        starting_capital=starting_capital,
        target_capital=target_capital,
        risk_per_trade_pct=risk_pct_ui / 100.0,
    )

    kpis = st.columns(5)
    with kpis[0]:
        render_kpi_card("Inicio", num_display(plan["starting_capital"]))
    with kpis[1]:
        render_kpi_card("Meta", num_display(plan["target_capital"], 0))
    with kpis[2]:
        render_kpi_card("Multiplicador", f"{num_display(plan['multiplier'], 0)}x", tone="watch")
    with kpis[3]:
        render_kpi_card("Riesgo/trade", num_display(plan["risk_per_trade"]), detail=f"{risk_pct_ui:.2f}%")
    with kpis[4]:
        render_kpi_card("Stop diario", num_display(plan["daily_stop"]), tone="avoid", detail="2R max")

    guardrail = plan.get("guardrail") or {}
    if guardrail:
        st.markdown("**Gobernador de riesgo**")
        guard_cols = st.columns(4)
        with guard_cols[0]:
            render_kpi_card("Estado", guardrail.get("status"), tone="buy" if guardrail.get("allowed") else "avoid")
        with guard_cols[1]:
            render_kpi_card("1R max", num_display(guardrail.get("per_trade_budget")))
        with guard_cols[2]:
            render_kpi_card("2R stop diario", num_display(guardrail.get("daily_stop")), tone="avoid")
        with guard_cols[3]:
            render_kpi_card("Riesgo libre", num_display(guardrail.get("remaining_daily_risk")))
        st.caption(str(guardrail.get("message") or ""))

    steps = pd.DataFrame(
        [
            {
                "movimiento_neto": move,
                "pasos_ganadores_netos": steps_needed,
                "semanas_a_3_pasos": int(math.ceil((steps_needed or 0) / 3)) if steps_needed else 0,
            }
            for move, steps_needed in plan["steps_to_target"].items()
        ]
    )
    st.markdown("**Chequeo realista de crecimiento compuesto**")
    st.dataframe(steps, width="stretch", hide_index=True)

    milestones = pd.DataFrame(plan["milestones"])
    if not milestones.empty:
        chart_df = portfolio_milestone_chart_frame(milestones)
        chart_df["target_label"] = chart_df["target"].map(lambda value: f"${value:,.0f}")
        if not chart_df.empty:
            target_min = float(chart_df["target"].min())
            target_max = float(chart_df["target"].max())
            padding = max(1.0, (target_max - target_min) * 0.08)
            milestone_chart = (
                alt.Chart(chart_df)
                .mark_line(point=True, color="#38bdf8")
                .encode(
                    x=alt.X("stage:O", title="Etapa"),
                    y=alt.Y(
                        "target:Q",
                        title="Meta de cuenta",
                        scale=alt.Scale(domain=[max(0.0, target_min - padding), target_max + padding]),
                    ),
                    tooltip=["stage:O", "target_label:N"],
                )
            )
            st.altair_chart(milestone_chart.properties(height=280), width="stretch")

        display = milestones.copy()
        for col in ["from", "target", "risk_per_trade", "daily_stop"]:
            display[col] = display[col].map(lambda value: num_display(value))
        display = display.rename(
            columns={
                "stage": "etapa",
                "phase": "fase",
                "from": "desde",
                "target": "meta",
                "risk_per_trade": "riesgo_trade",
                "daily_stop": "stop_diario",
                "trades_2pct": "trades_2pct",
                "trades_5pct": "trades_5pct",
                "trades_10pct": "trades_10pct",
                "products": "productos",
                "rule": "regla",
            }
        )
        st.markdown("**Escalera de metas**")
        st.dataframe(
            display[
                [
                    "etapa",
                    "fase",
                    "desde",
                    "meta",
                    "riesgo_trade",
                    "stop_diario",
                    "trades_2pct",
                    "trades_5pct",
                    "trades_10pct",
                    "productos",
                    "regla",
                ]
            ],
            width="stretch",
            hide_index=True,
            height=360,
        )

    st.markdown("**Reglas Roxy para una cuenta de $500**")
    rule_cols = st.columns(2)
    for idx, rule in enumerate(plan["rules"]):
        with rule_cols[idx % 2]:
            render_kpi_card("Regla", rule, tone="watch" if idx < 3 else "neutral")

    st.info(
        "Para opciones, Roxy debe comparar perdida maxima por contrato contra el presupuesto de riesgo. "
        f"Con {risk_pct_ui:.2f}% de riesgo, el primer presupuesto es {num_display(plan['max_option_debit'])}."
    )
    st.caption(
        "Las reglas del broker importan: cambios de margen intradia en EE. UU. empezaron el 4 de junio de 2026, "
        "pero los brokers pueden transicionar hasta el 20 de octubre de 2027. Confirma con tu broker antes de asumir margen o day-trading."
    )


