def selected_dashboard_symbol(table: pd.DataFrame) -> str:
    if not isinstance(table, pd.DataFrame) or table.empty:
        return ""
    try:
        return text_display(table.iloc[0].get("symbol")).upper()
    except Exception:
        return ""


