def render_dashboard_action_queue(table: pd.DataFrame) -> None:
    if table.empty:
        return
    pulse = market_pulse_summary(table)
    readiness = num_display(pulse.get("avg_readiness"), 0)
    dominant_filter = text_display(pulse.get("top_gate"))
    header_status = (
        f"Operar {int(pulse.get('ready') or 0)} · "
        f"Vigilar {int(pulse.get('watch') or 0)} · "
        f"Evitar {int(pulse.get('avoid') or 0)} · "
        f"Readiness {readiness}"
    )
    if dominant_filter != "-":
        header_status += f" · Filtro {dominant_filter}"
    cards = []
    for rank, (_, item) in enumerate(table.head(3).iterrows(), start=1):
        row = item.to_dict()
        card_status = trade_decision_card_status(row)
        proximity_event = entry_proximity_alert_event(row)
        action = text_display(card_status.get("action") or human_trade_action(row))
        tone = text_display(card_status.get("tone") or signal_tone(row.get("signal", "")))
        if str(action).lower().startswith("esperar"):
            tone = "watch"
        symbol = text_display(row.get("symbol")).upper()
        strategy = dashboard_strategy_label(row)
        market = text_display(row.get("market")).upper()
        timeframe = text_display(row.get("timeframe") or row.get("tf"))
        context_line = " · ".join(part for part in [strategy, market, timeframe] if part and part != "-")
        market_slug = "crypto" if market.lower().startswith("crypto") or "/" in symbol else "stock"
        tf_slug = timeframe if timeframe != "-" else "1h"
        asset_href = f"?view=Activo&symbol={quote(symbol, safe='')}&market={quote(market_slug, safe='')}&tf={quote(tf_slug, safe='')}"
        score = num_display(row.get("ai_score") or row.get("score"), 0)
        readiness = num_display(row.get("readiness"), 0)
        risk = pct_display(row.get("risk_pct"))
        next_step = text_display(card_status.get("next_step") or row.get("waiting_for") or row.get("next") or row.get("gate") or "Confirmar estructura.")
        next_prefix = "Acción" if tone == "buy" else "Evitar" if tone == "avoid" else "Falta"
        entry_value = safe_float(card_status.get("entry") or row.get("entry") or row.get("current_price") or row.get("price"))
        stop_value = safe_float(card_status.get("stop") or row.get("stop"))
        target_value = safe_float(card_status.get("target_2") or row.get("target") or row.get("take_profit") or row.get("target_price"))
        entry = price_display(entry_value)
        stop = price_display(stop_value)
        target = price_display(target_value)
        target = target if target != "-" else "pendiente"
        rr_value = None
        if (
            entry_value is not None
            and stop_value is not None
            and target_value is not None
            and abs(entry_value - stop_value) > 0
        ):
            rr_value = abs(target_value - entry_value) / abs(entry_value - stop_value)
        rr_text = f"1:{rr_value:.2f}" if rr_value is not None else "pendiente"
        rank_label = "prioridad" if rank == 1 else "seguimiento" if rank == 2 else "alternativa"
        proximity_line = text_display(proximity_event.get("state"))
        proximity_detail = text_display(proximity_event.get("detail"))
        cards.append(
            f'<article class="dashboard-action-card dashboard-action-{html.escape(tone)}">'
            f'<span>{html.escape(action)}</span>'
            f'<i class="dashboard-action-rank">#{rank} {html.escape(rank_label)}</i>'
            f'<a class="dashboard-action-symbol" href="{html.escape(asset_href)}">{html.escape(symbol)}</a>'
            f'<small>{html.escape(context_line)}</small>'
            f'<p><strong>{html.escape(next_prefix)}:</strong> {html.escape(next_step[:100])}</p>'
            f'<p><strong>Entrada:</strong> {html.escape(proximity_line)} · {html.escape(proximity_detail[:90])}</p>'
            f'<em>Score {html.escape(score)} · Ready {html.escape(readiness)} · Riesgo {html.escape(risk)}</em>'
            f'<b>Entrada {html.escape(entry)} · Stop {html.escape(stop)} · Target {html.escape(target)} · R:R {html.escape(rr_text)}</b>'
            f'<a class="dashboard-action-cta" href="{html.escape(asset_href)}">Ver gráfica interactiva →</a>'
            "</article>"
        )
    st.markdown(
        '<section class="dashboard-action-queue">'
        f"<header><strong>Próximas decisiones</strong><span>{html.escape(header_status)}</span></header>"
        f'<div>{"".join(cards)}</div>'
        "</section>",
        unsafe_allow_html=True,
    )


def priority_trade_lane_rows(table: pd.DataFrame, *, limit_per_lane: int = 3) -> dict[str, list[dict[str, str]]]:
    lanes = {"operate": [], "watch": []}
    if not isinstance(table, pd.DataFrame) or table.empty:
        return lanes
    for _, item in table.iterrows():
        row = item.to_dict()
        card_status = trade_decision_card_status(row)
        action = text_display(card_status.get("action") or human_trade_action(row))
        tone = text_display(card_status.get("tone") or signal_tone(row.get("signal", "")))
        if str(action).lower().startswith("esperar"):
            tone = "watch"
        lane_key = "operate" if tone == "buy" or opportunity_is_trade_ready(row) else "watch" if tone == "watch" else ""
        if not lane_key or len(lanes[lane_key]) >= limit_per_lane:
            continue
        symbol = text_display(row.get("symbol")).upper()
        market = text_display(row.get("market")).upper()
        timeframe = text_display(row.get("timeframe") or row.get("tf"))
        strategy = dashboard_strategy_label(row)
        entry = price_display(card_status.get("entry") or row.get("entry") or row.get("current_price") or row.get("price"))
        stop = price_display(card_status.get("stop") or row.get("stop"))
        target = price_display(card_status.get("target_2") or row.get("target") or row.get("take_profit") or row.get("target_price"))
        readiness = num_display(row.get("readiness") or row.get("alert_readiness_score") or row.get("score"), 0)
        reason = text_display(
            card_status.get("next_step")
            or row.get("waiting_for")
            or row.get("next")
            or row.get("gate")
            or opportunity_reason_label(row)
        )
        market_slug = "crypto" if market.lower().startswith("crypto") or "/" in symbol else "stock"
        tf_slug = timeframe if timeframe != "-" else "1h"
        lanes[lane_key].append(
            {
                "symbol": symbol,
                "market": market,
                "timeframe": timeframe,
                "strategy": strategy,
                "action": action,
                "entry": entry,
                "stop": stop,
                "target": target if target != "-" else "pendiente",
                "readiness": readiness,
                "reason": reason,
                "href": f"?view=Activo&symbol={quote(symbol, safe='')}&market={quote(market_slug, safe='')}&tf={quote(tf_slug, safe='')}",
            }
        )
        if all(len(rows) >= limit_per_lane for rows in lanes.values()):
            break
    return lanes


def render_priority_trade_lanes(table: pd.DataFrame) -> None:
    lanes = priority_trade_lane_rows(table)

    def lane_cards(rows: list[dict[str, str]], lane: str) -> str:
        if not rows:
            empty = (
                "Sin entradas listas ahora; Roxy espera confirmacion 15m/1h."
                if lane == "operate"
                else "Sin vigilancia priorizada en este scan."
            )
            return f'<div class="priority-lane-empty">{html.escape(empty)}</div>'
        cards = []
        for row in rows:
            cards.append(
                f'<article class="priority-trade-card priority-trade-{html.escape(lane)}">'
                f'<a href="{html.escape(row["href"])}">{html.escape(row["symbol"])}</a>'
                f'<span>{html.escape(row["action"])} · {html.escape(row["strategy"])} · {html.escape(row["timeframe"])}</span>'
                f'<p>{html.escape(row["reason"][:118])}</p>'
                f'<b>Entrada {html.escape(row["entry"])} · Stop {html.escape(row["stop"])} · Salida {html.escape(row["target"])}</b>'
                f'<small>Readiness {html.escape(row["readiness"])} · {html.escape(row["market"])}</small>'
                "</article>"
            )
        return "".join(cards)

    st.markdown(
        '<section class="priority-trade-lanes">'
        '<header><strong>Operar ahora / vigilar</strong><span>Separado por accion inmediata; solo paper/manual.</span></header>'
        '<div class="priority-lane-grid">'
        '<div><h4>Operar ahora</h4>'
        f'{lane_cards(lanes["operate"], "operate")}</div>'
        '<div><h4>Vigilar</h4>'
        f'{lane_cards(lanes["watch"], "watch")}</div>'
        "</div></section>",
        unsafe_allow_html=True,
    )


def render_opportunity_ranking_panel(
    table: pd.DataFrame,
    *,
    account_equity: float | None = None,
    risk_pct: float | None = None,
) -> None:
    equity = safe_float(account_equity)
    if equity is None:
        equity = safe_float(st.session_state.get("command_equity")) or 100.0
    risk_fraction = safe_float(risk_pct)
    if risk_fraction is None:
        risk_fraction = (safe_float(st.session_state.get("command_risk")) or 1.0) / 100.0
    rows = opportunity_ranking_rows(table, limit=8, account_equity=equity, risk_pct=risk_fraction)
    if rows.empty:
        st.caption(
            f"Ranking 2.1 ajustado a capital ${equity:,.2f}: sin oportunidades con entrada, stop y recompensa medible "
            "en este scan. Paper/manual; no ejecuta orden real."
        )
        return
    st.markdown("**Mejores oportunidades ahora**")
    st.caption(
        f"Ranking 2.1 ajustado a capital ${equity:,.2f} y 1R ${equity * risk_fraction:,.2f}. "
        "Prioriza oportunidades que caben en tu presupuesto, con stop y recompensa medible. Paper/manual; no ejecuta orden real."
    )
    display = rows.drop(columns=[column for column in ["_sort"] if column in rows.columns]).copy()
    column_config: dict[str, Any] = {
        "Activo": st.column_config.LinkColumn("Activo", display_text="Abrir plan", width="small"),
        "TradingView": st.column_config.LinkColumn("TradingView", display_text="Chart", width="small"),
        "Por que": st.column_config.TextColumn("Por que", width="large"),
        "Confirmacion": st.column_config.TextColumn("Confirmacion", width="large"),
        "Siguiente paso": st.column_config.TextColumn("Siguiente paso", width="large"),
        "Memoria setup+fuente": st.column_config.TextColumn("Memoria setup+fuente", width="medium"),
        "TV Webhook": st.column_config.TextColumn("TV Webhook", width="medium"),
        "Zona entrada": st.column_config.TextColumn("Zona entrada", width="medium"),
        "Capital fit": st.column_config.TextColumn("Capital fit", width="small"),
        "Producto": st.column_config.TextColumn("Producto", width="small"),
    }
    for column in ["Entrada", "Stop", "Target 2%", "Target 5%", "Target 10%", "Capital usado", "Riesgo $", "Ganancia 2% $"]:
        if column in display.columns:
            display[column] = pd.to_numeric(display[column], errors="coerce")
            column_config[column] = st.column_config.NumberColumn(column, format="$%.2f", width="small")
    for column in ["R:R 2%", "R:R presupuesto"]:
        if column in display.columns:
            display[column] = pd.to_numeric(display[column], errors="coerce")
            column_config[column] = st.column_config.NumberColumn(column, format="1:%.2f", width="small")
    if "Tamano" in display.columns:
        display["Tamano"] = pd.to_numeric(display["Tamano"], errors="coerce")
        column_config["Tamano"] = st.column_config.NumberColumn("Tamano", format="%.4f", width="small")
    if "Riesgo" in display.columns:
        display["Riesgo"] = pd.to_numeric(display["Riesgo"], errors="coerce")
        column_config["Riesgo"] = st.column_config.NumberColumn("Riesgo", format="%.2f%%", width="small")
        display["Riesgo"] = display["Riesgo"] * 100.0
    if "Readiness" in display.columns:
        display["Readiness"] = pd.to_numeric(display["Readiness"], errors="coerce").fillna(0).clip(0, 100)
        column_config["Readiness"] = st.column_config.ProgressColumn("Readiness", min_value=0, max_value=100, format="%d%%")
    st.dataframe(
        display,
        width="stretch",
        hide_index=True,
        height=min(430, 80 + 34 * len(display)),
        column_config=column_config,
    )


def render_paper_readiness_gap_panel(table: pd.DataFrame) -> None:
    rows = paper_readiness_gap_rows(table, limit=8)
    st.markdown("**Por que no esta lista para paper**")
    if rows.empty:
        st.info(
            "Sin oportunidades suficientes para diagnosticar paper readiness en este momento. "
            "Roxy espera fuente live, TradingView/BUY, plan READY, precio en zona y R:R valido."
        )
        return
    ready_count = int(rows["Listo paper"].astype(str).eq("SI").sum()) if "Listo paper" in rows.columns else 0
    missing_counts: dict[str, int] = {}
    for value in rows.get("Faltan", pd.Series(dtype=str)).astype(str).tolist():
        for item in value.split("|"):
            clean = item.strip()
            if clean and clean != "-":
                missing_counts[clean] = missing_counts.get(clean, 0) + 1
    top_missing = sorted(missing_counts.items(), key=lambda item: item[1], reverse=True)[:3]
    top_missing_text = ", ".join(f"{name} ({count})" for name, count in top_missing) or "sin bloqueos visibles"
    st.caption(
        f"Diagnostico de monetizacion: {ready_count} listas en la muestra; principales faltantes: {top_missing_text}. "
        "TradingView BUY fresco puede confirmar WATCH, pero solo con fuente live, plan READY, precio en zona y R:R valido."
    )
    display = rows.drop(columns=[column for column in ["_sort"] if column in rows.columns]).copy()
    column_config: dict[str, Any] = {
        "Bloqueo principal": st.column_config.TextColumn("Bloqueo principal", width="large"),
        "Faltan": st.column_config.TextColumn("Faltan", width="large"),
        "Confirmado": st.column_config.TextColumn("Confirmado", width="large"),
        "Siguiente paso": st.column_config.TextColumn("Siguiente paso", width="large"),
        "Readiness": st.column_config.ProgressColumn("Readiness", min_value=0, max_value=100, format="%d%%"),
    }
    for column in ["Entrada", "Stop", "Target 2%"]:
        if column in display.columns:
            display[column] = pd.to_numeric(display[column], errors="coerce")
            column_config[column] = st.column_config.NumberColumn(column, format="$%.2f", width="small")
    if "R:R 2%" in display.columns:
        display["R:R 2%"] = pd.to_numeric(display["R:R 2%"], errors="coerce")
        column_config["R:R 2%"] = st.column_config.NumberColumn("R:R 2%", format="1:%.2f", width="small")
    if "Riesgo" in display.columns:
        display["Riesgo"] = pd.to_numeric(display["Riesgo"], errors="coerce") * 100.0
        column_config["Riesgo"] = st.column_config.NumberColumn("Riesgo", format="%.2f%%", width="small")
    st.dataframe(
        display,
        width="stretch",
        hide_index=True,
        height=min(410, 82 + 34 * len(display)),
        column_config=column_config,
    )


def render_tradingview_webhook_panel(rows: pd.DataFrame | None = None) -> None:
    data = rows if isinstance(rows, pd.DataFrame) else cached_tradingview_webhook_rows()
    st.markdown("**TradingView Webhooks**")
    st.caption(
        "Confirmacion entrante 15m/1h para ranking y Trade Decision Card. Solo analisis/paper; no ejecuta orden real."
    )
    try:
        from tools.tradingview_tunnel import tradingview_tunnel_readiness

        tunnel_status = tradingview_tunnel_readiness()
    except Exception as exc:
        tunnel_status = {
            "ready": False,
            "public_webhook_url_safe": "",
            "recommended_tool": "diagnostico",
            "suggested_command": "make tradingview-tunnel-check",
            "next_action": f"No se pudo leer tunnel: {exc}",
        }
    bridge_secret_configured = bool(text_display(os.getenv("TRADINGVIEW_WEBHOOK_SECRET")))
